CREATE TABLE IF NOT EXISTS `${schema}` (
  id bigint(20) AUTO_INCREMENT,
  uid BIGINT NOT NULL UNIQUE,
  owner_uid bigint(20),
  creator_uid bigint(20),
  agenda_uid bigint(20),
  location_uid bigint(20),
  slug VARCHAR(255) NOT NULL UNIQUE,
  title VARCHAR(2000) NOT NULL,
  description VARCHAR(2000) NOT NULL,
  long_description TEXT,
  keywords VARCHAR(2000),
  conditions VARCHAR(2000),
  image VARCHAR(1500),
  draft TINYINT(1) DEFAULT 1,
  private TINYINT(1) DEFAULT 0,
  timezone VARCHAR(255) NOT NULL,
  timings TEXT,
  accessibility VARCHAR( 100 ),
  age VARCHAR( 50 ),
  registration VARCHAR(2000),
  `references` VARCHAR(2000),
  links TEXT,
  created_at DATETIME NOT NULL,
  updated_at DATETIME NOT NULL,
  deleted_at DATETIME,
  file_key varchar(32),
  UNIQUE INDEX id_idx (id),
  UNIQUE INDEX uid_idx (uid),
  UNIQUE INDEX slug_idx (slug),
  INDEX agenda_uid_idx (agenda_uid),
  INDEX owner_uid_idx (owner_uid),
  INDEX location_uid_idx (location_uid)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;



(146173, 3564473, 77814844, 73237661, 73783828, 'a-fancy_194', '{"fr":"A Fancy"}', '{"fr":"Musiques de scène anglaises de la fin du XVIIe siècle"}', '{"fr":"_A FANCY, version chambriste_\\n\\nLe Caravansérail\\n\\nBertrand Cuiller, direction et clavecin\\n\\nRachel Redmond, soprano\\n\\net 6 instrumentistes\\n\\nA la fin du XVIIe siècle à Londres, l’opéra entièrement chanté, venu d’Italie, prenait peu à peu la place du masque, genre typiquement anglais mêlant le parlé au chanté, dans le cœur du public londonien.\\n\\nDes personnages d’Ariel, Milcha ou des Diables dans une Tempête héritée de Shakespeare, à une Venus présentée dans un sublime écrin orchestral dans Psyché, Matthew Locke et ses collègues Reggio, Banister, Hart et Humphrey nous font voyager dans un monde onirique où s’entremêlent des chants aux sonorités naïves à des pièces orchestrales de la plus grande richesse : ouverture plantureuse, danse sensuelle ou endiablée, fantaisie, ou canon spéculatif - voire rude. Ces compositeurs s’inscrivent dans la juste évolution de la musique anglaise, restée depuis le 16e siècle aussi intelligente que touchante.\\n\\nA son tour, Louis Grabu, un français à Londres, nous plonge dans les tréfonds de l’âme humaine avec l’air d’Augusta dans Albion et Albanius, et son accompagnement d’orchestre rappelant certaines pages de la Médée de Charpentier.\\n\\nHenry Purcell, de son côté, nous invite dans une perfection où rythme, harmonie et mélodie trouvent leur juste équilibre. Il ouvre les portes d’un opéra anglais, qui se refermeront malheureusement à sa mort.\\n\\nŒuvres extraites de :\\n\\nMatthew Locke : The Tempest (1674), Psyche (1675), The Rare Theatrical\\n\\nLouis Grabu : Albion and Albanius\\n\\nHenry Purcell, G B Draghi : The Theater of Music (1685 à 1687)\\n\\nHenry Purcell : Timon of Athens, Abdelazer, The Virtuous Wife, Regulus\\n\\nJohn Blow : Venus & Adonis\\n\\n_Pour A Fancy - version chambriste, Le Caravansérail bénéficie de l’aide au projet de la DRAC Ile de France_"}', '{"fr":[ "purcell","locke", "baroque", "soprano", "musique de chambre" ] }', NULL, '{"filename":"event_a-fancy_194_63588.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-fancy_194_63588.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-fancy_194_63588.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-11-20T16:00:00.000Z","end":"2016-11-20T17:00:00.000Z"},{"begin":"2016-11-20T17:00:00.000Z","end":"2016-11-20T17:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '[]', '2016-11-04 09:19:42', '2016-11-04 09:19:42', NULL ),

(146007, 64549836, 37874488, NULL, 8686304, 'a-la-decouverte-d-activites-numeriques-innovantes', '{"fr":"A la découverte d''activités numériques innovantes !"}', '{"fr":"Venez découvrir en famille des activité numériques innovantes.  L''objet prend une dimension différente grâce au numérique."}', '{"fr":"Nous vous proposons de découvrir des nouvelles pratiques numériques avec les ateliers suivants :\\n\\n- Découpe numérique au fil chaud (réalisation d''objets à l''aide de la minicut2d)  \\n- Immersion en réalité augmentée (avec l’utilisation de cardboards)  \\n- Parcours d''agilité à partir de robots connectés (Olie & Sphéro)  \\n- Conception de petits circuits électroniques (découverte)  \\n- Apprendre à utiliser l''Arduino (atelier basique pour enfants 6 -9 ans)  \\n- Utiliser la conductivité électrique lors du CollaboThon (jeu collaboratif sportif sur base de Makey Makey et scratch)  \\n- Course de robots dessinateurs réalisés par les enfants"}', '{}', NULL, '{"filename":"event_a-la-decouverte-d-activites-numeriques-innovantes_729193.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-la-decouverte-d-activites-numeriques-innovantes_729193.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-la-decouverte-d-activites-numeriques-innovantes_729193.jpg","size":{"height":null,"width":null}}]}', 0, 1, 'Europe/Paris', '[{"begin":"2016-10-12T11:30:00.000Z","end":"2016-10-12T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '[]', '2016-11-04 09:19:50', '2016-11-04 09:19:50', NULL ),
(147530, 48641508, 15723194, NULL, 17083912, 'a-la-decouverte-de-metiers-du-moyen-age-originaux-et-insolites', '{"fr":"A la découverte de métiers du Moyen-Âge originaux et insolites"}', '{"fr":"Initiation aux techniques des métiers du Moyen-Âge..."}', '{"fr":"Munis d’un diplôme de chevalier, initiez-vous aux techniques des métiers pratiqués au Moyen-Âge : technique de la corderie, du cuir, de la cotte de maille. Vous confectionnerez une bourse de cuir et  sa  cordelette servant à conserver les échantillons des anneaux que vous aurez fabriqués. Les usages des plantes médicinales médiévales n’auront plus de secret pour vous : la Compagnie de Roland guidera et accompagnera ces découvertes."}', '{"fr":[ "famille", "animation", "enfant", "monument" ] }', NULL, '{"filename":"event_a-la-decouverte-de-metiers-du-moyen-age-originaux-et-insolites_274260.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-la-decouverte-de-metiers-du-moyen-age-originaux-et-insolites_274260.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-la-decouverte-de-metiers-du-moyen-age-originaux-et-insolites_274260.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T12:00:00.000Z","end":"2016-10-22T14:30:00.000Z"},{"begin":"2016-10-23T12:00:00.000Z","end":"2016-10-23T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":14}', '["02 54 20 27 18","http://www.fougeres-sur-bievre.fr"]', '2016-11-04 09:18:28', '2016-11-04 09:18:28', NULL ),
(145565, 93890465, 91869064, NULL, 47895599, 'a-la-decouverte-de-notre-dame-du-haut', '{"fr":"Visite architecturale \\"A la découverte de Notre-Dame-du-Haut\\""}', '{"fr":"visite artistique et culturelle"}', '{"fr":"Pendant plus de deux heures les 25 collégiens de 3e du  Collège Lucie Aubrac seront accompagnés par  Karine Terral architecte conseiller au CAUE du Doubs pour découvrir la colline et plus particulièrement la chapelle de Notre-Dame-du-Haut. Seront abordés le rapport au site, les péripéties de la commande, le comment ça tient, pour finir sur l''esthétique et les émotions que cette architecture suscite.\\n\\nCette visite s''inscrit  dans le cadre du projet artistique et culturel « Habitat durable »  accompagné par le CAUE tout le long de l''année avec vendredi 14 octobre une journée spéciale sur la découverte de Le Corbusier, le matin étant consacré à son \\"cabanon\\"."}', '{"fr":", visite"}', NULL, '{"filename":"event_a-la-decouverte-de-notre-dame-du-haut_489066.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-la-decouverte-de-notre-dame-du-haut_489066.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-la-decouverte-de-notre-dame-du-haut_489066.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T11:30:00.000Z","end":"2016-10-14T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["03 81 82 71 14","caue25-sensibilisation@wanadoo.fr"]', '2016-11-04 09:20:10', '2016-11-04 09:20:10', NULL ),
(146567, 63992802, 34255101, 27545135, 37403200, 'a-la-decouverte-des-energies_85', '{"fr":"A la découverte des énergies"}', '{"fr":"Venez découvrir les différentes sources d''énergie en réalisant de nombreuses expériences scientifiques et ludiques!"}', '{"fr":"Venez découvrir les différentes sources d''énergie en réalisant de nombreuses expériences scientifiques et ludiques. Qu''est ce que l''énergie? D''où vient elle? Comment la produit on? Nous vous invitons à répondre à toutes ces questions grâce au parcours d''animations, et à remplir notre quizz qui vous permettra de gagner des pass pour le Vaisseau!"}', '{"fr":", Energie - Production - Expériences scientifiques - pass Vaisseau"}', NULL, '{"filename":"event_a-la-decouverte-des-energies_85_156790.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-la-decouverte-des-energies_85_156790.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-la-decouverte-des-energies_85_156790.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":1,"max":99}', '[]', '2016-11-04 09:19:23', '2016-11-04 09:19:23', NULL ),
(146692, 73468357, 38565623, 27545135, 73524367, 'a-la-decouverte-des-requins-et-des-raies-de-martinique', '{"fr":"A la découverte des requins et des raies de Martinique"}', '{"fr":"Conférence sur les requins et les raies."}', '{"fr":"Conférence grand public sur les requins et les raies. Présentation générale sur leur rôle dans les écosystèmes marins, présentation des études réalisées en Martinique et sur l’ensemble des Antilles françaises (méthodes, résultats).\\n\\nIntervenante : Océane Beaufort, Coordinatrice du REGUAR (réseau requins des Antilles françaises)"}', '{"fr":",    Raie,   Requin,  écosystèmes marins, Martinique"}', NULL, '{"filename":"event_a-la-decouverte-des-requins-et-des-raies-de-martinique_826888.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-la-decouverte-des-requins-et-des-raies-de-martinique_826888.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-la-decouverte-des-requins-et-des-raies-de-martinique_826888.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["0690 080 544","http://www.reguar.org"]', '2016-11-04 09:19:16', '2016-11-04 09:19:16', NULL ),
(145599, 16319926, 14933280, NULL, 54464225, 'a-la-decouverte-du-ciel-d-automne_571', '{"fr":"A la découverte du ciel d''automne"}', '{"fr":"Balade céleste commentée et observation du ciel nocturne aux télescopes"}', '{"fr":"Comme l’ont fait tous les hommes à travers les âges, levez les yeux vers le ciel à l’occasion de de cette soirée et venez découvrir, à l’œil nu puis au télescope, les splendeurs du ciel d’automne.\\n\\nCette soirée débutera par une balade céleste commentée qui sera l’occasion de découvrir à l’œil nu les principales constellations et certains des astres observables à cette période de l’année, mais également de présenter les grands principes régissant la vie et la mort des étoiles. Dans un deuxième temps, l’observation au télescope permettra de découvrir les paysages de notre seul satellite naturel, la Lune, de s''intéresser à notre proche voisine, la planète Mars, et également de mieux apprécier la beauté de la nébuleuse de la Lyre, du double amas de Persée ainsi que de celui des Pléiades, ou bien encore de la grande galaxie d’Andromède."}', '{"fr":"astronomie, observation, télescope, ciel, univers"}', NULL, '{"filename":"event_a-la-decouverte-du-ciel-d-automne_571_982573.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-la-decouverte-du-ciel-d-automne_571_982573.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-la-decouverte-du-ciel-d-automne_571_982573.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T18:30:00.000Z","end":"2016-10-15T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":3,"max":99}', '["clubvega83@free.fr","0661440638"]', '2016-11-04 09:20:08', '2016-11-04 09:20:08', NULL ),
(147516, 39902297, 15723194, NULL, 41953567, 'a-la-recherche-du-temps-passe', '{"fr":"A la recherche du temps passé..."}', '{"fr":"A cette occasion, venez découvrir ou redécouvrir ce site gallo-romain unique en famille..."}', '{"fr":"Au son des romains\\n\\nQuels étaient les sons qui rythmaient la vie des gallo- romains ? Préparez-vous à écouter et jouer sur la musique de cette époque.\\n\\nAtelier à 14h30 - Pour les 7-13 ans - 2h d’atelier. Places limitées - Réservation conseillée\\n\\nUne fouille qui en dit long…\\n\\nPour devenir un archéologue hors pair, venez partager un moment de fouilles sur le site ! Un archéologue du site vous montrera les ficelles du métier pour mettre au jour les objets enfouis. Que vous raconteront-ils ? A vous de le découvrir !\\n\\nAtelier à 14h30 - Pour les 7-13 ans - 2h d’atelier. Places limitées - Réservation conseillée\\n\\nSur la piste de Sanxay\\n\\nProfitez d’un grand jeu de piste pour découvrir le site et en apprendre un peu plus sur la place du spectacle à l’époque gallo-romaine.\\n\\nPour les 10-15 ans - 2h de jeu de piste pendant les horaires d’ouverture du site.\\n\\nLes enfants doivent être accompagnés d’un adulte."}', '{"fr":"animation, enfant, monument, famille"}', NULL, '{"filename":"event_a-la-recherche-du-temps-passe_277627.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_a-la-recherche-du-temps-passe_277627.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_a-la-recherche-du-temps-passe_277627.jpg","size":{"height":null,"width":null}}]}', 0, 1, 'Europe/Paris', '[{"begin":"2016-10-22T12:30:00.000Z","end":"2016-10-22T15:30:00.000Z"},{"begin":"2016-10-23T12:30:00.000Z","end":"2016-10-23T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":7,"max":15}', '["05 49 53 61 48","http://www.sanxay.fr"]', '2016-11-04 09:18:29', '2016-11-04 09:18:29', NULL ),
(146750, 1517683, 67195558, 27545135, 25756772, 'a-luzech-portes-ouvertes-au-musee-la-planete-des-moulins', '{"fr":"A Luzech, portes ouvertes au musée \\"La Planète des Moulins\\""}', '{"fr":"Portes ouvertes"}', '{"fr":"Découvrez de façon très concrète l''histoire de la domestication des énergies naturelles : humaine, animale, hydraulique et éolienne. Manipulez de nombreuses maquettes animées. Le musée vous propose une initiation par expérimentation de l''observation d''une riche collection des petits moulins domestiques ou artisanaux.\\n\\nRenseignements : 06 80 83 24 24 / [laplanetedesmoulins@wanadoo.fr](mailto:laplanetedesmoulins@wanadoo.fr)\\n\\nwww.museelaplanetedesmoulins.fr"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-09T12:00:00.000Z","end":"2016-10-09T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:12', '2016-11-04 09:19:12', NULL ),
(146834, 2994107, 56882225, NULL, 78444871, 'aborder-autrement-les-transitions-numeriques-20-octobre-2016', '{"fr":"“Aborder autrement les transitions numériques\\" (20 octobre 2016)"}', '{"fr":"Journée contributive organisée par la FING"}', '{"fr":"L’angle des travaux, \\"Think Small\\", s’avère très fertile pour aborder autrement les transitions numériques.\\n\\nLa journée permettra d’en approfondir les dimensions technologiques, économiques, politiques, sociales, territoriales, d’en caractériser les figures marquantes et la portée stratégique.\\n\\nPour plus d''informations, cliquez [ici](http://fing.org/?Journee-contributive-Questions).\\n\\nCet événement est une formation. Pour vous inscrire, contactez votre [chargé-e de formation](http://planet.loire-atlantique.fr/group/cg44/alize?p_p_id=alize_WAR_alizeportlet&p_p_lifecycle=0&p_p_state=normal&_alize_WAR_alizeportlet_url=http%3A%2F%2Fsso-planet-alize.loire-atlantique.fr%2Fjcms%2Fplanet_807957%2Fvos-contacts-pour-vous-inscrire-en-formation#p_alize_WAR_alizeportlet) du service emploi et compétences ou du service ressources."}', '{}', NULL, '{"filename":"event_aborder-autrement-les-transitions-numeriques-20-octobre-2016_342502.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_aborder-autrement-les-transitions-numeriques-20-octobre-2016_342502.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_aborder-autrement-les-transitions-numeriques-20-octobre-2016_342502.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-20T07:30:00.000Z","end":"2016-10-20T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":17}', '["http://planet.loire-atlantique.fr/group/cg44/alize?p_p_id=alize_WAR_alizeportlet&p_p_lifecycle=0&p_p_state=normal&_alize_WAR_alizeportlet_url=http%3A%2F%2Fsso-planet-alize.loire-atlantique.fr%2Fjcms%2Fplanet_807957%2Fvos-contacts-pour-vous-inscrire-en-for"]', '2016-11-04 09:19:08', '2016-11-04 09:19:08', NULL ),
(147407, 31638453, 29067808, 19108949, 11651637, 'abou-diarra-au-hangar', '{"fr":"Abou Diarra en concert au Hangar d''Ivry-sur-Seine"}', '{"fr":"Concert pour la sortie du nouvel album \\"Koya\\""}', '{"fr":"ABOU DIARRA compte parmi ces artistes rares qui ne s’engagent dans un nouveau projet, qu’après y avoir été poussés par une nécessité intérieure profonde. \\"KOYA\\", ainsi nommé pour rendre hommage à sa mère éponyme, s’inscrit dans la continuité d’une longue réflexion musicale, en même temps qu’il emprunte de nouvelles directions. Pour la première fois, Abou se confronte aux tissages de samples de Nicolas Repac, à ses grooves plus electro, mais aussi au blues de l’harmoniciste Vincent Bucher. Pour autant, au kamele n’goni comme au chant, habilement soutenu par Toumani Diabaté, et les musiciens du Donko Band, il ne s’écarte jamais d’une spiritualité musicale authentiquement malienne."}', '{}', NULL, '{"filename":"event_abou-diarra-au-hangar_863813.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_abou-diarra-au-hangar_863813.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_abou-diarra-au-hangar_863813.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-18T19:30:00.000Z","end":"2016-11-18T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":4,"max":25}', '["http://www.lehangar94.fr/hangar/concerts/abou-diarra-evenement-rfi"]', '2016-11-04 09:18:35', '2016-11-04 09:18:35', '2016-11-07 09:18:35' ),
(147408, 68645096, 29067808, 19108949, 7084801, 'abou-diarra-en-concert-au-festival-africolor', '{"fr":"Abou Diarra en concert au Festival Africolor"}', '{"fr":"Concert pour la sortie du nouvel album \\"Koya\\""}', '{"fr":"Abou Diarra est un artiste libre et curieux qui joue le kamele ngoni (luth/harpe). Telle qu’il la raconte, sa vie s’est déroulée dans une atemporalité où le pouvoir des images, de la parole et des symboles se révèlent un marqueur de sa musique aux rondeurs de la tradition mandingue ainsi qu’à une créativité moderne. En effet, Nicolas Repac, arrangeur de ce quatrième album, baptisé Koya, du nom de la mère d’Abou, a su dynamiser sa musique, en l’habillant de touches d’électro discrètes, sans jamais la trahir ou la dénaturer ni entamer son balancement caractéristique. L’harmonica de Vincent Bucher ajoute à la tonalité blues de l’album, tandis que le griot Toumani Diabaté joue de la kora sur deux titres, Djarabi et Labanko. Et bien sûr, les complices de longue date qui l’accompagnent aussi sur scène, Daouda Dembelé à la guitare et Moussa Koita aux claviers, sont venus prêter leur renfort sur ce nouvel album très réussi.\\n\\nFormé par un maître virtuose et aveugle, connu sous le pseudonyme de «Vieux Kanté – sans commentaire», il a sillonné, pendant plusieurs mois, les routes d’Abidjan-Bamako-Conakry à pied, accompagné de son seul instrument. Traversant les villages les plus reculés d’Afrique de l’Ouest comme les mégalopoles modernes, il y a puisé tour à tour des sons cachés traditionnels et des musiques urbaines contemporaines. Sa musique parle du voyage, de l’exil, du mouvement."}', '{}', NULL, '{"filename":"event_abou-diarra-en-concert-au-festival-africolor_191206.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_abou-diarra-en-concert-au-festival-africolor_191206.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_abou-diarra-en-concert-au-festival-africolor_191206.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-12-24T17:30:00.000Z","end":"2016-12-24T00:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":4,"max":25}', '["http://www.africolor.com/artiste/abou-diarra/"]', '2016-11-04 09:18:35', '2016-11-04 09:18:35', NULL ),
