(146399, 74935370, 97862464, NULL, 14047593, 'accentus-et-arsys-bourgogne-au-carre-belle-feuille', '{"fr":"Accentus et Arsys Bourgogne au Carré Belle Feuille"}', '{"fr":"Les plus grandes pages du romantisme allemand"}', '{"fr":"**Accentus / Arsys Bourgogne**\\n\\nMonuments sonores du romantisme allemand\\n\\nVendredi 4 novembre à 20h30\\n\\nLes chanteurs d’accentus et d’Arsys Bourgogne s’associent pour offrir les plus grandes pages du romantisme allemand pour double et triple choeur !\\n\\nCe programme regroupe les oeuvres monumentales, antiphoniques, des compositeurs romantiques allemands : Cornelius, Schumann, Brahms et Reger.\\n\\n**Avant-concert à 19h30 au Carré Club**"}', '{}', NULL, '{"filename":"event_accentus-et-arsys-bourgogne-au-carre-belle-feuille_467047.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_accentus-et-arsys-bourgogne-au-carre-belle-feuille_467047.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_accentus-et-arsys-bourgogne-au-carre-belle-feuille_467047.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-04T18:30:00.000Z","end":"2016-11-04T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":16}', '["0155185400"]', '2016-11-04 09:19:32', '2016-11-04 09:19:32', NULL ),
(147174, 17689936, 31245604, NULL, 35621340, 'accrochage-oeuvre-du-mois-de-novembre', '{"fr":"Accrochage \\"Oeuvre du mois\\" de novembre"}', '{"fr":"Quand les œuvres racontent des histoires : conte d''Halloween au musée !!"}', '{"fr":"**Œuvre du mois spéciale familles**\\n\\n**_\\"Comment une simple ferme peut devenir l''antre d''une sorcière\\"_**\\n\\nAu travers d''un conte, Juliette Catalan, médiatrice, fera découvrir une œuvre du musée. **Des histoires à faire peur... un peu, beaucoup, pour petits et grands !**\\n\\n**Mercredi 2 novembre à 18h /** Entrée libre et gratuite pour le conte.\\n\\nLégende du visuel : Jean Daullé d''après Teniers, _La Ménagère flamande_, Abbeville, Musée Boucher-de-Perthes (détails)."}', '{"fr":", halloween"}', NULL, '{"filename":"event_accrochage-oeuvre-du-mois-de-novembre_918583.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_accrochage-oeuvre-du-mois-de-novembre_918583.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_accrochage-oeuvre-du-mois-de-novembre_918583.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-16T13:00:00.000Z","end":"2016-11-16T17:00:00.000Z"},{"begin":"2016-11-02T17:00:00.000Z","end":"2016-11-02T18:00:00.000Z"},{"begin":"2016-11-14T13:00:00.000Z","end":"2016-11-14T17:00:00.000Z"},{"begin":"2016-11-30T13:00:00.000Z","end":"2016-11-30T17:00:00.000Z"},{"begin":"2016-11-13T13:00:00.000Z","end":"2016-11-13T17:00:00.000Z"},{"begin":"2016-11-27T13:00:00.000Z","end":"2016-11-27T17:00:00.000Z"},{"begin":"2016-11-12T13:00:00.000Z","end":"2016-11-12T17:00:00.000Z"},{"begin":"2016-11-25T13:00:00.000Z","end":"2016-11-25T17:00:00.000Z"},{"begin":"2016-11-11T13:00:00.000Z","end":"2016-11-11T17:00:00.000Z"},{"begin":"2016-11-23T13:00:00.000Z","end":"2016-11-23T17:00:00.000Z"},{"begin":"2016-11-10T13:00:00.000Z","end":"2016-11-10T17:00:00.000Z"},{"begin":"2016-11-20T13:00:00.000Z","end":"2016-11-20T17:0