', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":11}', '["http://www.exit-art.fr"]', '2016-11-04 09:19:25', '2016-11-04 09:19:25', NULL ),
(145814, 74092403, 99246400, NULL, 21700399, 'adissan-des-logements-et-ateliers-d-art-pour-creer-du-lien', '{"fr":"Exposition \\"Adissan - Des logements et ateliers d''art pour créer du lien\\""}', '{"fr":"sur une ancienne friche industrielle, à partir d''une volonté de créer de nouveaux bâtiments, les étudiants de l''ENSAM ont proposé des solutions"}', '{"fr":"La mairie d’Adissan accueille l’exposition Habitat en densité urbaine, la multiplicité des usages. Les étudiants ont répondu à la demande de la mairie désireuse sur une friche industrielle située dans le centre d’Adissan, de créer un bâtiment mixte abritant logements sociaux, commerces de proximité et une pépinière d’entreprise. L’aménagement d’une voirie piétonne traversante complétant ce programme. Cet ensemble s’inscrirait dans un projet oeno-touristique en créant un lieu public comme lien entre le centre ancien et les extensions urbaines. Au caractère écologique demandé, l’architecture proposée devait être simple, respectueuse de l’environnement visuel et apte à se transformer ou à évoluer tant en matière d’urbanisme que d’articulation avec le contexte patrimonial.\\n\\nCe programme a réuni divers intervenants: la commune d’Adissan, un bailleur social (Hérault Habitat), la Communauté d’Agglomération Hérault Méditerranée, et l’Établissement Public Foncier Languedoc-Roussillon."}', '{"fr":",            ENSAM,            Adissan,           Ecole d''architecture,          architecture,         village,        centre bourg,      logements,      bâtiments neufs,     friche,   étudiants,  hlm, bailleurs sociaux"}', NULL, '{"filename":"event_adissan-des-logements-et-ateliers-d-art-pour-creer-du-lien_375083.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_adissan-des-logements-et-ateliers-d-art-pour-creer-du-lien_375083.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_adissan-des-logements-et-ateliers-d-art-pour-creer-du-lien_375083.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T06:30:00.000Z","end":"2016-10-13T10:00:00.000Z"},{"begin":"2016-10-13T13:30:00.000Z","end":"2016-10-13T15:30:00.000Z"},{"begin":"2016-10-14T06:30:00.000Z","end":"2016-10-14T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":2}', '[]', '2016-11-04 09:20:00', '2016-11-04 09:20:00', NULL ),
(146498, 1056159, 50869293, NULL, 70780847, 'afterwork-business-et-numerique', '{"fr":"AFTERWORK BUSINESS ET NUMERIQUE"}', '{"fr":"AFTERWORK #1  : COMMERCE ET NUMÉRIQUE A CAEN"}', '{"fr":"Commerçants, e-commerçants, responsables de vente et du marketing, venez rencontrer de jeunes entreprises innovantes de votre territoire ayant des solutions à vous proposer pour :\\n\\n*   Booster votre commerce,\\n*   Capter de nouveaux clients et développer votre notoriété\\n*   Simplifier votre quotidien  (logistique, administration…)\\n*   Améliorer l’expérience utilisateur de vos clients …\\n\\n**Au Programme :**\\n\\n19h30 : Accueil par Mme Debelle, Directrice d''Attitude et Maire-adjointe de la ville de Caen en charge du commerce, de l''artisanat et des professions libérales.\\n\\n19h40 : Présentation du baromètre Centre-Ville et Commerce par Clear Channel\\n\\n19h45 - 20h15 : des entreprises et startups vous présentent leurs solutions innovantes pour votre activitéORANGE - HOLIBAG - MARCHE-PRIVE.COM - DEJAMOBILE - VOICI-MON-BIEN.COM\\n\\n20h15 - 21h : Apéritif convivial, échanges et réseautages. Découverte du showroom de solutions innovantesCO''MERCEA - VITAMEAN - EYYE - MATRIX 3D - RESTOFOLIO\\n\\n[INSCRIPTION GRAUITE OBLIGATOIRE](https://www.weezevent.com/afterwork-business-numerique)"}', '{"fr":"commerce, startup, numérique, normandie, normandyfrenchtech, Caen, pitch, paiement, fidélisation, réalité augmentée, holibag, marche privé.com, orange, co''mercea"}', NULL, '{"filename":"event_afterwork-business-et-numerique_847003.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_afterwork-business-et-numerique_847003.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_afterwork-business-et-numerique_847003.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-18T17:30:00.000Z","end":"2016-10-18T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '["https://www.weezevent.com/afterwork-business-numerique"]', '2016-11-04 09:19:26', '2016-11-04 09:19:26', NULL ),
(147352, 30330516, 46215251, NULL, 85938504, 'afterwork-euro-information', '{"fr":"AfterWork Euro Information"}', '{"fr":"Conférence Métiers #2"}', '{"fr":"Filiale informatique du groupe Crédit Mutuel/CIC, **Euro Information vient à la rencontre des étudiants d''Epitech Strasbourg!**\\n\\n*   Présentation de l''activité \\n*   Présentation des opportunités de stages pour Tek3/5\\n\\nRendez-vous au Hub à partir de 16h30.\\n\\n**Inscription** ►Intranet"}', '{}', NULL, '{"filename":"event_afterwork-euro-information_421396.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_afterwork-euro-information_421396.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_afterwork-euro-information_421396.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-17T14:30:00.000Z","end":"2016-10-17T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":119}', '[]', '2016-11-04 09:18:38', '2016-11-04 09:18:38', '2016-11-07 09:14:32' );
