(145793, 94217854, 35653040, NULL, 74775739, 'afterwork-pitchpainting-1kubator-x-le-wagon-lyon', '{"fr":"Afterwork pitchpainting - 1kubator x Le Wagon Lyon"}', '{"fr":"Jeudi, c''est afterwork pitchpainting chez 1kubator avec Le Wagon Lyon à partir de 18h ! Au programme : du street-art, des pitchs de startups, un cocktail et un DJ, à ne pas manquer :)"}', '{"fr":"**1kubator** (startup incubator) et **Le Wagon Lyon** (coding school pour entrepreneurs et esprits créatifs) vous invitent ce jeudi 29 septembre à leur afterwork pitchpainting à partir de 18h ! Des street-artists coloreront les bureaux d''1kubator, un DJ nous fera une performance-live et des startups comme Le Wagon Lyon pourront pitcher leur concept. Que demander de plus ?\\n\\nInscription gratuite ici > [here](http://www.meetup.com/Le-Wagon-Lyon-Coding-Station/events/234368160/)."}', '{"fr":"Code, Web, Startup, Afterwork, Incubateur, Dev, Street-art"}', NULL, '{"filename":"event_afterwork-pitchpainting-1kubator-x-le-wagon-lyon_844304.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_afterwork-pitchpainting-1kubator-x-le-wagon-lyon_844304.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_afterwork-pitchpainting-1kubator-x-le-wagon-lyon_844304.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-29T16:00:00.000Z","end":"2016-09-29T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["http://www.meetup.com/Le-Wagon-Lyon-Coding-Station/events/234368160/"]', '2016-11-04 09:20:00', '2016-11-04 09:20:00', NULL ),
(145812, 39094511, 60512013, 27805494, 25310114, 'ag-de-lutte-pour-defendre-notre-dame-des-landes', '{"en":"AG de lutte pour défendre Notre-Dame-des-Landes,"}', '{"en":"Retrouvons-nous pour préparer la manifestation des 8-9 octobre et les suites de la lutte"}', '{"en":"Après les mobilisations massives contre le projet d''aéroport de Notre-Dame-des-Landes, le gouvernement a organisé en juin une consultation biaisée. Se croyant forts du résultat de cette mascarade qui ne masque pourtant pas l''opposition de la population locale au projet, les pro-aéroport et le premier ministre ont confirmé leur intention de procéder cet automne à l''évacuation et à la destruction de la ZAD de Notre-Dame-des-Landes, de ses cultures, de sa faune et de sa flore, de ses habitats et activités ainsi que des liens entre toutes celles et ceux qui se sont attaché.es à ce bocage. Ces déclarations font fi de la situation juridique du dossier puisqu''entre autres les autorisations de travaux ne sont toujours pas accordées."}', '{}', NULL, '{"filename":"event_ag-de-lutte-pour-defendre-notre-dame-des-landes_188919.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_ag-de-lutte-pour-defendre-notre-dame-des-landes_188919.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_ag-de-lutte-pour-defendre-notre-dame-des-landes_188919.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-09-28T17:30:00.000Z","end":"2016-09-28T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":2}', '[]', '2016-11-04 09:20:00', '2016-11-04 09:20:00', NULL ),
(145841, 28845579, 57892073, NULL, 72298625, 'agence-alain-demarquette-architecte-le-touquet', '{"fr":"Portes ouvertes \\"Agence Alain Demarquette Architecte\\""}', '{"fr":"Installé à la fois sur le Nord-Pas-de-Calais et sur la région parisienne, l''agence travaille entourée de partenaires à partir des différentes structures situées sur Cambrai, Le Touquet et Paris."}', '{"fr":"Depuis ses plusieurs structures, Alain Demarquette et son équipe ont eu l’opportunité et la volonté de concevoir et de réaliser des constructions qui permettent de remplir les paramètres nécessaires et indispensables selon lui pour devenir et rester une architecture « cohérente et sensible ».\\n\\n Car selon lui, l’architecture conditionne quotidiennement notre existence et médiatise presque secrètement notre rapport au monde, mais elle semble pourtant se dérober à toute détermination. Contrairement à la peinture ou à la sculpture qui nous demandent souvent d’entrer d’abord dans un musée ou une galerie, nous sommes toujours plongés dans l’architecture, sans jamais avoir toujours le recul nécessaire pour l’analyser, comme si elle était proche pour pouvoir être appréhendée et comprise pour elle-même. L’architecture agit sur une infinité de niveaux étroitement imbriqués : le ciel et la lumiere, le sol et l’être-ensemble, la forme et la couleur, la construction et les matières. Plus qu’un simple savoir-faire, elle s’apparente à une pensée. Une pensée muette qui n’utilise ni mots ni concepts, mais des parois, comme autant de caches ; des percements, comme autant de cadres, pour transformer un territoire en paysage, des individus dispersés en communauté. Elle informe ces matériaux inépuisables, pour faire surgir des mondes, comme autant de fictions, comme autant d’œuvres."}', '{"fr":",      architecte au Touquet,      Cote d''Opale,    villa,   maison individuelle,  extension, surélévation"}', NULL, '{"filename":"event_agence-alain-demarquette-architecte-le-touquet_348667.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_agence-alain-demarquette-architecte-le-touquet_348667.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_agence-alain-demarquette-architecte-le-touquet_348667.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T11:00:00.000Z"},{"begin":"2016-10-13T12:30:00.000Z","end":"2016-10-13T16:00:00.000Z"},{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T11:00:00.000Z"},{"begin":"2016-10-14T12:30:00.000Z","end":"2016-10-14T16:00:00.000Z"},{"begin":"2016-10-15T07:00:00.000Z","end":"2016-10-15T11:00:00.000Z"},{"begin":"2016-10-15T12:30:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":30,"max":60}', '["alain.demarquette@free.fr"]', '2016-11-04 09:19:58', '2016-11-04 09:19:58', NULL ),
(145842, 93506751, 57892073, NULL, 72298625, 'agence-alain-demarquette-architecte-le-touquet_472', '{"fr":"Agence Alain Demarquette Architecte - Le Touquet -"}', '{"fr":"Installé à la fois sur le Nord-Pas-de-Calais et sur la région parisienne, l''agence travaille entourée de partenaires à partir de des différentes structures situées sur Cambrai, Le Touquet et Paris."}', '{"fr":"Depuis ses plusieurs structures, Alain Demarquette et son équipe ont eu l’opportunité et la volonté de concevoir et de réaliser des constructions qui permettent de remplir les paramètres nécessaires et indispensables selon lui pour devenir et rester une architecture « cohérente et sensible ».\\n\\n Car selon lui, l’architecture conditionne quotidiennement notre existence et médiatise presque secrètement notre rapport au monde, mais elle semble pourtant se dérober à toute détermination. Contrairement à la peinture ou à la sculpture qui nous demandent souvent d’entrer d’abord dans un musée ou une galerie, nous sommes toujours plongés dans l’architecture, sans jamais avoir toujours le recul nécessaire pour l’analyser, comme si elle était proche pour pouvoir être appréhendée et comprise pour elle-même. L’architecture agit sur une infinité de niveaux étroitement imbriqués : le ciel et la lumiere, le sol et l’être-ensemble, la forme et la couleur, la construction et les matières. Plus qu’un simple savoir-faire, elle s’apparente à une pensée. Une pensée muette qui n’utilise ni mots ni concepts, mais des parois, comme autant de caches ; des percements, comme autant de cadres, pour transformer un territoire en paysage, des individus dispersés en communauté. Elle informe ces matériaux inépuisables, pour faire surgir des mondes, comme autant de fictions, comme autant d’œuvres."}', '{"fr":",      architecte au Touquet,      Cote d''Opale,    villa,   maison individuelle,  extension, surélévation"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T11:00:00.000Z"},{"begin":"2016-10-13T12:30:00.000Z","end":"2016-10-13T16:00:00.000Z"},{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T11:00:00.000Z"},{"begin":"2016-10-14T12:30:00.000Z","end":"2016-10-14T16:00:00.000Z"},{"begin":"2016-10-15T07:00:00.000Z","end":"2016-10-15T11:00:00.000Z"},{"begin":"2016-10-15T12:30:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":30,"max":60}', '["alain.demarquette@free.fr"]', '2016-11-04 09:19:58', '2016-11-04 09:19:58', NULL ),
(147281, 98553803, 62636241, 64499330, 59396508, 'agro-au-feminin-midi-pyrenees', '{"en":"Agro au féminin Midi-Pyrénées"}', '{"en":"Le Marketing de soi : comment communiquer efficacement en recrutement ou en entreprise"}', '{"en":"Suite au succès des deux précédentes soirées, nous vous proposons de nous retrouver le 17 Octobre, pour un nouvel évènement !\\n\\nPour rappel, le groupe Agro au Féminin est ouvert à toutes les ingénieures Agro et a pour ambition de favoriser l''échange d’expériences afin d’identifier d’autres modèles de carrières, de s’approprier de nouvelles opportunités professionnelles et de prendre conseil. Nous vous invitons nombreuses à venir à cette nouvelle soirée AAF Midi-Pyrénées.\\n\\nCe sera l’occasion d’écouter les conseils d’un spécialiste en recrutement et d’échanger entre femmes ingénieures agronomes, vos carrières, vos difficultés, vos réussites.\\n\\nLe thème retenu suite à l''enquête menée auprès des ingénieures Agro présentes le 7 mars est : \\"Le Marketing de soi : comment communiquer efficacement en recrutement ou en entreprise\\".\\n\\nL’intervention sera assurée par Paul Herrera, de la société Talents RH et sera suivie d''ateliers d''échanges en petits groupes de 45 minutes.\\n\\nAVIS aux témoignages : nous avons besoin de trois témoignages pour les ateliers ; si vous avez été coachée sur la communication et/ou le marketing de soi, si vous avez mis en pratique des conseils en communication qui ont eu un impact sur votre carrière, VENEZ TEMOIGNER ET PARTAGER VOTRE EXPERIENCE !!\\n\\nComme sur les autres soirées nous partagerons ensuite  autour d''un buffet dînatoire …et de cocktails originaux créés par Sandra, dirigeante de  « L’atelier du cocktail ». \\n\\nVenez nombreuses ! Ce sera l''occasion de se revoir ou de se rencontrer.\\n\\nA très vite Les bénévoles d’Agro au Féminin Midi Pyrénée"}', '{}', NULL, '{"filename":"event_agro-au-feminin-midi-pyrenees_948686.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_agro-au-feminin-midi-pyrenees_948686.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_agro-au-feminin-midi-pyrenees_948686.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-17T17:00:00.000Z","end":"2016-10-17T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":3,"max":99}', '["http://www.midi-pyrenees.uniagro.fr/gene/main.php?base=1189&id_agenda=4546"]', '2016-11-04 09:18:43', '2016-11-04 09:18:43', NULL ),
(146656, 40777786, 70453612, NULL, 14936724, 'aire-de-jeu-de-la-qualite-de-l-air-de-l-ireps', '{"fr":"Aire de Jeu de la qualité de l''air de l''IREPS"}', '{"fr":"Venez jouer avec l''IREPS pour améliorer l''air de votre maison."}', '{}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-08T08:00:00.000Z","end":"2016-10-08T16:00:00.000Z"},{"begin":"2016-10-09T08:00:00.000Z","end":"2016-10-09T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '[]', '2016-11-04 09:19:18', '2016-11-04 09:19:18', NULL ),
(146643, 40551783, 92423239, NULL, 23410644, 'aix-en-provence-autour-des-cites-universitaires', '{"fr":"Promenade urbaine \\"Aix-en-Provence, autour des cités universitaires\\""}', '{"fr":"Des parcours à télécharger ou à suivre directement sur son téléphone sur www.architectouro.fr pour voir la ville méditerranéenne autrement par le Syndicat des Architectes des Bouches-du-Rhône"}', '{"fr":"La ville méditerranéenne ne se donne pas, elle se découvre. C''est pourquoi le Syndicat des Architectes des Bouches-du Rhône se propose de s''aventurer avec vous sur ce chemin afin de se(re)découvrir certaines de ses richesses architecturales contemporaines, de décrypter ses codes construits, ses quartiers, ses ambiances...C''est le principe de la promenade architecturale. Chaque parcours a pour départ un lieu culturel majeur et se termine sur un espace de rencontre, de vie urbaine ou un lieu de contemplation.\\n\\nLe parcours autour des cités universitaires à Aix-en-Provence,\\n\\nFlâner dans le campus universitaire, entre les bâtiments de Fernand Pouillon et de René Egger et découvrir une ville dans la ville vivant à un autre rythme et marquée par les époques et les inspirations néo-classique, régionaliste, moderne. A la veille de grands travaux de restructuration…\\n\\nLe parcours est disponible via son téléphone à cette adresse :\\n\\n[http://www.architectouro.fr//parcoursai21.html](http://www.architectouro.fr//parcoursai21.html)\\n\\nIl est aussi possible de télécharger un pdf à cette adresse :\\n\\n[http://www.architectouro.fr//plan/AI2-A4.pdf](http://www.architectouro.fr//plan/AI2-A4.pdf)"}', '{"fr":",  Balades urbaines, Aix-en-Provence"}', NULL, '{"filename":"event_aix-en-provence-autour-des-cites-universitaires_552638.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_aix-en-provence-autour-des-cites-universitaires_552638.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_aix-en-provence-autour-des-cites-universitaires_552638.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T05:00:00.000Z","end":"2016-10-13T04:00:00.000Z"},{"begin":"2016-10-14T05:00:00.000Z","end":"2016-10-14T04:00:00.000Z"},{"begin":"2016-10-15T05:00:00.000Z","end":"2016-10-15T04:00:00.000Z"},{"begin":"2016-10-16T05:00:00.000Z","end":"2016-10-16T04:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '[]', '2016-11-04 09:19:18', '2016-11-04 09:19:18', NULL ),
(146635, 98822101, 92423239, NULL, 80585862, 'aix-en-provence-autour-du-pavillon-noir', '{"fr":"Promenaide urbaine \\"Aix-en-Provence, autour du pavillon Noir\\""}', '{"fr":"Des parcours à télécharger ou à suivre directement sur son téléphone sur www.architectouro.fr pour voir la ville méditerranéenne autrement par le Syndicat des Architectes des Bouches-du-Rhône"}', '{"fr":"La ville méditerranéenne ne se donne pas, elle se découvre. C''est pourquoi le Syndicat des Architectes des Bouches-du Rhône se propose de s''aventurer avec vous sur ce chemin afin de se(re)découvrir certaines de ses richesses architecturales contemporaines, de décrypter ses codes construits, ses quartiers, ses ambiances...C''est le principe de la promenade architecturale. Chaque parcours a pour départ un lieu culturel majeur et se termine sur un espace de rencontre, de vie urbaine ou un lieu de contemplation.\\n\\nLe parcours aurour du Pavillon Noir à Aix-en-Provence\\n\\nDémarrer par les dernières productions des grands noms de l’architecture internationale contemporaine pour terminer par l’œuvre de jeunesse de Fernand Pouillon, presqu’un siècle d‘écart en quelques mètres. Balade au cœur de la ZAC Sextius, une des opérations les plus importantes de ces vingt dernières années en Europe, jusqu’au bas du cours Mirabeau.\\n\\nLe parcours est disponible via son téléphone à cette adresse :\\n\\nhttp://www.architectouro.fr//parcoursai11.html\\n\\nIl est aussi possible de télécharger un pdf à cette adresse :\\n\\nhttp://www.architectouro.fr//plan/AI1-A4.pdf"}', '{"fr":",   balades urbaines,   Aix-en-Provence, Pavillon noir"}', NULL, '{"filename":"event_aix-en-provence-autour-du-pavillon-noir_719672.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_aix-en-provence-autour-du-pavillon-noir_719672.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_aix-en-provence-autour-du-pavillon-noir_719672.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T05:00:00.000Z","end":"2016-10-13T04:00:00.000Z"},{"begin":"2016-10-14T05:00:00.000Z","end":"2016-10-14T04:00:00.000Z"},{"begin":"2016-10-15T05:00:00.000Z","end":"2016-10-15T04:00:00.000Z"},{"begin":"2016-10-16T05:00:00.000Z","end":"2016-10-16T04:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":3}', '[]', '2016-11-04 09:19:19', '2016-11-04 09:19:19', NULL ),
(146710, 11189019, 50569937, NULL, 19890057, 'ajn-2-la-culture-sur-butte-le-graal', '{"fr":"AJN 2 : La culture sur butte : le Graal?"}', '{"fr":"Atelier jardinage naturel 2"}', '{}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T12:00:00.000Z","end":"2016-10-22T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":99}', '[]', '2016-11-04 09:19:15', '2016-11-04 09:19:15', NULL ),
(147327, 59444757, 96905458, NULL, 22574401, 'akale-wube-au-studio-de-l-ermitage_980', '{"fr":"AKALÉ WUBÉ au STUDIO DE L''ERMITAGE"}', '{"fr":"ETHIO GROOVE"}', '{"fr":"En 6 ans d’existence, Akalé Wubé n’a cessé d’élargir le cadre où se déploie sa musique, de plus en plus riche et profonde, à l’image de sa source d’inspiration première : le répertoire populaire éthiopien des années 60 et 70.\\n\\nA l''origine rassemblé autour de reprises de la série \\"Ethiopiques\\", le groupe a grandi en s''immergeant profondément dans les musiques d''Éthiopie et en multipliant les collaborations avec des musiciens et danseurs éthiopiens, africains et européens. Peu à peu, les quelque deux cents concerts d’Akalé Wubé en Europe, en Asie et en Afrique en ont fait l’un des ambassadeurs mondiaux du groove éthiopien.\\n\\nDavid GEORGELET : Drums\\n\\nOliver DEGABRIELE : Bass\\n\\nLoïc Réchard : Guitar\\n\\nÉtienne DE LA SAYETTE : Flûtes, Sax\\n\\nPaul BOUCLIER : Krar, trumpet, percussions"}', '{"fr":"Akalé Wubé, Ethio, groove, ethiopie, jazz, studio de l''ermitage, live, concert, musique, paris, menilmontant, salle de concert, musique du monde"}', NULL, '{"filename":"event_akale-wube-au-studio-de-l-ermitage_980_18657.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_akale-wube-au-studio-de-l-ermitage_980_18657.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_akale-wube-au-studio-de-l-ermitage_980_18657.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-04T19:30:00.000Z","end":"2016-11-04T22:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":99}', '["http://www.studio-ermitage.com/agenda/date/akale-wube-18"]', '2016-11-04 09:18:40', '2016-11-04 09:18:40', NULL ),
