(147093, 2450813, 60769607, NULL, 96552271, 'anatomie-de-l-ecoute', '{"fr":"Anatomie de l''écoute"}', '{"fr":"Spectacle"}', '{"fr":"Grand Magasin concepteurs\\n\\nConception  Grand Magasin\\n\\nDirection musicale Laurent Cuniot\\n\\nMezzo- soprano Sylvia Vadimova\\n\\nClarinette Nicolas Fargeix\\n\\nVibraphone Gianny Pizzolato\\n\\nVioloncelle David Simpson\\n\\nMaîtres de cérémonie Pascale Murtin, François Hiffler\\n\\nProgramme révélé en fin de concert\\n\\n**Coproduction** TM+, Grand Magasin, Maison de la musique de Nanterre\\n\\n**Avec le soutien** d’Arcadi Île-de-France"}', '{"fr":"Anatomie de l''écoute, écoute, Grand Magasin, TM+, question"}', NULL, '{"filename":"event_anatomie-de-l-ecoute_843834.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_anatomie-de-l-ecoute_843834.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_anatomie-de-l-ecoute_843834.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-30T18:30:00.000Z","end":"2016-11-30T19:30:00.000Z"},{"begin":"2016-12-01T18:30:00.000Z","end":"2016-12-01T19:30:00.000Z"},{"begin":"2016-12-02T18:30:00.000Z","end":"2016-12-02T19:30:00.000Z"},{"begin":"2016-12-03T18:30:00.000Z","end":"2016-12-03T19:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '["http://www.rodrigue.fr/transact/venteenligne.asp?WCI=panier_listeseances&langue=fr&site=&idstructure=390&origine=&nocal=0&urlretour=&idmanif=230"]', '2016-11-04 09:18:53', '2016-11-04 09:18:53', NULL ),
(146514, 30647999, 97862464, NULL, 14047593, 'andre-ceccarelli-west-side-au-carre-belle-feuille', '{"fr":"André Ceccarelli West Side au Carré belle feuille"}', '{"fr":"Un hommage à West Side Story"}', '{"fr":"**André Ceccarelli West Side**\\n\\n**Mercredi 7 décembre à 20h30**\\n\\nMusique : Leonard Bernstein. Arrangements : André Ceccarelli\\n\\nChorégraphie : Philip Cheeb et Régis Truchy. Batterie : André Ceccarelli\\n\\nVoix : Walter Ricci. Sax alto: Rosario Giuliani. Piano : Julian Oliver Mazzariello\\n\\nContrebasse, basse électrique et batterie : Rémi Vignolo\\n\\nPercussions : Gerard Carocci. Danseurs : Régis Truchy, Bruce Ykanji et Nathalie Fauquette.\\n\\nStreet Artists : Jérôme Mesnager, Artiste Ouvrier et Stoul\\n\\nDanseurs-phares de la scène hip hop, artistes de renom issus du street art et la crème des musiciens de jazz réunis sous la houlette d’ André Ceccarelli !\\n\\nEnsemble, ils rendent hommage à l’une des plus célèbres comédies musicales modernes : West Side Story."}', '{}', NULL, '{"filename":"event_andre-ceccarelli-west-side-au-carre-belle-feuille_214252.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_andre-ceccarelli-west-side-au-carre-belle-feuille_214252.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_andre-ceccarelli-west-side-au-carre-belle-feuille_214252.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-12-07T19:30:00.000Z","end":"2016-12-07T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":77}', '["01 55 18 54 00"]', '2016-11-04 09:19:26', '2016-11-04 09:19:26', NULL ),
(147029, 67150913, 56928802, NULL, 50524303, 'andre-minvielle-journal-intime-sortie-cd', '{"fr":"ANDRÉ MINVIELLE + JOURNAL INTIME (Sortie CD)"}', '{"fr":"concert de sortie du nouveau CD du voc’alchimiste André Minvielle avec Journal Intime."}', '{"fr":"## ANDRÉ MINVIELLE + JOURNAL INTIME « 1time » (Sortie CD)\\n\\nC’est intime et one time. C’est le nouveau CD en live du voc’alchimiste André Minvielle. Textes et chansons originales comprises. C’est syncrétique et laïc. Une ode à « Saint Cop ». Pour fêter l’Anthropophonie et chasser la glottophobie. Seul en scène avec sa « main-vielle à roue » ou avec ses invités choisis.\\n\\nAvec\\n\\nAndré MINVIELLE : voix, « main-vielle à roue », batterie, pad wave drum, bouteille électrique\\n\\nAvec par ordre d’apparition :\\n\\nTI’BAL TRIBAL :\\n\\nFernand NINO FERRER : basse\\n\\nJuliette MINVIELLE : clavier/chant\\n\\nJOURNAL INTIME :\\n\\nFred GASTARD : saxophones\\n\\nSylvain BARDIAU : trompette\\n\\nMatthias MALHER : trombone\\n\\n[http://www.triojournalintime.com](http://www.triojournalintime.com)"}', '{"fr":"Jazz, Journal Intime, André Minvielle"}', NULL, '{"filename":"event_andre-minvielle-journal-intime-sortie-cd_111502.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_andre-minvielle-journal-intime-sortie-cd_111502.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_andre-minvielle-journal-intime-sortie-cd_111502.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-11T19:00:00.000Z","end":"2016-10-11T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '["01 44 62 02 86"]', '2016-11-04 09:18:57', '2016-11-04 09:18:57', NULL ),
(147010, 99515981, 98615996, NULL, 66699249, 'angelique-ionatos-katerina-fotinaki', '{"fr":"angelique ionatos & katerina fotinaki"}', '{"fr":"Une amitié qui dure mais aussi une collaboration qui sans arrêt s’enrichit au fil du temps."}', '{"fr":"Ce qui constitue un pont entre les deux amies c''est l''amour commun pour la poésie, le rythme et leurs guitares.Elles ont réalisé ensemble un disque Comme un jardin la nuit et deux disques où l''une participe à celui de l''autre.Elles ont fait deux fois le Festival d''Avignon, et six créations : Comme un jardin la nuit, Le prince heureux (spectacle pour jeune public), Anatoli, Et si l''arbre brûlé, Et les rêves prendront leur revanche (créé au Théâtre de la Ville à Paris dans le cadre des \\"Chantiers d''Europe\\") et Reste la lumière.\\n\\nL''anniversaire de ces 10 ans d''amitié et de collaboration a fait jaillir le désir de fêter cela avec un récital en puisant dans leur répertoire commun plus des nouvelles chansons pour cette occasion."}', '{"fr":", angelique ionatos katerina fotinaki"}', NULL, '{"filename":"event_angelique-ionatos-katerina-fotinaki_240490.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_angelique-ionatos-katerina-fotinaki_240490.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_angelique-ionatos-katerina-fotinaki_240490.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-12-13T20:00:00.000Z","end":"2016-12-13T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '["http://www.letriton.com/programmation/angelique-ionatos-katarina-fotinaki-1974"]', '2016-11-04 09:18:58', '2016-11-04 09:18:58', NULL ),
(146318, 68568944, 14963029, NULL, 66333672, 'animation-cine-parents-la-guerre-est-declaree', '{"fr":"Ciné-parents: \\"La guerre est déclarée\\""}', '{"fr":"Entre Roméo et Juliette, c''est le coup de foudre, et bientôt un bébé..."}', '{"fr":"Quand Adam est diagnostiqué d''une maladie grave, ses parents mettent en place un plan de bataille pour en venir à bout. Seul l''amour pouvait permettre à la vie de l''emporter...\\n\\nDrame de Valérie Donzelli (2011).\\n\\nhttps://www.youtube.com/watch?v=oY7LGzaebMc\\n\\n**_Les soirées Ciné-parents proposent des opportunités pour découvrir de nouvelles connaissances, apprendre de la science et de l''expérience pédagogique, échanger et témoigner entre parents._**"}', '{"fr":"ciné,     cinéma,     parents,     enfant,    animation,    animations,  parent,  enfants"}', NULL, '{"filename":"event_animation-cine-parents-la-guerre-est-declaree_20826.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_animation-cine-parents-la-guerre-est-declaree_20826.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_animation-cine-parents-la-guerre-est-declaree_20826.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-15T18:30:00.000Z","end":"2016-11-15T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', 'min":12,"max":14}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:36', '2016-11-04 09:19:36', NULL ),
(147112, 39027321, 61942157, NULL, 3077425, 'animation-decouverte-gyropode', '{"fr":"Animation découverte Gyropode"}', '{"fr":"Venez vous initier au gyropode sur un parcours balisé.  5 véhicules sont mis à votre disposition pour des essais gratuits et de l''information. Des casques vous seront fournis."}', '{}', '{}', NULL, '{"filename":"event_animation-decouverte-gyropode_973818.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_animation-decouverte-gyropode_973818.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_animation-decouverte-gyropode_973818.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T12:00:00.000Z","end":"2016-10-16T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":14}', '[]', '2016-11-04 09:18:52', '2016-11-04 09:18:52', NULL ),
