(145553, 75716929, 91869064, NULL, 4710608, 'animation-lis-la-facade', '{"fr":"Animation \\"Lis la façade\\""}', '{"fr":"jeu éducative"}', '{"fr":"Animations pour les classes primaires, du CP au CM2\\n\\nAprès observation in situ, l''enfant retrouve grâce à un jeu des erreurs les éléments constitutifs de la façade du Palais Granvelle.\\n\\nLes animations proposées a titre de \\"Besançon ville d''art et d''histoire\\" sont réservées exclusivement aux établissements scolaires de Besançon.\\n\\nVille de Besançon\\n\\nDirection de Patrimoine Historique\\n\\nService Transmission Valorisation Médiation\\n\\nInscriptions par téléphone : 0381615207\\n\\ncontact : Karine Ménégaux-Doré\\n\\ncrédit photo : ©mdabesancon"}', '{"fr":"jeu"}', NULL, '{"filename":"event_animation-lis-la-facade_862487.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_animation-lis-la-facade_862487.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_animation-lis-la-facade_862487.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T09:30:00.000Z"},{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T09:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":11}', '["0381615207","karine.menegaux-dore@besancon.fr"]', '2016-11-04 09:20:10', '2016-11-04 09:20:10', NULL ),
(146075, 91540066, 99823672, NULL, 99950334, 'anti-rubber-brain-fact0ry-mar0kait', '{"fr":"Anti RubBer brAiN fAct0ry  & Mar0kAït"}', '{"fr":"Free Jazz, Groove, swing, improvisations collectives et transe"}', '{"fr":"L’Anti RubBer brAiN fAct0ry   (A.r.b.f) est une nébuleuse d’expérimentation sonore qui lutte contre le formatage des cerveaux.\\n\\nFree Jazz, Groove, swing, improvisations collectives et transe sont les maître-mots et les ingrédients de la grande marmite Arbf. Au menu de ce 30 septembre 2016, le répertoire marokaît : Pot-pourri quelques perles sonores revisitées, issues de différents répertoires traditionnels marocains.\\n\\nDistribution :\\n\\nNicolas Souchal (trompette), Jean-Michel Couchet (sax alto, soprano), Florent Dupuit (Sax tenor, flûte, piccolo), Benoit Guenoun (sax tenor), Jean-Brice Godet (clarinettes), Paul Wacrenier (vibraphone, perc), Yoram Rosilio (contrebasse), Rafael Koerner (batterie)"}', '{"fr":", Free Jazz"}', NULL, '{"filename":"event_anti-rubber-brain-fact0ry-mar0kait_276412.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_anti-rubber-brain-fact0ry-mar0kait_276412.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_anti-rubber-brain-fact0ry-mar0kait_276412.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-30T17:00:00.000Z","end":"2016-09-30T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '["http://www.lelieudelautre.com/"]', '2016-11-04 09:19:47', '2016-11-04 09:19:47', NULL ),
(146117, 21553295, 67650229, 73237661, 35021978, 'antonin-leymarie-trio-hyperactive-leslie', '{"fr":"Antonin Leymarie Trio - Hyperactive Leslie"}', '{"fr":"Trio électronique improvisé composé d''Antonin Leymarie, Sabina Sciubba et Fabrizio Rat"}', '{"fr":"Fondateur du Magnetic Ensemble, Antonin Leymarie est batteur et compositeur, et joue notamment au sein de différentes formations comme Surnatural Orchestra ou la compagnie Impérial. \\n\\nJubilant à l’idée même d’un nouveau projet, Antonin Leymarie n’hésite pas à expérimenter sans cesse de nouvelles formes, et nous ne sommes pas les premiers - ni les derniers - à nous en délecter. \\n\\nEn guise de clôture de cette première soirée, Antonin vient tester une nouvelle forme en compagnie de la chanteuse et actrice Sabina Sciubba et du pianiste Fabrizio Rat.  Les seules règles: une musique toujours originale prônant une approche libre, sensible et organique, des morceaux comme autant d’invitations au relâchement complet pour libérer les mouvements de l’instinct et de l’instant.\\n\\nParce-que chacune des tentatives d’Antonin Leymarie est toujours fascinante à souhait et gorgée d’une folle énergie, on ne va certainement pas cacher notre enthousiasme ni s’empêcher de danser. Et vous ?\\n\\n​\\n\\nAVEC\\n\\nAntonin Leymarie, batterie\\n\\nSabina Sciubba, chant\\n\\nFabrizio Rat, piano"}', '{"fr":"jazz,  electro, impro"}', NULL, '{"filename":"event_antonin-leymarie-trio-hyperactive-leslie_165957.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_antonin-leymarie-trio-hyperactive-leslie_165957.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_antonin-leymarie-trio-hyperactive-leslie_165957.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-11-05T19:00:00.000Z","end":"2016-11-05T00:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":77}', '["https://yurplan.com/event/ATLAST-1-la-premiere/10959"]', '2016-11-04 09:19:45', '2016-11-04 09:19:45', NULL ),
