(146545, 54874424, 89069264, NULL, 7766347, 'aperotech-nancy-2', '{"fr":"APEROTECH #Nancy #2"}', '{"fr":"Une startup prometteuse + un DJ confirmé"}', '{"fr":"Une start-up prometteuse et un DJ confirmé... Harmonic Pharma est l’invité de l’@peroTech#2 animé par Francine Dubail de France Télévision et Saïd Labidi de L’Est Républicain."}', '{"fr":", #startup #dj #harmonicpharma"}', NULL, '{"filename":"event_aperotech-nancy-2_186642.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_aperotech-nancy-2_186642.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_aperotech-nancy-2_186642.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T17:00:00.000Z","end":"2016-10-13T19:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["said.labidi@estrepublicain.fr"]', '2016-11-04 09:19:24', '2016-11-04 09:19:24', NULL ),
(147464, 79815724, 88859858, NULL, 26501488, 'apidae-l-information-touristique', '{"fr":"Apidae : l''information touristique !"}', '{"fr":"Découvrez la platefome collaborative pour les acteurs du tourisme"}', '{"fr":"La plateforme Apidae Tourisme est une base d’informations en ligne. Elle permet de créer et de diffuser de l’information touristique.\\n\\nVenez découvrir comment fonctionne cette plateforme et trouver le rôle que vous pouvez jouer dans cet écosystème : prestataire technique, diffuseur, AMO ou encore usager !\\n\\nVenez découvrir un process, une technique, un logiciel, un savoir-faire… 70 min de découverte dans une ambiance détendue et chaleureuse à partir de 12h30\\\\. La Forge vous offre le jus de fruit et les chips, bien sûr ! Mais n''hésitez pas à venir avec votre salade, sandwich, quiche, etc. et restez déjeuner avec nous !"}', '{}', NULL, '{"filename":"event_apidae-l-information-touristique_406353.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_apidae-l-information-touristique_406353.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_apidae-l-information-touristique_406353.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-29T11:30:00.000Z","end":"2016-11-29T13:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":17}', '[]', '2016-11-04 09:18:32', '2016-11-04 09:18:32', NULL ),
(146618, 74835775, 57966576, NULL, 93830418, 'apprentis-journalistes-scientifiques', '{"fr":"Apprentis journalistes scientifiques"}', '{"fr":"Jouez les apprentis journalistes scientifiques en interviewant des chercheurs dans le studio de Radio Campus Besançon."}', '{}', '{"fr":",  journalisme, journaliste"}', NULL, '{"filename":"event_apprentis-journalistes-scientifiques_962632.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_apprentis-journalistes-scientifiques_962632.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_apprentis-journalistes-scientifiques_962632.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T15:00:00.000Z"},{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T15:00:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"},{"begin":"2016-10-16T12:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":11}', '["03 81 66 20 95","jeremy.querenet@univ-fcomte.fr"]', '2016-11-04 09:19:20', '2016-11-04 09:19:20', NULL ),
(145949, 84275493, 2088543, NULL, 28870286, 'apprentissage-automatique-et-interaction-avec-nao-le-robot', '{"fr":"Apprentissage automatique avec Nao, le robot"}', '{"fr":"TELECOM SUD PARIS - 2"}', '{"fr":"A travers sa caméra embarquée, il analyse la scène devant lui.\\n\\nUn algorithme d’apprentissage supervisé lui permet de détecter l’activité de la personne qui se trouve en face de lui.\\n\\n*   **assistance aux personnes âgées**\\n*   **détection de comportement anormaux**\\n*   **aide à l’apprentissage d’enfants fragiles,**\\n\\n**les champs d’application de ces travaux de recherche sont nombreux.**"}', '{"fr":",        caméra,       robot,      apprentissage,     interaction,    embarquée,   algorithme,  assistance, détection"}', NULL, '{"filename":"event_apprentissage-automatique-et-interaction-avec-nao-le-robot_781903.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_apprentissage-automatique-et-interaction-avec-nao-le-robot_781903.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_apprentissage-automatique-et-interaction-avec-nao-le-robot_781903.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T14:30:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '["isabelle.goulette@iledescience.org"]', '2016-11-04 09:19:53', '2016-11-04 09:19:53', NULL ),
(146197, 62719176, 43868984, NULL, 50219314, 'apres-midi-familial-d-un-monde-a-l-autre-art-science-genre-termite', '{"fr":"D''un Monde a l''Autre en famille - Genre Termite ?"}', '{"fr":"Après-midi familial. Venez découvrir en famille l''univers des termites et les inspirations artistiques qu''ils vont provoquer. Quizz scientifique, Animations scientifiques, Spectacles, Exposition..."}', '{"fr":"### D''Un Monde à l''Autre\\n\\n**Genre termite ?**\\n\\n_Depuis 2011, nous assistons, sur Créteil, à la rencontre d’un scientifique et d’un artiste dans un laboratoire de la faculté des sciences et technologie de l’Université Paris-Est Créteil._\\n\\n_**De cette rencontre va naître une exposition, un trait d’union entre ces deux mondes que l’on imagine trop souvent incompatibles…**_\\n\\n_Cette année, c’est l’enseignant-chercheur Philippe Mora de l’équipe biologie des termites et fonctionnement des écosystèmes tropicaux du laboratoire IEES Paris* qui a accueilli durant quelques heures Fabien Léaustic, artiste plasticien. A partir de cette visite, cet artiste qui réalise des installations sensibles, mêlant l’histoire des sciences et les technologies récentes, a eu trois mois de réflexion pour réaliser une œuvre inspirée de leur rencontre._\\n\\nBande annonce :\\n\\n[https://vimeo.com/181461405](https://vimeo.com/181461405)\\n\\n### **APRES-MIDI FAMILIAL**\\n\\n**Samedi 15 octobre 14h – 18h**\\n\\n*   **14h** - Quizz de Philippe Mora, enseignant chercheur de l''Institut d’Ecologie et des Sciences de l’Environnement de Paris. Découvrez, jouez, zapper dans l’univers des termites. (A partir de 6 ans)\\n\\n*   **15h** - Animations scientifiques et créatives. (Tout public)\\n\\n*   **16h** - Danse. Extraits du spectacle **_Arman_**, une Déambulation / Performance dansée sur l''oeuvre au noir d''Armand de Montmartel, Marquis de Brunoy. Compagnie la Planquette des animaux humides. (Tout public)\\n\\n*   **17h** - Spectacle de Conte, familial, **_Le Vertige du Lombric_**. Créé et interprété par le conteuse Cécile de Lagillardaie (A partir de 10 ans)\\n\\n**En continu découvrez l’exposition et rencontrez l’artiste.**\\n\\n### EXPOSITION\\n\\n13 octobre – 12 novembre\\n\\nOuverte du mardi au vendredi 10h-19h et le samedi 10h-17h.\\n\\nDu lundi au vendredi 10h-17h pendant les vacances scolaires. Fermée le 31 octobre.\\n\\nCe projet à l’initiative de la Ville de Créteil et de l’association MJC Mont-Mesly Madeleine Rebérioux, en partenariat avec la faculté des sciences et technologie de l’UPEC et les médiathèques du Grand Paris Sud Est Avenir s’est rapproché de la classe de 1re et terminale option arts plastiques de Mme Fouqueray du Lycée Saint-Exupéry qui a participé à l’œuvre réalisée par l’artiste.\\n\\nProgramme complet :\\n\\nwww.mjccreteil.com Onglet Fête de la science 2016.\\n\\nwww.ville-creteil.fr\\n\\nA VOS AGENDAS : Festival Art & Science samedi 22 avril…"}', '{"fr":",        spectacles ,       quizz conférence,      Animations scientifiques,     Conte,    Danse,   Exposition,  Création, Découverte"}', NULL, '{"filename":"event_apres-midi-familial-d-un-monde-a-l-autre-art-science-genre-termite_130599.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_apres-midi-familial-d-un-monde-a-l-autre-art-science-genre-termite_130599.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_apres-midi-familial-d-un-monde-a-l-autre-art-science-genre-termite_130599.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '["0141941815"]', '2016-11-04 09:19:41', '2016-11-04 09:19:41', NULL ),
(147082, 63212205, 60769607, NULL, 96094000, 'arborescences_423', '{"fr":"Arborescences"}', '{"fr":"Concert"}', '{"fr":"**Compositeurs**\\n\\nJosé Manuel López López, _Trio III_ pour violon, violoncelle et piano\\n\\nLuis de Pablo, _Epistola el transeúnte_ pour flute, clarinette, piano, violon, alto et violoncelle\\n\\nAlberto Posadas, _Arborescencias_ pour violon et trio a cordes\\n\\nOriol Saladrigues, _Teixits_ (création mondiale) pour flute, clarinette, piano, percussions, violon, violoncelle\\n\\n**Distribution**\\n\\nGilles Burgos Flute\\n\\nFrank Scalisi Clarinette\\n\\nFrédéric Lagarde Piano\\n\\nFlorent Jodelet Percussions\\n\\nNoëmi Schindler Violon\\n\\nMaud Lovett Violon\\n\\nMarion Plard Alto\\n\\nFlorian Lauridon Violoncelle\\n\\nLaurent Cuniot Direction\\n\\n**Production** TM+"}', '{"fr":"Maison de la Radio, Compositeurs espagnols, Musique espagnole contemporaine, Alberto Posadas, Oriol Saladrigues, Luis de Pablo, Jose Manuel Lopez Lopez, Laurent Cuniot, TM+"}', NULL, '{"filename":"event_arborescences_423_232747.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_arborescences_423_232747.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_arborescences_423_232747.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-23T14:00:00.000Z","end":"2016-10-23T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '["https://billetterie.maisondelaradio.fr/selection/event/seat?perfId=592866013"]', '2016-11-04 09:18:54', '2016-11-04 09:18:54', NULL ),
(146933, 80267507, 73913296, NULL, 47481301, 'archi-a-la-plage', '{"fr":"ENSAP Bordeaux / Archi à la Plage"}', '{"fr":"L''ensapBx fait l''archi à la Plage le vendredi 14/10 à partir de minuit. VENEZ FAIRE LA FETE AVEC LE BDE DE L''ENSAP DE BORDEAUX A LA PLAGE, LE CLUB !!"}', '{"fr":"Les **étudiants de l’ensapBx** investissent un lieu emblématique de la fête pour aller à la rencontre de la jeunesse bordelaise et lui faire découvrir l’architecture dans un contexte décalé. Faire partager, faire découvrir, faire porter un regard nouveau du grand public sur ce qui l’entoure, fait partie du rôle de l’architecte. Médiateur, acculturateur, facilitateur, l’architecte créé du lien démocratique.\\n\\nSituée dans un morceau de ville en mutation, dans des bâtiments transformés, La Plage fait le lien entre architecture, mutation urbaine et vie en société.\\n\\nDans un moment fort où plus que jamais l’ouverture à l’autre, le respect de la diversité et la lutte contre les préjugés sont de mise, faire bouger les lignes est un enjeu capitale pour demain."}', '{"fr":"architecture, architecte, fête, la plage, projection, DJs set, animation, BDE ensapBx, étudiants"}', NULL, '{"filename":"event_archi-a-la-plage_18221.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_archi-a-la-plage_18221.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_archi-a-la-plage_18221.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T22:00:00.000Z","end":"2016-10-15T04:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["http://www.bordeaux.archi.fr","https://www.facebook.com/events/1114950021927562/"]', '2016-11-04 09:19:02', '2016-11-04 09:19:02', NULL ),
(146028, 10226577, 51980619, NULL, 2646375, 'archi-dating', '{"fr":"Archi Dating : Portes ouvertes"}', '{"fr":"Venez rencontrer les architectes conseillers du CAUE du Val-d''Oise : posez vos questions, participez à un atelier, trouvez un livre, une revue..."}', '{"fr":"*   **Conseils gratuits** : Vous désirez construire, agrandir ou rénover ? Venez rencontrer un architecte-conseiller du CAUE pour discuter de vos projets.\\n\\n*   **Atelier :** Construire, rénover sa maison : les clefs du projet - démarches, conseils pour aborder sereinement votre projet de construction ou d''extension - 15h00\\n\\n*   **Foire aux livres :** Le CAUE fait don de livres et revues sur l''architecture, le paysage et l''urbanisme...\\n\\n*   **Atelier maquette :** \\"Construis ta maison idéale\\" de 7 à 77 ans, chaque enfant pourra repartir avec sa création."}', '{}', NULL, '{"filename":"event_archi-dating_141484.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_archi-dating_141484.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_archi-dating_141484.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":17}', '["http://www.caue95.org/content/archi-dating-journ%C3%A9es-nationales-de-larchitecture-2016"]', '2016-11-04 09:19:49', '2016-11-04 09:19:49', NULL ),
(146930, 75953677, 73913296, NULL, 92842009, 'archi-hors-les-murs', '{"fr":"ENSAP Bordeaux / Archi hors les murs"}', '{"fr":"L''ensapBx fait l''archi hors les murs"}', '{"fr":"Visite commentée de l’exposition **La fabrique du patrimoine**, fruit de la collaboration entre le CIAP et l''ensapBx\\n\\n+\\n\\nConférence / Conversation  \\n**L’architecture d’aujourd’hui sera-t-elle le patrimoine de demain ?**\\n\\navec **Chantal Callais** et **Thierry Jeanmonod**, enseignants à l''ensapBx, chercheurs à l’UMR CNRS Passages, auteurs des ouvrages _**Bordeaux patrimoine mondial - La fabrication de la ville**_ (2012) et de _**Bordeaux patrimoine mondial - Habiter le patrimoine**_ (2014).\\n\\n& les étudiants* de l’école nationale supérieure d’architecture et de paysage de Bordeaux auteurs de l’exposition.\\n\\n_* Audrey Bousigues, Victoria Caubet, Marion Dando, Sevdzhan Hasan, Alice Herbert, Perrine Lartigau, Charles Moueix, Eugénie Olive, Pamela Saillant, Louise Schmidt-Wilshin, Laura Stoffel._\\n\\nL''exposition est visible au CIAP jusqu''au 08.01.2017."}', '{"fr":"architecture, ensap Bordeaux, CIAP, Bordeaux, exposition, conférence, patrimoine, ville"}', NULL, '{"filename":"event_archi-hors-les-murs_554296.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_archi-hors-les-murs_554296.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_archi-hors-les-murs_554296.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T15:00:00.000Z","end":"2016-10-14T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["communication@bordeaux.archi.fr","http://www.bordeaux.archi.fr"]', '2016-11-04 09:19:02', '2016-11-04 09:19:02', NULL ),
(146583, 9365262, 64614126, NULL, 76619907, 'archicache-art-nouveau-art-deco-la-ligne-mise-a-nu', '{"fr":"Promenade urbaine \\"Archicache : Art Nouveau / Art déco, la ligne mise à nu\\""}', '{"fr":"Promenade dans le 16e arrondissement de Paris"}', '{"fr":"_Pendant les journées nationales de l''architecture, participez à la plus grande chasse au trésor qui existe actuellement, le geocaching, et découvrez des architectures et des paysages quotidiens, ignorés ou parfois méconnus._\\n\\nLe tournant du XXe siècle constitue un véritable jalon de l''histoire de l''architecture, une rupture avec les règles classiques héritées de l''Antiquité. Entre 1890 et 1910, l''Europe entière est gagnée par une véritable fièvre Art Nouveau (en France et Belgique), Jugendstil (en Allemagne), Sécession (à Vienne), Modern Style (en Angleterre)... Sous la floraison d''une ornementation exhubérante, les volumes prennent leur autonomie ; la ligne courbe dessine l''objet architectural ; les architectes s''appuient sur l''utilisation de nouveaux matériaux et de nouvelles techniques constructives au service d''une oeuvre d''art totale. Au sortir de la Première Guerre Mondiale, ces préoccupations évoluent et se concrétisent dans de nouveaux mouvements, l''Art Décoratif, le mouvement Moderne et le Style International.\\n\\nAu travers de six étapes architecturales, cette chasse au trésor vous offrira un aperçu des réalisations parisiennes de cette période.\\n\\n**Pour accéder à chacune des notices de ce parcours :**\\n\\n*   Connectez-vous ou créez votre profil de géocacheur gratuitement sur le site www.geocaching.com ®\\n*   Téléchargez gratuitement l''application mobile (AppleStore, Google Play) : c:geo / geocaching\\n*   Retrouvez des tutoriels déjà existants, vous expliquant le fonctionnement des applications et les étapes de la recherche des caches : [Tutoriel 1](https://tofgeocaching.wordpress.com/2012/02/24/logiciel-geocaching-android-cgeo/) / [Tutoriel 2](http://www.nature-obsession.fr/technologie/trouver-premiere-geocache-grace-application-cgeo.html)"}', '{"fr":"promenade urbaine, 16e, art nouveau, art déco, mouvement moderne, famille"}', NULL, '{"filename":"event_archicache-art-nouveau-art-deco-la-ligne-mise-a-nu_461114.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_archicache-art-nouveau-art-deco-la-ligne-mise-a-nu_461114.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_archicache-art-nouveau-art-deco-la-ligne-mise-a-nu_461114.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T05:00:00.000Z","end":"2016-10-13T05:00:00.000Z"},{"begin":"2016-10-14T05:00:00.000Z","end":"2016-10-14T05:00:00.000Z"},{"begin":"2016-10-15T05:00:00.000Z","end":"2016-10-15T05:00:00.000Z"},{"begin":"2016-10-16T05:00:00.000Z","end":"2016-10-16T05:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:22', '2016-11-04 09:19:22', NULL ),
(146587, 75398820, 64614126, NULL, 9703260, 'archicache-habiter-d-haussmann-a-aujourd-hui', '{"fr":"Promenade urbaine \\"Archicache : Habiter, d''Haussmann à aujourd''hui\\""}', '{"fr":"Promenade dans le 17e arrondissement de Paris"}', '{"fr":"_Pendant les journées nationales de l''architecture, participez à la plus grande chasse au trésor qui existe actuellement, le geocaching, et découvrez des architectures et des paysages quotidiens, ignorés ou parfois méconnus._\\n\\nLe logement est l’une des matières premières de la fabrication de la ville. Ainsi les différentes réglementations qui régissent l’aménagement des villes sont indissociables des modes d’habiter. La liberté de plus en plus importante donnée aux architectes depuis Haussmann a permis de faire naître de nouveaux usages. Cette liberté est à la fois le fruit de l’évolution des réglementations et des avancés techniques en matière de construction.\\n\\nCette promenade vous propose de parcourir l’histoire du logement d’Haussmann à aujourd’hui. A travers six étapes architecturales vous parcourrez le temps depuis la restructuration de Paris, en passant par les prémices de l’industrialisation de la construction jusqu’à l’architecture contemporaine et les nouveaux enjeux de l’aménagement urbain. Attention, il s''agit d''un parcours multi-caches, composés d''un point de départ et de plusieurs étapes, qui mises ensemble permettent de récolter des indices révélant l''emplacement de la cache finale.\\n\\n**Pour accéder à chacune des notices de ce parcours :**\\n\\n*   Connectez-vous ou créez votre profil de géocacheur gratuitement sur le sitewww.geocaching.com ®\\n*   Téléchargez gratuitement l''application mobile (AppleStore, Google Play) : c:geo / geocaching\\n*   Retrouvez des tutoriels déjà existants, vous expliquant le fonctionnement des applications et les étapes de la recherche des caches : [Tutoriel 1](https://tofgeocaching.wordpress.com/2012/02/24/logiciel-geocaching-android-cgeo/) /[Tutoriel 2](http://www.nature-obsession.fr/technologie/trouver-premiere-geocache-grace-application-cgeo.html)"}', '{"fr":",      promenade urbaine,      habitat,    Haussman,   logement,  aménagement urbain, famille"}', NULL, '{"filename":"event_archicache-habiter-d-haussmann-a-aujourd-hui_214604.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_archicache-habiter-d-haussmann-a-aujourd-hui_214604.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_archicache-habiter-d-haussmann-a-aujourd-hui_214604.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T05:00:00.000Z","end":"2016-10-13T05:00:00.000Z"},{"begin":"2016-10-14T05:00:00.000Z","end":"2016-10-14T05:00:00.000Z"},{"begin":"2016-10-15T05:00:00.000Z","end":"2016-10-15T05:00:00.000Z"},{"begin":"2016-10-16T05:00:00.000Z","end":"2016-10-16T05:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:21', '2016-11-04 09:19:21', NULL ),
(146931, 52932959, 73913296, NULL, 95773795, 'architect-ure-demain', '{"fr":"ENSAP Bordeaux / Architect(ure) demain"}', '{"fr":"L''ensapBx et arc en rêve centre d''architecture proposent ARCHITECT(URE) DEMAIN - Les architectes sur le ring"}', '{"fr":"**Quelle architecture demain ?  \\nQuel avenir pour les architectes ?**  \\n**Quelles pratiques ?  \\nQuelles postures ?  \\nQuelle école ?**\\n\\nDe toute génération, des architectes viennent exposer leurs idées, leurs envies, leurs ambitions.\\n\\nIls ont accepté de monter sur le ring pour _un round de 3 minutes_ chacun :\\n\\n*   **Chloé Bodart** - _Construire_\\n\\n*   **Manon Borie** & **Nathalie Giraud -**_Villages Verts_\\n\\n*   **Christophe Bouriette** et **Marion Vaconsin** - _Atelier Bouriette et Vaconsin_\\n\\n*   **Olivier Brochet** - _BLP (Brochet, Lajus, Pueyo)_\\n\\n*   **Diane Camus** - _Doctorante au Laboratoire de recherche UMR PASSAGES/ensapBx_\\n\\n*   **Gauthier Claramunt** - _Dauphins architecture_\\n\\n*   **Oriane Deville** - _collectif Encore_\\n\\n*   **Stéphane Duprat** - _collectif Alpage_\\n\\n*   **Sébastien Gafari** et **Hélène Grialou** - _Le cabinet d’architecture_\\n\\n*   **Christophe Gautié**, _Flint_\\n\\n*   **Alan Gentil** - _Bureau Baroque_\\n\\n*   **Lucas Geoffriau**, **Camille Ricard** et **Etienne Henry** - _collectif Moonwalklocal_\\n\\n*   **Jules Mansart** - _collectif Cancan_\\n\\n*   **Vincent Milla** - _Baobab, dealer d''espace_\\n\\n*   **Frédéric Neau** - _Atelier d''architecture King Kong_\\n\\n*   **Paul Rolland** - _2:pm architectures_\\n\\n*   **Joe Vérons** - _Hessamfar et Vérons_"}', '{"fr":"architecture, architecte, demain, conférence, débat, projection, ensap Bordeaux, arc en rêve"}', NULL, '{"filename":"event_architect-ure-demain_732246.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architect-ure-demain_732246.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architect-ure-demain_732246.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T16:00:00.000Z","end":"2016-10-14T17:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["communication@bordeaux.archi.fr","http://www.bordeaux.archi.fr"]', '2016-11-04 09:19:02', '2016-11-04 09:19:02', NULL ),
(145738, 57473902, 58428515, NULL, 35811397, 'architecte-en-herbe', '{"fr":"Atelier pédagogique \\"Architecte en herbe\\""}', '{"fr":"Relève le défi de la tour la plus haute ! - Atelier pour enfants"}', '{"fr":"Un atelier \\"jeu de construction en bois\\" vous est proposé par le CAUE de la Sarthe : l''occasion d''appréhender la structure d''un bâtiment tout en s''amusant !"}', '{"fr":",      atelier,     CAUE de la Sarthe,    Mécabois,   jeu de construction,  enfants, architecture"}', NULL, '{"filename":"event_architecte-en-herbe_36356.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architecte-en-herbe_36356.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architecte-en-herbe_36356.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T12:30:00.000Z","end":"2016-10-15T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":12}', '["e.rodriguez@caue-sarthe.com","0243723531"]', '2016-11-04 09:20:03', '2016-11-04 09:20:03', NULL ),
(146719, 30362344, 36253948, NULL, 82014065, 'architecture-a-pommiers', '{"fr":"Exposition \\"Architecture à Pommiers\\""}', '{"fr":"Petite exposition sur l’architecture ancienne et moderne à Pommiers"}', '{"fr":"Nous avons envie de montrer des constructions exemplaires du passé, des constructions plus récentes et aussi quelques images de l’extension de l’école élémentaire. En même temps il y aura la possibilité pour tous (enfants et adultes) de se lancer dans les constructions ludique, à petite échelle bien sûr."}', '{"fr":",  exposition,  jeux"}', NULL, '{"filename":"event_architecture-a-pommiers_195146.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architecture-a-pommiers_195146.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architecture-a-pommiers_195146.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T10:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":99}', '[]', '2016-11-04 09:19:14', '2016-11-04 09:19:14', NULL ),
(146456, 61380410, 82460052, NULL, 24724545, 'architecture-contemporaine-en-aveyron', '{"fr":"Exposition \\"Architectures contemporaines en Aveyron\\""}', '{"fr":"La médiathèque de Rodez et le CAUE s''associent pour présenter une exposition sur les architectures contemporaines en Aveyron."}', '{"fr":"Cette exposition, accompagnée d''une sélection documentaire effectuée parmi les collections de la médiathèque, est présentée du 8 au 17 octobre 2016.\\n\\n2 projections sont proposées le samedi 15 octobre dans la petite salle de la médiathèque."}', '{"fr":"architecture, construire, maison, équipement public, livre"}', NULL, '{"filename":"event_architecture-contemporaine-en-aveyron_647658.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architecture-contemporaine-en-aveyron_647658.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architecture-contemporaine-en-aveyron_647658.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T12:00:00.000Z","end":"2016-10-13T16:30:00.000Z"},{"begin":"2016-10-14T10:00:00.000Z","end":"2016-10-14T16:30:00.000Z"},{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T10:30:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '[]', '2016-11-04 09:19:29', '2016-11-04 09:19:29', NULL ),
(145858, 87610168, 74430646, NULL, 24685571, 'architecture-et-aleas-naturels', '{"fr":"Table ronde & conférence \\"Architecture et Aléas Naturels\\""}', '{"fr":"Problématiques relatives aux aléas naturels à l''heure de la transition écologique."}', '{"fr":"Dans le cadre des journées nationales de l''architecture lancées par le Ministère de la culture et de la communication les 14, 15 et 16 octobre 2016, l’École nationale supéieure d''architecture de Paris La Villette organise une grande journée \\"Architecture et Aléas naturels\\" pour discuter et débattre de l''architecture et de ses confrontations aux aléas naturels. Cette journée aura lieu le vendredi 14 octobre à l''amphithéâtre 302 de 9h30 à 17h.\\n\\nG. Schauner et M. Guignard, deux conférenciers extérieurs, interviendront le matin puis l''après-midi sera consacré à une table ronde composée des enseignants de l''école qui le souhaitent, et portera sur la pédagogie du projet d''architecture au regard des problématiques relatives aux aléas naturels à l''heure de la transition écologique."}', '{"fr":", climat-transition energétique-coop21-"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T08:00:00.000Z"},{"begin":"2016-10-14T16:00:00.000Z","end":"2016-10-14T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":19,"max":80}', '[]', '2016-11-04 09:19:58', '2016-11-04 09:19:58', NULL ),
(147425, 26507966, 74430646, NULL, 24685571, 'architecture-et-aleas-naturels-le-vendredi-14-oct-2016', '{"fr":"Exposition \\"''Architecture et aléas naturels\\""}', '{"fr":"exposition : en attendant la crue"}', '{"fr":"Pour la Journée Architecture et Aléas naturels, ET ALORS investit la galerie de l’ENSAPLV avec des recherches en cours sur l’adaptation de la ville à l’augmentation de la mer.\\n\\nA la croisée de plusieurs disciplines (recherche, pratique artistique et enseignement), ET ALORS présente un extrait de la Résidence « Villes estuaires + 1M » à Hambourg et Lisbonne, des travaux d’écriture et des propositions d’étudiants en Master 2 dans des contextes soumis à des risques d''inondation. L''exposition puisera dans : - le projet \\"Villes estuaire +1M\\" lauréat de la Bourses Hors les Murs de l''Institut Français, résidence 2014 à Hambourg et Lisbonne- le mémoire de recherche en DPEA à la Villette (\\"Habiter l''incertitude\\") mené en parallèle de la résidence en immersion au Gerphau- l''article écrit pour l''Architecture d''Aujourd''hui (\\"L''eau en toutes lettres\\")- une approche de l''enseignement sur le risque menée avec Eric Daniel-Lacombe"}', '{"fr":", eau- risques naturels"}', NULL, '{"filename":"event_architecture-et-aleas-naturels-le-vendredi-14-oct-2016_890403.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architecture-et-aleas-naturels-le-vendredi-14-oct-2016_890403.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architecture-et-aleas-naturels-le-vendredi-14-oct-2016_890403.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:30:00.000Z","end":"2016-10-14T08:30:00.000Z"},{"begin":"2016-10-14T08:30:00.000Z","end":"2016-10-14T09:30:00.000Z"},{"begin":"2016-10-14T09:30:00.000Z","end":"2016-10-14T10:30:00.000Z"},{"begin":"2016-10-14T10:30:00.000Z","end":"2016-10-14T11:30:00.000Z"},{"begin":"2016-10-14T11:30:00.000Z","end":"2016-10-14T12:30:00.000Z"},{"begin":"2016-10-14T12:30:00.000Z","end":"2016-10-14T13:30:00.000Z"},{"begin":"2016-10-14T13:30:00.000Z","end":"2016-10-14T14:30:00.000Z"},{"begin":"2016-10-14T14:30:00.000Z","end":"2016-10-14T15:30:00.000Z"},{"begin":"2016-10-14T15:30:00.000Z","end":"2016-10-14T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":10,"max":80}', '["01 44 65 23 00"]', '2016-11-04 09:18:34', '2016-11-04 09:18:34', '2016-11-07 09:14:32' );
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at` ) VALUES
(145783, 80880054, 99246400, NULL, 45938497, 'architecture-et-environnement-la-pierre-incomparable-alliee', '{"fr":"Exposition \\"Architecture et environnement: La pierre, incomparable alliée\\""}', '{"fr":"exposition de 9 panneaux du résultat du concours photo sur la pierre naturelle en Languedoc-Roussillon, organisé par Maisons Paysannes et table ronde sur la modernité du matériau."}', '{"fr":"Les Journées Nationales de l’Architecture sont pour l’École Nationale Supérieure d’Architecture de Montpellier l’occasion de présenter différentes architectures de pierre. En partenariat avec la délégation héraultaise de l’association Maisons Paysannes de France, l’ENSAM veut sensibiliser le public à ce matériau ancestral et hautement symbolique. En 2015, Maisons Paysannes de France a remis les prix du concours de photos qu’elles avaient lancés. Parmi les participants, des étudiants de l’ENSAM dont trois ont été lauréats de plusieurs prix. Avec les clichés primés, d’autres illustreront tout au long de cette exposition la diversité et la richesse d’expression de la pierre. Une table ronde aura donné lieu le 12 octobre à 12h30 à l’ENSAM à débats sur la modernité de ce matériau."}', '{"fr":"table ronde, exposition, photo, exposition photo, pierre sèche, architecture contemporaine, patrimoine, architecture, ruralité, matériaux"}', NULL, '{"filename":"event_architecture-et-environnement-la-pierre-incomparable-alliee_677014.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architecture-et-environnement-la-pierre-incomparable-alliee_677014.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architecture-et-environnement-la-pierre-incomparable-alliee_677014.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:30:00.000Z","end":"2016-10-14T17:00:00.000Z"},{"begin":"2016-10-13T07:30:00.000Z","end":"2016-10-13T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '[]', '2016-11-04 09:20:01', '2016-11-04 09:20:01', NULL ),
(145954, 23282814, 67248378, NULL, 3032475, 'architecture-xxe-siecle-visite-de-la-citee-rebard', '{"fr":"Visite architecturale: Architecture moderne et contemporaine"}', '{"fr":"Venez découvir l''architecture moderniste du XXe siècle grâce à un parcours en petit train incluant la visite guidée de la cité Rebard"}', '{"fr":"Venez en apprendre plus sur les caractéristiques de l''architecture moderniste du XXe siècle en compagnie d''un architecte du patrimoine grâce à un parcours thématique en petit train et à une visite guidée de la cité Rebard. Cette première édition des Journées nationales de l''architecture vous donnera l''occasion d''admirer des exemples d''architecture moderne à travers la ville et vous permettra de découvrir un témoignage de l''architecture moderniste tropicale grâce à la visite de la cité Rebard !"}', '{}', NULL, '{"filename":"event_architecture-xxe-siecle-visite-de-la-citee-rebard_155468.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architecture-xxe-siecle-visite-de-la-citee-rebard_155468.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architecture-xxe-siecle-visite-de-la-citee-rebard_155468.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T06:30:00.000Z","end":"2016-10-16T09:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '["05 94 25 54 15","mariamejia@culture.gouv.fr"]', '2016-11-04 09:19:52', '2016-11-04 09:19:52', NULL ),
(146377, 97891211, 1314960, NULL, 41974092, 'architectures-comparees', '{"fr":"Exposition \\"Architectures comparées\\""}', '{"fr":"Exposition de travaux d''étudiants de l''ENSA-V réalisés lors du 2e semestre 2016"}', '{"fr":"L’exposition « Architectures comparées » présente une sélection de travaux d’étudiants de l’ENSA-V réalisés lors du 2ème semestre de 2016\\\\. Conçue comme un cabinet de curiosités, elle réunit des documents, dessins, plans, perspectives ou maquettes juxtaposés pour former des ensembles cohérents.\\n\\nSophie Delhay et Martial Marquet, architectes et enseignants à l’ENSA-V, proposent une exposition qui n’est ni exhaustive, ni progressive, mais au contraire spontanée, immédiate, intense et riche, comme peut l’être l’entrée dans une école d’architecture pour les étudiants de 1ère année.\\n\\nLes projets d’étudiants n’y sont pas présentés dans leur intégralité ni classés selon une progression dans le cursus ; ils sont plutôt rassemblés par mode de représentation, par échelle, par format ou encore par couleur.\\n\\nCette exposition est l’occasion de présenter des documents rarement vus à leur échelle réelle, souvent vite décrochés et oubliés à la fin d’un semestre par les étudiants eux-mêmes, alors qu’ils ont pourtant nécessité de nombreuses heures de travail et démontrent l’acquisition des outils nécessaires au métier d’architecte.\\n\\nIl s''agit d''un « arrêt sur image » de la production de l’école qui permet d’appréhender la diversité des approches et des enseignements coexistant et se complétant dans un même lieu.\\n\\nExposition présentée jusqu''au 28 octobre 2016, du lundi au vendredi, 10h-12h / 14h-17h."}', '{"fr":"architecture, travaux, projets, étudiants, représentation, maquette, echelle, axonométrie, dessin, plan, mémoire, projet de fin d''études, perspectives"}', NULL, '{"filename":"event_architectures-comparees_475884.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architectures-comparees_475884.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architectures-comparees_475884.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T08:00:00.000Z","end":"2016-10-13T10:00:00.000Z"},{"begin":"2016-10-13T12:00:00.000Z","end":"2016-10-13T15:00:00.000Z"},{"begin":"2016-10-14T08:00:00.000Z","end":"2016-10-14T10:00:00.000Z"},{"begin":"2016-10-14T12:00:00.000Z","end":"2016-10-14T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":16}', '[]', '2016-11-04 09:19:33', '2016-11-04 09:19:33', NULL ),
(145880, 82725582, 99246400, NULL, 69995179, 'architectures-ephemeres-pres-des-remparts-d-aigues-mortes', '{"fr":"Exposition \\"Architectures éphémères près des remparts d''Aigues-Mortes\\""}', '{"fr":"Des planches montrant les possibilités d''insertion d''équipements mobiles respectant le lieu et permettant des activités."}', '{"fr":"Le Prix d’Architecture, organisé par le Conseil Régional de l’Ordre des Architectes Languedoc-Roussillon (CROA LR), veut mieux faire connaître et diffuser la production architecturale régionale contemporaine. Il comporte un Prix d’Architecture et un Prix Étudiant.\\n\\nEn 2015 le thème du Prix Étudiant a proposé aux étudiants de l’École d’Architecture de Montpellier de travailler sur l’implantation d’un équipement éphémère au sud des remparts d’Aigues-Mortes constitué de divers éléments exploitables en toute saison et en liaison avec les remparts. L’ENSAM et l''administratrice du monument d’Aigues-Mortes ont voulu enrichir leur partenariat avec l’exposition de quelques-uns de ces projets et servir l’une des finalités des Journées Nationales de l’Architecture : présenter une architecture au service du quotidien et de l’environnement."}', '{"fr":"Prix de l''ordre des architectes,    CROA LR,    CMN,    Remparts,    Monuments nationaux,    ENSAM,     architecture éphémère,   étudiants,  Ecole d''architecture de Montpellier, environnement"}', NULL, '{"filename":"event_architectures-ephemeres-pres-des-remparts-d-aigues-mortes_35848.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architectures-ephemeres-pres-des-remparts-d-aigues-mortes_35848.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architectures-ephemeres-pres-des-remparts-d-aigues-mortes_35848.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T08:00:00.000Z","end":"2016-10-14T15:30:00.000Z"},{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T15:30:00.000Z"},{"begin":"2016-10-16T08:00:00.000Z","end":"2016-10-16T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":11}', '[]', '2016-11-04 09:19:57', '2016-11-04 09:19:57', NULL ),
(146787, 83656502, 99708626, NULL, 38928664, 'architectures-habitees-de-l-ile-de-nantes-2010-2016', '{"fr":"Architectures habitées de l''Ile de Nantes 2010-2016"}', '{"fr":"Exposition du 7 octobre au 17 décembre 2016 - Du mardi au samedi de 13h à 19h"}', '{"fr":"L''île de Nantes connaît une forte dynamique de projets depuis le début des années 2000.\\n\\nLa Samoa, maître d''ouvrage, et l''équipe d''architectes urbanistes Smets/uapS, a instauré depuis 2010 une nouvelle approche qui tisse une attentive relation entre projet urbain et architecture, notamment à travers les questions d''usages et de mixités.\\n\\nL''exposition \\"Architectures habitées de l''île de Nantes 2010-2016\\" présente le processus de conception des projets lancés sur la période et les ambitions de leurs différentes expressions architecturales.\\n\\n_Pour enrichir cette exposition, un programme de visites et de rencontres est proposé par l''Agence des rencontres urbaines :_\\n\\n_- Samedi 15 octobre, de 9h30 à 12h : \\"Explo, dérive à travers l''Ile habitée\\"_\\n\\n_- Lundi 17 octobre, de 18h à 19h30 : \\"A la découverte d''une agence d''architecture\\"_\\n\\n_- Jeudi 27 octobre, de 18h à 19h : \\"Rencontres avec les nouveaux acteurs de la maîtrise d''usage\\"_\\n\\n_- Jeudi 24 novembre, de 11h30 à 13h : \\"Rencontre avec les acteurs d''un chantier\\"_\\n\\n_- Jeudi 8 décembre, de 12h30 à 14h : \\"L''ile Bus Tour\\"_\\n\\n_Visites et rencontres sur inscription :_\\n\\nENTREE LIBRE"}', '{"fr":"visite, exsposition, rencontres"}', NULL, '{"filename":"event_architectures-habitees-de-l-ile-de-nantes-2010-2016_556563.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_architectures-habitees-de-l-ile-de-nantes-2010-2016_556563.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_architectures-habitees-de-l-ile-de-nantes-2010-2016_556563.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-13T11:00:00.000Z","end":"2016-10-13T17:00:00.000Z"},{"begin":"2016-10-14T11:00:00.000Z","end":"2016-10-14T17:00:00.000Z"},{"begin":"2016-10-15T11:00:00.000Z","end":"2016-10-15T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":16}', '["http://www.iledenantes.rencontres-urbaines.fr"]', '2016-11-04 09:19:10', '2016-11-04 09:19:10', NULL ),
(146631, 21744719, 92423239, NULL, 92192261, 'arles-a-travers-la-ville-antique', '{"fr":"Promenade urbaine \\"Arles, à travers la ville antique\\""}', '{"fr":"Des parcours à télécharger ou à suivre directement sur son téléphone sur www.architectouro.fr pour voir la ville méditerranéenne autrement par le Syndicat des Architectes des Bouches-du-Rhône"}', '{"fr":"La ville méditerranéenne ne se donne pas, elle se découvre. C''est pourquoi le Syndicat des Architectes des Bouches-du Rhône se propose de s''aventurer avec vous sur ce chemin afin de se(re)découvrir certaines de ses richesses architecturales contemporaines, de décrypter ses codes construits, ses quartiers, ses ambiances...C''est le principe de la promenade architecturale. Chaque parcours a pour départ un lieu culturel majeur et se termine sur un espace de rencontre, de vie urbaine ou un lieu de contemplation.\\n\\nLe parcours Arles, à travers la ville antique\\n\\nUne balade à travers la ville qui retrace les grands moments de l’histoire de l’ancienne Cité romaine. Des vestiges de l’Antiquité aux opérations de relogement de l’après-guerre en passant par les anciennes friches ferroviaires, avec comme point de départ le musée qui raconte les origines de la ville...\\n\\nLe parcours est disponible via son téléphone à cette adresse :\\n\\nhttp://www.architectouro.fr//parcoursar11.html\\n\\nIl est aussi possible de télécharger un pdf à cette adresse :\\n\\n[http://www.architectouro.fr//plan/AR1-A4.pdf](http://www.architectouro.fr//plan/AR1-A4.pdf)"}', '{"fr":",  Arles, Balades urbaines"}', NULL, '{"filename":"event_arles-a-travers-la-ville-antique_597440.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_arles-a-travers-la-ville-antique_597440.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_arles-a-travers-la-ville-antique_597440.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T05:00:00.000Z","end":"2016-10-13T04:00:00.000Z"},{"begin":"2016-10-14T05:00:00.000Z","end":"2016-10-14T04:00:00.000Z"},{"begin":"2016-10-15T05:00:00.000Z","end":"2016-10-15T04:00:00.000Z"},{"begin":"2016-10-16T05:00:00.000Z","end":"2016-10-16T04:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":3}', '[]', '2016-11-04 09:19:19', '2016-11-04 09:19:19', NULL ),
(145853, 68926119, 1273136, NULL, 26127766, 'arno-futur-release-party-zebra', '{"fr":"ARNO FUTUR RELEASE PARTY + ZEBRA"}', '{"fr":"Rock, Chanson"}', '{"fr":"Pour fêter comme il se doit la sortie du premier album solo d''Arno Futur, RDV le 20 octobre au Chinois de Montreuil dès 20h30.\\n\\n▬▬▬▬▬▬▬▬▬ LINE UP ▬▬▬▬▬▬▬▬▬\\n\\n► Arno Futur\\n\\nSourire repeint à l’acide, jeux de maux, claque sur le coup de soleil, l’empêcheur de penser ron-ron est de retour.Trafiqueur de sons, dealer d’electro punk rock, Arno et ses complices Benjamin (Amok, Popelek, Juge Fulton), Jipi Jungle & Stéphane (Reviens Fernande), Thierry Saul (Colditz) se soucient peu des structures toutes faites.Arno pose sa voix déclamante ou grinçante selon l’humeur, sur des riffs de guitares métalliques et une rythmique persistante.Un peu d''autodestruction. Beaucoup de dérision.\\n\\nEcouter: https://soundcloud.com/arnofutur\\n\\n► ZEBRA\\n\\nAntoine Zebra sort actuellement son album \\"Plaisirs et dissidence\\" et viendra présenter sa nouvelle formation live pour la première fois à Montreuil. Un duo guitares / batterie au service de chansons rock n'' roll en français, voix grave, textes corrosifs ou sensuels... Une nouvelle peau de zèbre pour celui qui a été DJ et concepteur de mélanges inattendus pendant plus de 15 ans. Cette fois, c''est par son jeu de guitare et ses textes qu''il vous surprendra.\\"Plaisirs et dissidence\\" est dispo jusqu''au 22 Octobre sur https://www.ulule.fr/antoine-zebra/\\n\\nEcouter: www.zebramix.frVoir: https://www.youtube.com/watch?v=f-u9PTnLwKs\\n\\n► GUESTS (TBA)\\n\\n▬▬▬▬▬▬▬▬▬▬ INFOS ▬▬▬▬▬▬▬▬▬▬\\n\\n► Le Chinois\\n\\n6, place du Marché93 100 Montreuil\\n\\nLigne 9: Croix de Chavaux\\n\\n► 20h30 - 01h00"}', '{"fr":"Rock, Chanson, Arno Futur, Gratuit"}', NULL, '{"filename":"event_arno-futur-release-party-zebra_861033.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_arno-futur-release-party-zebra_861033.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_arno-futur-release-party-zebra_861033.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-20T18:00:00.000Z","end":"2016-10-20T00:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '[]', '2016-11-04 09:19:58', '2016-11-04 09:19:58', NULL ),
(147557, 15116070, 90489806, NULL, 74182014, 'ars-musica-presences-electronique-bruxelles', '{"fr":"ARS Musica / Présences électronique Bruxelles Part I"}', '{"fr":"Festival de la création musicale qui explore les possibles sonores s’affranchissant des frontières et des dogmes"}', '{"fr":"La seconde édition de Présences Electronique Brussels est l’’occasion d’une plongée en apnée dans la musique électronique expérimentale autour de l’acousmonium, formidable orchestre de haut parleurs, dont la vocation première réside dans la spatialisation du son. Créé à Paris en 2004, Présences Electronique présente depuis plusieurs années, une étonnante diversité des propositions musicales où ne s’impose pas une esthétique dominante, mais au contraire où naît une constellation de possibles et d’expressions liées à de nombreuses modalités ou façons de produire ces musiques. Instruments acoustiques ou électroniques, platines, laptops, magnétophones, prototypes de circonstance sont autant de sources et de ressources pour exprimer notre époque à tous les niveaux.\\n\\n**TODOROFF**\\n\\n— Todor Todoroff (BE)Électroniques\\n\\nTodor Todoroff (1963).Different RitesCréation mondiale – commande d’Ars Musica\\n\\nCette pièce s’inspire des sons des taikos japonais, du « kuchi-shōga », système phonétique qui associe une syllabe à chacun des sons de l’instrument, et des formes musicales associées. Ces formes se réfèrent aux rituels des sanctuaires shintos et des temples bouddhistes ainsi qu’au phénomène kumi-daiko, ensembles de taiko nés dans les années 50, où la puissance des rythmes polyphoniques est décuplée par les gestes synchronisés et chorégraphiés des interprètes. Elle transpose les codes et explore, à travers plusieurs mouvements, les points de rencontre avec les synthétiseurs analogiques modulaires historiques du GRM, les séquences-jeu, le montage, le geste et les traitements numériques interactifs spatialisés.\\n\\n**TANAKA**\\n\\n— Atau Tanaka (JP)Électroniques\\n\\nAtau Tanaka (1963).Le Loup.Lifting.Myogram\\n\\nCes trois oeuvres reposent sur un processus développé par Atau Tanaka depuis de nombreuses années : des capteurs placés sur les bras du musicien permettent à un logiciel d’analyser la tension musculaire et de transformer ces informations en sons et séquences musicales. Le propre corps de l’interprète devient alors instrument, lui permettant d’articuler le son par le geste. Naturels et synthétiques, les timbralités exploitent également le son du corps. Ainsi Myogram, une oeuvre conçue avec Miguel Ortiz, prend sa source dans l’analyse stochastique reflétant l’activité musculaire du musicien, dont le résultat sonore est filtré par des résonateurs et des filtres\\n\\n**MORMONT**\\n\\n— Loup Mormont (BE)Électroniques\\n\\nLoup Mormont (1981).K52 pour électro-acoustiqueK52 voor elektroakoestiekCréation mondiale – commande d’Ars Musica\\n\\nDans le roman le Convoi de l’Eau d’Akira Yoshimura, « K44 » est le nom d’un barrage construit dans un Japon sauvage et inexploré. Avec cette pièce, Loup Mormont a composé des espaces hybrides et y a tracé des frontières pour mieux en jouer.  les clivages entre comportement mécanique et état sauvage, entre rythmes et masses, entre notes et bruits, se déplacent, se précisent ou s’évanouissent. De ces territoires mouvants, on peut voir surgir des créatures sonores, débris robotiques ou résonances fantomatiques, qui se croisent et se métamorphosent.\\n\\n**VIGROUX & VAINIO**\\n\\n— Franck Vigroux (FR)Électroniques— Mika Vainio (FI)Électroniques\\n\\nFranck Vigroux (1973)& Mika Vainio (1963).Peau Froide, Léger Soleil\\n\\nLa collaboration entre le Finlandais Mika Vainio, co-fondateur de Pan- Sonic et le Français Frank Vigroux remonte à 2012 autour d’un projet discographique baptisé : Peau Froide, Léger Soleil. Au regard de leur itinéraire respectif, il était naturel que les points de fusions soient multiples et riches. Ambient, texture, couleur et qualité intrinsèque du son, donnent à ce projet une singularité que certains n’hésitent pas à classer sous le terme « d’harmonie chaotique ».\\n\\nComme des frappes sporadiques, des rythmiques cinglantes et de cuts chirurgicaux, leurs univers cohabitent avec des éléments parfois focalisés sur l’ambiance et la sphère sonore que les deux musiciens se plaisent à aérer, à geler dans l’espace pour mieux les saturer de hachures, de stries radioactives et de fréquences létales.\\n\\nRetrouvez plus d''informations sur le festival ARS Musica"}', '{"fr":"musique électronique, présence électronique, GRM, Ina, musique expérimentale"}', NULL, '{"filename":"event_ars-musica-presences-electronique-bruxelles_167899.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_ars-musica-presences-electronique-bruxelles_167899.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_ars-musica-presences-electronique-bruxelles_167899.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-17T19:00:00.000Z","end":"2016-11-16T23:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":5,"max":14}', '["http://www.arsmusica.be/2016/?concert=presences-electronique-brussels"]', '2016-11-04 09:18:26', '2016-11-04 09:18:26', NULL ),
(147577, 83066537, 90489806, NULL, 74182014, 'ars-musica-presences-electronique-bruxelles-part-ii', '{"fr":"ARS Musica / Présences électronique Bruxelles Part II"}', '{"fr":"Festival de la création musicale qui explore les possibles sonores s’affranchissant des frontières et des dogmes"}', '{"fr":"La seconde édition de Présences Electronique Brussels est l’’occasion d’une plongée en apnée dans la musique électronique expérimentale autour de l’acousmonium, formidable orchestre de haut parleurs, dont la vocation première réside dans la spatialisation du son. Créé à Paris en 2004, Présences Electronique présente depuis plusieurs années, une étonnante diversité des propositions musicales : ne s’impose pas une esthétique dominante, mais au contraire une constellation de possibles et d’expressions liées à de nombreuses modalités ou façons de produire ces musiques. Instruments acoustiques ou électroniques, platines, laptops, magnétophones, prototypes de circonstance sont autant de sources et de ressources pour exprimer notre époque à tous les niveaux.\\n\\n**MORI**\\n\\n— Ikue Mori (JP/US)Acousmonium\\n\\nPour ce concert exceptionnel, Ikue Mori s’est inspiré des écrits d’Izumi Kyoka, romancier, dramaturge et poète japonais qui chevaucha les 19ème et 20ème siècles. Ses premières oeuvres sont souvent des fantaisies gothiques, emplies de superstitions, d’évènements surnaturels inexplicables et de fantômes en rupture avec la littérature de cette époque qui se tournait plutôt vers l’industrialisation et les sciences occidentales cartésiennes.\\n\\nIkue Mori expérimente la narration sans mots, en esquissant un catalogue timbrique inspiré par la nature notamment, donnant naissance à une atmosphère sonore aux facettes plurielles. Cet univers est fait de rêve pour le rêve, emmenant l’auditeur dans des mondes gothiques impalpables.\\n\\n**GOTO & HIRANO**\\n\\n— Makiko Goto (JP)Acousmonium— Mayu Hirano (JP)Acousmonium\\n\\nMayu Hirano (1979).Création pour musique mixte (électroniques et instruments) Creatie voor gemengde muziek (elektronisch en instrumenten)Création mondiale – commande d’Ars Musica\\n\\nPour cette oeuvre, Mayu Hirano s’est penchée sur le phénomène de « la mémoire à court terme ou mémoire de travail ». Cette facette singulière de la mémoire permet à une personne de disposer d’un espace de travail mental qui maintient des informations pendant plusieurs secondes. La compositrice a élaboré une oeuvre, se référant à ce phénomène, en s’appuyant sur une chronologie qui joue sur la répétition et la permutation des éléments sonores. Tout comme un mot décomposé et combiné différemment, ce montage trouble la mémoire. Cette forme ne se limite pas à une simple permutation chronologique ; elle est construite comme un grand plan musical découpé et remonté en fragments, mais aussi sur une évolution de la temporalité.\\n\\n**ASANO**\\n\\n— Koji Asano (JP)Acousmonium\\n\\nKoji Asano fait des sons du quotidien son instrumentarium. Air conditionné, verres, plats, distributeur d’eau, bouilloire, cuisson d’aliments, machines à café, tout est prétexte à enrichir sa palette sonore. Pour Asano, le rôle du compositeur est de mettre en relation les sons entre eux, de les faire vibrer les uns avec les autres, de polir un espace pour créer une musique différente. Si le compositeur pose la question de la naissance du son, il évoque aussi son extinction, sa disparition. Depuis que des scientifiques suédois ont réussi, pour la première fois, à capturer le son d’un atome, se pose la question d’un étrange phénomène de physique quantique où les vagues sonores se comportent comme de la lumière. Koji Asano cultive cette recherche et se pose la question de la vie et de la « mort » d’un son. Celui-ci n’est-il pas finalement éternel ?\\n\\n**YOSHIHIDE**\\n\\n— Otomo Yoshihide (JP)Acousmonium\\n\\nOtomo Yoshihide (1959).Création pour guitare et électronique Creatie voor gitaar en elektronicaCréation mondiale – commande d’Ars Musica\\n\\nLibre de tout schéma prévisible, Otomo Yoshihide esquisse une expression musicale qui ne cesse de surprendre l’auditeur par ses formes inattendues. Des platines au piano, en passant par la guitare, instrument de prédilection du musicien japonais ; les outils de Yoshihide ne sont que le médium d’une pensée musicale structurée, qui a fait de l’improvisation un terrain d’expérimentation en tout genre. Bousculant les codes, anamorphosant les classements et les genres, ce musicien activiste, en phase avec son environnement direct, « improvise » sur le moment de manière magistrale et fait de chaque concert un évènement en soi, un moment unique."}', '{"fr":"musique électronique, musique expérimentale, GRM, Ina, présence électronique"}', NULL, '{"filename":"event_ars-musica-presences-electronique-bruxelles-part-ii_953168.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_ars-musica-presences-electronique-bruxelles-part-ii_953168.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_ars-musica-presences-electronique-bruxelles-part-ii_953168.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-18T19:00:00.000Z","end":"2016-11-17T23:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":7,"max":14}', '["http://www.arsmusica.be/2016/?concert=presences-electronique-brussels-2"]', '2016-11-04 09:18:25', '2016-11-04 09:18:25', NULL ),
(147200, 78581601, 47307733, NULL, 88604102, 'art-et-liberte', '{"fr":"Art et liberté"}', '{"fr":"Le Centre Pompidou consacre ‑ pour la première fois dans un musée ‑ une exposition au groupe Art et Liberté, un collectif associé au surréalisme international, fondé au Caire le 22 décembre 1938."}', '{"fr":"**Le Centre Pompidou présente la première exposition d’envergure dédiée au groupe Art et Liberté (jama’at al-fann wa al-hurriyyah), un collectif surréaliste d’écrivains et d’artistes résidant et travaillant au Caire.**\\n\\nFondé le 22 décembre 1938, avec la publication du manifeste Vive l’art dégénéré, le groupe a offert à une jeune génération d’artistes, d’intellectuels et d’activistes une plate-forme hétérogène propice aux réformes culturelles et politiques. Ses membres ont compté parmi les acteurs d’un réseau international d’écrivains et d’artistes surréalistes. À l’aube de la Seconde Guerre mondiale, pendant la période de domination coloniale exercée sur l’Égypte par l’Empire britannique, le groupe Art et Liberté a défié le fascisme, le nationalisme et le colonialisme. Au travers de sa nouvelle définition du surréalisme, il a acquis un langage littéraire et pictural contemporain singulier, aussi engagé internationalement qu’enraciné dans les préoccupations artistiques et politiques locales.Cette exposition présente cent trente tableaux, œuvres sur papier et photographies de la fin des années 1920 au début des années 1950, ainsi qu’un grand nombre de documents d’archives, photographies, séquences de films et manuscrits jamais exposés auparavant. Les œuvres patiemment cherchées et retrouvées ont été empruntées à plus d’une cinquantaine de collections publiques et privées en Égypte et à travers le monde, dans onze autres pays."}', '{}', NULL, '{"filename":"event_art-et-liberte_964436.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_art-et-liberte_964436.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_art-et-liberte_964436.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-12-02T10:00:00.000Z","end":"2016-12-02T20:00:00.000Z"},{"begin":"2016-10-19T09:00:00.000Z","end":"2016-10-19T19:00:00.000Z"},{"begin":"2016-12-01T10:00:00.000Z","end":"2016-12-01T20:00:00.000Z"},{"begin":"2017-01-16T10:00:00.000Z","end":"2017-01-16T20:00:00.000Z"},{"begin":"2016-11-30T10:00:00.000Z","end":"2016-11-30T20:00:00.000Z"},{"begin":"2017-01-14T10:00:00.000Z","end":"2017-01-14T20:00:00.000Z"},{"begin":"2016-11-27T10:00:00.000Z","end":"2016-11-27T20:00:00.000Z"},{"begin":"2017-01-12T10:00:00.000Z","end":"2017-01-12T20:00:00.000Z"},{"begin":"2016-11-26T10:00:00.000Z","end":"2016-11-26T20:00:00.000Z"},{"begin":"2017-01-08T10:00:00.000Z","end":"2017-01-08T20:00:00.000Z"},{"begin":"2016-11-25T10:00:00.000Z","end":"2016-11-25T20:00:00.000Z"},{"begin":"2017-01-06T10:00:00.000Z","end":"2017-01-06T20:00:00.000Z"},{"begin":"2016-11-24T10:00:00.000Z","end":"2016-11-24T20:00:00.000Z"},{"begin":"2017-01-04T10:00:00.000Z","end":"2017-01-04T20:00:00.000Z"},{"begin":"2016-11-23T10:00:00.000Z","end":"2016-11-23T20:00:00.000Z"},{"begin":"2016-12-31T10:00:00.000Z","end":"2016-12-31T20:00:00.000Z"},{"begin":"2016-11-20T10:00:00.000Z","end":"2016-11-20T20:00:00.000Z"},{"begin":"2016-12-29T10:00:00.000Z","end":"2016-12-29T20:00:00.000Z"},{"begin":"2016-11-19T10:00:00.000Z","end":"2016-11-19T20:00:00.000Z"},{"begin":"2016-12-25T10:00:00.000Z","end":"2016-12-25T20:00:00.000Z"},{"begin":"2016-11-18T10:00:00.000Z","end":"2016-11-18T20:00:00.000Z"},{"begin":"2016-12-23T10:00:00.000Z","end":"2016-12-23T20:00:00.000Z"},{"begin":"2016-11-17T10:00:00.000Z","end":"2016-11-17T20:00:00.000Z"},{"begin":"2016-12-21T10:00:00.000Z","end":"2016-12-21T20:00:00.000Z"},{"begin":"2016-11-16T10:00:00.000Z","end":"2016-11-16T20:00:00.000Z"},{"begin":"2016-12-17T10:00:00.000Z","end":"2016-12-17T20:00:00.000Z"},{"begin":"2016-11-13T10:00:00.000Z","end":"2016-11-13T20:00:0