(145608, 65186952, 61648715, NULL, 25035006, 'art-et-science-l-archipel-aganta-kairos', '{"fr":"Art et science : l''archipel Aganta Kairos"}', '{"fr":"Plate-forme d''actions culturelles à géométrie variable qui enrichit le lien entre une expérience fondamentale de physique et un geste artistique"}', '{"fr":"Mettant en résonance les savoirs d’artistes, de scientifiques, de chamans, de philosophes, de sociologues, d’anthropologues avec ceux de la société civile, comme autant d’îles à relier dans un souci de démocratisation de l’accès aux sciences, l’Archipel Aganta Kairos s’organise dans chaque ville en synergie avec les équipes d’actions culturelles qui accueillent le projet.\\n\\nDans cette optique, le Centre de Physique des Particules de Marseille et la compagnie Eolie Songe de Lille, qui collaborent depuis 2012 au projet Aganta Kairos,initient conjointement diverses actions en région PACA, dont l’enchaînement fera sens sur le territoire de Toulon Provence Méditerranée."}', '{"fr":",   Art et Science,   physique des particules,"}', NULL, '{"filename":"event_art-et-science-l-archipel-aganta-kairos_467817.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_art-et-science-l-archipel-aganta-kairos_467817.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_art-et-science-l-archipel-aganta-kairos_467817.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-07T06:30:00.000Z","end":"2016-10-07T10:00:00.000Z"},{"begin":"2016-10-07T11:30:00.000Z","end":"2016-10-07T14:30:00.000Z"},{"begin":"2016-10-08T08:00:00.000Z","end":"2016-10-08T15:30:00.000Z"},{"begin":"2016-10-09T08:00:00.000Z","end":"2016-10-09T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":5,"max":99}', '["fetedelasciencevar@gmail.com"]', '2016-11-04 09:20:08', '2016-11-04 09:20:08', NULL ),
(146363, 8578578, 37159011, NULL, 42880672, 'artem-fete-la-science', '{"fr":"ARTEM Fête la Science !"}', '{"fr":"3ème édition de la fête de la science - village des sciences"}', '{"fr":"Plus d''une trentaine d''ateliers, expositions, conférences, débats, jeu-concours concentrés les 14 et 15 octobre au Campus ARTEM."}', '{}', NULL, '{"filename":"event_artem-fete-la-science_401041.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_artem-fete-la-science_401041.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_artem-fete-la-science_401041.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T12:00:00.000Z","end":"2016-10-14T16:00:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '["http://www.artemfetelascience.fr","03 55 66 26 00"]', '2016-11-04 09:19:34', '2016-11-04 09:19:34', NULL ),
(146701, 39476638, 96230177, NULL, 57834117, 'as-handball-lycee-alfred-nobel-clichy-sous-bois', '{"fr":"AS HANDBALL Lycée Alfred Nobel , Clichy sous bois"}', '{"fr":"Démocratisation du handball au lycée Alfred Nobel grâce à la création d''une Association sportive spécifique à cette activité."}', '{"fr":"En septembre 2015 le lycée Alfred Nobel de Clichy sous bois à ouvert une association sportive Handball pour permettre d''exploiter un potentiel certain au sein du lycée et ainsi compléter les autres AS déjà proposées.\\n\\nDès la première année le lycée a enregistré l''inscription d''environ 20 élèves avec une mixité parfaite , 10 filles et 10 garçons.\\n\\nDès la 1ère année notre équipe Juniors filles s''est qualifiés pour les Championnat de France de Handball à St Chamond et a terminé 8ème en perdant contre le finaliste de la compétition Besançon.\\n\\nDe plus notre arbitre masculin, Walid , a participé à la compétition et a raté de justesse la validation France. Il reste arbitre Académique et espère retenter la validation dans un Championnat de France pour obtenir des points en plus au BAC.\\n\\nEnfin en septembre 2016 , soit la 2ème année d''existence de L''As Handball , l''affluence s''établit à plus de 35 élèves par séance.\\n\\nNous souhaitons récompenser et surtout accroître cette dynamique \\"HANDBALL\\" au Lycée grâce au Mondial de Handball.\\n\\nEt surtout proposer aux élèves d’assister et de participer à cet événement car le milieu social et culturel des élèves ne permet pas toujours d''avoir accès à ce type d’événement."}', '{"fr":"Handball,   intégration,   mixité,   pédagogie,  Education, Autonomie"}', NULL, '{"filename":"event_as-handball-lycee-alfred-nobel-clichy-sous-bois_808145.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_as-handball-lycee-alfred-nobel-clichy-sous-bois_808145.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_as-handball-lycee-alfred-nobel-clichy-sous-bois_808145.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-02-07T16:30:00.000Z","end":"2017-02-07T18:00:00.000Z"},{"begin":"2016-10-04T15:30:00.000Z","end":"2016-10-04T17:00:00.000Z"},{"begin":"2017-01-31T16:30:00.000Z","end":"2017-01-31T18:00:00.000Z"},{"begin":"2017-06-13T15:30:00.000Z","end":"2017-06-13T17:00:00.000Z"},{"begin":"2017-01-24T16:30:00.000Z","end":"2017-01-24T18:00:00.000Z"},{"begin":"2017-05-30T15:30:00.000Z","end":"2017-05-30T17:00:00.000Z"},{"begin":"2017-01-17T16:30:00.000Z","end":"2017-01-17T18:00:00.000Z"},{"begin":"2017-05-16T15:30:00.000Z","end":"2017-05-16T17:00:00.000Z"},{"begin":"2017-01-10T16:30:00.000Z","end":"2017-01-10T18:00:00.000Z"},{"begin":"2017-05-02T15:30:00.000Z","end":"2017-05-02T17:00:00.000Z"},{"begin":"2017-01-03T16:30:00.000Z","end":"2017-01-03T18:00:00.000Z"},{"begin":"2017-04-18T15:30:00.000Z","end":"2017-04-18T17:00:00.000Z"},{"begin":"2016-12-27T16:30:00.000Z","end":"2016-12-27T18:00:00.000Z"},{"begin":"2017-04-04T15:30:00.000Z","end":"2017-04-04T17:00:00.000Z"},{"begin":"2016-12-20T16:30:00.000Z","end":"2016-12-20T18:00:00.000Z"},{"begin":"2017-03-21T16:30:00.000Z","end":"2017-03-21T18:00:00.000Z"},{"begin":"2016-12-13T16:30:00.000Z","end":"2016-12-13T18:00:00.000Z"},{"begin":"2017-03-07T16:30:00.000Z","end":"2017-03-07T18:00:00.000Z"},{"begin":"2016-12-06T16:30:00.000Z","end":"2016-12-06T18:00:00.000Z"},{"begin":"2017-02-21T16:30:00.000Z","end":"2017-02-21T18:00:00.000Z"},{"begin":"2016-11-29T16:30:00.000Z","end":"2016-11-29T18:00:00.000Z"},{"begin":"2017-06-06T15:30:00.000Z","end":"2017-06-06T17:00:00.000Z"},{"begin":"2016-11-22T16:30:00.000Z","end":"2016-11-22T18:00:00.000Z"},{"begin":"2017-05-09T15:30:00.000Z","end":"2017-05-09T17:00:00.000Z"},{"begin":"2016-11-15T16:30:00.000Z","end":"2016-11-15T18:00:00.000Z"},{"begin":"2017-04-11T15:30:00.000Z","end":"2017-04-11T17:00:00.000Z"},{"begin":"2016-11-08T16:30:00.000Z","end":"2016-11-08T18:00:00.000Z"},{"begin":"2017-03