(145646, 82497149, 67035877, NULL, 86632513, 'assemblee-et-ateliers-soiree-thematique-la-convergence-des-luttes-comme-alternative', '{"fr":"Assemblée et ateliers - Soirée thématique \\"La convergence des luttes comme alternative\\""}', '{"fr":"Rendez-vous jeudi 29 septembre place du Capitole"}', '{"fr":"Dorénavant Nuit Debout se réunit tous les jeudis place du Capitole ainsi que les 10, 20 et 30 du mois !\\n\\n[https://www.facebook.com/events/534703156720878/](https://www.facebook.com/events/534703156720878/)\\n\\n**18h** - Assemblée populaire \\"Les luttes en cours à Toulouse et ailleurs\\"\\n\\n**19h30** - Ateliers \\n\\nHôpital Debout / Faculté du Mirail / Latécoère / TAFTA-CETA / Notre Dame des Landes / MétéO en lutte / Un local pour Nuit Debout Toulouse + tout ce que vous proposerez !\\n\\n**21H - **Assemblée de restitution des ateliers.\\n\\n**21h30 -** Projection \\"L''intérêt général et moi\\" ou \\"Comme des lions\\""}', '{}', NULL, '{"filename":"event_assemblee-et-ateliers-soiree-thematique-la-convergence-des-luttes-comme-alternative_681121.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_assemblee-et-ateliers-soiree-thematique-la-convergence-des-luttes-comme-alternative_681121.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_assemblee-et-ateliers-soiree-thematique-la-convergence-des-luttes-comme-alternative_681121.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-29T16:30:00.000Z","end":"2016-09-28T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":11,"max":15}', '[]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
