(146983, 77757507, 16516950, 67271358, 31698321, 'assemblee-generale_397', '{"fr":"Assemblée générale"}', '{"fr":"Assemblée générale du Cercle des Services"}', '{"fr":"Notre Assemblée Générale fixée au 3 mars 2016 au restaurant le Céladon à Creney, sera l''occasion pour nous de revoir l''année passée et surtout de nous projeter sur celle à venir.\\n\\nC''est un moment de bilan, de réflexion, d''orientation, d''information, de communication, d''expression et surtout d''échanges.\\n\\nC''est un nouveau point de départ pour de nouvelles directions, de nouveaux challenges qui sont et resteront le fil conducteur de notre BUSINESS.\\n\\nC''est tout simplement notre feuille de route pour une route remplie de contacts et d''affaires.\\n\\nLe Cercle bouge, bougez avec lui!\\n\\nLa Présidente\\n\\nClaudine CORVO"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-03-03T06:00:00.000Z","end":"2016-03-03T06:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":12}', '[]', '2016-11-04 09:19:00', '2016-11-04 09:19:00', '2016-11-07 09:14:32' );
