(147258, 18955276, 26172308, NULL, 66811182, 'assemblee-populaire-thematique-avec-podemos-grenoble', '{"fr":"Assemblée Populaire Thématique avec Podemos Grenoble"}', '{"fr":"RDV à 19h au parc Paul Mistral (devant la Bobine)"}', '{"fr":"Le jeudi 13 octobre, Nuit Debout Grenoble vous convie à son Assemblée Populaire thématique, à laquelle seront présents des membres de Podemos Grenoble pour nous parler de ce mouvement.\\n\\nRDV 19h au parc Paul Mistral (devant la Bobine).\\n\\n**Au programme :**\\n\\n*   Historique du mouvement\\n*   Les problématiques liées à la communication\\n*   Podemos aujourd''hui\\n\\nVenez assister et participer à cette Assemblée !"}', '{}', NULL, '{"filename":"event_assemblee-populaire-thematique-avec-podemos-grenoble_384255.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_assemblee-populaire-thematique-avec-podemos-grenoble_384255.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_assemblee-populaire-thematique-avec-podemos-grenoble_384255.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T17:00:00.000Z","end":"2016-10-13T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":12}', '[]', '2016-11-04 09:18:44', '2016-11-04 09:18:44', NULL ),
(146370, 41455455, 26172308, NULL, 66811182, 'assemblee-populaire-thematique-sur-les-communs', '{"fr":"Assemblée populaire thématique sur les Communs"}', '{"fr":"Rdv jeudi 6 octobre, à 19h, au parc Paul Mistral, devant la Bobine"}', '{"fr":"Depuis plusieurs semaines, une commission s''est mise en place au sein de Nuit Debout Grenoble pour réfléchir aux communs.\\n\\nQu''est-ce-que les communs ? Comment se les réapproprier ?\\n\\nCette assemblée thématique réunira les membres de la commission et toutes les personnes intéressées pour imaginer comment agir pour les communs à Grenoble !"}', '{}', NULL, '{"filename":"event_assemblee-populaire-thematique-sur-les-communs_23902.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_assemblee-populaire-thematique-sur-les-communs_23902.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_assemblee-populaire-thematique-sur-les-communs_23902.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-06T17:00:00.000Z","end":"2016-10-06T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:33', '2016-11-04 09:19:33', NULL ),
(146650, 44068355, 70453612, NULL, 14936724, 'association-ciel-montbeliard-le-systeme-solaire', '{"fr":"A la découverte du système solaire"}', '{"fr":"Le système solaire et les instruments d''observation, Matériel d’observation astronomique et informatique, projection de documents, maquettes, photos et quiz sur les connaissances en astronomie"}', '{}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-08T08:00:00.000Z","end":"2016-10-08T16:00:00.000Z"},{"begin":"2016-10-09T08:00:00.000Z","end":"2016-10-09T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '[]', '2016-11-04 09:19:18', '2016-11-04 09:19:18', NULL ),
(145888, 62150968, 53556778, NULL, 8520184, 'association-sportive-du-college-de-boris-vian', '{"fr":"Association Sportive du collège de Boris Vian"}', '{"fr":"L''AS Handball du collège de Boris Vian a ouvert ses portes en 2015. Cette AS propose aux élèves de découvrir une activité qui ne fait pas partie de leur cursus scolaire."}', '{"fr":"L''association sportive du collège Boris Vian propose tout un tas d''activité. Depuis 2015, s''est ajouté à la liste le handball. Il était important de proposer une activité qui ne leur était par proposé dans le cursus scolaire traditionnel d''Education Physique et Sportive. L''idée du handball était d''autant plus intéressante que les élèves de ce collège ne le pratiquent que très exceptionnellement en club. Le basket-ball et le football étant les deux sports phares des élèves.  \\nL''objectif ici est de faire découvrir une activité dans toute sa complexité. Aussi bien motrice qu''affective. Les entrainements ont pour vocation d''affirmer le potentiel de ces jeunes enfants qui s''investissent grandement. Les compétitions du mercredi après-midi leur servent à s''affirmer et à se confronter à différents niveaux de pratique. Cela leur permet de voir le chemin qu''il leur reste à parcourir mais également d''apprendre auprès de ces joueurs souvent plus aguerris par leur pratique de club.\\n\\nLes membres de l''AS sont principalement des élèves de 4ème (année 2003). C''est un public extrêmement motivés et il me parait très intéressant de leur faire découvrir ce qu''est le haut niveau. Quoi de mieux que ce formidable événement à Paris, si proche du collège, pour ressentir des émotions incomparables.  \\nCette opportunité d''assister à un match du mondial serait un formidable vecteur de développement pour cette AS naissante dont tout le potentiel reste à exploiter.\\n\\nToute l''association va s''investir dans ce mondial en travaillant notamment sur le flashmob organisé par la FFHB. Handballeurs ou non, tous seront conviés à participer."}', '{"fr":",     Association,    handball,    Découverte,   Plaisir, Mondial 2017"}', NULL, '{"filename":"event_association-sportive-du-college-de-boris-vian_373998.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_association-sportive-du-college-de-boris-vian_373998.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_association-sportive-du-college-de-boris-vian_373998.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-31T11:30:00.000Z","end":"2016-10-31T12:30:00.000Z"},{"begin":"2016-09-26T10:30:00.000Z","end":"2016-09-26T11:30:00.000Z"},{"begin":"2016-12-05T11:30:00.000Z","end":"2016-12-05T12:30:00.000Z"},{"begin":"2016-10-03T10:30:00.000Z","end":"2016-10-03T11:30:00.000Z"},{"begin":"2016-10-10T10:30:00.000Z","end":"2016-10-10T11:30:00.000Z"},{"begin":"2016-10-17T10:30:00.000Z","end":"2016-10-17T11:30:00.000Z"},{"begin":"2016-10-24T10:30:00.000Z","end":"2016-10-24T11:30:00.000Z"},{"begin":"2016-11-28T11:30:00.000Z","end":"2016-11-28T12:30:00.000Z"},{"begin":"2016-11-07T11:30:00.000Z","end":"2016-11-07T12:30:00.000Z"},{"begin":"2016-11-14T11:30:00.000Z","end":"2016-11-14T12:30:00.000Z"},{"begin":"2016-11-21T11:30:00.000Z","end":"2016-11-21T12:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '[]', '2016-11-04 09:19:56', '2016-11-04 09:19:56', NULL ),
(146119, 10893391, 30512841, NULL, 37321461, 'astro-boy', '{"fr":"ASTRO BOY"}', '{"fr":"Film d''animation en relief américano-japonais de David Bowers de 2009 d''après le personnage iconique d''Osamu Tezuka, Astro, le petit robot."}', '{"fr":"La surface de la Terre est désormais un immense dépotoir, abandonnée par les privilégiés pour une ville flottante, Metro City. Là, le président sortant est prêt à tout pour sa réélection. Il lance l''essai d''un robot militaire, qui tourne mal, et le chercheur en chef, le professeur Tenma, y perd son fils Toby. Le professeur Tenma décide alors de le recréer en fabriquant un robot à son image, doté de pouvoirs exceptionnels et des souvenirs de Toby…"}', '{"fr":", cinéma; robot; projection; dessin animé;"}', NULL, '{"filename":"event_astro-boy_440904.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_astro-boy_440904.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_astro-boy_440904.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-08T15:00:00.000Z","end":"2016-10-08T16:35:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":77}', '["http://www.rambouillet.fr/--la-lanterne--.html"]', '2016-11-04 09:19:45', '2016-11-04 09:19:45', NULL ),
(145755, 94778349, 63982580, NULL, 6538561, 'atelier-architecture-et-eco-construction', '{"fr":"Atelier pédagogique \\"Architecture et éco-construction\\""}', '{"fr":"Atelier de découverte de l''éco-construction et des principes bio-climatiques"}', '{"fr":"A l''occasion des Journées Nationales de l''Architecture, les architectes Caroline Chapellet et Sabine Freytag vous proposent un atelier de découverte de l''éco-construction et des principes bio-climatiques, à travers des études de cas séculaires et contemporains.\\n\\nL''architecture n''est jamais l''application d''une recette, elle est belle et bien une synthèse d''un contexte paysager, économique, social, culturel, technique et temporel. Nous verrons comment les dogmes sont parfois à assouplir en intelligence avec les lieux et les hommes. Et c’est pourquoi, vous participerez avec vos interrogations, vos doutes, votre curiosité et vos projets qui amèneront le débat et le déroulé de l''atelier.\\n\\nL''atelier se déroulera à l''association Oïkos, association spécialisée dans la promotion de l''éco-construction et l''éco-rénovation depuis 25ans. L''occasion de venir découvrir nos projets, nos évènements et nos formations comme notre bâtiment en ossature bois-paille.\\n\\nAu plaisir de vous retrouver !"}', '{}', NULL, '{"filename":"event_atelier-architecture-et-eco-construction_733708.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-architecture-et-eco-construction_733708.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-architecture-et-eco-construction_733708.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T17:30:00.000Z","end":"2016-10-14T19:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":119}', '["lr@oikos-ecoconstruction.com"]', '2016-11-04 09:20:02', '2016-11-04 09:20:02', NULL ),
(146862, 6600255, 93003160, NULL, 17126684, 'atelier-architecture-pour-adolescents', '{"fr":"Atelier pédagogique \\"Architecture pour adolescents\\""}', '{"fr":"Avec Studio Quetzal, lauréats du 1er Festival International d''architecture d''intérieur Design Parade Toulon"}', '{"fr":"atelier design en famille avec le Studio Quetzal, lauréats Design Parade Toulon en 2016, autour de l’architecture de la villa Noailles. (durée 3h, pour les adolescents de 13 à 16 ans)"}', '{"fr":",     atelier,     adolescents,    architecture,   studio quetzal,  design parade toulon"}', NULL, '{"filename":"event_atelier-architecture-pour-adolescents_545473.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-architecture-pour-adolescents_545473.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-architecture-pour-adolescents_545473.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T12:30:00.000Z","end":"2016-10-15T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":13,"max":16}', '["mediation@villanoailles-hyeres.com","04 98 08 01 98","04 98 08 01 93"]', '2016-11-04 09:19:06', '2016-11-04 09:19:06', NULL ),
(146627, 55439390, 57966576, NULL, 93830418, 'atelier-autour-des-engrenages', '{"fr":"Atelier autour des engrenages"}', '{"fr":"Invitation à un voyage au cœur de l’horloge, d’où tu ressortiras expert en engrenages."}', '{"fr":"Une montre, une horloge mécanique, c’est un assemblage de rouages et de pièces, imbriqués les uns avec les autres. Mais comment cela fonctionne-t-il ? Roues dentées, pignons, engrenages … quèsaco ?"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T15:00:00.000Z"},{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T15:00:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"},{"begin":"2016-10-16T12:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":77}', '["03 81 66 20 95","jeremy.querenet@univ-fcomte.fr"]', '2016-11-04 09:19:19', '2016-11-04 09:19:19', NULL ),
(145855, 83915367, 35786151, NULL, 96804899, 'atelier-bibliotheque-en-scene', '{"fr":"[ATELIER] Bibliothèque en scène !"}', '{"fr":"La bibliothèque d''accueil de l''Adepeda 35 vous propose de venir tourner une petite vidéo de présentation du lieu en LSF ! Soyons créatifs !"}', '{"fr":"La bibliothèque d''accueil de l''ADEPEDA 35 souhaite créer une vidéo de présentation du lieu en LSF.\\n\\nPetits et grands sont conviés à venir imaginer un scénario humoristique / décalé / poétique / surprenant durant le temps d''un après-midi !"}', '{"fr":",       bibliothèque,      cinéma,     tournage,    vidéo,   lsf,  accueil, adepeda35"}', NULL, '{"filename":"event_atelier-bibliotheque-en-scene_709043.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-bibliotheque-en-scene_709043.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-bibliotheque-en-scene_709043.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-05T14:00:00.000Z","end":"2016-10-05T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["adepeda35@gmail.com"]', '2016-11-04 09:19:58', '2016-11-04 09:19:58', NULL ),
