(146011, 25453411, 83002070, NULL, 85938504, 'atelier-coding-club_534', '{"fr":"Atelier Coding Club"}', '{"fr":"Atelier d''initiation à la programmation"}', '{"fr":"Vous êtes lycéen(ne)s et passionné(e)s d''informatique?\\n\\nRejoignez le Coding Club et participez à des ateliers gratuits d’initiation à la programmation et au développement : jeux vidéo, robotique, web, etc…\\n\\nAucune compétence préalable en programmation n''est nécessaire et ceux qui le souhaitent peuvent amener leur propre ordinateur !\\n\\nInscription ► [http://codingclub.epitech.eu/inscription-strasbourg.html](http://codingclub.epitech.eu/inscription-strasbourg.html)\\n\\nRejoignez la communauté ► [Coding Club Strasbourg](https://www.facebook.com/groups/coding.club.strasbourg/)"}', '{}', NULL, '{"filename":"event_atelier-coding-club_534_810576.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-coding-club_534_810576.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-coding-club_534_810576.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-12-14T13:00:00.000Z","end":"2016-12-14T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":80}', '["http://codingclub.epitech.eu/inscription-strasbourg.html"]', '2016-11-04 09:19:50', '2016-11-04 09:19:50', NULL ),
(147555, 64360038, 80293505, NULL, 43300102, 'atelier-dans-les-coulisses-du-crowdfunding-intervention-de-sylvain-dumas-mardi-18-octobre-des-14h30', '{"fr":"Atelier \\"Dans les coulisses du Crowdfunding\\" : Mardi 18 Octobre dès 14h30"}', '{"fr":"Outils et méthodes du financement participatif par Sylvain Dumas. Suite de la présentation du 13 octobre organisée par la CCD."}', '{"fr":"Vous souhaitez mettre en place et réussir une campagne de crowdfunding. Sylvain Dumas tentera de répondre à vos questions et de vous aider à vous poser les bonnes."}', '{"fr":"crowdfunding, financement participatif, communication, projets, plateforme, contreparties, présenter son projet, coûts de la campagne"}', NULL, '{"filename":"event_atelier-dans-les-coulisses-du-crowdfunding-intervention-de-sylvain-dumas-mardi-18-octobre-des-14h30_550413.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-dans-les-coulisses-du-crowdfunding-intervention-de-sylvain-dumas-mardi-18-octobre-des-14h30_550413.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-dans-les-coulisses-du-crowdfunding-intervention-de-sylvain-dumas-mardi-18-octobre-des-14h30_550413.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-18T12:30:00.000Z","end":"2016-10-18T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":14}', '["contact@latelier.in"]', '2016-11-04 09:18:27', '2016-11-04 09:18:27', NULL ),
(147122, 22886511, 90883520, NULL, 89085435, 'atelier-de-web-design', '{"fr":"Atelier de web Design"}', '{"fr":"Tout ce que vous avez toujours voulu savoir sur le web design ... sans jamais oser le demander"}', '{"fr":"Webdesign, UI, mobil first, UX - si ces mots vous semblent ésotériques, mais que vous les entendez parfois, alors les ateliers du Web Design sont là pour vous ! Au travers d’expériences de professionnels, ces ateliers ont pour objectifs de vous présenter clairement et pratiquement ce qui se cache derrière ces vocabulaires, mais aussi et surtout les tendances du web qu’ils représentent.\\n\\nLes Ateliers du Web Design sont des événements mensuels pour promouvoir la veille, la rencontre et le partage entre apprentis ou professionnels du webdesign.\\n\\nUne fois par mois, des intervenants animeront un atelier sur l’une des nombreuses thématiques liées au web design, de la représentation graphique du besoin d’un client à son intégration technique.\\n\\nLe temps d’une soirée, venez échanger des méthodes et des outils, puis partager vos connaissances avec d’autres membres de la communauté numérique de la région - étudiants, professionnels ou autodidactes - dans une ambiance conviviale et décontractée.\\n\\nLes sujets abordés durant cette première saison iront de questions législatives et d’accessibilité, à la conception de mock-up et de l’expérience utilisateur, jusqu’à la mise en place technique du projet qu’elle soit pensée “App First” ou encore avec un framework.\\n\\nRetrouvez la liste complète des thématiques pour 2016/2017 ci-dessous :\\n\\n2016\\n\\n  Octobre - Veilles et tendances (outils, sites à consulter…) - Marie Cottu & Christèle Maitre\\n\\n Novembre - App First => de l’application au Desktop - Android - Peter Bardu\\n\\n Décembre - App First => de l’application au Desktop - IOS - Mathieu Bolard\\n\\n2017\\n\\n Janvier - Atelier spécial UI / UX - Manyssin Thin\\n\\n Février - Sketch / Invision (les mockups) - Arnaud Delpit\\n\\n Mars - Design Thinking - Cédric Neige\\n\\n Avril - L’accessibilité dans le web - Ludovic Evelin\\n\\n Mai - Framework - bootstrap, foundation - Olivier Plessis\\n\\n Juin - Animations HTML JS CSS3 - Benoits Lawniczak\\n\\n Juillet - Atelier optimisation des pages web (sass, less, taille des images)\\n\\n Septembre - SEO : webdesign & micro-data - Laure Ricote\\n\\n Octobre - Le droit dans le web - Valérie Leperlier-Roy\\n\\nLes ateliers sont gratuits et ouverts à tous. Des compétences en web sont néanmoins requises pour faciliter les échanges."}', '{"fr":", web design"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-27T17:00:00.000Z","end":"2016-10-27T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '[]', '2016-11-04 09:18:52', '2016-11-04 09:18:52', NULL ),
