(145944, 37612065, 40364112, NULL, 69982144, 'atelier-google-my-business_510', '{"fr":"Atelier Google My Business"}', '{"fr":"Améliorez votre référencement local en créant votre fiche personnalisée"}', '{"fr":"Améliorez votre référencement local en créant votre fiche personnalisée sur Google My Business : ajoutez vos horaires, vos coordonnées et des photos de votre entreprise.\\n\\nVotre référencement local et votre visibilité sur les moteurs de recherche seront accrus."}', '{}', NULL, '{"filename":"event_atelier-google-my-business_510_173454.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-google-my-business_510_173454.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-google-my-business_510_173454.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-21T09:00:00.000Z","end":"2016-11-21T11:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":9}', '["coworking@mairie-livron.fr","0786908320"]', '2016-11-04 09:19:53', '2016-11-04 09:19:53', NULL ),
(145889, 90522993, 80352427, NULL, 37330823, 'atelier-guides-spirituels_592', '{"fr":"Atelier Guides spirituels"}', '{"fr":"A la rencontre des êtres qui nous guident"}', '{"fr":"On parle beaucoup de guides spirituels. Qui sont-ils ? Que font-ils ? Comment les sentir ?\\n\\nVoici une invitation pour mieux comprendre ce concept, aller à leur rencontre en conscience et éviter les dérives.\\n\\n**Méditation, exercices de ressentis énergétiques, apprendre à percevoir sa guidance intérieure sont au programme.**\\n\\nInscription annuelle de 10€ pour l''Espace des possibles (lieu géré par une association - valable pour toutes les activités du lieu) + 15€ la séance.\\n\\nBâtiment A - Résidence Le Rubis 3 Impasse du Tacot des Batignolles, 63200 Riom (merci de rester discrets dans la cage d''escaliers pour le confort de nos voisins)\\n\\nRenseignements et inscriptions : Xavier Xael Girard 06.38.87.43.91 xavierxaelgirard@live.fr [http://xavierxaelgirard.wix.com/meditation](http://xavierxaelgirard.wix.com/meditation)"}', '{}', NULL, '{"filename":"event_atelier-guides-spirituels_592_391957.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-guides-spirituels_592_391957.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-guides-spirituels_592_391957.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-30T12:00:00.000Z","end":"2016-09-30T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '["0638874391","xavierxaelgirard@live.fr"]', '2016-11-04 09:19:56', '2016-11-04 09:19:56', NULL ),
(145851, 56795830, 74652048, NULL, 26210979, 'atelier-imagine-ta-place-publique-ideale', '{"fr":"Atelier pédagogique \\"Imagine ta place publique idéale\\""}', '{"fr":"atelier pédagogique sur la place Jean Jaurès"}', '{"fr":"La place Jean Jaurès appelée la place de la Plaine va être transformée par la ville de Marseille.\\n\\nNous proposons aux élèves en petit groupe d''imaginer leur place publique idéale en réfléchissant aux contraintes. Ils pourront se mettre dans la peau d''un architecte, urbaniste pour proposer un projet de rénovation de la place.\\n\\nUn temps d''observation de la place suivant des critères (mobilier urbain, espace de circulation, les usagers) et un temps d''interview des usagers précèdent la réflexion pour l''amélioration de la place. \\n\\nUn temps de restitution des idées est organisé avec vue aérienne de la place légendée et présenté aux autres groupes."}', '{"fr":",    architecture,    urbanisme,  mobilier urbain, atelier pédagogique"}', NULL, '{"filename":"event_atelier-imagine-ta-place-publique-ideale_249911.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-imagine-ta-place-publique-ideale_249911.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-imagine-ta-place-publique-ideale_249911.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T12:00:00.000Z","end":"2016-10-13T14:30:00.000Z"},{"begin":"2016-10-14T07:30:00.000Z","end":"2016-10-14T09:30:00.000Z"},{"begin":"2016-10-14T12:00:00.000Z","end":"2016-10-14T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":18}', '["communication.artcade@gmail.com"]', '2016-11-04 09:19:58', '2016-11-04 09:19:58', NULL ),
(145947, 44869615, 40364112, NULL, 69982144, 'atelier-imprimante-3d_964', '{"fr":"Atelier imprimante 3D"}', '{"fr":"Découvrez l''impression 3D et repartez avec votre objet"}', '{"fr":"Découvrez l''impression 3D et repartez avec votre objet !\\n\\nAu programme, explications sur le fonctionnement de l''impression 3D, présentation et manipulation du logiciel de dessin SketchUp, puis impression de votre objet."}', '{}', NULL, '{"filename":"event_atelier-imprimante-3d_964_984201.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_atelier-imprimante-3d_964_984201.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_atelier-imprimante-3d_964_984201.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-12-12T09:00:00.000Z","end":"2016-12-12T11:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '["coworking@mairie-livron.fr","0786908320"]', '2016-11-04 09:19:53', '2016-11-04 09:19:53', NULL ),
