(146686, 10635632, 38565623, 27545135, 92084673, 'baguage-d-oiseaux', '{"fr":"Baguage d’oiseaux"}', '{"fr":"Participer à une séance de baguage"}', '{"fr":"Venez participer à une séance de baguage à Plateau Boucher (pose de filets, identification, mesures biométriques, baguage…).\\n\\nPrévoir vêtement de pluie, jumelles…\\n\\nNiveau de difficulté : 1 (accessible à tous)"}', '{}', NULL, '{"filename":"event_baguage-d-oiseaux_398015.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_baguage-d-oiseaux_398015.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_baguage-d-oiseaux_398015.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-15T05:00:00.000Z","end":"2016-10-15T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["0696 224 704"]', '2016-11-04 09:19:16', '2016-11-04 09:19:16', NULL ),
(145588, 13333313, 1273136, NULL, 26127766, 'bal-afro-latino-felabration-w-kologbo-monkuti', '{"fr":"Bal Afro-Latino - Felabration w/ Kologbo & Monkuti"}', '{"fr":"Afrobeat, Cumbia"}', '{"fr":"❉ ▬ LE BAL AFRO-LATINO DE PANAME #5 special FELABRATION ▬ ❉▬▬▬▬▬▬▬▬▬▬▬ Hommage à Fela Kuti ▬▬▬▬▬▬▬▬▬▬▬\\n\\n◈ OGHENE KOLOGBO from EGYPT 70''s (afrobeat/live) ◈◈ MONKUTI (afrobeat/live) ◈ ◈ DJ CUCURUCHO & MOODY MATT (tropical grooves) ◈\\n\\n▧ ▧ ▧ 29 OCT 2016 ▧ ▧ ▧ 20H A 5H ▧ ▧ ▧ 8€ / 5€ (after party) ▧ ▧ ▧\\n\\n★|★▬▬▬▬▬▬▬▬▬▬▬ STYLES ▬▬▬▬▬▬▬▬▬▬▬★|★\\n\\n✦ AFROBEAT ✦ CUMBIA ✦ CHAMPETA ✦ AFRO FUNK ✦ SOUKOUSS ✦ BULLERENGUE ✦ AFRO PERUANO ✦ COUPE DECALE ✦ RAGGA ✦ DANCEHALL ✦ MANDINGO BEAT ✦ ANTILLES ✦ CALYPSO ✦ ZOUK\\n\\n●|● ▬▬▬▬▬▬▬▬▬▬▬ L I N E - U P ▬▬▬▬▬▬▬▬▬▬▬ ●|●\\n\\n★ LIVE ★\\n\\n● OGHENE KOLOGBO (Nigeria - Afrobeat / Live ) ● Le légendaire guitariste Oghene Kologbo est né a Warri, au Nigeria en 1957\\\\. Son père était un musicien highlife bien connu: Joe King Kologbo. A 13 ans il rejoint le maitre de l’Afrobeat Fela Kuti. Kologbo a enregistré plus de trente albums avec Fela. Principalement guitar ténor il a aussi enregistre basse et guit rythmique au sein des legendaires Africa 70\\\\. Kologbo était l’assistant de Fela ‘le magnétophone humain’ son travail était de se rappeler les mélodies que Fela lui chantait tard dans la nuit, et de les enseigner le lendemain au cours des répétitions au groupe Africa 70\\\\. En 1978, après un concert au Festival de Jazz de Berlin, Kologbo a quitté le groupe avec Tony Allen et quelques autres, ils sont restés à Berlin. Dans les années 1980 et les années 1990, Kologbo travailla avec le légendaire Roots Anabo. Il a aussi enregistré avec King Sunny Ade (Synchro System) et Brenda Fassie, parmi d’autres.https://www.facebook.com/OgheneKologbohttps://www.youtube.com/watch?v=QWJbl0yyGk4\\n\\n● MONKUTI (Afrobeat / Live ) ● Monkuti convoque les rythmes Vaudoun du Bénin associés au groove céleste de l''afrobeat Nigérian.https://www.facebook.com/monkutimusichttps://www.youtube.com/watch?v=l16Dwb5VPUk\\n\\n★ DJ SET ★\\n\\n● CUCURUCHO (Groovalizacion Radio / Tropical Grooves) ●Co-fondateur de Radio Groovalizacion et basé Paris, nomade sonore spécialiste de la sono-tropical et les fusions improbables entre la musique afro, caribe, latin, arabe ou indien avec des rythmes urbaines globaux... Ce véritable groove-trotter a partagé des soirées avec artistes internationales comme Bomba Estereo, Seu Jorge, Balkan Beat Box, Salif Keita, Systema Solar, Dhoad Gypsies of Rajasthan, La Yegros ou Chicha Libre. Showcase au Womex 2013.https://www.facebook.com/djcucuruchohttp://www.mixcloud.com/musicasmigratoriashttp://www.groovalizacion.com/cucurucho\\n\\n● MOODY MATT (Inna di Mood / Afro Grooves) ●Du reggae à foison, des musiques tropicales, du Hip-Hop épique, des instrumentaux revisités, des variantes remixées et des versions dubifiées, INNA DI MOOD Podcast regorge de musiques savoureuses patiemment sélectionnées et assemblées en mixes thématiques.www.innadimood.com"}', '{"fr":"Montreuil, Afro beat, Felabration, Fela Kuti"}', NULL, '{"filename":"event_bal-afro-latino-felabration-w-kologbo-monkuti_893523.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bal-afro-latino-felabration-w-kologbo-monkuti_893523.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bal-afro-latino-felabration-w-kologbo-monkuti_893523.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-29T18:00:00.000Z","end":"2016-10-29T03:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":8}', '[]', '2016-11-04 09:20:09', '2016-11-04 09:20:09', NULL ),
(146523, 9407660, 53176644, 77951488, 72807885, 'bal-folk_454', '{"fr":"Bal Folk"}', '{"fr":"Bal folk"}', '{"fr":"Bal Folk avec **LES PAPIS ESSOUFFLES** et **Gelée de Groseilles**"}', '{"fr":", Danses"}', NULL, '{"filename":"event_bal-folk_454_351933.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bal-folk_454_351933.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bal-folk_454_351933.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-05T19:30:00.000Z","end":"2016-11-04T23:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":77}', '["sujetjc@gmail.com"]', '2016-11-04 09:19:25', '2016-11-04 09:19:25', NULL ),
(146426, 89656800, 45925510, NULL, 3483191, 'balade-architecturale-sika-road-tour', '{"fr":"Balade architecturale \\"Sika Road Tour\\""}', '{"fr":"Belles charrettes et architecture dans la Forêt-Noire"}', '{"fr":"Cette année le SIKA Road Tour traverse le Rhin à la découverte de l’architecture de la Forêt Noire. La Chapelle de Saint Jean, l’hôtel Die Halde et autres oeuvres architecturales cachées dans la forêt sont au programme.\\n\\nInscrivez-vous avec votre voiture ou demandez un covoiturage !\\n\\nRendez-vous : Hôtel Mercure – 2, avenue de la Marne Entrée gratuite sur inscription.\\n\\n**Adhésion à la Maison européenne de l''architecture obligatoire.**"}', '{"fr":"Architecture,     Voiture,    Parcours vélo,   Circuit,  Alsace, Colmar"}', NULL, '{"filename":"event_balade-architecturale-sika-road-tour_340629.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_balade-architecturale-sika-road-tour_340629.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_balade-architecturale-sika-road-tour_340629.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T07:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["ml@knlarchitecture.com"]', '2016-11-04 09:19:30', '2016-11-04 09:19:30', NULL ),
(146696, 12045061, 38565623, 27545135, 7138035, 'balade-nocturne-sous-les-etoiles', '{"fr":"Balade nocturne sous les étoiles"}', '{"fr":"Description des constellations"}', '{"fr":"Acheminement en bus sur un site d’observation du ciel. Descriptions des constellations. Observation à l’oeil nu et avec des instruments.\\n\\n*   Cible : adultes uniquement\\n*   Niveau de difficulté : 1 (accessible à tous)\\n*   RDV à 18h00 devant l’ATRIUM (boulevard du Général de Gaulle à Fort-de-France)\\n*   Prévoir vêtement de pluie, chaussures fermées, jumelles"}', '{"fr":",   Constellation,  CDSA, Martinique"}', NULL, '{"filename":"event_balade-nocturne-sous-les-etoiles_263224.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_balade-nocturne-sous-les-etoiles_263224.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_balade-nocturne-sous-les-etoiles_263224.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-14T16:00:00.000Z","end":"2016-10-14T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["0696 456 056","http://www.cieltropical.com"]', '2016-11-04 09:19:15', '2016-11-04 09:19:15', '2016-11-07 09:14:32' );
