(146394, 81797740, 97862464, NULL, 14047593, 'ben-eco-responsable-au-carre-belle-feuille', '{"fr":"Ben \\"Eco responsable\\" au Carré Belle Feuille"}', '{"fr":"stand up"}', '{"fr":"Ben “Eco Responsable“\\n\\nMardi 11 octobre à 20h30\\n\\nÉcrit et mis en scène par Ben et Thibault Segouin\\n\\nDu “Djamel Comedy Club“ à la “Matinale de France Inter“, en passant par “On n’demande qu’à en rire”, Ben est un touche-à-tout de génie. Il interpelle son public avec sincérité, pour l’emmener, l’air de rien, là où plusieurs kilomètres avant, bien des humoristes ont fait demi-tour."}', '{}', NULL, '{"filename":"event_ben-eco-responsable-au-carre-belle-feuille_31057.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_ben-eco-responsable-au-carre-belle-feuille_31057.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_ben-eco-responsable-au-carre-belle-feuille_31057.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-11T18:00:00.000Z","end":"2016-10-11T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":16}', '["0155185400"]', '2016-11-04 09:19:32', '2016-11-04 09:19:32', NULL ),
(146052, 98179685, 64614166, NULL, 22266601, 'benediction-mondiale-de-l-uterus_724', '{"fr":"Bénédiction Mondiale de l''Utérus."}', '{"fr":"Groupe de méditation guidée."}', '{"fr":"Bonjour à toutes,\\n\\nJ''organise un groupe pour la Bénédiction Mondiale de l''Utérus.\\n\\nJe vous propose de vous guider pour recevoir cette belle énergie qui nous reconnecte à notre nature féminine.\\n\\nCette méditation d''octobre, nous invite à guérir notre lignée maternelle. Dans les profondeurs de notre être, enfoui aux confins de notre ADN et de nos mémoires cellulaires, nous sommes reliées à nos ancêtres maternelles ; à leurs trauma, douleur et souffrance, mais aussi à leur force, courage, ressources et sagesse. La Méditation de guérison des Ancêtres Maternels est une guérison puissante pour toutes les femmes. (Newsletter : http://ymlp.com/z3wQfc )\\n\\nRendez-vous :\\n\\n~> 18h15 pour celle de 19h\\n\\nEn pleine nature, si la météo le permet (le lieu sera fixé en fonction).\\n\\nPour participer, c''est simple :\\n\\n1 - vous inscrire sur le site de Miranda, pour recevoir l''énergie :\\n\\n-> pour les femmes : [http://www.mirandagray.co.uk/register.html](http://www.mirandagray.co.uk/register.html)\\n\\n2 - m''envoyer un mail ou sms pour réserver une place pour la méditation guidée (le nombre de places est limité)\\n\\nAu plaisir de partager ce moment avec vous...\\n\\nLydie *"}', '{"fr":"Bénédiction Mondiale de l''Utérus, Méditation guidée, Groupe de femmes, Guérir sa lignée maternelle"}', NULL, '{"filename":"event_benediction-mondiale-de-l-uterus_724_845915.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_benediction-mondiale-de-l-uterus_724_845915.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_benediction-mondiale-de-l-uterus_724_845915.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T16:15:00.000Z","end":"2016-10-16T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '["etre_o_feminin@hotmail.com","06 83 31 28 54"]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(146054, 66128341, 64614166, NULL, 22266601, 'benediction-mondiale-de-l-uterus_804', '{"fr":"Bénédiction Mondiale de l''Utérus."}', '{"fr":"Groupe de méditation guidée."}', '{"fr":"Bonjour à toutes,\\n\\nJ''organise un groupe pour la Bénédiction Mondiale de l''Utérus.\\n\\nJe vous propose de vous guider pour recevoir cette belle énergie qui nous reconnecte à notre nature féminine.\\n\\nCette méditation d''octobre, nous invite à guérir notre lignée maternelle. Dans les profondeurs de notre être, enfoui aux confins de notre ADN et de nos mémoires cellulaires, nous sommes reliées à nos ancêtres maternelles ; à leurs trauma, douleur et souffrance, mais aussi à leur force, courage, ressources et sagesse. La Méditation de guérison des Ancêtres Maternels est une guérison puissante pour toutes les femmes. (Newsletter : [http://ymlp.com/z3wQfc](http://ymlp.com/z3wQfc) )\\n\\nRendez-vous :\\n\\n~> 12h15 pour celle de 13h\\n\\nEn pleine nature, si la météo le permet (le lieu sera fixé en fonction).\\n\\nPour participer, c''est simple :\\n\\n1 - vous inscrire sur le site de Miranda, pour recevoir l''énergie :\\n\\n-> pour les femmes : [http://www.mirandagray.co.uk/register.html](http://www.mirandagray.co.uk/register.html)\\n\\n2 - m''envoyer un mail ou sms pour réserver une place pour la méditation guidée (le nombre de places est limité)\\n\\nAu plaisir de partager ce moment avec vous...\\n\\nLydie *"}', '{"fr":"Bénédiction Mondiale de l''Utérus, Méditation guidée, Groupe de femmes, Guérir sa lignée maternelle"}', NULL, '{"filename":"event_benediction-mondiale-de-l-uterus_804_54976.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_benediction-mondiale-de-l-uterus_804_54976.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_benediction-mondiale-de-l-uterus_804_54976.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T10:15:00.000Z","end":"2016-10-16T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '["etre_o_feminin@hotmail.com","06 83 31 28 54"]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(145564, 81720289, 99535145, NULL, 22535410, 'bertrand-de-billy-dirige-le-konzerthausorchester-berlin-dans-le-double', '{"fr":"Bertrand de Billy dirige le Konzerthausorchester Berlin dans \\"Le Double\\""}', '{"fr":"La deuxième symphonie d''Henri Dutilleux à Berlin, Isabelle Faust au violon pour le 2e concerto de Bartok"}', '{"fr":"## Programme :\\n\\n*   Henri Dutilleux _Symphonie_ No.2 (\\"Le double\\")\\n*   Béla Bartók _Concerto pour violon et orchestre_ No. 2\\n*   Maurice Ravel _La Valse_ - Poème chorégraphique pour orchestre\\n\\n## Avec :\\n\\n*   Konzerthausorchester Berlin\\n*   Bertrand de Billy, direction\\n*   Isabelle Faust, violon"}', '{"fr":"concert, 2016-2017, Dutilleux, centenaire, Berlin, symphonie, orchestre, Ravel"}', NULL, '{"filename":"event_bertrand-de-billy-dirige-le-konzerthausorchester-berlin-dans-le-double_951519.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bertrand-de-billy-dirige-le-konzerthausorchester-berlin-dans-le-double_951519.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bertrand-de-billy-dirige-le-konzerthausorchester-berlin-dans-le-double_951519.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-22T18:00:00.000Z","end":"2016-09-22T21:00:00.000Z"},{"begin":"2016-09-23T18:00:00.000Z","end":"2016-09-23T21:00:00.000Z"},{"begin":"2016-09-24T18:00:00.000Z","end":"2016-09-24T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["https://www.konzerthaus.de/en/programm/konzerthausorchester-berlin-bertrand-de-billy/730"]', '2016-11-04 09:20:10', '2016-11-04 09:20:10', NULL ),
