(146693, 53539933, 38565623, 27545135, 73524367, 'biodiversite-meconnue-de-la-rbi-des-pitons', '{"fr":"Biodiversité méconnue de la RBI des Pitons"}', '{"fr":"Présentation des premiers résultats sur la faune entomologique de la RBI des Pitons"}', '{"fr":"L’un des défis importants de l’humanité dans son environnement concerne la préservation de la biodiversité, élément majeur du bon fonctionnement des écosystèmes, donc de sa survie. Mais pour protéger, il faut d’abord connaître et force est de constater que dans ce domaine, de nombreuses lacunes persistent.\\n\\nC’est dans ce contexte que s’intègre « l’étude de la faune entomologique et d’autres invertébrés de la RBI des Pitons », programme de recherche pluridisciplinaire sur le terrain dont les buts, les attentes et les premiers résultats seront présentés et discutés avec le public.\\n\\nIntervenant : Patrick MARECHAL, Président de l’ICNC et Directeur du programme «Pitons»"}', '{"fr":",  Biodiversité,  Martinique"}', NULL, '{"filename":"event_biodiversite-meconnue-de-la-rbi-des-pitons_532244.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_biodiversite-meconnue-de-la-rbi-des-pitons_532244.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_biodiversite-meconnue-de-la-rbi-des-pitons_532244.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-15T10:00:00.000Z","end":"2016-10-15T11:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["0696 100 400","http://www.icnc.fr"]', '2016-11-04 09:19:16', '2016-11-04 09:19:16', NULL ),
(145575, 89876698, 73486620, NULL, 90235356, 'bistrot-du-boss-club-chez-cinephase', '{"fr":"Bistrot du Boss club chez Cinéphase"}', '{"fr":"Le Bistrot du Boss Club PME se déplace à Vanves ce mois-ci pour la visite de l''entreprise CINEPHASE"}', '{"fr":"L''entreprise vanvéenne CINEPHASE ouvrira ses portes pour découvrir le monde magique et très technique de la post production, du doublage au mixage en passant par le bruitage.\\n\\nLe bistrot du Boss club sera également l''occasion d''assister à une présentation d''Eric Mathivet, président de l''agence éditoriale sur web Mativox sur les bons choix à prendre dans l''utilisation d''Internet pour trouver des clients. Editeur et auteur depuis 25 ans, Eric Mathivet a suivi l''évolution d''Internet, des débuts du référencement naturel à la déferlante actuelle des contenus. Il a adapté son savoir-faire éditorial aux nouvelles stratégies de webmarketing et aide les entreprises à attirer de nouveaux prospects.\\n\\n*   [Site web du Boss Club PME](http://www.boss-club.net/accueil/)\\n*   [Site web de CINEPHASE](http://cinephase.com/fr/home/)\\n*   [Site web de l''agence MATIVOX](http://www.mativox.fr/)"}', '{"fr":"Boss Club, Vanves, Cinephase"}', NULL, '{"filename":"event_bistrot-du-boss-club-chez-cinephase_335472.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bistrot-du-boss-club-chez-cinephase_335472.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bistrot-du-boss-club-chez-cinephase_335472.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-05T16:45:00.000Z","end":"2016-10-05T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["evenement@boss-club.net"]', '2016-11-04 09:20:09', '2016-11-04 09:20:09', NULL ),
(147276, 34759749, 44642279, 19096631, 54813425, 'blair-witch', '{"fr":"Blair witch"}', '{"fr":"Interdit - 12 ans !"}', '{"fr":"Date de sortie 21 septembre 2016 (1h 30min)\\n\\nDe Adam Wingard\\n\\nAvec Brandon Scott, Callie Hernandez, Valorie Curry...\\n\\nGenre Epouvante-horreur\\n\\nNationalité Américain\\n\\n### Synopsis et détails\\n\\n### Interdit aux moins de 12 ans\\n\\nJames et un groupe d''amis décident de s''aventurer dans la forêt de Black Hills dans le Maryland, afin d''élucider les mystères autour de la disparition en 1994 de sa sœur, que beaucoup croient liée à la légende de Blair Witch. Au départ, les jeunes étudiants s''estiment chanceux en tombant sur deux personnes de la région qui leur proposent de les guider à travers les bois sombres et sinueux. Mais tandis qu''ils s''enfoncent dans la nuit, le groupe est assailli par une présence menaçante. Peu à peu, ils commencent à comprendre que la légende est bien réelle et bien plus terrifiante que ce qu''ils pouvaient imaginer...\\n\\nDistributeur Metropolitan FilmExport\\n\\n### Lien bande annonce\\n\\n[http://www.allocine.fr/video/player_gen_cmedia=19564966&cfilm=241777.html](http://www.allocine.fr/video/player_gen_cmedia=19564966&cfilm=241777.html)"}', '{"fr":", blair witch"}', NULL, '{"filename":"event_blair-witch_465626.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_blair-witch_465626.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_blair-witch_465626.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-25T18:30:00.000Z","end":"2016-10-25T20:05:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":70}', '["02 38 44 81 01"]', '2016-11-04 09:18:43', '2016-11-04 09:18:43', NULL ),
(147296, 33533273, 50390586, NULL, 20343066, 'blendwebmix_16', '{"fr":"BlendWebMix"}', '{"fr":"Les 2 jours de conférences les + WEB de l''année !"}', '{"fr":"BlendWebMix est la plus importante conférence web francophone.\\n\\nC''est un lieu idéal pour apprendre, comprendre, et se rencontrer, entre \\"webmakers\\".BlendWebMix, c''est 2 jours pour être plus efficace les 363 autres jours de l''année !\\n\\nBlendWebMix en bref :\\n\\n*   Les deux jours les plus web de l''année ...Conférences, ateliers pratiques, networking, startups, speed démos, party-night et bien d''autres choses encore !\\n*   Zéro compromis sur la qualité éditoriale !BlendWebMix est une conférence de haut niveau pour comprendre et apprendre : notre objectif est que chaque participant progresse grâce aux partages.\\n*   Une ouverture vers la recherche ...BlendWebMix, est une chance exceptionnelle de rencontrer les chercheurs et découvrir, de manière pédagogique, ce qui fera le web dans quelques années.\\n*   Préparer sa transition digitale !BlendWebMix c''est aussi l''opportunité, pour les entreprises plus classiques, de rencontrer et comprendre l''écosystème web et ses acteurs.\\n\\nLe billet d’accès à Blend Web Mix vous donne droit à :\\n\\n90 conférences et tables rondes de qualité.\\n\\n*   Un buffet haut de gamme et des pauses café chaque jour de la conférence.\\n*   Un espace networking permanent pour partager avec l’ensemble des conférenciers et faire du business.\\n\\nPossibilité de packs entreprises avec places non nominatives - adressez-vous à contact@blendwebmix.com.\\n\\nSite web : : www.blendwebmix.com"}', '{"fr":",          Conférence web,          web,         Business,        Webmarketing,       Tech,      Design,     Développement,    Startup,   networking,"}', NULL, '{"filename":"event_blendwebmix_16_859010.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_blendwebmix_16_859010.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_blendwebmix_16_859010.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-02T07:00:00.000Z","end":"2016-11-02T21:00:00.000Z"},{"begin":"2016-11-03T07:00:00.000Z","end":"2016-11-03T17:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":99}', '["http://www.blendwebmix.com/"]', '2016-11-04 09:18:42', '2016-11-04 09:18:42', NULL ),
(146980, 4049729, 93924860, 77951488, 82518866, 'boeuf_478', '{"fr":"Boeuf"}', '{"fr":"Initiation suivie d''un boeuf"}', '{"fr":"Venez découvrir les danses folk avec en première partie une initiation.\\n\\nElle sera suivie d''un boeuf.\\n\\nMusiciens bienvenus.\\n\\nChacun peut ramener un truc à manger pour faire une auberge espagnole.\\n\\nVenez nombreux.\\n\\nN''hésitez pas à consulter notre page facebook ou notre site Internet\\n\\nhttp://folkenboeuf.jimdo.com/"}', '{"fr":"boeuf, initiation"}', NULL, '{"filename":"event_boeuf_478_144634.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_boeuf_478_144634.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_boeuf_478_144634.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-20T16:30:00.000Z","end":"2016-10-20T19:15:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":77}', '["folkenboeuf@gmail.com"]', '2016-11-04 09:19:00', '2016-11-04 09:19:00', NULL ),
(146368, 56999886, 45925510, NULL, 93129105, 'boites-a-anamorphoses-premier-exercice-d-architecture', '{"fr":"Atelier pédagogique \\"Boîtes à anamorphoses\\", premier exercice d''architecture"}', '{"fr":"Atelier ouvert au grand public autour de la perspective"}', '{"fr":"Des étudiants en architecture de l’INSA et de l’ENSA de Strasbourg encadreront un atelier ouvert au grand public pour la réalisation de « boîtes à anamorphoses » ou comment modifier la perception de la perspective dans une boite en carton de 20 cm de côté.\\n\\nSi possible venir avec ciseaux, cutter et tubes de colle…"}', '{"fr":",      Atelier,      Workshop,    Architecture,   Journées de l''architecture,  Strasbourg, Alsace"}', NULL, '{"filename":"event_boites-a-anamorphoses-premier-exercice-d-architecture_767278.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_boites-a-anamorphoses-premier-exercice-d-architecture_767278.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_boites-a-anamorphoses-premier-exercice-d-architecture_767278.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T11:30:00.000Z","end":"2016-10-15T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:33', '2016-11-04 09:19:33', NULL ),
