(147265, 84118669, 82405274, 21475128, 21624924, 'bondy-handball-tour-2016', '{"fr":"Bondy Handball''Tour 2016"}', '{"fr":"Découverte du handball par des ateliers d''initiation ludiques de pratique, d''arbitrage et tournoi sportif"}', '{"fr":"Ce projet, à caractère éducatif, a vocation d’amener des jeunes à la pratique sportive grâce à la découverte d’une activité portant des valeurs d’intégration, de solidarité et de respect, mais aussi de promouvoir et de développer le handball. \\n\\nLe Bondy Handball’ Tour, qui s’inscrit dans une phase d’expérimentation, englobe :\\n\\n*   L’initiation et la découverte du handball\\n*   La sensibilisation au respect des règles"}', '{"fr":",   quizz arbitrage,  découverte, ateliers d''initiation"}', NULL, '{"filename":"event_bondy-handball-tour-2016_502397.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bondy-handball-tour-2016_502397.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bondy-handball-tour-2016_502397.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-20T07:30:00.000Z","end":"2016-10-20T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":12}', '[]', '2016-11-04 09:18:44', '2016-11-04 09:18:44', NULL ),
(147270, 79109166, 82405274, 21475128, 99829066, 'bondy-handball-tour-2016_214', '{"fr":"Bondy Handball''Tour 2016"}', '{"fr":"Découverte du handball par des ateliers d''initiation ludiques de pratique, d''arbitrage et tournoi sportif"}', '{"fr":"Ce projet, à caractère éducatif, a vocation d’amener des jeunes à la pratique sportive grâce à la découverte d’une activité portant des valeurs d’intégration, de solidarité et de respect, mais aussi de promouvoir et de développer le handball. Le Bondy Handball’ Tour 2016, qui s’inscrit dans une phase d’expérimentation, englobe :\\n\\n*   L’initiation et la découverte du handball\\n*   La sensibilisation au respect des règles"}', '{}', NULL, '{"filename":"event_bondy-handball-tour-2016_214_406923.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bondy-handball-tour-2016_214_406923.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bondy-handball-tour-2016_214_406923.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-21T07:30:00.000Z","end":"2016-10-21T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":12}', '[]', '2016-11-04 09:18:43', '2016-11-04 09:18:43', NULL ),
(147274, 85595460, 82405274, 21475128, 22378693, 'bondy-handball-tour-2016_990', '{"fr":"Bondy Handball''Tour 2016"}', '{"fr":"Découverte du handball par des ateliers d''initiation ludiques de pratique, d''arbitrage et tournoi sportif"}', '{"fr":"Ce projet, à caractère éducatif, a vocation d’amener des jeunes à la pratique sportive grâce à la découverte d’une activité portant des valeurs d’intégration, de solidarité et de respect, mais aussi de promouvoir et de développer le handball. Le Bondy Handball’ Tour, qui s’inscrit dans une phase d’expérimentation, englobe :\\n\\n*   L’initiation et la découverte du handball\\n*   La sensibilisation au respect des règles"}', '{}', NULL, '{"filename":"event_bondy-handball-tour-2016_990_340459.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bondy-handball-tour-2016_990_340459.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bondy-handball-tour-2016_990_340459.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-24T07:30:00.000Z","end":"2016-10-24T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":12}', '[]', '2016-11-04 09:18:43', '2016-11-04 09:18:43', NULL ),
(147513, 85150279, 19878801, NULL, 84972793, 'boom-boom-kid-la-fraction-restsar-bai-naim', '{"fr":"BOOM BOOM KID, LA FRACTION, RESTSAR BAI NAIM"}', '{"fr":"Punk"}', '{"fr":"Le Vendredi 11 Novembre, à l''Olympic café...\\n\\nLe grand retour de Boom boom kid (Argentine), héros du punk rock sud américain, en Europe, accompagné des héros du punk rock français, les inimitables La Fraction, ainsi que des inénarrables Restar bai naim (Paris), héros de je ne sais pas quoi, ou peut etre du nombre de changement de formation en très peu de temps.\\n\\nBoom boom Kid; Boom Boom Kid est un groupe de hardcore d''Argentine . Ce groupe a des influences de rockabilly , psychobilly et salsa . [1] Le groupe a été formé en 2001 par le musicien Carlos Rodríguez ; après la séparation de Fun People . Le nom, \\"Boom Boom Kid\\" (ci - après BBK); il est aussi le nom de scène de Rodriguez. Absolument géniaux sur sène, grosse patate et super fun!https://www.facebook.com/boomboomkidoficial/https://soundcloud.com/boomboomkidz/vegetales\\n\\nLa FractionEn 1992 la Fraction Pastaga (Magali-chant/DD-guitare) abandonne le pastis et les reprises d’OTH avec l’arrivée de deux nouveaux membres (Boris-batterie/Thierry-basse). Ils sortent un 45 tours en soutien aux communautés en lutte au Chiapas (Guerre d’espérance) en 1996 et font une tournée en Allemagne de l’Est. Etrangement, pendant pas mal de temps, ils seront plus demandés à l’étranger qu’en France, ça tombe bien, aucune envie d’être prophète. Musicalement, ils trouvent leurs marques assez rapidement, ce sera un punk rock nerveux et mélodique, servi par un chant aux accents réalistes d’une Edith Piaf. Leurs textes sont existentiels et sociétaux, mais néanmoins émouvants. Anti rock-stars invétérées à l’humanité et la chaleur facile, ils tissent au fil des années des amitiés solides un peu partout en Europe, soutenant dès que possible les lieux et les collectifs dont ils se sentent proches. Ce lien fort avec la scène DIY les amène naturellement à travailler avec des labels de plus en plus nombreux – outre l’éternel Crash Disques présent dès le premier album – en France, en Allemagne, en Pologne, aux USA. À l’instar des THUGS, avec qui ils partagent quelques similitudes dans la rectitude de leur parcours, ils sont allés par deux fois tourner dans le pays du grand satan en 2003 puis en 2007, juste avant que Thierry ne décide de passer à autre chose et que Coxs (ex-Maximum Kouette) ne le remplace, puis Pascal (ex-Louise Mitchell, Besoin Dead).�https://lafraction.bandcamp.com/\\n\\nRetsar bain naim;Fast core de Paris, avec des membre d''Unlogistic, Bile clinton, Hakfleish, Semi playback, premier concert avec la drumstar camille, avec un peu de chance ça sera la release partie de leur prem!ère K7 magnétique, avec des nouveaux morceaux et tout le tralala, bref, je sais pas trop quoi dire, je joue dedans...https://retsarbainaim.bandcamp.com/\\n\\nViendez nombreux!!!!!!\\n\\nLe prix, ça sera 6 euros."}', '{"fr":"Punk, OLympic, Hardcore, Barbes"}', NULL, '{"filename":"event_boom-boom-kid-la-fraction-restsar-bai-naim_601713.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_boom-boom-kid-la-fraction-restsar-bai-naim_601713.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_boom-boom-kid-la-fraction-restsar-bai-naim_601713.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-11T19:00:00.000Z","end":"2016-11-11T00:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":14}', '[]', '2016-11-04 09:18:29', '2016-11-04 09:18:29', NULL ),
(145902, 20049832, 39724848, NULL, 72170095, 'boostec', '{"fr":"Contribution aux études d''optimisation des futurs détecteurs d''ondes gravitationnelles‎: MERSEN BOOSTEC et LGP ENIT"}', '{"fr":"Présentation du parcours et du travail d''un doctorant"}', '{"fr":"Le 14 Septembre 2015, à 09:50:45 UTC, les 2 détecteurs du laboratoire LIGO aux USA observent simultanément le passage d''une onde gravitationnelle. C''est une première mondiale. Elle confirme la théorie de la relativité générale d''Einstein appliquée, dans ce cas précis, à la fusion de deux trous noirs.\\n\\nUn détecteur similaire est implanté à PISE en Italie : VIRGO. Il est piloté par un consortium européen (EGO) de scientifiques partenaires et collaborant avec le consortium américain. Ce consortium a établi le programme GraWIToN, financé par la Commission Européenne dans le cadre des actions Marie Curie, pour lequel MERSEN BOOSTEC fournira un matériau d''exception capable de contribuer aux performances de tels détecteurs.\\n\\nLe doctorant, salarié de MERSEN BOOSTEC, financé dans le cadre du programme GraWIToN, et dirigé par l''ENIT, sera présent sur le stand. Il expliquera son parcours pour accéder à cette unité de recherche. Il décrira également, à l''aide de posters et de vidéos, les objectifs de ces projets complexes qui ouvrent à la voie à une nouvelle astronomie."}', '{}', NULL, '{"filename":"event_boostec_570812.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_boostec_570812.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_boostec_570812.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-12T07:00:00.000Z","end":"2016-10-12T10:00:00.000Z"},{"begin":"2016-10-12T11:30:00.000Z","end":"2016-10-12T14:30:00.000Z"},{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":5,"max":80}', '[]', '2016-11-04 09:19:56', '2016-11-04 09:19:56', NULL ),
(147580, 10932458, 12338150, NULL, 74079805, 'bourbriac_19', '{"fr":"Bourbriac"}', '{"fr":"ORCHESTRE FASILA"}', '{}', '{"fr":", bal"}', NULL, '{"filename":"event_bourbriac_19_355485.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bourbriac_19_355485.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bourbriac_19_355485.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-13T13:30:00.000Z","end":"2016-11-13T18:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":4,"max":14}', '[]', '2016-11-04 09:18:25', '2016-11-04 09:18:25', '2016-11-07 09:14:32' );
