(145955, 86237031, 19878801, NULL, 84972793, 'boytoy-burger-records-hawai-burger-buddy-records-dj-set', '{"fr":"BOYTOY (Burger Records) // Hawaï Burger // Buddy Records DJ Set"}', '{"fr":"Garage, Indie"}', '{"fr":"BOYTOY // USA // Burger Records (Garage - Pop) :\\n\\nA écouter ici : http://boytoy.bandcamp.com/\\n\\nHawaï Burger // France (Surf - Pop) :\\n\\nLa pop d''HawaÏ Burger parle de paysages, de nostalgie, de road trips autour du monde. Après s''être faits remarqués lors du concours Les Inrocks Lab en 2013, le groupe a été nommé parmi \\"les 5 groupes à suivre\\" des Inrocks, puis playlistés par Le Mouv'' avec leur morceau Spring Break. Influencée par Ty Segall, Parquet Courts, My Bloody Valentine ou Alan Vega, leur musique est un aller simple pour déguster un cocktail de xanax sur une plage japonnaise, au crépuscule. Ils viendront défendre leur nouvel EP, \\"Guitar Hero\\".\\n\\nViens écouter ici : https://soundcloud.com/hawaiburger\\n\\n+\\n\\nPour clôturer la soirée, les larrons de Buddy Records te proposeront un DJ set mâtiné de Post-Punk, Garage, Psyché, Shoegaze ou d''autres curiosités auditives. Mets ton plus beau futal, ainsi que ta plus belle paire de Clarks."}', '{"fr":"Olympic, Garage, Barbès"}', NULL, '{"filename":"event_boytoy-burger-records-hawai-burger-buddy-records-dj-set_151606.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_boytoy-burger-records-hawai-burger-buddy-records-dj-set_151606.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_boytoy-burger-records-hawai-burger-buddy-records-dj-set_151606.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-18T18:00:00.000Z","end":"2016-10-17T23:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":17}', '[]', '2016-11-04 09:19:52', '2016-11-04 09:19:52', NULL ),
(146049, 43894480, 58428515, NULL, 35811397, 'brad-livres', '{"fr":"Braderie \\"Brad''Livres\\""}', '{"fr":"Braderie des ouvrages du CAUE pour une seconde vie"}', '{"fr":"Le CAUE de la Sarthe procède à l''actualisation de son fonds documentaire et retire de la bibliothèque les ouvrages en surnombres ou ne correspondant plus à la demande du public. Une braderie est organisée afin de donner une seconde vie à ces livres; vous y trouverez de nombreux ouvrages et revues sur l''architecture, le paysage, l''urbanisme et le patrimoine, à prix réduit."}', '{"fr":",     Livre,     Portes ouvertes,   architecture,  urbanisme, paysage"}', NULL, '{"filename":"event_brad-livres_664543.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_brad-livres_664543.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_brad-livres_664543.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '[]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(146771, 87351452, 19878801, NULL, 84972793, 'brand-new-hate-dick-tracy-lords-the-true-faiths', '{"fr":"BRAND NEW HATE + DICK TRACY LORDS + THE TRUE FAITHS"}', '{"fr":"High Energy Rock"}', '{"fr":"Concert Rock''n Roll / Punkrock avec\\n\\n• Brand New Hate (RnR - Saint Etienne)www.facebook.com/brandnewhatehttp://brandnewhate.bandcamp.com/\\n\\n• Dick Tracy Lords (Hi-Energy RnR - Paris)www.facebook.com/dicktracylordswww.dicktracylords.com/\\n\\n• The True Faith (Hi-Energy RnR -Paris)\\n\\nLe Vendredi 21 Octobre à L''Olympic Café, 20 rue Léon, Paris 18ème20 h - 6 €"}', '{"fr":"Olympic, Barbès"}', NULL, '{"filename":"event_brand-new-hate-dick-tracy-lords-the-true-faiths_562816.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_brand-new-hate-dick-tracy-lords-the-true-faiths_562816.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_brand-new-hate-dick-tracy-lords-the-true-faiths_562816.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-21T18:00:00.000Z","end":"2016-10-20T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:11', '2016-11-04 09:19:11', NULL ),
(146866, 49763505, 10710705, 32214778, 2681149, 'breakfast-with-kant', '{"fr":"Breakfast With Kant"}', '{"fr":"dans le cadre du festival Bar-Bars"}', '{"fr":"Issu de la banlieue est de Paris, B.W.K s’immisce dans un maelström musical intense et violent. A la croisée du Doom, du Black Métal et du Hardcore, leur musique alterne entre riffs pachydermiques et tremolos torturés. Se voulant aussi enivrant qu’anxiogène, Breakfast With Kant développe un univers où l’amour, la haine et la mort sont à la fois amoureux fous et éternelles ennemies.\\n\\n[https://www.youtube.com/watch?v=pEdQix6UBYo](https://www.youtube.com/watch?v=pEdQix6UBYo)"}', '{"fr":"doom, black metal, hardcore"}', NULL, '{"filename":"event_breakfast-with-kant_743748.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_breakfast-with-kant_743748.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_breakfast-with-kant_743748.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-11-24T17:30:00.000Z","end":"2016-11-24T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:06', '2016-11-04 09:19:06', NULL ),
(146046, 23551856, 10220945, 75699098, 53680425, 'bribes-4-sortie-de-disque-the-bridge-4-shore-to-shore', '{"fr":"BRIBES 4 - Sortie de disque + THE BRIDGE #4 Shore to Shore"}', '{"fr":"BRIBES 4 : Geoffroy Gesser, Isabel Sörling, Yann Joussein, Romain Clerc-Renaud"}', '{"fr":"### **BRIBES 4**\\n\\nA l''origine, il y a BRIBES \\"tout court\\", un duo imprégné de l''énergie électrique et apocalyptique du free-jazz et du free-rock. Le quartet BRIBES 4 se veut une version plus explosive et excentrique de cet univers sonore. Le saxophoniste Geoffroy GESSER et le pianiste Romain CLERC-RENAUD ouvrent les portes de leur duo à la chanteuse-improvisatrice suédoise Isabel SÖRLING et au batteur Yann JOUSSEIN. Entre compositions et improvisations, ce quatuor mélange les esthétiques : musique contemporaine, électroacoustique, électronique, free-jazz, free-rock.\\n\\n### +\\n\\n### THE BRIDGE #4 Shore To Shore\\n\\nFrance, États-Unis / Shore to Shore, le nouvel avatar du programme d''échanges France-Chicago, expose deux bassistes, un guitariste et deux souffleurs aux quatre vents de l''improvisation.\\n\\nROB MAZUREK électronics, MWATA BOWDEN saxophone baryton, clarinette, JULIEN DESPREZ guitare électrique, MATT LUX basse électrique, MATHIEU SOURISSEAU basse électro-acoustique."}', '{"fr":",  free jazz,  free rock"}', NULL, '{"filename":"event_bribes-4-sortie-de-disque-the-bridge-4-shore-to-shore_226798.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bribes-4-sortie-de-disque-the-bridge-4-shore-to-shore_226798.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bribes-4-sortie-de-disque-the-bridge-4-shore-to-shore_226798.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-07T18:30:00.000Z","end":"2016-10-06T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '["https://www.banlieuesbleues.org/1_agenda.php"]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(147271, 99624922, 44642279, 19096631, 54813425, 'brice-3', '{"fr":"Brice 3"}', '{"fr":"de James Huth"}', '{"fr":"Date de sortie 19 octobre 2016 (1h 35min)\\n\\nDe James Huth\\n\\nAvec Jean Dujardin, Clovis Cornillac, Bruno Salomone...\\n\\nGenre Comédie\\n\\nNationalité Français\\n\\n### Synopsis et détails\\n\\nBrice est de retour. Le monde a changé, mais pas lui. Quand son meilleur ami, Marius, l’appelle à l’aide, il part dans une grande aventure à l’autre bout du monde… Les voyages forment la « jaunesse » mais restera-t-il le roi de la casse ?\\n\\nDistributeur Gaumont Distribution\\n\\n### lien bande annonce\\n\\n[http://www.allocine.fr/video/player_gen_cmedia=19565100&cfilm=238953.html](http://www.allocine.fr/video/player_gen_cmedia=19565100&cfilm=238953.html)"}', '{"fr":", brice 3"}', NULL, '{"filename":"event_brice-3_680704.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_brice-3_680704.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_brice-3_680704.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-19T12:45:00.000Z","end":"2016-10-19T14:25:00.000Z"},{"begin":"2016-10-19T18:45:00.000Z","end":"2016-10-19T20:25:00.000Z"},{"begin":"2016-10-21T19:00:00.000Z","end":"2016-10-21T20:40:00.000Z"},{"begin":"2016-10-22T15:00:00.000Z","end":"2016-10-22T16:40:00.000Z"},{"begin":"2016-10-22T19:15:00.000Z","end":"2016-10-22T20:55:00.000Z"},{"begin":"2016-10-23T14:45:00.000Z","end":"2016-10-23T16:25:00.000Z"},{"begin":"2016-10-25T16:30:00.000Z","end":"2016-10-25T18:10:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":12}', '["02 38 44 81 01"]', '2016-11-04 09:18:43', '2016-11-04 09:18:43', NULL ),
(147255, 34294438, 44642279, 19096631, 54813425, 'bridget-jones-baby', '{"fr":"Bridget Jones baby"}', '{"fr":"VF"}', '{"fr":"Date de sortie 5 octobre 2016 (2h 03min)\\n\\nDe Sharon Maguire Avec Renée Zellweger, Colin Firth, Patrick Dempsey...\\n\\nGenres Comédie, Romance Nationalités Britannique, Irlandais, Français, Américain\\n\\n### Synopsis et détails\\n\\nAprès avoir rompu avec Mark Darcy, Bridget se retrouve de nouveau célibataire, 40 ans passés, plus concentrée sur sa carrière et ses amis que sur sa vie amoureuse. Pour une fois, tout est sous contrôle ! Jusqu’à ce que Bridget fasse la rencontre de Jack… Puis retrouve Darcy… Puis découvre qu’elle est enceinte… Mais de qui ???\\n\\nTitre original Bridget Jones''s Baby\\n\\nDistributeur StudioCanal\\n\\n### LIEN BANDE ANNONCE\\n\\n[http://www.allocine.fr/video/player_gen_cmedia=19563754&cfilm=170004.html](http://www.allocine.fr/video/player_gen_cmedia=19563754&cfilm=170004.html)"}', '{"fr":", bridget jones baby"}', NULL, '{"filename":"event_bridget-jones-baby_588723.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bridget-jones-baby_588723.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bridget-jones-baby_588723.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-12T18:30:00.000Z","end":"2016-10-12T20:35:00.000Z"},{"begin":"2016-10-14T16:45:00.000Z","end":"2016-10-14T18:50:00.000Z"},{"begin":"2016-10-15T18:45:00.000Z","end":"2016-10-15T20:50:00.000Z"},{"begin":"2016-10-16T12:30:00.000Z","end":"2016-10-16T14:35:00.000Z"},{"begin":"2016-10-16T16:45:00.000Z","end":"2016-10-16T18:50:00.000Z"},{"begin":"2016-10-18T18:45:00.000Z","end":"2016-10-18T20:50:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":12}', '["02 38 44 81 01"]', '2016-11-04 09:18:44', '2016-11-04 09:18:44', NULL ),
(147581, 46723653, 15723194, NULL, 45711438, 'bulle-une-odyssee', '{"fr":"Bulle - Une Odyssée"}', '{"fr":"Plongeon dans un spectacle théâtral et musical sur le thème de l’eau..."}', '{"fr":"C’est l’histoire d’un enfant, Bulle, qui comme beaucoup d’enfants, quand il avait soif, trouvait toujours de l’eau à portée de main.\\n\\nOr, il arriva qu’un jour l’eau vint à manquer, celle qui s’échappe du robinet, de l’orange et même celle du bocal à poisson, poisson rouge qui avait laissé un mot tout au fond : « Ce n’est plus vivable pour moi ici, je pars à la recherche du grand lac Tank-Yana-Sava». Bulle alors s’en alla à la quête de l’eau et de son poisson.\\n\\nLes enfants et leurs familles plongeront dans un spectacle théâtral et musical sur le thème de l’eau, et dont le personnage principal est lui-même un enfant.\\n\\nCe spectacle a été écrit pendant une résidence d’écriture de la compagnie BAL au monastère de Saorge durant l’été 2015\\\\. Le thème de la quête de l’eau et d’un environnement préservé résonne particulièrement bien avec le monument, son cadre naturel exceptionnel et son circuit de l’eau remarquable.\\n\\nLe spectacle sera suivi d’une visite guidée du circuit de l’eau et des bassins d’irrigation du jardin en terrasses du monastère."}', '{"fr":"famille, animation, enfant, monument"}', NULL, '{"filename":"event_bulle-une-odyssee_787286.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_bulle-une-odyssee_787286.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_bulle-une-odyssee_787286.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T13:00:00.000Z","end":"2016-10-22T15:30:00.000Z"},{"begin":"2016-10-23T13:00:00.000Z","end":"2016-10-23T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":4,"max":14}', '["04 93 04 55 55","http://www.monastere-saorge.fr"]', '2016-11-04 09:18:25', '2016-11-04 09:18:25', NULL ),
(146985, 35181858, 28865248, NULL, 83125303, 'business-success', '{"fr":"BUSINESS SUCCESS"}', '{"fr":"Un Salon dédié à la création, au développement, aux réseaux d''entreprises, au financement des Start''ups du numérique et à la transition digitale."}', '{"fr":"VILLAGE CREATION ET DEVELOPPEMENT : Le Salon dédié à la création, au développement commercial et aux réseaux d’entreprises.\\n\\nFINANCIAL ‘IT DAY : Le Forum dédié au financement des start’ups du numérique et des autres filières.\\n\\n(En collaboration avec le PRN)\\n\\nMY DIGITAL ENTREPRISE : Le Showroom de la transition digitale. (En collaboration avec MLG consulting)\\n\\nNe manquez pas ce salon de fin d''année !\\n\\nVous souhaitez être exposant ?\\n\\nContactez-nous au 06.14.71.41.98 ou au 03.20.11.25.43"}', '{"fr":",      Salon entrepreneur,     création entreprise,     développement,    financement,   transition digitale,  lille"}', NULL, '{"filename":"event_business-success_73628.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_business-success_73628.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_business-success_73628.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-16T08:30:00.000Z","end":"2016-11-16T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":12}', '["http://www.business-success.fr/inscription-visiteurs/"]', '2016-11-04 09:18:59', '2016-11-04 09:18:59', NULL ),
