(146683, 95350006, 90485267, NULL, 75730142, 'c-est-le-cirque-a-nohant', '{"fr":"C''est le cirque à Nohant !"}', '{"fr":"La magie du cirque au travers d''ateliers jonglage, trapèze, magie, acrobaties, jeux d’équilibre..."}', '{"fr":"Petits et grands, laissez-vous porter par la magie du cirque lors d’un magnifique spectacle mené par les élèves de l’école de Bourges « Le Nez dans les étoiles ». Découvrez l’univers actuel du cirque et participez aux ateliers jonglage, trapèze, magie, acrobaties, jeux d’équilibre...\\n\\nAteliers pour les enfants à partir de 7 ans.\\n\\nRenseignements et réservations 02 54 31 06 04\\n\\nLieu de rendez-vous : accueil librairie du domaine"}', '{"fr":"spectacle,       magie,       cirque,       enfants,      ateliers,      jonglage,     trapèze,   acrobaties,   jeux,"}', NULL, '{"filename":"event_c-est-le-cirque-a-nohant_225408.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_c-est-le-cirque-a-nohant_225408.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_c-est-le-cirque-a-nohant_225408.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-23T12:30:00.000Z","end":"2016-10-23T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":14}', '["02 54 31 06 04"]', '2016-11-04 09:19:16', '2016-11-04 09:19:16', NULL ),
