(145802, 57002870, 90347873, NULL, 16917670, 'cafe-citoyen-a-la-libellule-cafe-librairie', '{"fr":"Café  citoyen à la libellule café-librairie"}', '{"fr":"La libellule accueille la maison des citoyens de colmar"}', '{"fr":"La libellule accueille le vendredi 21 octobre prochain à  partir de 19 h la maison des citoyens de colmar pour sa première rencontre. AU programme un échange sur la façon dont vous avez envie de compter, de vous engager, et d''être présents sur notre territoire, dans notre commune, et au delà,  et de ce que vous aurez envie de partager ! Une courte présentation d''une initiative de démocratie locale sera également proposée."}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-21T17:00:00.000Z","end":"2016-10-21T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:20:00', '2016-11-04 09:20:00', NULL ),
