(145807, 88126748, 51191483, NULL, 15015245, 'cafe-citoyen-pause-dejeuner-bar-zebre-la-place-place-pie-avignon_706', '{"fr":"Café Citoyen pause déjeuner Bar \\"Zèbre\\" La Place Place Pie Avignon"}', '{"fr":"Parceque tout le monde à le droit à sa pause ventre tendu et citoyenneté"}', '{"fr":"## Parce que nous avons envie de changer le monde. ​\\n\\n## Parce que nous partageons autre chose que le porte monnaie.\\n\\n## Parce que nous aimons nos vies, nos territoires et notre pays.\\n\\n## Parce que que nous croyons plus à une parole mais à des dialogues nous allons construire NOTRE MAISON! ​\\n\\n## Âmes de ce pays, habitants de cette belle dame France vous êtes bienvenue dans cette maison (ré)créative! ​\\n\\n## Amusons-nous ensemble.\\n\\n## Faizons. Dizons. Allons Zy! ​"}', '{"fr":"dégustation nourriture partage action boisson citoyennete convivialité, parole écriture penser dire acter, defaire refaire éclater émettre écouter redire déduire comprendre apprendre"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-09-29T10:30:00.000Z","end":"2016-09-29T11:30:00.000Z"},{"begin":"2016-10-13T10:00:00.000Z","end":"2016-10-13T11:00:00.000Z"},{"begin":"2016-10-06T10:30:00.000Z","end":"2016-10-06T11:30:00.000Z"},{"begin":"2016-10-20T10:30:00.000Z","end":"2016-10-20T11:30:00.000Z"},{"begin":"2016-10-27T10:30:00.000Z","end":"2016-10-27T11:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '["leszebres84@gmail.com"]', '2016-11-04 09:20:00', '2016-11-04 09:20:00', NULL ),
(147358, 77811158, 2558641, NULL, 36983051, 'cafe-citoyen-sur-l-herbe-marseillaise', '{"fr":"Café Citoyen sur l''Herbe Marseillaise"}', '{"fr":"3ème café citoyen citoyen marseillais"}', '{"fr":"Notre prochain café citoyen se déroulera au Parc Borély pour un Petit Déjeuner sur l''Herbe.\\n\\nEt oui, pour cette fois-ci on change de lieu et de jour !\\n\\nAlors à vos serviettes, thermos, croissants pour une nouvelle rencontre en détente.\\n\\nConjoints, enfanst et amis sont, bien entendu, les bienvenus !\\n\\nRDV à 10h00 devant les grilles : nous serons visibles +1\\n\\nSi le temps ne nous le permet pas, nous prendrons un café au Skating juste devant l''entrée du parc."}', '{}', NULL, '{"filename":"event_cafe-citoyen-sur-l-herbe-marseillaise_462081.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cafe-citoyen-sur-l-herbe-marseillaise_462081.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cafe-citoyen-sur-l-herbe-marseillaise_462081.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T08:30:00.000Z","end":"2016-10-22T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":119}', '[]', '2016-11-04 09:18:38', '2016-11-04 09:18:38', NULL ),
(147017, 10547523, 17027226, NULL, 98374835, 'cafe-de-chantiier', '{"fr":"Rencontres \\"Café de chantier\\""}', '{"fr":"Découverte du chantier du quartier de la gare"}', '{"fr":"Participez au premier café de chantier autour de l''actualité du chantier d''aménagement du pôle multimodal de la gare conçu dans le respect de l''histoire urbaine des quartiers cheminots."}', '{"fr":",  urbanisme, gare"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T09:00:00.000Z","end":"2016-10-15T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '["http://www.thouars.fr/vah/"]', '2016-11-04 09:18:58', '2016-11-04 09:18:58', NULL ),
(145897, 22522428, 20200589, NULL, 98062885, 'cafe-debat-citoyen-canton-la-roche-bernard-de-l-individuel-au-collectif-comment-agir-dans-sa-commune', '{"fr":"café débat citoyen - canton la roche-bernard : \\"De l''individuel au collectif, comment agir dans sa commune?\\""}', '{"fr":"Rencontrons-nous pour discuter du rôle du citoyen dans sa commune."}', '{"fr":"Le citoyen est appelé à voter, mais il a d''autres responsabilités dans la vie locale. \\n\\nQuelles sont ses possibilités d''actions locales? Comment regrouper les énergies et sur quels mouvements sur peut-on s''appuyer. Observons ce qui est fait ailleurs. débattons."}', '{"fr":"action locale, citoyen, vie politique, élus, responsabilité, la roche-bernard, morbihan, débat, collectif"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-28T18:00:00.000Z","end":"2016-10-28T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":5,"max":80}', '[]', '2016-11-04 09:19:56', '2016-11-04 09:19:56', NULL ),
(146962, 73293241, 85967955, NULL, 61542586, 'cafe-des-citoyens-a-paris-5', '{"fr":"Café des citoyens à Paris 5"}', '{"fr":"Ce café citoyens nous permettra d''échanger sur ce mouvement qui fait du bien. Venir, c''est déjà agir. Le nom du café sera précisé la veille."}', '{}', '{"fr":", Bienveillance"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T09:00:00.000Z","end":"2016-10-16T09:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":77}', '[]', '2016-11-04 09:19:01', '2016-11-04 09:19:01', NULL ),
(145782, 95321761, 96925482, NULL, 86103313, 'cafe-des-citoyens-beziers', '{"fr":"Café des Citoyens-Beziers"}', '{"fr":"1ère reunion le Jeudi 29 septembre 2016 à 18H30"}', '{"fr":"[La maison des citoyens-Béziers](https://www.facebook.com/LesFaiseuxDeBeziers/) \\n\\nTop départ !\\n\\nLa maison des Citoyens-Béziers tiendra sa première réunion le Jeudi 29 Septembre à partir de 18h30 au café des arts 13 rue de la coquille à Béziers. Ouvert à toutes et à tous. Buzzez tant que vous pouvez, plus nous serons nombreux, plus nous compterons et surtout n''oubliez de faire inscrire vos invités sur le site de la Maison Des Citoyens."}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-29T16:30:00.000Z","end":"2016-09-29T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '[]', '2016-11-04 09:20:01', '2016-11-04 09:20:01', NULL ),
(145811, 92516884, 74437987, NULL, 51733065, 'cafe-des-citoyens-guadeloupe', '{"fr":"CAFE DES CITOYENS GUADELOUPE"}', '{"fr":"2ième rendez vous présentation de la Maison des Citoyens"}', '{"fr":"Voici notre 2ième rendez vous, des café Citoyens rendez vous chez Dobré DONUTS, à Jarry qui nous accueille!!!\\n\\nEnvie de découvrir la Maison des Citoyens\\n\\nEnvie de VOUS COMPTER dans notre belle Maison …\\n\\nEnvie de faire découvrir à des amis, à des membres de votre famille, les valeurs fondatrices de la Maison du Citoyen 1+1+1…\\n\\nEnvie de METTRE EN LUMIERE DES \\"FAIZEUX\\" GUADELOUPE : des associations, des entrepreneurs, des personnes … qui dans votre quartier, votre arrondissement, en tous les cas NOTRE Ile à mené des actions concrètes et profitables à notre territoire. (chômage, écologie, éducation…).\\n\\nAlors VENEZ !!!\\n\\nVenez passer un MOMENT D''ECHANGE SIMPLE, HEUREUX ET CONSTRUCTIF puisque partagé !\\n\\nIMPORTANT : Merci d’indiquer rapidement votre participation à ce 2ième CAFE CITOYENS GUADELOUPE"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-01T09:00:00.000Z","end":"2016-10-01T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":2}', '["https://www.facebook.com/events/1291084510924797/?ref=1&action_history=%5B%7B%22surface%22%3A%22permalink%22%2C%22mechanism%22%3A%22surface%22%2C%22extra_data%22%3A%5B%5D%7D%5D"]', '2016-11-04 09:20:00', '2016-11-04 09:20:00', NULL ),
(146266, 94669741, 30061828, NULL, 55627149, 'cafe-outil-gerez-vos-taches-et-optimisez-votre-temps-avec-wunderlist', '{"fr":"Café outil - Gérez vos tâches et optimisez votre temps avec Wunderlist"}', '{"fr":"Gestionnaire de tâche collaboratif"}', '{"fr":"L''équipe du Pôle Numérique teste régulièrement des nouveaux outils (logiciels, applications, services, équipements ...) que nous vous proposons de les découvrir sous la forme d''un retour d''expériences.\\n\\nLe format : 30 minutes de présentation + 30 minutes d''échanges, de pratique et de test.Les outils que nous vous présentons, nous les avons testés dans un contexte d''utilisation professionnel et dans différents environnements (au bureau, en salle de réunion, en mobilité, dans un espace de coworking...)Ces solutions visent à faciliter la collaboration en interne et en externe, à optimiser certaines tâches, à améliorer la productivité, à nous faciliter la vie tout en évitant la surcharge d''information et la distraction numérique.\\n\\nLes outils et solutions retenues sont techniquement faciles à mettre en œuvre sans investissement lourd pour des petites structures, TPE, travailleurs indépendants, salariés, élus. Disponibles sur le web en mode hébergé, elles peuvent aussi être déployées dans des organisations plus grandes.\\n\\nAu programme de ce café outil :\\n\\nla gestion des tâches personnelles ou en équipe pour mener à bien vos projets, planifier un évènement afin de mieux organiser votre temps.\\n\\n[http://www.howtochoosealaptop.com/wp-content/uploads/2015/03/Wunderlist-logo.jpg](http://www.howtochoosealaptop.com/wp-content/uploads/2015/03/Wunderlist-logo.jpg)\\n\\n[https://docs.google.com/forms/d/e/1FAIpQLScXsppBW7OvHYGkCAYbd_Hzs6ft4UUY3Mm7VwMlCtQNZ5LPTQ/viewform](https://docs.google.com/forms/d/e/1FAIpQLScXsppBW7OvHYGkCAYbd_Hzs6ft4UUY3Mm7VwMlCtQNZ5LPTQ/viewform)\\n\\nCette action est cofinancée par l''Union européenne, la Région Auvergne-Rhône-Alpes et le Département de la Drôme."}', '{"fr":"veille, collaborative, participative, numérique, digital, startup, curation"}', NULL, '{"filename":"event_cafe-outil-gerez-vos-taches-et-optimisez-votre-temps-avec-wunderlist_710669.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cafe-outil-gerez-vos-taches-et-optimisez-votre-temps-avec-wunderlist_710669.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cafe-outil-gerez-vos-taches-et-optimisez-votre-temps-avec-wunderlist_710669.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-04T08:00:00.000Z","end":"2016-11-04T09:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":5,"max":11}', '["https://docs.google.com/forms/d/e/1FAIpQLScXsppBW7OvHYGkCAYbd_Hzs6ft4UUY3Mm7VwMlCtQNZ5LPTQ/viewform"]', '2016-11-04 09:19:38', '2016-11-04 09:19:38', NULL ),
(147307, 62689931, 24803623, NULL, 22404503, 'cafe-repaire-de-saintes-d-octobre', '{"fr":"Café Repaire de Saintes d''octobre"}', '{"fr":"Les BIG DATA"}', '{}', '{"fr":"BIB DATA,  café repaire"}', NULL, '{"filename":"event_cafe-repaire-de-saintes-d-octobre_983748.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cafe-repaire-de-saintes-d-octobre_983748.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cafe-repaire-de-saintes-d-octobre_983748.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-12T16:00:00.000Z","end":"2016-10-12T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":15,"max":99}', '[]', '2016-11-04 09:18:41', '2016-11-04 09:18:41', NULL ),
(146175, 59565068, 79324779, 64178931, 38470648, 'cafe-repaire-la-rochelle', '{"fr":"Café Repaire la Rochelle"}', '{"fr":"Partenariat public-privé : ange ou démon ?"}', '{"fr":"Procédé de mise en œuvre de satisfaction de besoins publics de l’État et des collectivités territoriales, voire même d’établissements publics, le PPP (partenariat public-privé) a souvent mauvaise presse, et pas seulement en France.\\n\\nDéjà, de par son origine, anglo-saxonne. Source diabolique s’il en est.\\n\\nLe recours à ce type de marchés publics est justifié pour diverses raisons, certaines très honorables, d’autres moins, même si cela ne signifie pas malhonnêtes. Chacun des protagonistes du PPP (le maître d’ouvrage et l’exécutant) a ses priorités. Quelles sont-elles ? Sont-elles incompatibles ?\\n\\nLe PPP n’est pas seulement un procédé, il est aussi une réponse à un besoin dans un contexte économique basé sur une philosophie politique qu’il est plus facile d’évacuer d’un revers de main que d’en vouloir réfuter les arguments.\\n\\nPlusieurs exemples mettent en évidence les risques pour le donneur d’ordre, certains sont même emblématiques. Mais les risques peuvent avoir des origines diverses et l’impact sera, au regard de l’analyse, très différent : juridiques ou techniques, économiques ou politiques.\\n\\nMais si le PPP ne méritait ni une détestation aveugle ni une approbation silencieuse ?"}', '{"fr":",     Café repaire,    Attac,   public,  privé, partenariat"}', NULL, '{"filename":"event_cafe-repaire-la-rochelle_752403.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cafe-repaire-la-rochelle_752403.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cafe-repaire-la-rochelle_752403.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-21T17:00:00.000Z","end":"2016-10-21T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["http://la-bas.org/les-repaires-de-la-bas/les-repaires-par-regions/poitou-charentes/la-rochelle?id_evenement=278"]', '2016-11-04 09:19:42', '2016-11-04 09:19:42', NULL ),
(145810, 44131437, 74437987, NULL, 57851898, 'cafes-des-citoyens-guadeloupe', '{"fr":"CAFES DES CITOYENS GUADELOUPE"}', '{"fr":"Présentation de la maison des citoyens Guadeloupe et ses Iles"}', '{"fr":"Envie de découvrir la Maison des Citoyens\\n\\nEnvie de VOUS COMPTER dans notre belle Maison …\\n\\nEnvie de faire découvrir à des amis, à des membres de votre famille, les valeurs fondatrices de la Maison du Citoyen 1+1+1…\\n\\nEnvie de METTRE EN LUMIERE DES \\"FAIZEUX\\" GUADELOUPE : des associations, des entrepreneurs, des personnes … qui dans votre quartier, votre arrondissement, en tous les cas NOTRE ville ont mené des actions concrètes et profitables à notre territoire. (chômage, écologie, éducation…).\\n\\nAlors VENEZ !!!\\n\\nVenez passer un MOMENT D''ECHANGE SIMPLE, HEUREUX ET CONSTRUCTIF puisque partagé !\\n\\nIMPORTANT : Merci d’indiquer rapidement votre participation à ce PREMIER CAFE CITOYEN GUADELOUPE\\n\\nA noter une participation de 5€ ou votre pass requis Doxa pour l''Ambiance café ce lieu d''échange et de partage permets d''exister, chacun peut y venir, écrire, se divertir, rencontrer, rêver, merci pour compréhension"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-30T17:00:00.000Z","end":"2016-09-30T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":2}', '["https://www.facebook.com/events/302189456824057/?ref=1&action_history=%5B%7B%22surface%22%3A%22permalink%22%2C%22mechanism%22%3A%22surface%22%2C%22extra_data%22%3A%5B%5D%7D%5D"]', '2016-11-04 09:20:00', '2016-11-04 09:20:00', '2016-11-07 09:14:32' );
