(147389, 56519256, 65936671, 27545135, 59683001, 'casinio-vaccination-pour-le-vernissage-de-lk-exposition-pasteur-et-la-rage', '{"fr":"Casinio Vaccination pour le vernissage de lk''exposition Pasteur et la Rage"}', '{"fr":"Misez sur vos connaissances  de votre carnet de santé!"}', '{"fr":"A l''heure où certains doutes de l''intérêt de la vaccination, dépassionnez  le débat en jouant à notre casino des vaccinations! Découvrez par la même occasion l''exposition crée par la ville d''Arbois Pasteur et la rage."}', '{"fr":"vaccin, rage, Louis Pasteur"}', NULL, '{"filename":"event_casinio-vaccination-pour-le-vernissage-de-lk-exposition-pasteur-et-la-rage_165343.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_casinio-vaccination-pour-le-vernissage-de-lk-exposition-pasteur-et-la-rage_165343.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_casinio-vaccination-pour-le-vernissage-de-lk-exposition-pasteur-et-la-rage_165343.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-11T16:30:00.000Z","end":"2016-10-11T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":99}', '[]', '2016-11-04 09:18:36', '2016-11-04 09:18:36', NULL ),
