(145928, 69834063, 2088543, NULL, 28870286, 'cauchois-et-la-spectroscopie', '{"fr":"Cauchois et la spectroscopie"}', '{"fr":"Spectroscopes et sources de lumière..."}', '{"fr":"**Femmes de science**\\n\\nYvette Cauchois était une physicienne française, professeure des universités, connue pour ses travaux en\\n\\nspectroscopie et en optique.\\n\\n.\\n\\nPlanète Sciences Ile-de-France - 4"}', '{"fr":",     Expérimentation,    spectroscopes,   spectroscopie,  sources, lumière"}', NULL, '{"filename":"event_cauchois-et-la-spectroscopie_994703.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cauchois-et-la-spectroscopie_994703.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cauchois-et-la-spectroscopie_994703.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T14:30:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"},{"begin":"2016-10-16T09:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["isabelle.goulette@iledescience.org"]', '2016-11-04 09:19:54', '2016-11-04 09:19:54', NULL ),
