(145562, 48919337, 99535145, NULL, 88625609, 'centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-festival-de-laon-aisne', '{"fr":"Centenaire Dutilleux 2016 : l''Orchestre français des Jeunes en tournée avec Renaud Capuçon - Festival de Laon (Aisne)"}', '{"fr":"Le concerto pour violoncelle d''Henri Dutilleux sous le signe de la jeunesse, et sous la baguette de David Zinman"}', '{"fr":"## 28e Festival de musique française de Laon\\n\\nL’avant-dernier ouvrage de Rachmaninov précédant les ultimes _Danses symphoniques_. Un immense orchestre et un condensé du style final du compositeur, mixant certaines imprégnations de l’Amérique où il émigra et un profond enracinement dans sa culture russe.\\n\\nAux côtés de cette œuvre postromantique du XXème siècle, le \\"classique\\" concerto pour violoncelle de Dutilleux, créé par Rostropovitch en 1970 au Festival d’Aix-en-Provence. Inspiré des _Fleurs du mal_, le traitement de l’instrument soliste tel un « médium entre l’univers de Baudelaire et le monde sonore, pour tout ce qui s’identifie à l’idée d’évasion ». Une page d’exception lumineuse et lyrique, pour le centenaire du compositeur.\\n\\n## Programme :\\n\\n*   Sergei Rachmaninov, _Symphonie_ no3, en la mineur, op. 4\\n*   Henri Dutilleux \\"Tout un monde lointain...\\"4\\n\\n## Avec :\\n\\n*   Orchestre Français des Jeunes\\n*   David Zinman, direction\\n*   Gautier Capuçon, violoncelle"}', '{"fr":"concert,       2016-2017,      symphonique,     orchestre,    Dutilleux,   centenaire,  #Dutilleux2016, festival"}', NULL, '{"filename":"event_centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-festival-de-laon-aisne_974721.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-festival-de-laon-aisne_974721.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-festival-de-laon-aisne_974721.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-09T18:30:00.000Z","end":"2016-09-09T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["0323208750","http://picardie-billet.for-system.com/z8501e4f34345x34345_fr-FESTIVAL-DE-LAON.aspx?Param/IdProprio=2811"]', '2016-11-04 09:20:10', '2016-11-04 09:20:10', NULL ),
(145559, 12405721, 99535145, NULL, 22535410, 'centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-young-euro-classic-2016', '{"fr":"Centenaire Dutilleux 2016 : l''Orchestre français des Jeunes en tournée avec Renaud Capuçon - Young Euro Classic 2016"}', '{"fr":"Le concerto pour violoncelle d''Henri Dutilleux sous le signe de la jeunesse, et sous la baguette de David Zinman"}', '{"fr":"## Programme :\\n\\n*   Claude Debussy, _Marche écossaise sur un thème populaire_\\n*   Henri Dutilleux \\"Tout un monde lointain...\\"\\n*   Sergei Rachmaninov, _Symphonie_ no3, op. 44\\n\\n## Avec :\\n\\n*   Orchestre Français des Jeunes\\n*   David Zinman, direction\\n*   Gautier Capuçon, violoncelle"}', '{"fr":"concert,      2016-2017,     symphonique,    orchestre,   Dutilleux,  centenaire, #Dutilleux2016"}', NULL, '{"filename":"event_centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-young-euro-classic-2016_901103.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-young-euro-classic-2016_901103.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_centenaire-dutilleux-2016-l-orchestre-francais-des-jeunes-en-tournee-avec-renaud-capucon-young-euro-classic-2016_901103.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-03T18:00:00.000Z","end":"2016-09-03T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["https://www.konzerthaus.de/en/programm/orchestre-francais-des-jeunes/1168"]', '2016-11-04 09:20:10', '2016-11-04 09:20:10', NULL ),
(146199, 21528944, 64614166, NULL, 97172353, 'cercle-de-femmes_534', '{"fr":"Cercle de femmes"}', '{"fr":"Un espace à vous offrir, juste pour vous..."}', '{"fr":"Bonjour à toutes,\\n\\nvenez prendre un moment pour vous.\\n\\nVenez vous pausez en cercle pour un moment entre sœurs.\\n\\nVenez partager votre vie de femme, ce qui vous anime, ce qui vous fait vibrer et vous traverse.\\n\\nVenez déposer ce qui vous pèse, vous encombre et vous empêche d''avancer.\\n\\nNous serons toutes là dans le respect, la bienveillance et la sororité pour accueillir vos joies, vos mots/maux, vos peines, vos bonheurs...\\n\\nVenez vous offrir cet espace, cette respiration dans votre vie.\\n\\nJe vous accueille à partir de 20h, début du cercle à 20h30.\\n\\nAu plaisir de partager ce moment avec vous,\\n\\nLydie*"}', '{"fr":"Cercle de paroles, Femmes, Sororité, Bienveillance"}', NULL, '{"filename":"event_cercle-de-femmes_534_146811.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cercle-de-femmes_534_146811.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cercle-de-femmes_534_146811.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-02T19:00:00.000Z","end":"2016-11-02T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '["etre_o_feminin@hotmail.com","06 83 31 28 54"]', '2016-11-04 09:19:41', '2016-11-04 09:19:41', NULL ),
