(147485, 7192200, 62731149, NULL, 23540337, 'ces-enfants-que-l-on-dit-differents', '{"fr":"« Ces enfants que l’on dit différents »"}', '{"fr":"Groupe de parole parents"}', '{"fr":"La Maison des Parents et de la Famille est un lieu convivial de rencontres où il est possible de prendre son temps pour échanger en toute confiance avec d’autres parents et des professionnels.\\n\\nC’est un lieu non stigmatisant et déculpabilisant, pour aider les parents à prendre du recul et à trouver des appuis pour l’éducation de leurs enfants. Elle a, dans le cadre général de sa mission de soutien à la fonction parentale, vocation à accompagner les parents de manière collective et/ou individuelles dans leurs doutes, leurs questionnements, mais aussi dans la valorisation de leur réussite.\\n\\nLe groupe de parole est animé par Michèle Guimelchain-Bonnet, psychologue et co-fondatrice du café des aidants.\\n\\n> Horaires d’ouverture\\n\\nLundi, mercredi, jeudi et vendredi\\n\\nde 9h à 12h30 et de 14h à 17h30\\n\\nMardi de 9h à 12h30 et de 14h à 19h30"}', '{}', NULL, '{"filename":"event_ces-enfants-que-l-on-dit-differents_169284.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_ces-enfants-que-l-on-dit-differents_169284.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_ces-enfants-que-l-on-dit-differents_169284.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-25T16:00:00.000Z","end":"2016-10-25T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":14,"max":30}', '["01 48 48 39 63","mdlp@ville-bondy.fr"]', '2016-11-04 09:18:31', '2016-11-04 09:18:31', NULL ),
