(145744, 31213582, 2088543, NULL, 28870286, 'chanter-avec-les-mains', '{"fr":"Chanter avec les mains"}', '{"fr":"Des instruments de synthèse vocale à l''essai : la Cantor Digitalis et Calliphony"}', '{"fr":"Nous présentons deux instruments de synthèse vocale contrôlés par le geste manuel: **la Cantor Digitalis et Calliphony.**\\n\\nLe premier repose sur un modèle mathématique de l''appareil vocal, le second est un système de modification en temps-réel de voix pré-enregistrées.\\n\\nCes deux instruments nous permettent de \\"chanter avec nos mains\\" à l''aide de tablettes graphiques. Les domaines abordés iront de la biologie (présentation des organes qui permettent la production de la parole) à l''informatique (introduction aux différentes techniques de synthèse vocale et de contrôle de l''articulation).\\n\\n**Les participants pourront tester ces instruments, et regarder des vidéos rendant compte de leurs capacités lorsqu''ils sont utilisés par des utilisateurs entrainés.**"}', '{"fr":",           geste manuel,          appareil vocal,         voix pré-enregistrées,        mains,       tablettes,      graphiques,     biologie,    informatique,   synthèse,   vocale, articulation"}', NULL, '{"filename":"event_chanter-avec-les-mains_56784.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chanter-avec-les-mains_56784.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chanter-avec-les-mains_56784.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T14:30:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"},{"begin":"2016-10-16T09:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":12}', '["isabelle.goulette@iledescience.org"]', '2016-11-04 09:20:03', '2016-11-04 09:20:03', NULL ),
(146207, 49451336, 96271593, NULL, 94075159, 'chantier-de-recolte', '{"fr":"Chantier de récolte"}', '{"fr":"Présentation du matériel agricole utilisé pour la récolte : round baller, faneuse, telescopique -déchargement -paille"}', '{"fr":"Découvrez les engins agricoles utilisés au domaine de l''Inra pour la récolte."}', '{}', NULL, '{"filename":"event_chantier-de-recolte_986335.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chantier-de-recolte_986335.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chantier-de-recolte_986335.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T16:00:00.000Z"},{"begin":"2016-10-16T08:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":14,"max":18}', '[]', '2016-11-04 09:19:41', '2016-11-04 09:19:41', NULL ),
(146886, 41838187, 45381015, NULL, 89026793, 'charlieu-le-patrimoine-comme-support-de-transformation', '{"fr":"Exposition \\"Charlieu : le patrimoine comme support de transformation\\""}', '{"fr":"L’exposition présente les travaux des étudiants de l’ENSASE de l’atelier de S2 « L’Architecture pour la Ville - Février à Juin 2015 »"}', '{"fr":"L’exposition présente les travaux des étudiants de l’ENSASE de l’atelier de S2 « L’Architecture pour la Ville - Février à Juin 2015 »\\n\\n**Enseignants responsables :**\\n\\nJean-Pierre Vettorello - Guillaume Benier - Xavier Wrona\\n\\n**Enseignants associés :**\\n\\nCarole Mathevon - Christian Massard - Pierre Doucerain - Francis Martinuzzi\\n\\nL’atelier est consacré au rapport entre l’architecture et la ville, sur la base d’une démarche d’exercices de conception\\n\\nmettant en avant la confrontation du projet d’architecture avec le contexte dans lequel il prend place :\\n\\nprojeter = transformer une situation par l’ajout d’une nouvelle valeur formelle.\\n\\nParallèlement à cette démarche de conception, les exercices sont également le prétexte pour les étudiants à une introduction\\n\\naux échelles du paysage, du territoire et de la ville, à partir de travaux d’expertises et de relevé in situ, de réécritures graphiques des lieux."}', '{"fr":"architecture, urbanisme, ville, conception, patrimoine, territoire, transformation"}', NULL, '{"filename":"event_charlieu-le-patrimoine-comme-support-de-transformation_2080.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_charlieu-le-patrimoine-comme-support-de-transformation_2080.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_charlieu-le-patrimoine-comme-support-de-transformation_2080.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T08:00:00.000Z","end":"2016-10-14T10:30:00.000Z"},{"begin":"2016-10-14T12:00:00.000Z","end":"2016-10-14T16:30:00.000Z"},{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T10:30:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:30:00.000Z"},{"begin":"2016-10-16T08:00:00.000Z","end":"2016-10-16T10:30:00.000Z"},{"begin":"2016-10-16T12:00:00.000Z","end":"2016-10-16T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '["04 77 60 09 97"]', '2016-11-04 09:19:05', '2016-11-04 09:19:05', NULL ),
(146395, 21640958, 70453612, NULL, 14936724, 'chaud-devant', '{"fr":"Chaud devant"}', '{"fr":"Inès est en CM2, elle est bien contente que la Terre se réchauffe car elle a toujours froid. Quels gestes quotidiens Inès va pouvoir trouver pour préserver l''environnement et leur santé?"}', '{}', '{}', NULL, '{"filename":"event_chaud-devant_93938.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chaud-devant_93938.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chaud-devant_93938.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-08T13:00:00.000Z","end":"2016-10-08T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":16}', '["03 81 94 4560"]', '2016-11-04 09:19:32', '2016-11-04 09:19:32', NULL ),
(146120, 58778316, 89226687, NULL, 5947763, 'chavire-concert-par-le-choeur-populaire-de-seine-saint-denis', '{"fr":"Chaviré : Concert par le Choeur populaire de Seine-Saint-Denis"}', '{"fr":"Le pain, la liberté, la paix par le Chœur populaire de Seine-Saint-Denis"}', '{"fr":"Samedi 1er octobre, à 11h à la P''tite Criée, revivez avec Angèle, jeune ouvrière de 1936, cette année exaltante. Ses souvenirs et les chansons de l''époque, au son de l''accordéon et du piano, nous plongent au cœur d''une période d''euphorie et d''espérance malgré le bruit des bottes qui résonne à nos frontières."}', '{}', NULL, '{"filename":"event_chavire-concert-par-le-choeur-populaire-de-seine-saint-denis_28245.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chavire-concert-par-le-choeur-populaire-de-seine-saint-denis_28245.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chavire-concert-par-le-choeur-populaire-de-seine-saint-denis_28245.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-01T09:00:00.000Z","end":"2016-10-01T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":77}', '[]', '2016-11-04 09:19:45', '2016-11-04 09:19:45', NULL ),
(146125, 73313249, 89226687, NULL, 5947763, 'chavire-spectacle-jeune-public', '{"fr":"Chaviré : Spectacle jeune public"}', '{"fr":"Samedi 8 octobre à 11h, le Cabarhéhéhé du Colectihihihif s''installe à la P''tite Criée, dans le cadre du 15e festival des clowns excentriques et burlesques du Samovar."}', '{"fr":"Ce cabaret ou plutôt, Cabarhéhéhé, est un spectacle, ou plutôt un spectahahahahacle hhilarant. Qu''on se le dise, vous allez rire, ou plutôt rihihihire ! Des numéros exfoliants et délirants s''enchaînent et se lient, se contrastent ou se stimulent ; quatre clowns aux mille facettes vivront des instants aussi drôles que tragiques. Un spectacle clownico-burlesque où s''entrechoquent joyeusement danse, cirque et musique. Du ridicule au sublime, pour votre plus grande hilarité.\\n\\nRendez-vous samedi 8 octobre à 11h à la P''tite Criée pour rhihihigoler !"}', '{}', NULL, '{"filename":"event_chavire-spectacle-jeune-public_66168.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chavire-spectacle-jeune-public_66168.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chavire-spectacle-jeune-public_66168.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-08T09:00:00.000Z","end":"2016-10-08T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":77}', '[]', '2016-11-04 09:19:45', '2016-11-04 09:19:45', NULL ),
(146707, 88123643, 85293408, NULL, 22744495, 'chevrefeuille-sauras-tu-garder-tes-arbres-et-ton-troupeau', '{"fr":"Chèvrefeuille, sauras-tu garder tes arbres et ton troupeau?"}', '{"fr":"Mettez-vous dans la peau d''un éleveur devant répondre aux besoins de son troupeau."}', '{"fr":"Lors de cette animation, vous serez invité à vous mettre dans la peau d’un éleveur devant répondre aux besoins alimentaires de son troupeau. Vous disposerez alors d’une exploitation d’arbres fourragers, première source alimentaire du troupeau. L’objectif du jeu sera d’assurer son alimentation sur une période de dix années grâce à une exploitation raisonnée des arbres fourragers présents. Saurez-vous garder vos arbres et votre troupeau ? Quelle stratégie adopterez-vous face aux aléas climatiques que vous rencontrerez ?"}', '{"fr":", chèvrefeuille - jeu - alimentation - arbre - troupeau"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T07:00:00.000Z","end":"2016-10-16T16:00:00.000Z"},{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":99}', '[]', '2016-11-04 09:19:15', '2016-11-04 09:19:15', NULL ),
(146768, 15866191, 7825239, NULL, 73714123, 'chevrefeuille-sauras-tu-garder-tes-arbres-et-ton-troupeau_651', '{"fr":"Chèvrefeuille, sauras-tu garder tes arbres et ton troupeau ?"}', '{"fr":"Le Laboratoire Population-Environnement-Développement vous propose de découvrir la notion de gestion forestière raisonnée autour d’un jeu d’apprentissage du développement durable."}', '{"fr":"Lors de cette animation, vous serez invité à vous mettre dans la peau d’un éleveur devant répondre aux besoins alimentaires de son troupeau. Vous disposerez alors d’une exploitation d’arbres fourragers, première source alimentaire du troupeau. L’objectif du jeu sera d’assurer son alimentation sur une période de dix années grâce à une exploitation raisonnée des arbres fourragers présents. Saurez-vous garder vos arbres et votre troupeau ? Quelle stratégie adopterez-vous face aux aléas climatiques que vous rencontrerez ?"}', '{}', NULL, '{"filename":"event_chevrefeuille-sauras-tu-garder-tes-arbres-et-ton-troupeau_651_62930.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chevrefeuille-sauras-tu-garder-tes-arbres-et-ton-troupeau_651_62930.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chevrefeuille-sauras-tu-garder-tes-arbres-et-ton-troupeau_651_62930.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:11', '2016-11-04 09:19:11', NULL ),
(146637, 95639344, 88859858, NULL, 56110536, 'chocolat-et-impression-3d', '{"fr":"Chocolat et impression 3D"}', '{"fr":"Venez découvrir en avant première une nouvelle entreprise de la Drôme"}', '{"fr":"## Chocolat et impression 3D en direct de la Drôme !!\\n\\nAvant l''inauguration officielle du 15 octobre, venez découvrir en avant-première les tablettes de chocolat personnalisées en 3D d’Art & Cie.\\n\\nEh oui, depuis un an Adrien travaille avec un ami/maître chocolatier, qui lui transmet son métier.\\n\\nIls travaillent du chocolat bio équitable en 70%\\n\\nPlaquettes diverses, aux fleurs cristallisées, à l''alcool, reproduction d’œuvres d''art...\\n\\nPlaquettes personnalisées en 3D à partir d''une photo, d''un logo..."}', '{"fr":"3D, Chocolat, Dégustation"}', NULL, '{"filename":"event_chocolat-et-impression-3d_235814.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chocolat-et-impression-3d_235814.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chocolat-et-impression-3d_235814.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-07T13:30:00.000Z","end":"2016-10-07T17:00:00.000Z"},{"begin":"2016-10-08T07:00:00.000Z","end":"2016-10-08T17:00:00.000Z"},{"begin":"2016-10-09T08:00:00.000Z","end":"2016-10-09T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":3}', '[]', '2016-11-04 09:19:19', '2016-11-04 09:19:19', NULL ),
(146856, 34491504, 22176242, NULL, 48147304, 'chromatik-kudiwa-street-charivari-party', '{"fr":"Chromatik + Kudiwa Street - Charivari Party !"}', '{"fr":"Chromatik et Kudiwa Street proposeront un plateau teinté de sonorités jazz, funk et soul."}', '{"fr":"**Chromatik**\\n\\nChromatik c’est une évasion, une envolée remplie de Groove et d’influences multiples comme le jazz, la funk, et le hip-hop. Les sept membres vous emmèneront dans leur univers avec leurs thèmes, leurs voix, et leurs solos. Vous y verrez une osmose entre tous les musiciens et une joie contagieuse d’être sur scène.\\n\\n[Soundcloud](http://bit.ly/2dYA205 )\\n\\n[Site](http://bit.ly/2cYXHI8)\\n\\n**Kudiwa Street**\\n\\nFruit d’un mélange parfaitement dosé de soul, de jazz, et de hip-hop, les cinq musiciens de Kudiwa Street propose un voyage autour de la musique Nu-Soul en explorant des sonorités énergiques et sans frontières.\\n\\n[Soundcloud](http://bit.ly/2dX8i8z )\\n\\n[Site](http://bit.ly/2djAMrI)\\n\\n**▬▬▬▬▬▬▬▬ INFOS PRATIQUES ▬▬▬▬▬▬▬▬▬**\\n\\nJeudi 27 octobre à 20h30\\n\\nTARIF : [8€ en prévente](http://bit.ly/2e8pACx) - 10€ sur place\\n\\n(Allez viens! Si tu te déguises en mode chic et plouc on te fait l''entrée au prix de 7 euros! :-) )\\n\\nPas de CB à la billetterie Restauration sur place Fermeture publique du lieu à minuit Accès à pied depuis les métros Garibaldi (10 mn) et Pte de Clignancourt (15 mn)"}', '{"fr":"Musique,    jazz,    funk,   soul,"}', NULL, '{"filename":"event_chromatik-kudiwa-street-charivari-party_215347.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_chromatik-kudiwa-street-charivari-party_215347.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_chromatik-kudiwa-street-charivari-party_215347.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-27T18:30:00.000Z","end":"2016-10-26T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":13,"max":16}', '["http://bit.ly/2e8pACx"]', '2016-11-04 09:19:06', '2016-11-04 09:19:06', NULL ),
(147470, 38742201, 45162898, NULL, 14591327, 'cine-archi-le-rebelle-de-king-vidor-1949', '{"fr":"Projection du film \\"Le Rebelle, de King Vidor\\" (1949)"}', '{"fr":"Ce film de King Vidor, portrait d''un architecte sans concession donne l''occasion de parler de l''architecte d''aujourd''hui."}', '{"fr":"Howard Roark (Gary Cooper) est un architecte talentueux et audacieux, trop même pour ses contemporains. Refusant tout compromis aux modes et aux désirs de ses commanditaires, il doit bientôt abandonner l’architecture faute de contrats et devient simple ouvrier de chantier dans une carrière appartenant à Gail Wynand, un riche et puissant magnat de la presse. La fille de Wynand, Dominique Françon (Patricia Neal), tombe amoureuse de Roark sans connaître sa véritable identité.\\n\\nLa projection du film sera suivie d’une discussion animée par Hugues Drapeau, architecte DPLG co-fondateur du collectif LA FABRIQUE DES LIEUX (Bordeaux/Angoulême)."}', '{"fr":",    cinéma,    architecture,  Royan,"}', NULL, '{"filename":"event_cine-archi-le-rebelle-de-king-vidor-1949_496021.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-archi-le-rebelle-de-king-vidor-1949_496021.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-archi-le-rebelle-de-king-vidor-1949_496021.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T16:30:00.000Z","end":"2016-10-13T18:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":14}', '["animation.patrimoine@mairie-royan.fr","05 46 39 9 4 45"]', '2016-11-04 09:18:31', '2016-11-04 09:18:31', NULL ),
(145622, 55781946, 42132110, NULL, 36906084, 'cine-atelier-bande-son', '{"fr":"Ciné-atelier : Bande son"}', '{"fr":"Après le film \\"Ma vie de courgette\\", Franck Goore Bi Tiesse, spécialiste de la prise de son et du design sonore, vous proposera l’expérience de création d''une vraie bande son de cinéma !"}', '{"fr":"Dans le Petit Trianon, après la séance de 14h30, Franck Goore Bi Tiesse, spécialiste de la prise de son et du design sonore, vous proposera l''expérience de CRÉATION D''UNE VRAIE BANDE SON DE CINÉMA !  \\nAu programme : bruitage et doublage de séquences extraites du film _Ma vie de courgette_.\\n\\nPlaces limitées. Durée : 1h environ. Gratuit sur réservation au 01 83 74 56 05/06.\\n\\n_**Ma vie de courgette  \\n**_Réalisé par Claude Barras  \\nFrance | 2015 | Drame, Animation | 01h06  \\nCristal d''or au Festival d''Annecy | Dès 7 ans  \\nCourgette n’a rien d’un légume, c’est un vaillant petit garçon. Il croit qu’il est seul au monde quand il perd sa mère. Mais c’est sans compter sur les rencontres qu’il va faire dans sa nouvelle vie au foyer pour enfants.\\n\\nCristal d’Or et Prix du public au Festival international du Film d’Animation d’Annecy, _Ma vie de Courgette_ est notre coup de cœur de la rentrée. C’est un concentré de vie, de joie et d’émotions, alors qu’il aborde un sujet difficile : le sentiment d’abandon de ces enfants placés en foyer d’accueil. Les personnages, marionnettes aux grands yeux, qui s’expriment avec le langage des enfants d’aujourd’hui, sont tous portés par un élan de vie. Par-delà leurs peurs et leurs échecs, les enfants surmontent les difficultés, dÉcouvrent la fraternité et l’amour, et en un mot grandissent. Extrêmement touchant, drôle et poétique, ce film est également une réussite graphique et musicale très originale, que nous sommes très heureux de vous faire découvrir en avant-première !"}', '{}', NULL, '{"filename":"event_cine-atelier-bande-son_977164.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-atelier-bande-son_977164.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-atelier-bande-son_977164.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T12:30:00.000Z","end":"2016-10-22T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '["http://www.cinematrianon.fr/index.php/evenements-et-festivals/item/2935-cine-atelier-bande-son"]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
(145618, 3746651, 42132110, NULL, 36906084, 'cine-danse_557', '{"fr":"Ciné-Danse"}', '{"fr":"Zoom sur la danse à travers deux documentaires magnifiques sur le sujet en écho à la programmation du film La Danseuse qui évoque la figure pionnière de Loie Fuller."}', '{"fr":"**18h30 : _Relève : histoire d''une création_**  \\nRéalisé par Thierry Demaizière  \\nFrance | 2015 | Documentaire | 2h  \\nAvec Benjamin Millepied \\n\\nBenjamin Millepied, danseur chorégraphe français, est nommé directeur de la danse de l’Opéra National de Paris en novembre 2014\\\\. Sa jeunesse, son regard moderne, sa culture et sa notoriété doivent apporter un renouveau dans la prestigieuse institution. Benjamin Millepied, danseur chorégraphe français, est nommé directeur de la danse de l''Opéra National de Paris en novembre 2014\\\\. Sa jeunesse, son regard moderne, sa culture et sa notoriété doivent apporter un renouveau dans la prestigieuse institution. Aussi bien dans ses choix créatifs que par ses méthodes de travail auprès des jeunes danseurs du corps de ballet, Benjamin Millepied va révolutionner les codes de la danse classique.\\n\\nC''est un documentaire captivant, d''une grande beauté visuelle, qui nous plonge, deux heures durant, au cœur du travail du chorégraphe Benjamin Millepied, alors directeur de la danse de l''Opéra de Paris (poste dont il a démissionné depuis). Personnage charismatique, doté d''une détermination sans faille apparente, passionné, exigeant, doué à l''extrême : Millepied embarque les danseurs dans la folle aventure d''une chorégraphie à réaliser en un temps record : celle du ballet Clear, Loud, Bright, Forward. Les réalisateurs Thierry Demaizière et Alban Teurlai suivent Millepied et sa troupe pas à pas, trois mois durant, et saisissent leur « work in progress ». Qu''il est fascinant d''observer ces corps au travail, la rigueur de celles et ceux qui, ensemble, traquent la grâce sur scène ! Outre les répétitions, les documentaristes posent également leur regard sur les coulisses administratives de cette grande institution. Il en ressort un contraste saisissant entre la vision moderniste et le tempérament impatient du chorégraphe, et les réactions, parfois rétives, d''une institution au poids colossal.\\n\\n**21h : _Mr Gaga, sur les pas d’Ohad Naharin_**  \\nRéalisé par Tomer Heymann  \\nIsraël | 2015 | Documentaire | 01h43  \\nAvec Ohad Naharin \\n\\nL’histoire fascinante d''Ohad Naharin, célèbre chorégraphe de la Batsheva Dance Company, dont les performances dégagent une puissance et une beauté inégalées. Le film nous dévoile le processus créatif d''un chef de file incontesté de la danse contemporaine, l''invention d''un langage chorégraphique unique et d''une technique de danse hors- norme appelée \\"Gaga\\".\\n\\nDocumentaire sur l''un des grands chorégraphes de notre temps qui a réinventé son art en bousculant tabous et conventions. Le chorégraphe israélien Ohad Naharin est talentueux, adulé, fascinant. Quand il dirige ses danseurs comme lorsqu''il s''oppose à la politique de son pays, il n''est jamais l''homme des compromis, des facilités. Face auréalisateur, qui a obtenu -non sans mal- l''autorisation de le suivre, il se tient sur ses gardes. Ce portrait habile n''en est que plus précieux... Retracé à travers des images d''archives et des films familiaux, le parcours du chorégraphe suit une logique passionnée et mystérieuse. Aux secrets souvent douloureux de la vie, la danse semble répondre comme un langage lumineux, mais pas forcément explicite. Toutes les répétitions et les spectacles sont traversés par une énergie vitale, magnifique. La « gaga dance » inventée par le chorégraphe- c''est le premier mot qu''il prononça dans sa vie est une fête du corps, à la fois entraînement sportif et recherche artistique. L''important est de bouger. Ce film en donne très envie. C''est par le lâcher-prise que l''on arrive, dans Mr. Gaga, à la danse..."}', '{"fr":"danse"}', NULL, '{"filename":"event_cine-danse_557_191386.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-danse_557_191386.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-danse_557_191386.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-11T16:30:00.000Z","end":"2016-10-11T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":5,"max":99}', '["http://www.cinematrianon.fr/index.php/evenements-et-festivals/item/2962-cine-danse"]', '2016-11-04 09:20:08', '2016-11-04 09:20:08', NULL ),
(146455, 77523605, 6669183, NULL, 76792327, 'cine-debat-autour-du-film-my-architect', '{"fr":"Ciné-débat autour du film \\"My Architect\\""}', '{"fr":"Projection du film ‘‘My Architect’’ de Nathaniel Kahn avec Louis Kahn, suivi d’une conférence de François-Xavier Legenne, actuellement en exposition au CAUE de l’Oise."}', '{"fr":"Synopsis :\\n\\nLouis Kahn s''inscrit comme l''un des plus grands architectes du XXe siècle. Il construisit des oeuvres monumentales à dimension universaliste et d''une grande élévation spirituelle. Sa vie, à l''image de ses édifices, fut chargée de mystère. Lorsqu''il succomba à un infarctus, dans les toilettes pour hommes de Penn Station en 1974, les nécrologies précisaient qu''il laissait une épouse, Esther, et une fille, Sue Ann.Mais il apparut que Kahn avait mené quatre vies à la fois : son travail, sa famille officielle, ainsi que deux autres femmes et les enfants qu''elles lui avaient donnés. Nathaniel Kahn, fils de Louis Khan et d''Harriet Pattison, une architecte paysagiste, avait onze ans quand son père mourut. Agé de 39 ans aujourd''hui, il revient sur les traces de son père à travers ce portrait intime d''un homme complexe et fascinant.\\n\\nFrançois-Xavier Legenne, artiste autodidacte et ancien architecte nous racontera comment"}', '{"fr":"projection, film, conférence, Kahn"}', NULL, '{"filename":"event_cine-debat-autour-du-film-my-architect_378045.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-debat-autour-du-film-my-architect_378045.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-debat-autour-du-film-my-architect_378045.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T14:00:00.000Z","end":"2016-10-14T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '["caue60@wanadoo.fr","03 44 82 14 14","http://www.caue60.com"]', '2016-11-04 09:19:29', '2016-11-04 09:19:29', NULL ),
(147331, 84202255, 34514828, NULL, 96169383, 'cine-debat-les-nouveaux-loups-du-web', '{"fr":"Ciné-débat: Les nouveaux loups du Web"}', '{"fr":"Projection du film “Les nouveaux loups du Web” + débat animé par Zoomacom. Soirée en partenariat avec le Collectif pour une Transition Citoyenne Loire."}', '{"fr":"## Les nouveaux loups du Web\\n\\nFilm américain de Cullen Hoback (2016 - 1h17min) avec Raymond Kurzweil, Joe Lipari, Richard ''Moby'' Hall...\\n\\nAvez vous déjà lu les conditions générales d’utilisation des données privées présentes sur chaque site internet que vous visitez, ou sur les applications que vous utilisez ? Bien sûr que non. Et pourtant, ces mentions autorisent les entreprises à utiliser vos informations personnelles dans un cadre au delà de votre imagination. Le film vous révèle ce que les entreprises et les gouvernements vous soustraient en toute légalité, à partir du moment où vous avez cliqué sur « J’accepte », et les conséquences scandaleuses qui en découlent.\\n\\nLe lundi 17 octobre à 20h00 au cinéma le Méliès - Jean Jaurès à St-Étienne\\n\\n**Débat animé par les médiateurs numériques de [l''association ZOOMACOM](http://www.zoomacom.org)  \\n**\\n\\nZOOMACOM a pour objet de permettre l’appropriation collective des pratiques et des usages numériques pour les mettre au service de projets économiques, sociaux et solidaires des territoires numériques qu’elle accompagne.\\n\\nSoirée en partenariat avec le [Collectif pour une Transition Citoyenne Loire](http://www.loire-site.org/) (CTC 42).\\n\\nPlus d''infos sur le site du cinéma le Méliès : [Ciné-débat: Les nouveaux loups du Web](http://www.lemelies.com/CINE-DEBAT,2117)"}', '{"fr":"GAFAM, Médiation Numérique, Les Nouveaux Loups du Web"}', NULL, '{"filename":"event_cine-debat-les-nouveaux-loups-du-web_433460.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-debat-les-nouveaux-loups-du-web_433460.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-debat-les-nouveaux-loups-du-web_433460.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-17T18:00:00.000Z","end":"2016-10-17T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":11,"max":15}', '["http://www.lemelies.com/-Informations-pratiques-"]', '2016-11-04 09:18:39', '2016-11-04 09:18:39', NULL ),
(146586, 47257108, 91345264, 325055, 84019114, 'cine-debat-sur-la-situation-en-grece', '{"fr":"Ciné-débat sur la situation en Grèce"}', '{"fr":"Avec trois courts-métrages, à la MIR. Organisé par ATTAC et Bretagne-Grèce Solidarité Santé."}', '{}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-06T17:30:00.000Z","end":"2016-10-06T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:22', '2016-11-04 09:19:22', NULL ),
(147343, 78599700, 4228484, NULL, 92093097, 'cine-discussion-du-film-demain-de-cyril-dion-et-melanie-laurent', '{"fr":"Ciné-discussion du film \\"Demain\\" de Cyril Dion et Mélanie Laurent"}', '{"fr":"En présence de productieur bio de l''AMAP de la Choisille et d''association Partenaires : Colibris, Énergie Citoyenne en Touraine, Les planches à Gabare, Nature et Progrès, La ferme Bus''Onnière"}', '{"fr":"https://www.youtube.com/watch?v=Bk2LnbrXx_I"}', '{}', NULL, '{"filename":"event_cine-discussion-du-film-demain-de-cyril-dion-et-melanie-laurent_414016.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-discussion-du-film-demain-de-cyril-dion-et-melanie-laurent_414016.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-discussion-du-film-demain-de-cyril-dion-et-melanie-laurent_414016.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T17:30:00.000Z","end":"2016-10-13T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":11,"max":15}', '[]', '2016-11-04 09:18:39', '2016-11-04 09:18:39', NULL ),
(145625, 5424841, 42132110, NULL, 36906084, 'cine-expo-atelier-la-chouette-entre-veille-et-sommeil', '{"fr":"Ciné-Expo-Atelier : La Chouette entre veille et sommeil"}', '{"fr":"Après le film, découvrez les coulisses du tournage du film d''animation La Moufle, puis ATELIER CONTE : invente tes propres histoires avec des cartes personnages créées pour les films du programme !"}', '{"fr":"Après la séance, rendez-vous dans le Petit Trianon pour découvrir à travers une exposition les coulisses du tournage du film d''animation _La Moufle_, puis ATELIER CONTE : invente tes propres histoires avec des cartes personnages créées pour les films du programme !\\n\\n_**La Chouette entre veille et sommeil**_  \\nRéalisé par Frits Standaert  \\nFrance | 2016 | Animation | 00h40 | Dès 4 ans  \\nLaissez-vous bercer par la Chouette du cinéma venue vous conter d’étonnantes histoires à la frontière du rêve et de la réalité. Vie nocturne entre voisins, bisou du soir, vision onirique… autant de thématiques qui toucheront les enfants comme les parents.\\n\\n**Réservations indispensables au 01 83 74 56 05/06.**"}', '{}', NULL, '{"filename":"event_cine-expo-atelier-la-chouette-entre-veille-et-sommeil_855564.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-expo-atelier-la-chouette-entre-veille-et-sommeil_855564.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-expo-atelier-la-chouette-entre-veille-et-sommeil_855564.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-29T14:00:00.000Z","end":"2016-10-29T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":3,"max":99}', '["http://www.cinematrianon.fr/index.php/evenements-et-festivals/item/2979-cine-expo-atelier"]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
(145619, 67616678, 42132110, NULL, 36906084, 'cine-geants', '{"fr":"Ciné-Géants"}', '{"fr":"Accueil gigantesque réaliseé par le Compagnie Obrigad0 dans le hall avant la séance ! Petits et Grands bienvenus !!!"}', '{"fr":"_**Les Petits géants**_  \\nFREILANDEIER - LA QUEUE DE LA SOURIS - LA LOI DU PLUS FORT - LE CHÂTEAU DES AUTRES - NAIN GÉANT - LE VÉLO DE L’ÉLÉPHANT - LE RENARD MINUSCULE  \\nProgramme de 7 courts-métrages d''animation sur le thème \\"Question de taille\\" | 54mn | Dès 5 ans\\n\\nGrand ou petit, tout dépend de son environnement ! Ces sept histoires réalisées par des auteurs différents et avec des techniques diverses nous font passer du gigantesque au minuscule, et sont une belle leçon de relativisme ! Elles démontent aussi les clichés, car le plus grand n''est pas toujours le plus terrifiant !"}', '{}', NULL, '{"filename":"event_cine-geants_228620.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-geants_228620.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-geants_228620.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T12:30:00.000Z","end":"2016-10-15T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":5,"max":99}', '["http://www.cinematrianon.fr/index.php/evenements-et-festivals/item/2978-accueil-geants"]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
(145626, 40203122, 42132110, NULL, 36906084, 'cine-halloween-miss-peregrine-et-les-enfants-particuliers', '{"fr":"Ciné-Halloween : Miss Peregrine et les enfants particuliers"}', '{"fr":"Rendez-vous tous au Trianon dans vos costumes les plus effrayants pour une séance monstrueuse !!! Séance photo avant le film et lâché de bonbons et frissons dans la salle à minuit !"}', '{"fr":"Après la tournée des maisons, des bonbons plein les poches, et la nuit tombée depuis bien longtemps, rendez-vous tous au Trianon dans vos costumes les plus effrayants pour une séance monstrueuse !!!\\n\\n**Séance photo avant le film et lâché de bonbons et frissons dans la salle à minuit !**\\n\\nMiss Peregrine et les enfants particuliers  \\nRéalisé par Tim Burton  \\nU.S.A. | 2016 | Aventure, Fantastique, Famille | 02h07 | Dès 8 ans \\n\\nÀ la mort de son grand-père, Jacob découvre l''existence d''un monde mystérieux. Plusieurs indices le mènent dans ce lieu magique : la Maison de Miss Peregrine pour Enfants Particuliers. Mais le mystère et le danger s''amplifient quand il apprend à connaître les résidents, leurs étranges pouvoirs... et leurs puissants ennemis. Finalement, Jacob découvre que seule sa propre \\"particularité\\" peut sauver ses nouveaux amis."}', '{}', NULL, '{"filename":"event_cine-halloween-miss-peregrine-et-les-enfants-particuliers_698972.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-halloween-miss-peregrine-et-les-enfants-particuliers_698972.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-halloween-miss-peregrine-et-les-enfants-particuliers_698972.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-31T20:00:00.000Z","end":"2016-10-30T23:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["http://www.cinematrianon.fr/index.php/evenements-et-festivals/item/2980-cine-halloween"]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
(146342, 95450320, 14963029, NULL, 66333672, 'cine-parents-le-premier-cri', '{"fr":"Ciné-parents: \\" Le Premier Cri\\""}', '{"fr":"Ce film n’est pas une fiction mais l’histoire vraie des naissances vécues au présent sous nos yeux. Le premier cri n’est pas seulement un film sur la naissance, c’est aussi un film sur les femmes"}', '{"fr":"C’est un hymne à la vie, un hommage à la féminité et à la maternité.10 femmes nous font partager cette expérience dans des pays tout en contrastes : les États-Unis, le Mexique, le Brésil, la France, le Niger, la Tanzanie, l’Inde, le Vietnam, le Japon et la Russie. Dans un intervalle de 48h sur la terre, le destin de plusieurs femmes se croise dans un moment unique et universel : la mise au monde de leur enfant. Du pôle nord aux steppes mongoles, de la savane africaine au désert saharien, des villages touaregs aux gigantesques hôpitaux de Chine ou du japon, ce film est le plus beau et le plus insolite des voyages. C’est l’éblouissante histoire vraie du tout premier cri de la vie. Celui que l’on pousse quand on naît et qui scelle notre venue sur le monde.\\n\\nFilm documentaire de Gilles de Maistre (2007)\\n\\n[https://www.youtube.com/watch?v=8foPgvAkzP0](https://www.youtube.com/watch?v=8foPgvAkzP0)\\n\\n**_Les soirées Ciné-parents proposent des opportunités pour découvrir de nouvelles connaissances, apprendre de la science et de l''expérience pédagogique, échanger et témoigner entre parents._**"}', '{"fr":"ciné,     cinéma,     parents,     enfant,    animation,    animations,  parent, enfants"}', NULL, '{"filename":"event_cine-parents-le-premier-cri_700323.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-parents-le-premier-cri_700323.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-parents-le-premier-cri_700323.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-24T18:30:00.000Z","end":"2016-11-24T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":10}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:35', '2016-11-04 09:19:35', '2016-11-07 09:14:32' );
