(146349, 84628082, 14963029, NULL, 66333672, 'cine-parents-loczy-une-ecole-de-civilisation', '{"fr":"Ciné-parents: \\" Loczy, une école de civilisation\\""}', '{"fr":"A Budapest, en Hongrie pendant soixante cinq ans, de 1946 à 2011, I''Institut PIKLER a été une pouponnière prestigieuse que visitaient des professionnels de la petite enfance venus du monde entier."}', '{"fr":"En 2006, sous la pression de circonstances extérieures, l’Institut que tout le monde appelle Lóczy, du nom de la petite rue où il se trouve, a dû se muer en crèche. Entre 1982 et aujourd’hui, Bernard MARTINO, cinéaste, s’est rendu très souvent à Lóczy.\\n\\nFilm documentaire de Bernard MARTINO (2014) présenté par Bernard GOLSE et Miriam RASSE Association Pikler Loczy France.\\n\\n[https://www.youtube.com/watch?v=FLAC1JvQgX8](https://www.youtube.com/watch?v=FLAC1JvQgX8)\\n\\n**_Les soirées Ciné-parents proposent des opportunités pour découvrir de nouvelles connaissances, apprendre de la science et de l''expérience pédagogique, échanger et témoigner entre parents._**"}', '{"fr":"ciné,     cinéma,     parents,     enfant,    animation,    animations,  parent,  enfants"}', NULL, '{"filename":"event_cine-parents-loczy-une-ecole-de-civilisation_525485.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-parents-loczy-une-ecole-de-civilisation_525485.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-parents-loczy-une-ecole-de-civilisation_525485.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-30T18:30:00.000Z","end":"2016-11-30T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":10}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:34', '2016-11-04 09:19:34', NULL ),
(145624, 6623531, 42132110, NULL, 36906084, 'cine-philo', '{"fr":"Ciné-Philo : Ma vie de courgette"}', '{"fr":"Après le film, jeu débat dans le Petit Trianon sur le thème \\"La joie est-elle une conquête ?\\". Goûter offert."}', '{"fr":"Après le film, jeu débat dans le Petit Trianon sur le thème \\"La joie est-elle une conquête ?\\".\\n\\nGoûter offert.\\n\\n_**Ma vie de courgette**_  \\nRéalisé par Claude Barras  \\nFrance | 2015 | Drame, Animation | 01h06  \\nCristal d''or au Festival d''Annecy | Dès 7 ans \\n\\nCourgette n’a rien d’un légume, c’est un vaillant petit garçon. Il croit qu’il est seul au monde quand il perd sa mère. Mais c’est sans compter sur les rencontres qu’il va faire dans sa nouvelle vie au foyer pour enfants.\\n\\nCristal d’Or et Prix du public au Festival international du Film d’Animation d’Annecy, _Ma vie de Courgette_ est notre coup de cœur de la rentrée. C’est un concentré de vie, de joie et d’émotions, alors qu’il aborde un sujet difficile : le sentiment d’abandon de ces enfants placés en foyer d’accueil. Les personnages, marionnettes aux grands yeux, qui s’expriment avec le langage des enfants d’aujourd’hui, sont tous portés par un élan de vie. Par-delà leurs peurs et leurs échecs, les enfants surmontent les difficultés, decouvrent la fraternité et l’amour, et en un mot grandissent. Extrêmement touchant, drôle et poétique, ce film est également une réussite graphique et musicale très originale, que nous sommes très heureux de vous faire découvrir en avant-première !"}', '{}', NULL, '{"filename":"event_cine-philo_95020.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cine-philo_95020.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cine-philo_95020.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-23T12:30:00.000Z","end":"2016-10-23T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '["http://www.cinematrianon.fr/index.php/evenements-et-festivals/item/2976-cine-philo"]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
(146360, 67186540, 45925510, NULL, 39081881, 'cinema-arch-lab', '{"fr":"Cinéma : Arch-Lab - Projections de courts-métrages «portraits d’architectes»"}', '{"fr":"Dans un lieu architectural remarquable, Arch-Lab"}', '{"fr":"Les projections cinématographiques procurent à ce lieu de culte à l’architecture des années 1960 de nouvelles perspectives.\\n\\nL’architecte **Alexandre Da Silva** présentera l’église Saint-François-d’Assise et sa symbolique, puis vous invitera à une discussion autour d’un verre."}', '{"fr":"Architecture, Cinéma, Projection, Journées de l''architecture, Arch-Lab, Mulhouse, Alsace"}', NULL, '{"filename":"event_cinema-arch-lab_748668.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cinema-arch-lab_748668.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cinema-arch-lab_748668.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T16:30:00.000Z","end":"2016-10-14T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:34', '2016-11-04 09:19:34', NULL ),
(145739, 65605267, 35786151, NULL, 18779132, 'cinema-cezanne-et-moi', '{"fr":"[CINEMA] Cézanne et moi,"}', '{"fr":"Séance de cinéma en VFST"}', '{"fr":"**RESUME :**\\n\\nIls s''aimaient comme on aime à treize ans : révoltes, curiosité, espoirs, doutes, filles, rêves de gloires, ils partageaient tout. Paul est riche. Emile est pauvre. Ils quittent Aix, « montent » à Paris, pénètrent dans l''intimité de ceux de Montmartre et des Batignolles. Tous hantent les mêmes lieux, dorment avec les mêmes femmes, crachent sur les bourgeois qui le leur rendent bien, se baignent nus, crèvent de faim puis mangent trop, boivent de l''absinthe, dessinent le jour des modèles qu''ils caressent la nuit, font trente heures de train pour un coucher de soleil... Aujourd''hui Paul est peintre. Emile est écrivain. La gloire est passée sans regarder Paul. Emile lui a tout : la renommée, l''argent une femme parfaite que Paul a aimé avant lui. Ils se jugent, s''admirent, s''affrontent. Ils se perdent, se retrouvent, comme un couple qui n''arrive pas à cesser de s''aimer."}', '{"fr":",         cinéma,        cézanne,       gaumont,      vfst,     sourds,    accessible,   film,  paul, drame"}', NULL, '{"filename":"event_cinema-cezanne-et-moi_704100.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cinema-cezanne-et-moi_704100.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cinema-cezanne-et-moi_704100.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-28T09:00:00.000Z","end":"2016-09-28T11:00:00.000Z"},{"begin":"2016-09-29T09:00:00.000Z","end":"2016-09-29T11:00:00.000Z"},{"begin":"2016-09-30T09:00:00.000Z","end":"2016-09-30T11:00:00.000Z"},{"begin":"2016-10-01T09:00:00.000Z","end":"2016-10-01T11:00:00.000Z"},{"begin":"2016-10-02T09:00:00.000Z","end":"2016-10-02T11:00:00.000Z"},{"begin":"2016-10-24T09:00:00.000Z","end":"2016-10-24T11:00:00.000Z"},{"begin":"2016-10-25T09:00:00.000Z","end":"2016-10-25T11:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":12}', '[]', '2016-11-04 09:20:03', '2016-11-04 09:20:03', NULL ),
(145743, 45657342, 35786151, NULL, 18779132, 'cinema-frantz-de-francois-ozon', '{"fr":"[CINEMA] Frantz, de François Ozon"}', '{"fr":"Séance de cinéma en VFST"}', '{"fr":"**Résumé :**\\n\\nAu lendemain de la guerre 14-18, dans une petite ville allemande, Anna se rend tous les jours sur la tombe de son fiancé, Frantz, mort sur le front en France. Mais ce jour-là, un jeune Français, Adrien, est venu se recueillir sur la tombe de son ami allemand. Cette présence à la suite de la défaite allemande va provoquer des réactions passionnelles dans la ville."}', '{"fr":"cinéma, frantz, françois, ozon, gaumont, vfst, sourds, accessible, sous-titre, drame, noir, blanc, guerre, 14-18"}', NULL, '{"filename":"event_cinema-frantz-de-francois-ozon_726187.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cinema-frantz-de-francois-ozon_726187.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cinema-frantz-de-francois-ozon_726187.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-28T09:00:00.000Z","end":"2016-09-28T11:00:00.000Z"},{"begin":"2016-09-29T09:00:00.000Z","end":"2016-09-29T11:00:00.000Z"},{"begin":"2016-09-30T09:00:00.000Z","end":"2016-09-30T11:00:00.000Z"},{"begin":"2016-10-01T09:00:00.000Z","end":"2016-10-01T11:00:00.000Z"},{"begin":"2016-10-02T09:00:00.000Z","end":"2016-10-02T11:00:00.000Z"},{"begin":"2016-10-03T09:00:00.000Z","end":"2016-10-03T11:00:00.000Z"},{"begin":"2016-10-04T09:00:00.000Z","end":"2016-10-04T11:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":12}', '[]', '2016-11-04 09:20:03', '2016-11-04 09:20:03', NULL ),
(145750, 10546511, 35786151, NULL, 18779132, 'cinema-la-taularde-d-audrey-estrougo', '{"fr":"[CINEMA] La Taularde, d''Audrey Estrougo"}', '{"fr":"Séance de cinéma en VFST"}', '{"fr":"**Résumé :**\\n\\nPour sauver l''homme qu''elle aime de la prison, Mathilde prend sa place en lui permettant de s''évader. Alors que sa survie en milieu carcéral ne dépend que de lui, Mathilde n''en reçoit plus aucune nouvelle. Isolée, soutenue uniquement par son fils, elle répond désormais au numéro d''e´crou 383205-B. Mathilde deviendra-t-elle une taularde comme une autre ?"}', '{"fr":"cinéma,       gaumont,       vfst,       la taularde,      sophie,     marceau,    rennes,   sourds,  accessible, film"}', NULL, '{"filename":"event_cinema-la-taularde-d-audrey-estrougo_739970.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cinema-la-taularde-d-audrey-estrougo_739970.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cinema-la-taularde-d-audrey-estrougo_739970.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-28T09:00:00.000Z","end":"2016-09-28T11:00:00.000Z"},{"begin":"2016-09-29T09:00:00.000Z","end":"2016-09-29T11:00:00.000Z"},{"begin":"2016-09-30T09:00:00.000Z","end":"2016-09-30T11:00:00.000Z"},{"begin":"2016-10-01T09:00:00.000Z","end":"2016-10-01T11:00:00.000Z"},{"begin":"2016-10-02T09:00:00.000Z","end":"2016-10-02T11:00:00.000Z"},{"begin":"2016-10-03T09:00:00.000Z","end":"2016-10-03T11:00:00.000Z"},{"begin":"2016-10-04T09:00:00.000Z","end":"2016-10-04T11:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":119}', '[]', '2016-11-04 09:20:02', '2016-11-04 09:20:02', NULL ),
(145740, 87402218, 35786151, NULL, 18779132, 'cinema-victoria-de-justine-triet', '{"fr":"[CINEMA] Victoria, de Justine Triet"}', '{"fr":"Séance de cinéma en VFST"}', '{"fr":"**Résumé :**\\n\\nVictoria Spick, avocate pénaliste en plein néant sentimental, débarque à un mariage où elle y retrouve son ami Vincent et Sam, un ex-dealer qu''elle a sorti d''affaire. Le lendemain, Vincent est accusé de tentative de meurtre par sa compagne. Seul témoin de la scène, le chien de la victime. Victoria accepte à contrecoeur de défendre Vincent tandis qu''elle embauche Sam comme jeune homme au pair. Le début d''une série de cataclysmes pour Victoria."}', '{"fr":",          cinéma,         vfst,        victoria,       gaumont,      film,     accessible,    sourds,   sous-titre,  avocat, virginie efira"}', NULL, '{"filename":"event_cinema-victoria-de-justine-triet_602596.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cinema-victoria-de-justine-triet_602596.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cinema-victoria-de-justine-triet_602596.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-28T09:00:00.000Z","end":"2016-09-28T11:00:00.000Z"},{"begin":"2016-09-29T09:00:00.000Z","end":"2016-09-29T11:00:00.000Z"},{"begin":"2016-09-30T09:00:00.000Z","end":"2016-09-30T11:00:00.000Z"},{"begin":"2016-10-01T09:00:00.000Z","end":"2016-10-01T11:00:00.000Z"},{"begin":"2016-10-02T09:00:00.000Z","end":"2016-10-02T11:00:00.000Z"},{"begin":"2016-10-03T09:00:00.000Z","end":"2016-10-03T11:00:00.000Z"},{"begin":"2016-10-04T09:00:00.000Z","end":"2016-10-04T11:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":12}', '[]', '2016-11-04 09:20:03', '2016-11-04 09:20:03', NULL ),
(146507, 63807486, 97862464, NULL, 14047593, 'cinematique-adrien-m-et-claire-b-au-carre-belle-feuille', '{"fr":"Cinématique Adrien M.et Claire B. au Carré belle Feuille"}', '{"fr":"danse et jonglage dans un environnement numérique"}', '{"fr":"**Cinématique Adrien M / Claire B**\\n\\n**Mardi 22 novembre 20h30**\\n\\nConception : Adrien Mondot. Danse : Marie Tassin. Jonglage : Joseph Viatte\\n\\nMusique : Christophe Sartori et Laurent Buisson\\n\\nCinématique entremêle réel et virtuel à la croisée de la danse, du jonglage et du motion-design. L’un jongle, l’autre danse et tous deux interagissent dans un espace fait de lignes, de points, de lettres, d’objets numériques projetés,créant ainsi un univers magique qui vient bousculer nos principes rationnels.\\n\\n**À partir de 8 ans - Durée : 70 mn**"}', '{}', NULL, '{"filename":"event_cinematique-adrien-m-et-claire-b-au-carre-belle-feuille_144834.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cinematique-adrien-m-et-claire-b-au-carre-belle-feuille_144834.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cinematique-adrien-m-et-claire-b-au-carre-belle-feuille_144834.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-22T19:30:00.000Z","end":"2016-11-22T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["01 55 18 54 00"]', '2016-11-04 09:19:26', '2016-11-04 09:19:26', NULL ),
(147154, 20738754, 87507213, NULL, 12152577, 'cinepelloche-prohjection-enfants-petits-et-grands-en-pellicule-16mm', '{"fr":"CinéPelloche Projection enfants petits et grands en péllicule 16MM"}', '{"fr":"à l''occasion de l''ouverture du Centre Social Autogéré"}', '{"fr":"## **Projection Ciné Pelloche et SynapsCes deux collectifs proposent deux projections par trimestre pour les familles l''après-midi, pour les adultes le soir. Ils voudraient engager un travail de mémoire en confrontant deux formats, deux réalités éloignées dans le temps : le numérique et la pellicule 16mm.**\\n\\n Tant qu’il y aura de la pellicule, communément appelée « ciné pelloche » ou « ciné mioches » est une association habitée par la certitude que rien ne pourra remplacer une séance de cinéma. Elle se propose de préserver ce qui reste possible en ce domaine grâce aux archives de la FOL qu’elle a récupéré. Elle a pour objet : de sauvegarder, restaurer, conserver, entretenir tout ce qui concerne la projection cinématographique faisant usage de la pellicule. D’organiser ou de participer à des projections cinématographiques et des débats. De transmettre les savoirs de la projection cinématographique, de l’entretien, de la conservation de la pellicule, des projecteurs, tout ce qui permet que l’on sache encore demain se servir de la pellicule et des appareils cinématographiques. Des groupes membres de l’association proposent ainsi des programmations en 16mm, dans différentes régions de France, selon les besoins et attentes du public, mais aussi des films disponibles archivés qui permettent de remonter le temps « quelques instants » et de débattre en partageant nos visions des histoires dans l’Histoire.\\n\\nSynaps imagine et tente de proposer de manière collective un nouveau rapport au cinéma et à l’audiovisuel. L’association expérimente d’autres voies de création et de diffusion, en réformant le lien entre ceux qui font les films et ceux qui les voient, en favorisant le partage de savoirs, en ayant des pratiques pédagogiques émancipatrices. Ce collectif propose un soutien à une « production alternative » en favorisant les liens entre différents corps de métiers de l’audiovisuel, en mettant à disposition de ses membres du matériel, en prenant le temps d’échanger sur les films en cours de réalisation et en partageant des idées. Il intervient aussi au bout du processus en favorisant la diffusion des films produits, notamment par le biais du cinéma voyageur. Pour répondre à un besoin d’autonomie face à l’omniprésence de l’image et du son dans le quotidien et avec l’envie de faire des expérimentations collectives de création, ce collectif met aussi en place des projets de formation à l’audiovisuel sous différentes formes."}', '{}', NULL, '{"filename":"event_cinepelloche-prohjection-enfants-petits-et-grands-en-pellicule-16mm_226249.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cinepelloche-prohjection-enfants-petits-et-grands-en-pellicule-16mm_226249.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cinepelloche-prohjection-enfants-petits-et-grands-en-pellicule-16mm_226249.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-19T12:00:00.000Z","end":"2016-10-19T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":7,"max":18}', '["http://synaps-audiovisuel.fr"]', '2016-11-04 09:18:50', '2016-11-04 09:18:50', NULL ),
