(146762, 5863768, 56882225, NULL, 64263975, 'civic-tech-et-community-organizing-10-novembre-2016', '{"fr":"Civic tech et Community organizing (10 novembre 2016)"}', '{"fr":"Séminaire organisé par le réseau DEL et Démocratie ouverte"}', '{"fr":"Le mouvement Civic tech, qui vise à mobiliser les citoyens via des outils numériques pour prendre part à l''activité démocratique, connait actuellement un engouement très important. Il soulève de nombreux espoirs en termes de mobilisation citoyenne et de transformation démocratique. Pourtant, il importe de ne pas se laisser emporter par \\"l''effet nouveauté\\" et réfléchir à la manière d''accompagner ces initiatives au-delà du stade expérimental.\\n\\nDans ce cadre nous proposons de poser les bases d''une démarche comparative avec un autre mouvement, le community organizing. Ce mouvement qui mobilise des citoyens pour agir dans leur environnement direct depuis plus de 20 ans s''est confronté à un certain nombre de problèmes (indépendance, institutionnalisation, capacité à s''inscrire dans des rapports de force...) qui se pose (ou se poseront également aux Civic tech. Quelles ont été les réponses apportées ?\\n\\nPour plus d''informations, cliquez [ici](http://institutdelaconcertation.org/wakka.php?wiki=AgendA&vue=consulter&pageID=1).\\n\\nCet événement est une formation. Pour vous inscrire, contactez votre [chargé-e de formation](http://planet.loire-atlantique.fr/group/cg44/alize?p_p_id=alize_WAR_alizeportlet&p_p_lifecycle=0&p_p_state=normal&_alize_WAR_alizeportlet_url=http%3A%2F%2Fsso-planet-alize.loire-atlantique.fr%2Fjcms%2Fplanet_807957%2Fvos-contacts-pour-vous-inscrire-en-formation#p_alize_WAR_alizeportlet) du service emploi et compétences ou du service ressources."}', '{"fr":", participation citoyenne"}', NULL, '{"filename":"event_civic-tech-et-community-organizing-10-novembre-2016_51443.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_civic-tech-et-community-organizing-10-novembre-2016_51443.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_civic-tech-et-community-organizing-10-novembre-2016_51443.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-10T16:00:00.000Z","end":"2016-11-10T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '["http://planet.loire-atlantique.fr/group/cg44/alize?p_p_id=alize_WAR_alizeportlet&p_p_lifecycle=0&p_p_state=normal&_alize_WAR_alizeportlet_url=http%3A%2F%2Fsso-planet-alize.loire-atlantique.fr%2Fjcms%2Fplanet_807957%2Fvos-contacts-pour-vous-inscrire-en-for"]', '2016-11-04 09:19:12', '2016-11-04 09:19:12', NULL ),
