(145994, 98819728, 91038462, NULL, 92990649, 'clement-oubrerie-a-la-librairie-les-mots-et-les-choses', '{"fr":"Clément Oubrerie à la librairie Les mots et les choses"}', '{"fr":"A l''occasion de la sortie du tome 3 des Royaumes du nord, Rencontre-Dédicace-Goûter avec Clément Oubrerie !"}', '{"fr":"Qui ne connaît pas la saga de Philipp Pullman, _Les royaumes du Nord_ ? Succès planétaire en librairie, adaptation prometteuse au cinéma avec le gratin des stars américaines... Clément Oubrerie (série _Pablo_) a relevé le défi de transcrire ce récit de fantasy hautement philosophique en BD (chez [Gallimard](http://lesmots-leschoses.us7.list-manage1.com/track/click?u=3563d6f98aaa0230ee9830433&id=4910370f73&e=c97acdb4f0)).\\n\\nEt il viendra en parler et rencontrer ses jeunes et moins jeunes lecteurs à l''occasion d''un goûter à la librairie Les mots et les choses, le 19 octobre à 16h30."}', '{}', NULL, '{"filename":"event_clement-oubrerie-a-la-librairie-les-mots-et-les-choses_845443.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_clement-oubrerie-a-la-librairie-les-mots-et-les-choses_845443.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_clement-oubrerie-a-la-librairie-les-mots-et-les-choses_845443.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-19T14:30:00.000Z","end":"2016-10-19T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":17}', '[]', '2016-11-04 09:19:51', '2016-11-04 09:19:51', NULL ),
