(146715, 8381433, 73442364, NULL, 98963851, 'coaching-solidaire', '{"fr":"Coaching solidaire"}', '{"fr":"Mets tes compétences au service des associations"}', '{"fr":"Présentation de:\\n\\n- ZupdeCo, des interlocuteurs directs et de la mission des étudiants d''Epitech auprès des jeunes en difficulté scolaire.\\n\\n- Emmaus Connect, des interlocuteurs directs et de la mission des étudiants d''Epitech auprès de l''accompagnement pédagogique pour les personnes ayant des difficultés d’accès au numérique."}', '{"fr":",    associations,   zupdeco,  emmausconnect, coachingsolidaire"}', NULL, '{"filename":"event_coaching-solidaire_591029.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_coaching-solidaire_591029.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_coaching-solidaire_591029.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-18T13:30:00.000Z","end":"2016-10-18T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":99}', '["https://intra.epitech.eu/module/2016/G-EPI-022/LIL-0-1/acti-230042/"]', '2016-11-04 09:19:14', '2016-11-04 09:19:14', NULL ),
(146053, 76888700, 10220945, 75699098, 89296231, 'coax-festival', '{"fr":"COAX FESTIVAL"}', '{"fr":"ZU, Oren Ambarchi, Rie Nakajima, Kunichiro Bueno & Yann Joussein, Prune Bécheau, Yes Deer, We Use Cookies, Mariachi on Fire!, Tumulus"}', '{"fr":"A travers son festival, le collectif Coax propose une programmation qui reflète ce qui le passionne, l''influence et l''inspire dans sa pratique artistique. De ZU à Oren Ambarchi en passant par des artistes pluridisciplinaires japonais, du Dj set boiteux à la performance de cocktail noise, ces deux jours intenses reflètent tous les univers sous-jacents au sein de la galaxie Coaxienne, ceux que l''on peut entendre et voir en toile de fond dans les différentes propositions du collectif.\\n\\n[http://www.coaxfestival.com/](http://www.coaxfestival.com/)\\n\\nhttp://www.fgo-barbara.fr/programmation/agenda/prune-becheau-we-use-cookie-kunichiro-bueno-et-yann-joussein-jpfr-zu-399"}', '{"fr":",     Free jazz,     performances,   noise music,  rock, musiques improvisées"}', NULL, '{"filename":"event_coax-festival_863485.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_coax-festival_863485.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_coax-festival_863485.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-28T18:00:00.000Z","end":"2016-10-27T22:00:00.000Z"},{"begin":"2016-10-29T18:00:00.000Z","end":"2016-10-28T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
