(147409, 30132728, 46726110, NULL, 61409463, 'coding-club-a-epitech-bordeaux-pour-la-codeweek-europe-2016', '{"fr":"CODING CLUB à EPITECH Bordeaux pour la CODEWEEK EUROPE 2016"}', '{"fr":"Venez vous initier à la programmation"}', '{"fr":"Le Coding Club est un atelier récurrent qui permet de vous initier à la programmation et au développement. Que ce soit par exemple le développement de jeux vidéo et bien d''autres activités ! Il est disponible dans toutes les écoles Epitech de France ! Les ateliers d''apprentissage (stages durant les vacances, sessions le mercredi ou le samedi) sont animés par des étudiants d''Epitech.\\n\\nContactez la ville de votre choix pour connaître le programme !\\n\\nQui peut y participer ?\\n\\nTous les lycéens ! C''est gratuit et aucune compétence préalable en programmation n''est nécessaire ! Il suffit juste de vous inscrire sur le site de la ville qui vous intéresse."}', '{"fr":"code, game, initiation, fun, epitech"}', NULL, '{"filename":"event_coding-club-a-epitech-bordeaux-pour-la-codeweek-europe-2016_225246.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_coding-club-a-epitech-bordeaux-pour-la-codeweek-europe-2016_225246.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_coding-club-a-epitech-bordeaux-pour-la-codeweek-europe-2016_225246.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":4,"max":25}', '["http://events.codeweek.eu/view/12125/coding-club/"]', '2016-11-04 09:18:35', '2016-11-04 09:18:35', NULL ),
