(146030, 22840828, 84816640, NULL, 27085826, 'coding-club_277', '{"fr":"Coding Club"}', '{"fr":"Découverte et apprentissage du code"}', '{"fr":"## Apprendre à coder dès le lycée\\n\\nLes ateliers CodingClub permettent la découverte et l’apprentissage de la programmation, du code, et de tous les principaux langages informatiques.\\n\\nNous utilisons différents supports (Codecombat, scratch, unity3d pour les jeux…) ; les participants peuvent choisir des thématiques spécifiques (ex la cyber-sécurité) et différents formats (demi- journée, journée ou stages de vacances…) suivant les sites.\\n\\nDes groupes ont été créé sur Facebook qui permettent aux participants de suivre les évènements sur chacun des sites (12 villes, 12 groupes) et de dialoguer avec les étudiants animateurs de ces sessions.\\n\\n### Comment participer ?\\n\\nPour devenir membre du CodingClub Epitech, il suffit de s’inscrire sur le site codingclub.epitech.eu et de choisir l’école Epitech où l’on souhaite suivre la session Les formules sont diverses et dépendent des différents sites Epitech (stage vacances, sessions du mercredi ou du samedi après-midi) Ces ateliers sont gratuits, animés par des étudiants d’Epitech Ils ont lieu en général dans le hub de chacune des 12 écoles Epitech Des machines peuvent être prêtées mais on peut venir avec son propre ordinateur"}', '{"fr":", code"}', NULL, '{"filename":"event_coding-club_277_601916.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_coding-club_277_601916.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_coding-club_277_601916.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-19T09:00:00.000Z","end":"2016-11-19T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":17}', '["http://codingclub.epitech.eu/"]', '2016-11-04 09:19:49', '2016-11-04 09:19:49', NULL ),
(146035, 57241420, 84816640, NULL, 27085826, 'coding-club_317', '{"fr":"Coding Club"}', '{"fr":"Découverte et apprentissage du code"}', '{"fr":"## Apprendre à coder dès le lycée\\n\\nLes ateliers CodingClub permettent la découverte et l’apprentissage de la programmation, du code, et de tous les principaux langages informatiques.\\n\\nNous utilisons différents supports (Codecombat, scratch, unity3d pour les jeux…) ; les participants peuvent choisir des thématiques spécifiques (ex la cyber-sécurité) et différents formats (demi- journée, journée ou stages de vacances…) suivant les sites.\\n\\nDes groupes ont été créé sur Facebook qui permettent aux participants de suivre les évènements sur chacun des sites (12 villes, 12 groupes) et de dialoguer avec les étudiants animateurs de ces sessions.\\n\\n### Comment participer ?\\n\\nPour devenir membre du CodingClub Epitech, il suffit de s’inscrire sur le site codingclub.epitech.eu et de choisir l’école Epitech où l’on souhaite suivre la session Les formules sont diverses et dépendent des différents sites Epitech (stage vacances, sessions du mercredi ou du samedi après-midi) Ces ateliers sont gratuits, animés par des étudiants d’Epitech Ils ont lieu en général dans le hub de chacune des 12 écoles Epitech Des machines peuvent être prêtées mais on peut venir avec son propre ordinateur"}', '{"fr":", code"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-02-25T09:00:00.000Z","end":"2017-02-25T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":17}', '["http://codingclub.epitech.eu/"]', '2016-11-04 09:19:49', '2016-11-04 09:19:49', NULL ),
(146727, 41935829, 80999393, NULL, 42754360, 'coding-club_450', '{"fr":"Coding Club"}', '{"fr":"Découverte et apprentissage du code"}', '{"fr":"## Apprendre à coder dès le lycée\\n\\nLes ateliers CodingClub permettent la découverte et l’apprentissage de la programmation, du code, et de tous les principaux langages informatiques.\\n\\nNous utilisons différents supports (Codecombat, scratch, unity3d pour les jeux…) ; les participants peuvent choisir des thématiques spécifiques (ex la cyber-sécurité) et différents formats (demi- journée, journée ou stages de vacances…) suivant les sites.\\n\\nDes groupes ont été créé sur Facebook qui permettent aux participants de suivre les évènements sur chacun des sites (12 villes, 12 groupes) et de dialoguer avec les étudiants animateurs de ces sessions.\\n\\n### Comment participer ?\\n\\nPour devenir membre du CodingClub Epitech, il suffit de s’inscrire sur le site codingclub.epitech.eu et de choisir l’école Epitech Nancy.\\n\\nLes formules sont diverses et dépendent des différents sites Epitech (stage vacances, sessions du mercredi ou du samedi après-midi)\\n\\nCes ateliers sont gratuits, animés par des étudiants d’Epitech\\n\\n**L''atelier aura lieu le samedi 22 et dimanche 23 de 10h00 à 17h00 au sein d''Epitech Nancy sur le thème ARDUINO et JEUX VIDEO.**\\n\\nAucune base n''est requise."}', '{"fr":",   code week ,  arduino, jeux video"}', NULL, '{"filename":"event_coding-club_450_350118.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_coding-club_450_350118.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_coding-club_450_350118.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-23T08:00:00.000Z","end":"2016-10-23T15:00:00.000Z"},{"begin":"2016-10-22T08:00:00.000Z","end":"2016-10-22T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":18}', '["http://codingclub.epitech.eu/"]', '2016-11-04 09:19:14', '2016-11-04 09:19:14', NULL ),
