(145981, 25729721, 14963029, 80515007, 64485437, 'collecte-solidaire-parvis-corentin-celton', '{"fr":"Collecte solidaire parvis Corentin Celton"}', '{"fr":"Apportez vos appareils électriques en état de marche ou hors d''usage. Des camions Emmaüs vous attendent pour recueillir vos dons."}', '{"fr":"[Eco-systèmes](http://www.eco-systemes.fr/) est un éco-organisme à but non lucratif agréé par les pouvoirs publics. Vos appareils seront triés, réemployés par une structure de l''économie sociale et solidaire locale, ou à défaut recyclés par Eco-systèmes.\\n\\n**Vous pouvez apporter:**\\n\\n- Petits appareils (mixeur, aspirateur, fer à repasser, téléphone...)\\n\\n- Matériel informatique (ordinateur, imprimante, scanner...)\\n\\n- Gros électroménager (frigo, cuisinière, machine à laver...)\\n\\n- Téléviseurs"}', '{"fr":"collecte, informatique, électroménager, électrique"}', NULL, '{"filename":"event_collecte-solidaire-parvis-corentin-celton_639229.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_collecte-solidaire-parvis-corentin-celton_639229.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_collecte-solidaire-parvis-corentin-celton_639229.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T12:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":17}', '[]', '2016-11-04 09:19:51', '2016-11-04 09:19:51', NULL ),
