(147521, 66862365, 52622298, NULL, 30607462, 'com-une-start-up-le-1er-prix-qui-recompense-la-communication-des-start-up', '{"fr":"Com''Une Start-Up, le 1er Prix qui récompense la communication des start-up"}', '{"fr":"La BigAddress, 1er écosystème de solutions de communication dédié aux start-up lance Com''Une Start-Up, le 1er prix récompensant la communication des Start-up"}', '{"fr":"La BigAddress, premier écosystème de solutions de communication dédié aux start-up lance Com''Une Start-Up, le 1er prix récompensant la communication des Start-up.\\n\\n[https://www.labigaddress.com/fr/](https://www.labigaddress.com/fr/)\\n\\nLa communication des start-up est devenue un des éléments prépondérant de leur valorisation.\\n\\nPour exister, émerger, se faire repérer par un investisseur ou son public cible, à l''instar de leur modèle rupturiste, les start-up réussissent à faire évoluer les outils et vecteurs de communication... en tout cas nous pouvons tous dire qu''elles communiquent différemment : Com'' Une Start up !\\n\\nAussi en complément de La BigAddress, nous avons décidé de valoriser les meilleures initiatives des Start-up dans ce domaine et de récompenser leur créativité, leur imagination, leur pertinence et leurs résultats...\\n\\nLes inscriptions pour le concours se font sur : [https://www.com-une-startup.com](https://www.com-une-startup.com)\\n\\nSi vous souhaitez venir participer à la soirée de remise des Prix le 15 novembre 2016, au Village by CA Paris, contactez : [sophie@com-une-startup.com](mailto:sophie@com-une-startup.com)"}', '{"fr":",    Start-up,   communication,  innovation, créativité"}', NULL, '{"filename":"event_com-une-start-up-le-1er-prix-qui-recompense-la-communication-des-start-up_932949.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_com-une-start-up-le-1er-prix-qui-recompense-la-communication-des-start-up_932949.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_com-une-start-up-le-1er-prix-qui-recompense-la-communication-des-start-up_932949.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-15T17:30:00.000Z","end":"2016-11-15T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":14}', '["https://www.com-une-startup.com/"]', '2016-11-04 09:18:29', '2016-11-04 09:18:29', NULL ),
(146152, 53126254, 14963029, NULL, 40542589, 'comedie-musicale-on-s-etait-dit', '{"fr":"Comédie musicale \\"On s''était dit\\""}', '{"fr":"Une bande copains quitte le lycée et se donne rendez-vous dix ans plus tard au café \\"Chez Laurette\\", leur QG de l''époque."}', '{"fr":"Une histoire d''amitié qui résiste au temps et aux épreuves : nostalgie, histoires d''amour, révélations surprenantes, humour....\\n\\nSur une idée originale et une mise en scène de Stéphane Métro (Roméo et Juliette, Les Misérables, Grease, Le Bal des Vampires), un orchestre live de 4 musiciens et 12 chanteurs-comédiens de la compagnie \\"DES SI DES LA\\", donnent à ce spectacle une énergie formidable qui se répand rapidement dans le public.\\n\\n[https://www.youtube.com/watch?v=BpqxZhK19MY](https://www.youtube.com/watch?v=BpqxZhK19MY)"}', '{"fr":"comédie musicale, chant, spectacle"}', NULL, '{"filename":"event_comedie-musicale-on-s-etait-dit_315123.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_comedie-musicale-on-s-etait-dit_315123.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_comedie-musicale-on-s-etait-dit_315123.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-19T18:30:00.000Z","end":"2016-10-19T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '["http://www.ticketac.com/spectacles/on-setait-dit-issy-les-moulineaux.htm"]', '2016-11-04 09:19:44', '2016-11-04 09:19:44', NULL ),
(146157, 86229581, 14963029, 4511419, 40542589, 'comedie-musicale-on-s-etait-dit_324', '{"fr":"Comédie musicale \\"On s''était dit\\""}', '{"fr":"Une bande copains quitte le lycée et se donne rendez-vous dix ans plus tard au café \\"Chez Laurette\\", leur QG de l''époque."}', '{"fr":"Une histoire d''amitié qui résiste au temps et aux épreuves : nostalgie, histoires d''amour, révélations surprenantes, humour....\\n\\nSur une idée originale et une mise en scène de Stéphane Métro (Roméo et Juliette, Les Misérables, Grease, Le Bal des Vampires), un orchestre live de 4 musiciens et 12 chanteurs-comédiens de la compagnie \\"DES SI DES LA\\", donnent à ce spectacle une énergie formidable qui se répand rapidement dans le public.\\n\\n[https://www.youtube.com/watch?v=BpqxZhK19MY](https://www.youtube.com/watch?v=BpqxZhK19MY)"}', '{"fr":"comédie musicale, chant, spectacle"}', NULL, '{"filename":"event_comedie-musicale-on-s-etait-dit_324_731529.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_comedie-musicale-on-s-etait-dit_324_731529.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_comedie-musicale-on-s-etait-dit_324_731529.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-20T18:30:00.000Z","end":"2016-10-20T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '["http://www.ticketac.com/spectacles/on-setait-dit-issy-les-moulineaux.htm"]', '2016-11-04 09:19:43', '2016-11-04 09:19:43', NULL ),
(147435, 96955628, 1488103, NULL, 6436073, 'comment-compter-les-poissons-les-campagnes-halieutiques', '{"fr":"Comment compter les poissons? Les campagnes halieutiques."}', '{"fr":"Comment compter les poissons? Les campagnes halieutiques."}', '{"fr":"campagne halieutique : identification, tri et mesures de poissons (et crustacés...) en polystyrène\\n\\n- mise en relation avec observation des échos sonar (\\"bancs de sardine\\") pour calculer tonnage poissons lié à tâche de l''écho sonar - + mise en relation avec lectures d''otolithes\\n\\n- film campagne IBTS, petits films mode de vie 3 espèces (benthique / pélagique/démersal)"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":99}', '[]', '2016-11-04 09:18:34', '2016-11-04 09:18:34', NULL ),
(145757, 19565145, 2088543, NULL, 28870286, 'comment-faire-parler-l-a-d-n-des-plantes-avec-l-electrophorese', '{"fr":"Comment faire parler l''ADN des plantes ?"}', '{"fr":"L''électrophorèse va vous servir à accéder au coeur de l''information"}', '{"fr":"Autrefois, la recherche sur les plantes se limitait à des observations visuelles, puis l’invention des méthodes d’analyse chimique a permis d’étudier leur fonctionnement de l’intérieur.\\n\\nAujourd’hui, l’analyse de l’ADN permet d’accéder directement au cœur de l’information génétique qui détermine l’apparence et le comportement des plantes dans un environnement donné : climat, sol, altitude...\\n\\n**L''atelier présente des expériences d’analyse de l''ADN et explique comment ces analyses sont utilisées pour l''amélioration des plantes cultivées.**\\n\\n[Génétique Quantitative et Evolution - Le Moulon - I.N.R.A. 2](http://moulon.inra.fr/index.php/fr/actualite/295-gqe-le-moulon-a-la-fete-de-la-science-2016)"}', '{"fr":",        recherche,       plantes,      ADN,     information,    génétique,   apparence,  analyses, amélioration"}', NULL, '{"filename":"event_comment-faire-parler-l-a-d-n-des-plantes-avec-l-electrophorese_262313.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_comment-faire-parler-l-a-d-n-des-plantes-avec-l-electrophorese_262313.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_comment-faire-parler-l-a-d-n-des-plantes-avec-l-electrophorese_262313.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T14:30:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T16:00:00.000Z"},{"begin":"2016-10-16T09:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":30}', '["isabelle.goulette@iledescience.org"]', '2016-11-04 09:20:02', '2016-11-04 09:20:02', NULL ),
(147368, 52524455, 62738857, NULL, 29286884, 'comment-seduire-un-cto-4', '{"fr":"Comment Séduire un CTO ? #4"}', '{"fr":"Venez vous inspirer des retours d''expériences et conseils de CTO de belles Startups !"}', '{"fr":"**Venez vous inspirer des conseils et retours d''expériences de CTO !**\\n\\nVous êtes porteur de projet et vous cherchez un CTO ? Vous êtes développeur et vous voulez devenir CTO ?\\n\\nAprès le succès de nos dernières éditions, nous posons nos valises au Hub BPI France, avec des CTO de renommée !\\n\\n*   Le CTO de LesFurets.com, Dimitri Baeli\\n\\n*   Le CTO de Vestiaire Collective, Alexandre Cognard\\n\\n*   Le CTO d''AzurGate (Se coucher moins bête), Boris Guéry\\n\\n*   Le CTO de JobTeaser, Romain Champourlier\\n\\nNous découvrirons leurs parcours, leurs quotidiens de CTO, discuterons de data science, de dette technique, et de quelle attitude adopter avec les non techs.\\n\\n**La conférence, se terminera par un cocktail networking afin de poursuivre les échanges entre participants (startupers, développeurs...) et intervenants.**\\n\\nProgramme :\\n\\n*   19h00 : Accueil\\n\\n*   19h15 : Table ronde / La parole aux CTOs\\n\\n*   20h00 : Questions & Réponses avec le public\\n\\n*   20h45 : Cocktail\\n\\nEntrée : 15 euros (Cocktail)\\n\\nLieu : Hub BPI France : 8 boulevard Haussmann, 75009 Paris\\n\\nTwitter : @seednetworking\\n\\n***** Attention ***** **Billetterie obligatoire ici : [https://www.weezevent.com/comment-seduire-un-cto-4](https://www.weezevent.com/comment-seduire-un-cto-4)**\\n\\nPour toute question : romain@warren-walter.com"}', '{"fr":",     cto,    développeur,   startup,  seednetworking, networking"}', NULL, '{"filename":"event_comment-seduire-un-cto-4_669562.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_comment-seduire-un-cto-4_669562.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_comment-seduire-un-cto-4_669562.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-26T17:00:00.000Z","end":"2016-10-26T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":99}', '["https://www.weezevent.com/comment-seduire-un-cto-4"]', '2016-11-04 09:18:37', '2016-11-04 09:18:37', NULL ),
