(147207, 60188878, 46479321, NULL, 79541680, 'commission-oid-modernisation-des-usages-quel-impact-sur-la-gestion-durable-des-espaces', '{"fr":"Commission OID - Modernisation des usages : quel impact sur la gestion durable des espaces ?"}', '{"fr":"Commission en partenariat avec Steam''O organisée à NUMA"}', '{}', '{}', NULL, '{"filename":"event_commission-oid-modernisation-des-usages-quel-impact-sur-la-gestion-durable-des-espaces_148956.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_commission-oid-modernisation-des-usages-quel-impact-sur-la-gestion-durable-des-espaces_148956.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_commission-oid-modernisation-des-usages-quel-impact-sur-la-gestion-durable-des-espaces_148956.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-14T18:00:00.000Z","end":"2016-11-14T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":3,"max":99}', '[]', '2016-11-04 09:18:47', '2016-11-04 09:18:47', NULL ),
(146063, 41289188, 74150368, NULL, 89573040, 'concert-cite-ana-carla-maza', '{"fr":"Concert-Cité / Ana Carla Maza"}', '{"fr":"Auditorium de la Cité internationale des arts, entrée libre, dans la limite des places disponibles"}', '{"fr":"Les « Concerts Cité » offrent la possibilité aux musiciens en cours de résidence à la Cité internationale des arts de présenter en public un court programme. Classique, contemporaine, jazz, électronique ou encore folk, ces soirées reflètent la diversité des artistes accueillis.\\n\\n▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\n D’emblée, **Ana Carla Maza**, la fille du célèbre pianiste chilien Carlos Maza, est rayonnante : maturité interprétative, profondeur intellectuelle et charisme. Seule en scène, elle fait corps avec le violoncelle dont elle explore les sonorités avec virtuosité. Sensuelle, la musicienne déploie une gamme de couleurs et de sensations, alternant tendresse et explosion. Dans le difficile exercice du concert solo, la toute jeune artiste impose son énergie naturelle.\\n\\n« Je vous invite à un voyage imaginaire en Amérique du Sud ». De la bossa nova brésilienne à la habanera cubaine, sa voix habitée et maîtrisée à la fois, fait merveille. Elle ose quelques chansons en français dont une interprétation d’une justesse infinie de « La javanaise » de Gainsbourg. Frissons garantis… Le violoncelle acoustique ou électrique et un Rhoder sont ses compagnons de scène : mélodique et rythmique, ils soulignent à la perfection sa voix où le chant prend toute sa puissance.\\n\\n ▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\nAuditorium de la Cité internationale des arts\\n\\nRetrouvez le détail des programmes sur : bit.ly/progciaRejoignez la page Facebook et le Twitter de la Cité internationale des arts et suivez notre actualité."}', '{}', NULL, '{"filename":"event_concert-cite-ana-carla-maza_499179.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concert-cite-ana-carla-maza_499179.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concert-cite-ana-carla-maza_499179.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-17T17:30:00.000Z","end":"2016-10-17T18:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '[]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(146065, 46042254, 74150368, NULL, 89573040, 'concert-cite-angela-legasa-peter-vukmirovik-stevens', '{"fr":"Concert-Cité / Angela Legasa & Peter Vukmirovik Stevens"}', '{"fr":"Auditorium de la Cité internationale des arts, entrée libre, dans la limite des places disponibles"}', '{"fr":"Les « Concerts Cité » offrent la possibilité aux musiciens en cours de résidence à la Cité internationale des arts de présenter en public un court programme. Classique, contemporaine, jazz, électronique ou encore folk, ces soirées reflètent la diversité des artistes accueillis.\\n\\n▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\n**1ère partie : Angèle Legasa**\\n\\nAngèle Legasa, résidente à la Cité internationale des arts, a formé il y a un an le trio Sōra avec Pauline Chenais au piano et Magdalena Geka au violon. Le trio a été récemment lauréat de l''académie Maurice Ravel ainsi que du concours « Musique au centre ». Admis à la Chapelle Musicale Reine Elisabeth en Belgique dans la classe du Quatuor Artemis, le trio Sōra est également entré au Conservatoire National Supérieur de Musique de Paris dans la classe de Claire Désert. Leur prix au concours « Musique au centre » leur a permis d''enregistrer leur premier CD qui sortira en novembre 2016\\\\. Après avoir été invité à l''émission « Génération Jeunes interprètes » de la radio France Musique, le trio s''est produit cet été en Lettonie, en Belgique mais également dans les festivals prestigieux comme celui de La Roque d''Anthéron ou le Kuhmo Chamber Music en Finlande.\\n\\n**Programme :**\\n\\n*   Mauricio Kagel, Trio n.2 \\"in einem Satz\\" (2001-2002)\\n*   Joseph Haydn, Trio Hob.XV:27 en Ut Majeur (1793-1795) Allegro / Andante / Finale. Presto \\n\\n**2ème partie : Peter Vukmirovic Stevens **\\n\\nPeter Vukmirovic Stevens est un compositeur, pianiste et artiste multimédia dont la musique et l''art sont guidés par ses voyages et sa vision des aspirations humaines. Ses premières influences musicales lui viennent de l’église orthodoxe serbe où il a chanté pendant les services religieux. Pour ce concert, Peter Vukmirovic Stevens joue une série de courts morceaux pour piano écrits entre 2006 et 2016\\\\. A travers ses compositions, il met en avant la complexité de l’écriture d’œuvres musicales. Dans chacun de ses morceaux, il cherche à capturer et à transmettre l’essence universelle de l’homme.\\n\\n**Programme :**\\n\\n*   Liminal Shift : PVS, 2016, 6 minutes\\n*   Corvus Meridian : PVS, 2011, 2 minutes\\n*   Prelude No. 2 : PVS, 2006 3 minutes\\n*   Demonland : PVS 2011 3 minutes\\n*   Sanctorale : PVS 2006 5 minutes\\n*   In Perpetuum : PVS 2006 2 minutes\\n\\n▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\nAuditorium de la Cité internationale des arts\\n\\nRetrouvez le détail des programmes sur : bit.ly/progcia\\n\\nRejoignez la page Facebook et le Twitter de la Cité internationale des arts et suivez notre actualité."}', '{}', NULL, '{"filename":"event_concert-cite-angela-legasa-peter-vukmirovik-stevens_602710.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concert-cite-angela-legasa-peter-vukmirovik-stevens_602710.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concert-cite-angela-legasa-peter-vukmirovik-stevens_602710.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-24T17:30:00.000Z","end":"2016-10-24T19:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '[]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(146066, 29825345, 74150368, NULL, 89573040, 'concert-cite-angela-legasa-peter-vukmirovik-stevens_232', '{"fr":"Concert-Cité / Angela Legasa & Peter Vukmirovik Stevens"}', '{"fr":"Auditorium de la Cité internationale des arts, entrée libre, dans la limite des places disponibles"}', '{"fr":"Les « Concerts Cité » offrent la possibilité aux musiciens en cours de résidence à la Cité internationale des arts de présenter en public un court programme. Classique, contemporaine, jazz, électronique ou encore folk, ces soirées reflètent la diversité des artistes accueillis.\\n\\n▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\n**1ère partie : Angèle Legasa**\\n\\nAngèle Legasa, résidente à la Cité internationale des arts, a formé il y a un an le trio Sōra avec Pauline Chenais au piano et Magdalena Geka au violon. Le trio a été récemment lauréat de l''académie Maurice Ravel ainsi que du concours « Musique au centre ». Admis à la Chapelle Musicale Reine Elisabeth en Belgique dans la classe du Quatuor Artemis, le trio Sōra est également entré au Conservatoire National Supérieur de Musique de Paris dans la classe de Claire Désert. Leur prix au concours « Musique au centre » leur a permis d''enregistrer leur premier CD qui sortira en novembre 2016\\\\. Après avoir été invité à l''émission « Génération Jeunes interprètes » de la radio France Musique, le trio s''est produit cet été en Lettonie, en Belgique mais également dans les festivals prestigieux comme celui de La Roque d''Anthéron ou le Kuhmo Chamber Music en Finlande.\\n\\n**Programme :**\\n\\n*   Mauricio Kagel, Trio n.2 \\"in einem Satz\\" (2001-2002)\\n*   Joseph Haydn, Trio Hob.XV:27 en Ut Majeur (1793-1795) Allegro / Andante / Finale. Presto \\n\\n**2ème partie : Peter Vukmirovic Stevens **\\n\\nPeter Vukmirovic Stevens est un compositeur, pianiste et artiste multimédia dont la musique et l''art sont guidés par ses voyages et sa vision des aspirations humaines. Ses premières influences musicales lui viennent de l’église orthodoxe serbe où il a chanté pendant les services religieux. Pour ce concert, Peter Vukmirovic Stevens joue une série de courts morceaux pour piano écrits entre 2006 et 2016\\\\. A travers ses compositions, il met en avant la complexité de l’écriture d’œuvres musicales. Dans chacun de ses morceaux, il cherche à capturer et à transmettre l’essence universelle de l’homme.\\n\\n**Programme :**\\n\\n*   Liminal Shift : PVS, 2016, 6 minutes\\n*   Corvus Meridian : PVS, 2011, 2 minutes\\n*   Prelude No. 2 : PVS, 2006 3 minutes\\n*   Demonland : PVS 2011 3 minutes\\n*   Sanctorale : PVS 2006 5 minutes\\n*   In Perpetuum : PVS 2006 2 minutes\\n\\n▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\nAuditorium de la Cité internationale des arts\\n\\nRetrouvez le détail des programmes sur : bit.ly/progcia\\n\\nRejoignez la page Facebook et le Twitter de la Cité internationale des arts et suivez notre actualité."}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-24T17:30:00.000Z","end":"2016-10-24T19:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '[]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(146062, 22253261, 74150368, NULL, 89573040, 'concert-cite-ayane-kawamura', '{"fr":"Concert-Cité / Ayane Kawamura"}', '{"fr":"Auditorium de la Cité internationale des arts, entrée libre, dans la limite des places disponibles"}', '{"fr":"Les « Concerts Cité » offrent la possibilité aux musiciens en cours de résidence à la Cité internationale des arts de présenter en public un court programme. Classique, contemporaine, jazz, électronique ou encore folk, ces soirées reflètent la diversité des artistes accueillis.\\n\\n▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\n**Ayane Kawamura** est née en 1996 à Yokohama au Japon où elle a commencé le violon à l’âge de 4 ans. Elle ensuite étudié à l’école de Musique de Toho à Tokyo avec M.Tsugio TokunagaEn 2015, elle a commencé à étudier au Conservatoire National Supérieur de Musique de Paris dans la classe de M.Ami Flammer et M.Frédéric Laroque.Elle a été lauréate de plusieurs prix au Japon et a brillamment réussi l’audition de l’Association Internationale d’Art de Tokyo. Elle a été sélectionnée à l’académie de l’Orchestre de Paris pour l’année 2016-2017 et elle interprétera un concert de musique de chambre à la Philharmonie de Paris en avril prochain.\\n\\n**Programme : **\\n\\n*   J.S Bach, Sonate n.1 Adagio et Fugue\\n*   Paganini, Caprice n.10\\n*   Éric Tanguy, Sonate brève\\n*   Sibelius, Concerto pour violon, 2ème et 3ème mouvement\\n*   Beethoven, Sonate pour violon et piano n.8\\n*   Debussy, Sonate pour violon et piano\\n*   Waxman, Carmen Fantasie\\n\\n▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬▬\\n\\nAuditorium de la Cité internationale des arts\\n\\nRetrouvez le détail des programmes sur : bit.ly/progciaRejoignez la page Facebook et le Twitter de la Cité internationale des arts et suivez notre actualité."}', '{}', NULL, '{"filename":"event_concert-cite-ayane-kawamura_696676.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concert-cite-ayane-kawamura_696676.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concert-cite-ayane-kawamura_696676.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-03T17:30:00.000Z","end":"2016-10-03T18:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '[]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
(145915, 22154807, 35786151, NULL, 4135652, 'concert-de-chocolate-genius-inc-les-tombees-de-la-nuit', '{"fr":"[Boucle magnétique] Concert de Chocolate Genius Inc / Les Tombées de la nuit"}', '{"fr":"Concert de blues Les Tombées de la nuit / boucle magnétique disponible"}', '{"fr":"L’américain Mark Anthony Thompson, alias Chocolate Génius inc., n’appartient pas au commun des songwriters. Depuis près de 25 ans, son parcours de guitariste et chanteur alterne coups d’éclat et périodes d’éclipse. Sa musique est subtilement universelle, en équilibre entre aventure sonore et écriture traditionnelle, une exploration des tréfonds de l’âme humaine qui croise les multiples composantes de l’identité américaine : on y retrouve la rage sèche du blues ancestral comme la jubilation frondeuse du jazz de Manhattan, l’énergie brute de l’indie-rock comme les feulements sensuels de la soul.\\n\\nEt c’est sur scène que Chocolate Génius inc. atteint la point culminant de son expression dans un souffle intime qui nous révèle la si  peu banale beauté de sa musique.\\n\\nChocolate Genius inc. sera accompagné du guitariste français Sébastien Martel ( -M-, Camille, Morcheeba…)"}', '{"fr":", concert blues / chocolate genius / opéra / 23 octobre / Tombées de la nuit"}', NULL, '{"filename":"event_concert-de-chocolate-genius-inc-les-tombees-de-la-nuit_961289.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concert-de-chocolate-genius-inc-les-tombees-de-la-nuit_961289.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concert-de-chocolate-genius-inc-les-tombees-de-la-nuit_961289.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-23T15:00:00.000Z","end":"2016-10-23T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["http://www.digitick.com/chocolate-genius-inc-concert-opera-rennes-23-octobre-2016-css4-digitick-pg101-ri4148813.html","http://lestombeesdelanuit.com/2016/chocolate-genius/"]', '2016-11-04 09:19:55', '2016-11-04 09:19:55', NULL ),
(146679, 41766401, 89493169, NULL, 98555116, 'concert-de-cloture-du-festival-des-heures-concert-des-complies', '{"fr":"Concert de Clôture du Festival des Heures; concert des Complies"}', '{"fr":"5° concert de la journée avec Vivaldi et son contemporain Hasse, interprétés par la violonvelliste Ophélie Gailard et son ensemble Pulcinella, et la Maîtrise de Radio France dirigée par Sofi Jeannin"}', '{"fr":"Hasse avec son adagio pour cordes et son Miserere, Vivaldi avec son concerto pour violoncelle et son Magnificat; une violoncelliste acclamée sur toutes les scènes, une maîtrise qui nous fera redécouvrir le Magnificat de Vivaldi à voix égales, tel que voulu par le compositeur."}', '{"fr":"Ophélie Gaillard, Sofi Jeannin, Radio France, Vivaldi, Pulcinella, Magnificat"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-19T19:30:00.000Z","end":"2016-11-19T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '["http://www.collegedesbernardins.fr"]', '2016-11-04 09:19:16', '2016-11-04 09:19:16', NULL ),
(146720, 47334142, 12879668, 96744614, 25211090, 'concert-de-jazz-a-toulon', '{"fr":"Concert de Jazz à Toulon !"}', '{"fr":"Avec le quintet de jazz de la Musique des Equipages de la Flotte"}', '{"fr":"C''est le Quintet de Jazz qui ouvrira la saison des concerts de la Musique des Equipages de la Flotte au Musée de la Marine de Toulon sur le thème de: \\"La Musique en noir et blanc\\" . Entrée : 4€50 sans réservation Renseignements au 04 22 42 02 01"}', '{"fr":"Musique des Equipages de la Flotte, Jazz, Concert, Toulon"}', NULL, '{"filename":"event_concert-de-jazz-a-toulon_881586.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concert-de-jazz-a-toulon_881586.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concert-de-jazz-a-toulon_881586.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-11T13:00:00.000Z","end":"2016-10-11T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":18}', '[]', '2016-11-04 09:19:14', '2016-11-04 09:19:14', '2016-11-07 09:14:32' );
