(146297, 48321027, 62902442, NULL, 28944832, 'concert-gennevilliers', '{"fr":"Concert Gennevilliers"}', '{"fr":"L''Ensemble Aleph interprète les pièces des étudiants lauréats de la SACEM de l''atelier de composition animé par José Manuel López López ainsi que des oeuvres du répertoire du 20ème siècle."}', '{"fr":"L''Ensemble Aleph interprète les pièces des étudiants lauréats de la SACEM de l''atelier de composition animé par José Manuel López López, mettant en regard des oeuvres du répertoire du 20ème siècle avec des créations de la génération des compositeurs d''aujourd''hui.\\n\\n**PROGRAMME:**\\n\\n**José Manuel López López**\\n\\n_Materia Oscura_ (2013)\\n\\nClarinette basse, deux violons, alto, violoncelle, contrebasse, piano\\n\\n**Bernd Alois Zimmermann**\\n\\n_Musiques pour les soupers du Roi Ubu_ (1962-1966)\\n\\nBallet noir en sept parties et une entrée\\n\\nVersion réalisée par **Dominique Clément**\\n\\nTrompette (cornet), clarinette (en si b, basse et contrebasse), violon, violoncelle, piano, percussion et acteur à bicyclette.\\n\\n**Christian Winther Christensen** (1977)\\n\\n_String Trio_ (2008-2009)\\n\\nViolon, alto, violoncelle\\n\\n**Aurel Stroe** (1932-2008)\\n\\n_Mozart Sound Introspection_ (1994)\\n\\nViolon, alto, violoncelle \\n\\n**Bastien David**\\n\\n_D''une Rayure_ (2016) Aide à l’écriture d’une œuvre musicale originale du Ministère de la Culture et de la Communication\\n\\nFlûte, clarinette, violon, alto, violoncelle, accordéon, piano, célesta, percussion\\n\\nLES LAURÉATS DE LA BOURSE SACEM :\\n\\n**Alvaro Oviedo**\\n\\n_La face à la bouche perdue_ (2016)\\n\\nClarinette, violon, alto, violoncelle et piano\\n\\n**Clota Villegas Carusso**\\n\\n_Küme newen-Fuerza nueva_ (2016)\\n\\nClarinette, violon, alto, violoncelle, piano"}', '{"fr":",       concert,       conservatoire ,     gennevilliers ,    musique contemporaine,   ensemble aleph,  sacem,  13 octobre"}', NULL, '{"filename":"event_concert-gennevilliers_582821.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concert-gennevilliers_582821.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concert-gennevilliers_582821.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T18:00:00.000Z","end":"2016-10-13T19:00:00.000Z"},{"begin":"2016-10-13T19:00:00.000Z","end":"2016-10-13T20:00:00.000Z"},{"begin":"2016-10-13T20:00:00.000Z","end":"2016-10-13T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["http://www.ensemblealeph.com"]', '2016-11-04 09:19:37', '2016-11-04 09:19:37', NULL ),
(147617, 31937842, 23159228, NULL, 89100326, 'concert-musique-danse-africaine-ssi', '{"fr":"Concert Musique Danse Africaine - SSI"}', '{"fr":"Concert du groupe \\"Adama Burkina\\""}', '{"fr":"Dans le cadre de la Semaine de la Solidarité Internationale, le Vendredi 18 novembre à 20h est organisé par l''association Peuples Solidaires d''Avignon, un concert de musique Burkinabée. Cela aura lieu au Théâtre de l''Etincelle (14 rue des Etudes, Avignon). C''est un concert du groupe \\"Adama Burkina\\" composé de 4 musiciens percussionnistes qui invitent à la danse, suivi d''une petite restauration. Tarif: 10 euros Réduit/Etudiant: 5 euros."}', '{}', NULL, '{"filename":"event_concert-musique-danse-africaine-ssi_717948.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concert-musique-danse-africaine-ssi_717948.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concert-musique-danse-africaine-ssi_717948.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-18T19:00:00.000Z","end":"2016-11-18T22:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":false,"vi":false,"sl":true}', '{"min":null,"max":null}', '[]', '2016-11-04 09:18:22', '2016-11-04 09:18:22', NULL ),
