(146093, 88896229, 75041546, NULL, 50345832, 'concours-archicote-2016-remise-des-trophees', '{"fr":"Concours ArchiCOTE 2016 / Remise des trophées"}', '{"fr":"La 4° édition du Concours d''Architecture Contemporaine ArchiCOTE crée par le SACA et COTE Magazine, dévoilera son palmarès 2016 le 13 octobre 2016 à la Villa Arson."}', '{"fr":"Le concours d''architecture contemporaine ArchiCOTE est né de la collaboration entre le Syndicat des Architectes de la Côte d''Azur et COTE Magazine. Destiné à distinguer les projets azuréens les plus remarquables, tous les architectes désireux de promouvoir un projet qui leur tient à cœur sont invités à y participer.\\n\\nEntre 30 et 40 projets concourent chaque année, un prix est décerné dans chaque catégorie.\\n\\nLa première édition a eu lieu en 2013\\\\. La quatrième édition viendra primer ses lauréats le 13 octobre 2016 lors d’une soirée à la Villa Arson.\\n\\nLe jury de ce concours est pluridisciplinaire et majoritairement composé d’architectes. Il analyse chaque dossier selon des critères très précis. En premier lieu, vérifier que la proposition était bien contemporaine et son rendu conforme au dossier de candidature. Dans un second temps, mesurer l’audace du projet, les exigences qualitatives que s’est donné l’architecte, l’intégration du projet dans le proche environnement, la qualité du rendu et du panneau de présentation.\\n\\nLes trophées décernés sont une création de l''artiste David Zeller (ZED) intitulés \\"Un toit sur la tête\\". Artiste comportementaliste, Zed illustre toutes les attitudes humaines avec son Flexo. Un personnage dont il a créé un exemplaire spécial pour les lauréats du concours ArchiCOTE."}', '{"fr":",    architecture,    concours,  prix, alpes maritimes"}', NULL, '{"filename":"event_concours-archicote-2016-remise-des-trophees_124951.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concours-archicote-2016-remise-des-trophees_124951.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concours-archicote-2016-remise-des-trophees_124951.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T17:30:00.000Z","end":"2016-10-13T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":3,"max":6}', '["lesaca@free.fr"]', '2016-11-04 09:19:46', '2016-11-04 09:19:46', NULL ),
(147428, 73252869, 76770532, 1083913, 19544859, 'concours-d-automne-2016-terrain-de-franchevaux-a-satigny-ch', '{"fr":"Concours d''Automne 2016, Terrain de Franchevaux à Satigny (CH)"}', '{"fr":"organisé par la Société d''Attelage de Genève et environs"}', '{"fr":"Toutes les dates de l’Agenda EspriTraiT sur\\n\\n[http://www.espritrait.com/agenda.html](http://www.espritrait.com/agenda.html)"}', '{}', NULL, '{"filename":"event_concours-d-automne-2016-terrain-de-franchevaux-a-satigny-ch_452449.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concours-d-automne-2016-terrain-de-franchevaux-a-satigny-ch_452449.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concours-d-automne-2016-terrain-de-franchevaux-a-satigny-ch_452449.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-23T06:00:00.000Z","end":"2016-10-23T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":10,"max":80}', '["http://www.attelage-sage.com"]', '2016-11-04 09:18:34', '2016-11-04 09:18:34', NULL ),
(147498, 70647292, 37155165, NULL, 79189916, 'concours-de-l-etudiant-entrepreneur-innovant-2016', '{"fr":"Concours de l''Etudiant Entrepreneur Innovant 2016"}', '{"fr":"Etre étudiant et créer sa start-up innovante, c''est possible !"}', '{"fr":"SEMIA, l’incubateur d’entreprises innovantes d’Alsace, organise pour la 4e année consécutive, dans le cadre d’ETENA PEPITE (Pôle de l’Entreprenariat Etudiant) un concours dont l’objectif est de soutenir des étudiants entreprenants, qui s’impliquent dans la création d’entreprises à contenu innovant en Alsace.\\n\\nQui peut concourir ?  \\nCe concours, en partenariat avec la Société Générale, est ouvert à tous les étudiants et jeunes diplômés de moins de 30 ans souhaitant créer une entreprise innovante en Alsace.\\n\\nL’innovation, c’est quoi ?  \\nPar innovation, il faut comprendre toute idée créative ou invention ayant identifié son marché.\\n\\nQue peuvent gagner les étudiants entrepreneurs ?  \\nLe concours est doté des prix suivants pour 3 lauréats :  \\n- un financement d’un montant maximum de 10 000 €  \\n- un accompagnement personnalisé par SEMIA, l’incubateur d’entreprises innovantes en Alsace durant une période de 12 mois  \\n- un accès à des locaux de co-workingdes invitations à des programmes de formation liés à l’entreprenariat."}', '{"fr":"innovation, start-up, étudiant entrepreneur, concours"}', NULL, '{"filename":"event_concours-de-l-etudiant-entrepreneur-innovant-2016_731979.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concours-de-l-etudiant-entrepreneur-innovant-2016_731979.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concours-de-l-etudiant-entrepreneur-innovant-2016_731979.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-26T23:00:00.000Z","end":"2016-11-26T23:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":14,"max":30}', '["http://www.semia-incal.com/index.php/actualites/42-news/259-concours-de-l-etudiant-entrepreneur-innovant"]', '2016-11-04 09:18:30', '2016-11-04 09:18:30', NULL ),
(145875, 84462702, 42372231, NULL, 24199260, 'concours-de-maquettes', '{"fr":"Concours de maquettes sur le thème \\"Matières en Rêves\\""}', '{"fr":"Architectures D''Automne - 07 et 08 octobre 2016 à Porto Vecchio. MAISON DE L''ARCHITECTURE DE CORSE en partenariat avec la D° REG. DES AFFAIRES CULTURELLES DE CORSE"}', '{"fr":"La Maison de l''Architecture de Corse se positionne à la croisée entre le public, le monde professionnel, les institutions et les collectivités.\\n\\nElle intervient auprès du grand public afin de diffuser la culture architecturale, promouvoir une architecture contemporaine et patrimoniale comprise par tous.\\n\\n Une des missions de la Maison de l''Architecture de Corse est de « transmettre » l’architecture par la sensibilisation de jeunes publics.\\n\\nDonner les clés pour regarder et comprendre son environnement, c’est fournir à tout citoyen, dès le plus jeune âge, les outils nécessaires pour qu’il devienne acteur et responsable de son cadre de vie.\\n\\nDans cette optique de pédagogie, la Maison de l''Architecture de Corse a lancé lors de la 1ère Édition des Architectures D’Automne (2015) à Porto Vecchio un concours de maquettes à destination de classes du primaire et du collège.\\n\\nTout au long de l’année scolaire, des architectes de la Maison d l''Architecture de Corse, soutenus par les équipes pédagogiques et les intervenants du Centre Culturel de la ville, ont animé des ateliers sur le thème « Matières en Rêves ».\\n\\nDe façon ludique, à travers la réalisation de ces maquettes, une réflexion sur quelques principes fondateurs tels que l’alliance de la technique et de la connaissance a permis la transmission empirique de notions fondamentales de l’architecture aux enfants.\\n\\nLe résultat de ce travail sera le point de départ de l’Édition 2016 des Architectures d''Automne.\\n\\nLes maquettes réalisées seront présentées par les enfants devant un jury et exposées au Centre Culturel de Porto Vecchio à partir du vendredi matin.\\n\\nCette 2e édition des Architectures d’Automne aura lieu les 07 et 08 octobre 2016 à Porto Vecchio."}', '{"fr":",     architecture,    enfants,   maquettes,  porto vecchio, Architectures D''Automne"}', NULL, '{"filename":"event_concours-de-maquettes_737105.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concours-de-maquettes_737105.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concours-de-maquettes_737105.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T05:00:00.000Z","end":"2016-10-16T06:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["maisonarchitecturecorse@gmail.com","0771730303"]', '2016-11-04 09:19:57', '2016-11-04 09:19:57', NULL ),
(147302, 75846156, 3152302, 90014930, 65468986, 'concours-de-maquettes-sur-le-theme-matieres-en-reves', '{"fr":"Concours de maquettes sur le thème \\"Matières en Rêves\\""}', '{"fr":"Architectures D''Automne - 07 et 08 octobre 2016 à Porto Vecchio. MAISON DE L''ARCHITECTURE DE CORSE en partenariat avec la D° REG. DES AFFAIRES CULTURELLES DE CORSE"}', '{"fr":"La Maison de l''Architecture de Corse se positionne à la croisée entre le public, le monde professionnel, les institutions et les collectivités.\\n\\nElle intervient auprès du grand public afin de diffuser la culture architecturale, promouvoir une architecture contemporaine et patrimoniale comprise par tous.\\n\\nUne des missions de la Maison de l''Architecture de Corse est de « transmettre » l’architecture par la sensibilisation de jeunes publics.\\n\\nDonner les clés pour regarder et comprendre son environnement, c’est fournir à tout citoyen, dès le plus jeune âge, les outils nécessaires pour qu’il devienne acteur et responsable de son cadre de vie.\\n\\nDans cette optique de pédagogie, la Maison de l''Architecture de Corse a lancé lors de la 1ère Édition des Architectures D’Automne (2015) à Porto Vecchio un concours de maquettes à destination de classes du primaire et du collège.\\n\\nTout au long de l’année scolaire, des architectes de la Maison d l''Architecture de Corse, soutenus par les équipes pédagogiques et les intervenants du Centre Culturel de la ville, ont animé des ateliers sur le thème « Matières en Rêves ».\\n\\nDe façon ludique, à travers la réalisation de ces maquettes, une réflexion sur quelques principes fondateurs tels que l’alliance de la technique et de la connaissance a permis la transmission empirique de notions fondamentales de l’architecture aux enfants.\\n\\nLe résultat de ce travail sera le point de départ de l’Édition 2016 des Architectures d''Automne.\\n\\nLes maquettes réalisées seront présentées par les enfants devant un jury et exposées au Centre Culturel de Porto Vecchio à partir du vendredi matin.\\n\\nCette 2e édition des Architectures d’Automne aura lieu les 07 et 08 octobre 2016 à Porto Vecchio."}', '{"fr":",     architecture,    enfants,   maquettes,  porto vecchio, architectures d''automme"}', NULL, '{"filename":"event_concours-de-maquettes-sur-le-theme-matieres-en-reves_455723.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concours-de-maquettes-sur-le-theme-matieres-en-reves_455723.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concours-de-maquettes-sur-le-theme-matieres-en-reves_455723.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T07:00:00.000Z","end":"2016-10-15T17:00:00.000Z"},{"begin":"2016-10-07T07:00:00.000Z","end":"2016-10-07T17:00:00.000Z"},{"begin":"2016-10-14T07:00:00.000Z","end":"2016-10-14T17:00:00.000Z"},{"begin":"2016-10-23T07:00:00.000Z","end":"2016-10-23T17:00:00.000Z"},{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T17:00:00.000Z"},{"begin":"2016-10-21T07:00:00.000Z","end":"2016-10-21T17:00:00.000Z"},{"begin":"2016-10-12T07:00:00.000Z","end":"2016-10-12T17:00:00.000Z"},{"begin":"2016-10-19T07:00:00.000Z","end":"2016-10-19T17:00:00.000Z"},{"begin":"2016-10-17T07:00:00.000Z","end":"2016-10-17T17:00:00.000Z"},{"begin":"2016-10-08T07:00:00.000Z","end":"2016-10-08T17:00:00.000Z"},{"begin":"2016-10-09T07:00:00.000Z","end":"2016-10-09T17:00:00.000Z"},{"begin":"2016-10-10T07:00:00.000Z","end":"2016-10-10T17:00:00.000Z"},{"begin":"2016-10-11T07:00:00.000Z","end":"2016-10-11T17:00:00.000Z"},{"begin":"2016-10-16T07:00:00.000Z","end":"2016-10-16T17:00:00.000Z"},{"begin":"2016-10-18T07:00:00.000Z","end":"2016-10-18T17:00:00.000Z"},{"begin":"2016-10-20T07:00:00.000Z","end":"2016-10-20T17:00:00.000Z"},{"begin":"2016-10-22T07:00:00.000Z","end":"2016-10-22T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":99}', '["maisonarchitecturecorse@gmail.com","0771730303"]', '2016-11-04 09:18:41', '2016-11-04 09:18:41', NULL ),
(145895, 31397152, 67248378, NULL, 90935859, 'concours-utopie', '{"fr":"\\"Utopie\\""}', '{"fr":"En compagnie d''architectes, venez former des équipes et proposer au spectateur votre vision utopiste de l''habitation !"}', '{"fr":"Pour ces premières Journées nationales de l''architecture, vous aurez l''occasion de concevoir votre propre vision d''un lieu idéal ! En collaboration avec des architectes, vous pourrez former des équipes afin de répondre au thème \\"utopie\\". Chacun est invité à passer le dimanche à la Direction des Affaires Culturelles de Guyane où les architectes et les participants pourront former des équipes afin de réfléchir à une proposition architecturale qui puisse répondre à leur vision utopiste de l''architecture. Vous pourrez ainsi venir former une équipe ou simplement assister au travail de conception des différentes équipes.\\n\\nDe 16h00 à 18h00 Les spectateurs deviendront ensuite les juges des différentes créations et pourront voter pour leur utopie préférée !\\n\\nPour plus de renseignements :\\n\\n*   05-94-25-54-15\\n\\nmaria.mejia-schuster@culture.gouv.fr"}', '{}', NULL, '{"filename":"event_concours-utopie_685513.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_concours-utopie_685513.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_concours-utopie_685513.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T08:00:00.000Z","end":"2016-10-16T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '[]', '2016-11-04 09:19:56', '2016-11-04 09:19:56', NULL ),
(146752, 8218750, 67195558, 27545135, 7338258, 'conference-a-puy-l-eveque', '{"fr":"Conférence à Puy L''Évêque !"}', '{"fr":"Conférence"}', '{"fr":"Le silicium et le quartz dans le Lot, ses propriétés, ses applications.\\n\\nRenseignements : 06 44 91 08 65 / cqst46@gmail.com"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-14T16:00:00.000Z","end":"2016-10-14T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:12', '2016-11-04 09:19:12', NULL ),
(146326, 39152271, 45925510, NULL, 30942434, 'conference-alexandre-chemetoff-le-monde-est-un-endroit-merveilleux', '{"fr":"Conférence : Alexandre Chemetoff \\"Le monde est un endroit merveilleux\\""}', '{"fr":"Le Plan-guide, un Plan guidant les actions : conférence sur la reconversion des friches industrielles"}', '{"fr":"**\\"Le monde est un endroit merveilleux\\"**\\n\\n**Alexandre Chemetoff** donnera le **13 octobre** à l’Université de Haute-Alsace de Mulhouse, une conférence exceptionnelle sur le thème de la conversion des friches industrielles. Il nous éclairera sur les richesses et les défis incarnés par ces environnements industriels en voie de reconversion dont la région regorge, et dont Mulhouse, riche d’un patrimoine industriel aux potentialités immenses, est l’un des plus brillant modèle."}', '{"fr":",           Conference,           Mulhouse,         Alsace,        Urbanisme,       Architecture,      Chemetoff,     Reconversion,    Developpement durable,   Paysage,   Plan d''action, Friches industrielles"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T16:30:00.000Z","end":"2016-10-13T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["inscription@ja-at.eu"]', '2016-11-04 09:19:35', '2016-11-04 09:19:35', NULL ),
(145968, 85317675, 67248378, NULL, 90935859, 'conference-architecture-xxe-siecle', '{"fr":"Conférence \\"Architecture XXe siècle\\""}', '{"fr":"Venez en apprendre plus sur les caractéristiques de l''architecture du XXe siècle grâce à la conférence donnée par un architecte du patrimoine"}', '{"fr":"Venez découvrir les caractéristiques de l''architecture moderniste du XXe grâce à une conférence donnée par un architecte du patrimoine. Cette conférence, qui complète la visite de la cité Rebard prévue de 9h00 à 10h00, sera l''occasion d''approfondir vos connaissances !\\n\\nPour plus de renseignements :\\n\\n*   05-94-25-54-15\\n*   [maria.mejia-schuster@culture.gouv.fr](http://mailto:-maria.mejia-schuster@culture.gouv.fr)"}', '{}', NULL, '{"filename":"event_conference-architecture-xxe-siecle_528219.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-architecture-xxe-siecle_528219.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-architecture-xxe-siecle_528219.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T16:00:00.000Z","end":"2016-10-16T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '[]', '2016-11-04 09:19:52', '2016-11-04 09:19:52', NULL ),
(146162, 6272078, 14963029, NULL, 38017671, 'conference-au-musee-de-la-carte-a-jouer-dans-le-cadre-de-la-fete-de-la-science', '{"fr":"Conférence au Musée dans le cadre de la Fête de la science"}', '{"fr":"Un métier à la croisée des chemins : la formation de restaurateur du patrimoine de l''Institut National du Patrimoine."}', '{"fr":"La conservation-restauration du patrimoine fait appel à des connaissances multiples alliant maîtrise technique, connaissances théoriques et esprit scientifique. Le département des restaurateurs de l''INP forme chaque année en 5 ans, un groupe d''une vingtaine d''étudiants qui se spécialisent sur neuf spécialités.\\n\\nJane Echinard, chargée de la formation initiale à l''INP vous présentera le métier et ses exigences ainsi que le déroulement de cette formation.\\n\\nSigrid Mirabaud, responsable du laboratoire de l''INP s''appuiera sur l''exemple des sciences au service du patrimoine et de sa conservation pour illustrer les multiples possibilités de partenariat existantes."}', '{"fr":",    conférence,   musée de la carte à jouer,  patrimoine, science"}', NULL, '{"filename":"event_conference-au-musee-de-la-carte-a-jouer-dans-le-cadre-de-la-fete-de-la-science_752620.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-au-musee-de-la-carte-a-jouer-dans-le-cadre-de-la-fete-de-la-science_752620.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-au-musee-de-la-carte-a-jouer-dans-le-cadre-de-la-fete-de-la-science_752620.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-20T16:30:00.000Z","end":"2016-10-20T18:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:43', '2016-11-04 09:19:43', NULL ),
(146889, 80608942, 18012221, NULL, 1743683, 'conference-berlioz-wagner-dix-ans-d-ecart-qui-definissent-le-passage-entre-l-art-francais-et-l-art-de-l-avenir', '{"fr":"Conférence : \\"Berlioz, Wagner, dix ans d''écart qui définissent le passage entre l''Art Français et l''Art de l''Avenir\\""}', '{"fr":"Cette conférence aura donc surtout pour but de scruter, d''analyser ces dix-ans là. Entre la formation purement française de Berlioz et la naissance d''un art dit « européen ».\\""}', '{"fr":"\\"Berlioz, Wagner, dix ans d''écart qui définissent le passage entre l''Art Français et l''Art de l''Avenir\\"\\n\\n\\"Berlioz a toujours été pour moi, depuis mon enfance, le modèle de l''artiste complet, cultivé, musicien mais pas uniquement, et prenant part aux combats esthétiques de son temps.\\n\\nLa Correspondance de Berlioz ne sera abordée que par des chemins de traverse. Car, en effet, depuis 1821, date officielle de l''«entrée en carrière musicale» d''Hector Berlioz jusqu''à sa fin, en 1869, on rencontre un peu tout le monde. Mais mon idée n''est pas de faire un portrait biographique, d''autres l''ont fait bien mieux que moi.\\n\\nParler de Berlioz revient aussi à tenter d''inventer une certaine forme d''histoire de l''art, ou de musicologie, ou de musicographie, en particulier sur un point qui me semble capital : Berlioz est né en 1803 et Wagner en 1813 ; or il est indéniable que ces dix ans, ces seuls dix ans suffisent à définir le passage entre ce qu''il est convenu d''appeler l''Art Français (qui remonte à Lully, Rameau et Couperin) et ce que Wagner appelait assez pompeusement « l''Art de l''Avenir ».Pour moi, Berlioz représente une contradiction, une aporie, une impasse. Noyé, bercé, nourri par toute la musique en train de naître en même temps que lui, Berlioz n''a pas, n''a jamais trouvé SA place dans ladite « Histoire de la musique ».Wagner s''y est parfaitement inscrit, de Bach à Beethoven.Cette conférence aura donc surtout pour but de scruter, d''analyser ces dix-ans là. Entre la formation purement française de Berlioz et la naissance d''un art dit « européen ».\\"  \\n\\nVincent Nordon  \\nNé en 1950 à Selongey en Côte d''Or, Vincent Nordon est réalisateur, scénariste, écrivain. Il est l''auteur d''un ouvrage paru aux Presses du réel en 2012, Straub/Huillet, non merci ? – La plainte d’un ami, et travaille actuellement sur l''élaboration d''un livre sur Berlioz et Wagner à paraître dans la même édition.  \\n\\nCette conférence sera suivie d''un échange informel avec Vincent Nordon autour d''un apéritif offert par Ricard.  \\n___  \\n\\nGratuit, sur réservation : 03 80 68 45 55 - servicedespublics@leconsortium.fr"}', '{"fr":"berlioz,  wagner,  conference, dijon"}', NULL, '{"filename":"event_conference-berlioz-wagner-dix-ans-d-ecart-qui-definissent-le-passage-entre-l-art-francais-et-l-art-de-l-avenir_23018.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-berlioz-wagner-dix-ans-d-ecart-qui-definissent-le-passage-entre-l-art-francais-et-l-art-de-l-avenir_23018.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-berlioz-wagner-dix-ans-d-ecart-qui-definissent-le-passage-entre-l-art-francais-et-l-art-de-l-avenir_23018.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-04T18:00:00.000Z","end":"2016-11-04T19:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":99}', '[]', '2016-11-04 09:19:05', '2016-11-04 09:19:05', NULL ),
(146287, 46378733, 14963029, NULL, 66333672, 'conference-comment-le-tout-petit-tisse-ses-premiers-liens-avec-l-autre', '{"fr":"Conférence : \\"Comment le tout petit tisse-t-il ses premiers liens avec l''autre ?\\""}', '{"fr":"Avec Pierre Delion, psychiatre, psychanalyste, il est professeur de pédopsychiatrie à la faculté de médecine de Lille et responsable du service psychiatrie infanto-juvénile au CHRU de Lille."}', '{"fr":"Pierre Delion est l''auteur de nombreux ouvrages dont _L''enfant autiste, le bébé et la sémiotique_ (PUF, 2005).\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"Naissance\\".** A l''occasion de la manifestation autour des droits de l''enfant en écho aux questions des parents et des futurs parents, et en collaboration avec La Cause des Bébes, l''espace Parent-Enfant a choisi d''évoquer le sujets de la naissance et de la paroles pour les tout-petits et des premiers liens.\\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,       parent,      parentalité,     enfant,    père,    mère,  parents, enfants"}', NULL, '{"filename":"event_conference-comment-le-tout-petit-tisse-ses-premiers-liens-avec-l-autre_235763.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-comment-le-tout-petit-tisse-ses-premiers-liens-avec-l-autre_235763.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-comment-le-tout-petit-tisse-ses-premiers-liens-avec-l-autre_235763.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-23T19:30:00.000Z","end":"2016-11-23T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:37', '2016-11-04 09:19:37', NULL ),
(147253, 15314839, 8074636, NULL, 46658476, 'conference-de-valerie-seguin-contacts-avec-sandra', '{"fr":"Conférence de Valérie SEGUIN - Contacts avec SANDRA"}', '{"fr":"Communication avec les défunts sans facultés médiumniques."}', '{"fr":"**SUR RESERVATION** (Il ne reste que quelques places - L''inscription via Facebook n''est pas valable)\\n\\nTous renseignements sur notre site : [http://www.lescygnes63.fr](http://www.lescygnes63.fr)\\n\\n**\\"Communication avec les défunts sans facultés médiumniques.\\"**\\n\\n**Valérie SEGUIN**, co-fondatrice de l’école du sens et auteur d’un récit enquête aux frontières de la mort vous présentera les différentes expériences aux frontières de la mort (vision des mourants, expérience de mort imminente, expérience de mort partagée, vécu subjectif de contact avec un défunt) et les études scientifiques s’y rapportant.\\n\\nElle vous présentera aussi les parallèles avec les livres des morts tibétains et chrétien. Elle insistera particulièrement sur les VSCD (Vécu Subjectif de Contact avec un Défunt) qui est une communication avec un défunt sans avoir de faculté médiumnique, ayant elle-même vécue ce phénomène suite au décès de son père.\\n\\nD’après les études, nous serions environ 25% à avoir vécu une communication avec un défunt, ces études ont répertorié différentes formes de manifestation qu’il est intéressant de connaître pour être en mesure de reconnaître ces signes. Elle exposera aussi comment accroître ses chances d''avoir un signe d’un proche décédé.\\n\\nElle vous dédicacera son livre avec plaisir :  \\n[\\"Les trois jours et demi après la mort de mon père\\"](https://www.amazon.fr/TROIS-JOURS-DEMI-APRES-MORT/dp/2352044332/ref=sr_1_1?s=books&ie=UTF8&qid=1442779903&sr=1-1&keywords=val%C3%A9rie+seguin) (Ed. Les Arènes 2015)\\n\\nLa conférence sera suivie de contacts en salle par **SANDRA**  \\nPour la joindre : 06 78 22 35 70 ou  \\n[http://www.semences-etoiles.org/nous-contacter/](http://www.semences-etoiles.org/nous-contacter/)\\n\\nHôtel Clermont-Estaing =>[\\"Plan ICI\\"](https://goo.gl/maps/rwa1uSpVPUw)"}', '{"fr":",    Spiritualité,   Conférence,  médium, médiumnité"}', NULL, '{"filename":"event_conference-de-valerie-seguin-contacts-avec-sandra_810173.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-de-valerie-seguin-contacts-avec-sandra_810173.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-de-valerie-seguin-contacts-avec-sandra_810173.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T13:00:00.000Z","end":"2016-10-16T17:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":12}', '[]', '2016-11-04 09:18:44', '2016-11-04 09:18:44', NULL ),
(145898, 29948089, 91997832, NULL, 27124991, 'conference-debat-bienveillance-plaisir-et-convivialite-dans-l-assiette-de-nos-convives-preparons-l-avenir', '{"fr":"Conférence - Débat « Bienveillance, plaisir et convivialité dans l’assiette de nos convives : préparons l’avenir »"}', '{"fr":"Conférence - Débat « Bienveillance, plaisir et convivialité dans l’assiette de nos convives : préparons l’avenir »"}', '{"fr":"Conférence - Débat « Bienveillance, plaisir et convivialité dans l’assiette de nos convives : préparons l’avenir »\\n\\nAvec :\\n\\n*   M. Saïd ACEF, Directeur délégué à l''autonomie de l''ARS\\n*   M. Alain ROQUEJOFFRE, Sociologue\\n*   M. Michel BILLE, Sociologue\\n*   M. David GIFFARD, Directeur Projets Groupe (Groupe SOS) - Organisateur Silver Fourchette\\n*   M. François BERGER, Co-fondateur de Nutri-Culture"}', '{"fr":"nutrition"}', NULL, '{"filename":"event_conference-debat-bienveillance-plaisir-et-convivialite-dans-l-assiette-de-nos-convives-preparons-l-avenir_309366.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-debat-bienveillance-plaisir-et-convivialite-dans-l-assiette-de-nos-convives-preparons-l-avenir_309366.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-debat-bienveillance-plaisir-et-convivialite-dans-l-assiette-de-nos-convives-preparons-l-avenir_309366.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-04T07:00:00.000Z","end":"2016-10-04T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":5,"max":80}', '["https://www.facebook.com/nutriculture/"]', '2016-11-04 09:19:56', '2016-11-04 09:19:56', NULL ),
(146272, 73966931, 57608264, 27545135, 19801684, 'conference-debat-sur-le-theme-des-naissances-de-la-pleine-lune', '{"fr":"Conférence-débat sur le thème des « Naissances de la pleine lune »"}', '{"fr":"Les naissances de la pleine Lune - Quelles sont les réponses de la science ?"}', '{"fr":"Les naissances de la pleine Lune : La Lune exerce sa fascination sur les peuples depuis des temps immémoriaux. Nombreux sont ceux qui pensent que le stress, l''insomnie, la criminalité ou encore les admissions aux urgences hospitalières sont soumis à l''influence de l''astre lunaire. Il en est de même pour la survenue des naissances : les nuits de pleine Lune, les hôpitaux et les cliniques seraient débordés. Quelles sont les réponses de la science ?"}', '{}', NULL, '{"filename":"event_conference-debat-sur-le-theme-des-naissances-de-la-pleine-lune_303471.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-debat-sur-le-theme-des-naissances-de-la-pleine-lune_303471.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-debat-sur-le-theme-des-naissances-de-la-pleine-lune_303471.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-12-02T17:30:00.000Z","end":"2016-12-02T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '["benoit.soyer@ird.fr"]', '2016-11-04 09:19:38', '2016-11-04 09:19:38', NULL ),
(145591, 25448264, 78508792, 19096631, 52218403, 'conference-debat_97', '{"fr":"Grandir en jouant"}', '{"fr":"Conférence de Jean EPSTEIN"}', '{"fr":"Jean EPSTEIN donnera une conférence sur le thème du développement psycho-sensoriel et moteur de l’enfant \\"GRANDIR EN JOUANT\\"."}', '{}', NULL, '{"filename":"event_conference-debat_97_385849.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-debat_97_385849.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-debat_97_385849.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-30T18:00:00.000Z","end":"2016-09-30T20:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":8}', '["multiaccueil@ville-beaugency.fr"]', '2016-11-04 09:20:08', '2016-11-04 09:20:08', NULL ),
(145913, 1264265, 55610710, 22289984, 1886305, 'conference-eclairee-de-guillaume-lecointre-transformation-evolution-classification-du-vivant', '{"fr":"Guillaume LECOINTRE : Transformation, évolution, classification du vivant"}', '{"fr":"Conférence éclairée dans le cadre du Tricentenaire de Daubenton"}', '{"fr":"**Guillaume LECOINTRE** est chercheur systématicien (science des classifications) et professeur au Muséum national d''Histoire naturelle où il dirige le département de recherche \\"systématique et évolution\\".\\n\\n**Mais savez-vous vraiment qui est Guillaume Lecointre ?**\\n\\nGuillaume Lecointre est enseignant-chercheur (UMR 7205), zoologiste, systématicien, professeur au Muséum national d’Histoire naturelle où il dirige le département de recherche « Systématique et évolution ». En 2015 il avait publié 106 publications professionnelles (indice h 34) et 16 livres. Ses recherches portent sur la phylogénie et la systématique des poissons téléostéens, tant à partir de données moléculaires qu’anatomiques. Son terrain de zoologiste est le plateau continental antarctique. Ses activités de diffusion des connaissances sont très significatives ; il a notamment tenu durant dix ans la rubrique scientifique hebdomadaire de Charlie Hebdo. Il est double Lauréat de la Société Zoologique de France (1996, 2006), Prix national 2009 du Comité Laïcité République, Prix 2012 de l’Union Rationaliste.\\n\\n**Découvrez quelques-unes de ses publications :**\\n\\n*   [L’évolution, questions d’actualité ?](http://www.quae.com/fr/r3911-l-evolution-question-d-actualite-.html) (Ed. Quae, 2014)\\n*   [Le Monde de Darwin](http://www.editionsdelamartiniere.fr/ouvrage/le-monde-de-darwin-/9782732471044) (avec P. Tort - Ed. La Martinière, 2015)\\n*   [Descendons-nous de Darwin ?](http://www.editions-lepommier.fr/ouvrage.asp?IDLivre=747) (Ed. Le Pommier, 2015)\\n*   [L’évolution : de l’Univers aux Sociétés. Concepts et Objets](http://materiologiques.com/sciences-philosophie-2275-9948/214-levolution-de-lunivers-aux-societes-objets-et-concepts-9782373610321.html) (2015, Matériologiques.com)\\n\\n### VENDREDI 14 OCTOBRE à 18H au Musée Buffon\\n\\n## Entrée libre et gratuite\\n\\n**Pour en savoir plus :**\\n\\n[Téléchargez le Dossier de presse du Tricentenaire de Daubenton](http://www.montbard.com/uploads/file/Mus%C3%A9e/Dossier_Presse_Tricentenaire_Daubenton_Mus%C3%A9e_Buffon.pdf)\\n\\n[Fête de la science](https://www.fetedelascience.fr/pid35201/fiche-evenement.html?identifiant=97081790)\\n\\n[Centre de Culture Scientifique Technique et Industrielle de Bourgogne](http://www.ccstib.fr/tricentenaire-de-daubention-musee-parc-buffon-montbard-2016/)"}', '{}', NULL, '{"filename":"event_conference-eclairee-de-guillaume-lecointre-transformation-evolution-classification-du-vivant_12467.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-eclairee-de-guillaume-lecointre-transformation-evolution-classification-du-vivant_12467.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-eclairee-de-guillaume-lecointre-transformation-evolution-classification-du-vivant_12467.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T16:00:00.000Z","end":"2016-10-14T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["musee-site-buffon@montbard.com"]', '2016-11-04 09:19:55', '2016-11-04 09:19:55', NULL ),
(146703, 15289492, 82790514, 39395859, 28409656, 'conference-entrepreneure', '{"fr":"Conférence \\"EntrepreneurE\\" !"}', '{"fr":"L''association Enactus vous invite à une conférence et un cocktail networking où une dizaine d''entrepreneures vous feront part de leurs expériences !"}', '{"fr":"Comment on dit déjà... \\"entrepreneuse\\" ou \\" entrepreneur\\" ? Non \\"EntrepreneurE\\" !\\n\\nC’est pourquoi Enactus UPEC propose la conférence « EntrepreneurE ! » pour permettre de mettre en lumière des initiatives entrepreneuriales principalement portées par des femmes.\\n\\nCette conférence c’est l’occasion de :- De faire avancer son projet de création ou de développement d’entreprise en échangeant avec les conférencières et réseaux d''accompagnement à la création, notamment au féminin ;- De profiter des conseils et retours d’expériences d’entrepreneures et d''experts ;- De développer son réseau en rencontrant d''autres entrepreneures.\\n\\nLes femmes créatrices d’entreprises - ou en passe de le devenir - se donnent donc rendez-vous au Campus Créteil de l’Université Paris-Est Créteil le 11 Octobre à 18H.\\n\\nProgramme :- 18h : Introduction par l’équipe Enactus UPEC- 18h15-19h30 : Intervention de créatrices d’entreprises- 19h30-21h : Cocktail Networking\\n\\nBien évidemment, tout le monde y est convié, que ce soit les porteurs de projets femmes ou hommes, des entrepreneurs débutants ou avertis, et des étudiants ou professionnels curieux."}', '{"fr":",     Entrepreneuriat,     entrepreneure,   région parisienne,  start-up,"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-11T16:00:00.000Z","end":"2016-10-11T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":99}', '["https://www.eventbrite.fr/e/billets-conference-entrepreneure-28368001456?aff=affiliate1","https://www.facebook.com/events/686002041564840/?ti=icl"]', '2016-11-04 09:19:15', '2016-11-04 09:19:15', NULL ),
(146298, 54707423, 14963029, NULL, 66333672, 'conference-et-de-quelles-participations-des-enfants-et-des-parents-aux-decisions-familiales', '{"fr":"Conférence : \\"Quelle participation des enfants et des parents aux décisions familiales ?\\""}', '{"fr":"Peut-on parler de démocratisation des relations éducatives au sein des familles ? Dans quelles circonstances peut-elle se déployer ?"}', '{"fr":"Comment la participation des enfants aux décisions qui les concernent influe-t-elle la vie des familles ?\\n\\nAvec Frédéric Jésu, médecin pédopsychiatre de service public, actuellement consultant et formateur pour accompagner la conception, la mise en oeuvre et l''évaluation de politiques sociales, familiales ou éducatives locales. Il est par ailleurs vice-président de l''ONG Défense des Enfants International France et co-président d''un centre social et culturel. Il est l''auteur de plusieurs ouvrages dont : _Co-éduquer, pour un développement social durable_ (Dunod, 2004), _Démocratiser les relations éducatives_, avec Jean le Gal (Chronique sociale, 2015), _Agir ensemble pour la réussite de tous les enfants_ (Edition de l''Atelier, 2016) et _Bientraitances - Mieux traiter les familles et professionnels_, avec Michel Manciaux et Marceline Gabel (Fleurus, 2000).\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"La place des parents\\".** Deux conférences qu visent à prendre le temps de mieux élaborer la place des parents dans le développement de l''enfant et à mieux saisir les modes de participation avec les enfants au sein des familles.\\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,     parent,    parentalité,   enfant,  père,  mère"}', NULL, '{"filename":"event_conference-et-de-quelles-participations-des-enfants-et-des-parents-aux-decisions-familiales_147098.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-et-de-quelles-participations-des-enfants-et-des-parents-aux-decisions-familiales_147098.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-et-de-quelles-participations-des-enfants-et-des-parents-aux-decisions-familiales_147098.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-04-25T18:30:00.000Z","end":"2017-04-25T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:37', '2016-11-04 09:19:37', NULL ),
(146346, 35257664, 80999393, NULL, 42754360, 'conference-github', '{"fr":"Conférence GITHUB"}', '{"fr":"GitHub est plus qu’un simple outil de programmation. Si vous voulez collaborer sur n’importe quoi, vous devriez l’essayer."}', '{"fr":"Pourquoi ? Parce que c’est un réseau social qui change drastiquement notre façon de travailler. Ayant démarré sous forme de plateforme collaborative pour développeurs, GitHub est désormais le plus grand espace de stockage de travaux collaboratifs dans le monde. Que vous soyez intéressé(e) pour participer à ce cerveau global ou tout simplement pour partir à la recherche de cet énorme réservoir de connaissances, vous vous devez d’y être."}', '{"fr":", GitHub"}', NULL, '{"filename":"event_conference-github_881518.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-github_881518.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-github_881518.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-10T17:00:00.000Z","end":"2016-10-10T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":10}', '["nancy@epitech.eu"]', '2016-11-04 09:19:34', '2016-11-04 09:19:34', NULL ),
(147172, 95618802, 80999393, NULL, 42754360, 'conference-github_543', '{"fr":"Conférence GITHUB"}', '{"fr":"GitHub est plus qu’un simple outil de programmation. Si vous voulez collaborer sur n’importe quoi, vous devriez l’essayer."}', '{"fr":"Pourquoi ? Parce que c’est un réseau social qui change drastiquement notre façon de travailler. Ayant démarré sous forme de plateforme collaborative pour développeurs, GitHub est désormais le plus grand espace de stockage de travaux collaboratifs dans le monde. Que vous soyez intéressé(e) pour participer à ce cerveau global ou tout simplement pour partir à la recherche de cet énorme réservoir de connaissances, vous vous devez d’y être."}', '{"fr":", GitHub"}', NULL, '{"filename":"event_conference-github_543_134200.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-github_543_134200.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-github_543_134200.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-24T16:30:00.000Z","end":"2016-10-24T18:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":5,"max":99}', '["nancy@epitech.eu"]', '2016-11-04 09:18:49', '2016-11-04 09:18:49', '2016-11-07 09:14:32' );
