(146335, 33616325, 45925510, NULL, 91772411, 'conference-jean-philippe-vassal-agence-lacaton-vassal', '{"fr":"Conférence : Jean-Philippe Vassal, Agence Lacaton & Vassal"}', '{"fr":"Conférence de Jean-Philippe Vassal auotur de la contrainte économique comme levier d''innovation"}', '{"fr":"Valeur sûre de l’architecture française, l’agence Lacaton & Vassal (Paris) est connue pour son approche pragmatique et sa volonté d’optimiser les ressources même si elles sont rares. Ainsi, dans ses projets, elle considère la contrainte économique comme un levier d’innovation. Parmi ses productions, on compte l’École d’architecture de Nantes, la Maison Latapie à Floirac ou encore la Cité manifeste à Mulhouse."}', '{"fr":"Vassal, Architecture, Architecte, Conférence, Strasbourg, Alsace, Perspective, Optimisation des ressources, Innovation, Journées de l''architecture"}', NULL, '{"filename":"event_conference-jean-philippe-vassal-agence-lacaton-vassal_177402.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-jean-philippe-vassal-agence-lacaton-vassal_177402.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-jean-philippe-vassal-agence-lacaton-vassal_177402.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T18:00:00.000Z","end":"2016-10-13T19:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":10}', '[]', '2016-11-04 09:19:35', '2016-11-04 09:19:35', NULL ),
(146279, 4076812, 14963029, 65333215, 52045061, 'conference-l-art-d-ecouter-les-bebes', '{"fr":"Conférence : \\"L''art d''écouter les bébés\\""}', '{"fr":"Conférence exceptionnelle organisée par l''Espace Icare."}', '{"fr":"Avec Catherine Dolto et Caroline Eliacheff. Catherine Dolto est médecin, haptothérapeute, présidente de l''Association Archives et documentation. Catherine Dolto enseigne l''haptonomie au Centre International de la recherche et du développement de l''haptonomie. Elle a publié de nombreux livres  pour les enfants.  \\n\\nCaroline Eliacheff est pédopsychiatre, psychanalyste, vice-présidente de La Cause pour les bébés, auteur notamment d_''A corps et à cri. Etre psychanalyste avec les tout-petits_ (Odile Jacob 1994) et _Vies privées. De l''enfant roi à l''enfant victime _(Odile Jacob 1997).\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"Naissance\\". **A l''occasion de la manifestation autour des droits de l''enfant en écho aux questions des parents et des futurs parents, et en collaboration avec La Cause des Bébes, l''espace Parent-Enfant a choisi d''évoquer le sujets de la naissance et de la paroles pour les tout-petits et des premiers liens. \\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,       parent,      parentalité,     enfant,    père,    mère,  parents, enfants"}', NULL, '{"filename":"event_conference-l-art-d-ecouter-les-bebes_836972.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-l-art-d-ecouter-les-bebes_836972.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-l-art-d-ecouter-les-bebes_836972.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-04T18:30:00.000Z","end":"2016-11-04T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:38', '2016-11-04 09:19:38', NULL ),
(146281, 35854030, 14963029, NULL, 66333672, 'conference-l-art-de-nourir-les-bebes', '{"fr":"Conférence : \\"L''art de nourir les bébés\\""}', '{"fr":"Avec Myriam Szejer, pédopsychiatre, psychanalyste. Elle est présidente de La Cause des bébés."}', '{"fr":"Myriam Szejer est l''auteure de _Ces neufs mois-là_, avec Richard Stewart (Laffont, 1994), _Des mots pour naître_ (Gallimard, 1997) et _Les femmes et les bébés d''abord_, avec Francine Dauphin (Albin Michel, 2001).\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"Naissance\\".** A l''occasion de la manifestation autour des droits de l''enfant en écho aux questions des parents et des futurs parents, et en collaboration avec La Cause des Bébes, l''espace Parent-Enfant a choisi d''évoquer le sujets de la naissance et de la paroles pour les tout-petits et des premiers liens.\\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,       parent,      parentalité,     enfant,    père,    mère,  parents,  enfants"}', NULL, '{"filename":"event_conference-l-art-de-nourir-les-bebes_919860.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-l-art-de-nourir-les-bebes_919860.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-l-art-de-nourir-les-bebes_919860.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-08T19:30:00.000Z","end":"2016-11-08T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:38', '2016-11-04 09:19:38', NULL ),
(146291, 62269238, 14963029, NULL, 66333672, 'conference-la-construction-de-l-intimite-a-l-adolescence', '{"fr":"Conférence : \\"La construction de l''intimité à l''adolescence\\""}', '{"fr":"L''intimité est le lien familier, sanctuaire qui ne se donne pas à voir spontanément mais qui en même temps s''offre à l''autre dans une intimité partagée où chacun retrouve un sentiment de complétude."}', '{"fr":"Espace paradoxal,  l''intimité se construit peu à peu sous l''influence des valeurs culturelles et sociales. L''adolescence est l''âge de cette construction sociale paradoxale dont la fonction sera de garantir sa liberté à celle/celui qui l''aura conquise. Il n''y a pas de liberté humain sans intimité. Le conférencier donnera quelques repères de cette élaboration en lien avec le processus d''adolescence et soulignera aussi les tensions particulièrement vives qui entourant cet espace intime avant de lui permettre de se déployer.\\n\\nAvec Daniel Marcelli, professeur de pédopsychiatrie, ancien chef du service de psychiatrie de l''enfant et de l''adolescent du CHU de Poitiers. Il est président de la fédération nationale des écoles des parents et des éducateurs (FNEPE). Il est aussi auteur de nombreux ouvrages dont _Le règne de la séduction : un pouvoir sans autorité_ (Albin Michel, 2012) et _Ces adolescents qui évitent de penser_, avec Nicole Catheline (Erès, 2011).\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"Naissance\\".** A l''occasion de la manifestation autour des droits de l''enfant en écho aux questions des parents et des futurs parents, et en collaboration avec La Cause des Bébes, l''espace Parent-Enfant a choisi d''évoquer le sujets de la naissance et de la paroles pour les tout-petits et des premiers liens.\\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,     parent,    parentalité,   enfant,  père,  mère"}', NULL, '{"filename":"event_conference-la-construction-de-l-intimite-a-l-adolescence_175496.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-la-construction-de-l-intimite-a-l-adolescence_175496.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-la-construction-de-l-intimite-a-l-adolescence_175496.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-01-24T19:30:00.000Z","end":"2017-01-24T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:37', '2016-11-04 09:19:37', NULL ),
(147169, 99464542, 58835827, NULL, 69874456, 'conference-lumieres-architecture', '{"fr":"Conférence \\"Lumières & Architecture\\""}', '{"fr":"Hervé Audibert, concepteur lumières, développera les principales dimensions de la lumière appliquées à l’architecture. Mécanismes créatifs, enjeux, rôles, usages,... Seront parmi les thèmes abordés."}', '{"fr":"Le 15 octobre 2016, à 14h à l’École Nationale Supérieure d''Architecture Paris-Val de Seine.\\n\\nA l’occasion des premières Journées nationales de l’architecture, lancées par le ministère de la Culture et de la Communication, Hervé Audibert – concepteur lumières – développera les principales dimensions de la lumière appliquées à l’architecture. Mécanismes créatifs, enjeux, rôles, usages, sources… Seront parmi les thèmes abordés.\\n\\nDurant son intervention, il partagera aussi des clés pratiques à propos du langage de la lumière ou encore l’appropriation des espaces.\\n\\n3-15 Quai Panhard et Levassor, 75013 Paris.\\n\\nProgramme complet des Journées national de l’architecture à l’ENSA Paris-Val de Seine, [ici](https://openagenda.com/jnarchi?oaq%5Bpassed%5D=1&oaq%5Borg%5D=ensa-paris-val-de-seine&oaq%5BorgLabel%5D=ENSA Paris-Val de Seine).\\n\\nA propos de l’atelier H. Audibert : [www.atelierherveaudibert.com](http://www.atelierherveaudibert.com)\\n\\n#jnarchi16"}', '{"fr":",  Conception Lumière , architecture"}', NULL, '{"filename":"event_conference-lumieres-architecture_295134.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-lumieres-architecture_295134.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-lumieres-architecture_295134.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T13:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":5,"max":99}', '[]', '2016-11-04 09:18:49', '2016-11-04 09:18:49', NULL ),
(146332, 57144708, 45925510, NULL, 93129105, 'conference-marie-kardasz-attica-urbanisme-et-paysage', '{"fr":"Conférence : Marie Kardasz - ATTICA, urbanisme et paysage"}', '{"fr":"Durant une semaine, chaque soir, une architecte diplômée de l’INSA vient présenter son travail. La succession des cinq conférences offre une mise en perspective de la pratique architecturale."}', '{}', '{}', NULL, '{"filename":"event_conference-marie-kardasz-attica-urbanisme-et-paysage_419802.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-marie-kardasz-attica-urbanisme-et-paysage_419802.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-marie-kardasz-attica-urbanisme-et-paysage_419802.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T17:30:00.000Z","end":"2016-10-13T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":9,"max":99}', '[]', '2016-11-04 09:19:35', '2016-11-04 09:19:35', NULL ),
(146265, 94502692, 14963029, NULL, 66333672, 'conference-metamorphose-de-la-parentalite', '{"fr":"Conférence : \\"Métamorphose de la parentalité\\""}', '{"fr":"Moins de mariages, augmentation des divorces, recomposition des familles, maintien du lien de filiation, mariage pour tous, vers quoi nous mènent les bouleversements en cours au sein de la famille ?"}', '{"fr":"Qu''annoncent les mutations en cours ? Autant de sujets qui seront partagés avec les participants de cette conférence.\\n\\nAvec Maurice Godelier, ancien directeur scientifique du département des sciences de l''homme et de la société au CNRS, dont il est médaillé d''or. Maurice Godelier est directeur d''études à l''EHESS. Ses derniers livres sont autant de classiques : La Production des grands hommes (Fayard, 1982) _L’Énigme du don_ (Fayard, 1996) _Métamorphoses de la parenté_ (Fayard, 2004) _Au Fondement des Sociétés Humaines._ _Ce que nous apprend l''anthropologie_ (Albin Michel, 2007), _L''Imaginé, l''Imaginaire et le Symbolique_ (CNRS, éditions 2015).\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"Parentalité et fonctions parentales\\"** Parentalité, famille, fonction paternelle, fonction maternelle... Chacun peut naturellement se perdre dans ces différentes expressions. Au travers de trois regards différents, le psychanalyse, le sociologue et l''anthropologue nous éclaireront sur ces différentes conceptualisations.\\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,     parent,    parentalité,   enfant,  père,  mère"}', NULL, '{"filename":"event_conference-metamorphose-de-la-parentalite_751604.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-metamorphose-de-la-parentalite_751604.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-metamorphose-de-la-parentalite_751604.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-03-21T19:30:00.000Z","end":"2017-03-21T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:38', '2016-11-04 09:19:38', NULL ),
(145956, 68511882, 30735439, NULL, 36199439, 'conference-n-4-paroles-de-charpentier', '{"fr":"Conférence N°4 \\"Paroles de...charpentier\\""}', '{"fr":"\\"....autour de la construction bois\\""}', '{"fr":"François Duclos, charpentier-menuisier à Montpellier, viendra nous parler de son engagement dans la filière bois, de son éthique, et nous livrer quelques conseils et retours d’expériences autour de ce matériau, de la construction à ossature bois appliquée à la maison et des enjeux environnementaux liés aux secteurs de la construction.\\n\\nConférence donnée en parallèle à la présentation de l’exposition “Profils Bois en Languedoc-Roussillon“ au CAUE du 3 au 28 octobre, dans le cadre des Journées Nationales de l’Architecture, et pour poursuivre notre cycle \\"Paroles de...\\""}', '{"fr":"architecture, bois"}', NULL, '{"filename":"event_conference-n-4-paroles-de-charpentier_886543.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-n-4-paroles-de-charpentier_886543.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-n-4-paroles-de-charpentier_886543.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T16:30:00.000Z","end":"2016-10-13T18:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":17}', '["http://www.caue-lr.fr/paroles-de-charpentier"]', '2016-11-04 09:19:52', '2016-11-04 09:19:52', NULL ),
(146390, 20102153, 46479321, NULL, 79541680, 'conference-oid-et-amundi-immobilier', '{"fr":"Conférence OID et Amundi Immobilier"}', '{"fr":"Baromètre OID 2016, à l''heure des promesses numériques !"}', '{}', '{}', NULL, '{"filename":"event_conference-oid-et-amundi-immobilier_802039.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-oid-et-amundi-immobilier_802039.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-oid-et-amundi-immobilier_802039.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-30T13:30:00.000Z","end":"2016-11-30T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":16}', '[]', '2016-11-04 09:19:32', '2016-11-04 09:19:32', NULL ),
(147208, 65804836, 46479321, NULL, 34650800, 'conference-oid-et-plan-batiment-durable', '{"fr":"Conférence OID et Plan Bâtiment Durable"}', '{"fr":"Conférence du cycle Immobilier & Prospective"}', '{}', '{}', NULL, '{"filename":"event_conference-oid-et-plan-batiment-durable_171909.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-oid-et-plan-batiment-durable_171909.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-oid-et-plan-batiment-durable_171909.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-02-21T07:30:00.000Z","end":"2017-02-21T09:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":3,"max":99}', '[]', '2016-11-04 09:18:47', '2016-11-04 09:18:47', NULL ),
(146261, 42510932, 14963029, NULL, 66333672, 'conference-pere-mere-fonction-incertaine', '{"fr":"Conférence : \\"Père, mère, fonction incertaine\\""}', '{"fr":"Pour chaque enfant,  c''est la famille conjugale qui est le premier lieu de l''humanisation. Les fonctions de la mère et du père restent différenciées et asymétriques."}', '{"fr":"Même si aujourd''hui, le mot de parentalité laisse souvent entendre le cas contraire, dans la plupart des cas, la mère est le premier autre, le père intervient en deuxième.Cependant, du fait des évolutions sociales de plus en plus de situations peuvent diverger de ce modèle, alors même que l''extension d''un parental qui serait neutre du point de vue de la sexuation tend à croître. L''intervenant rendra compte des raisons de cette évolution et de la complexité des questions qu''elle pose.\\n\\nAvec Gérard Neyrand, sociologue, professeur  à l''université de Toulouse, membre de l''équipe d''accueil CRESCO, directeur du CIMERSS, laboratoire associatif à Bouc Bel-Air. Il fait partie du comité de rédaction des revues Dialogues et Recherches familiales et participe au conseil scientifique de l''Espace Andrée Chedid. Il a publié de nombreux ouvrages : _Le dialogue familial, un idéal précaire_ (Erès 2009), _Monoparentalité précaire et femme sujet_, avec Patricia Rossi (Erès 2004), _Soutenir et contrôler les parents_ (Erès-poche 2011)\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"Parentalité et fonctions parentales\\"** Parentalité, famille, fonction paternelle, fonction maternelle... Chacun peut naturellement se perdre dans ces différentes expressions. Au travers de trois regards différents, le psychanalyse, le sociologue et l''anthropologue nous éclaireront sur ces différentes conceptualisations.\\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,     parent,    parentalité,   enfant,  père,  mère"}', NULL, '{"filename":"event_conference-pere-mere-fonction-incertaine_240608.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-pere-mere-fonction-incertaine_240608.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-pere-mere-fonction-incertaine_240608.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-12-13T19:30:00.000Z","end":"2016-12-13T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:39', '2016-11-04 09:19:39', NULL ),
(146293, 74869228, 14963029, NULL, 66333672, 'conference-pour-un-developpement-complet-de-l-enfance-et-de-l-adolescence-quelle-place-pour-les-parents', '{"fr":"Conférence : \\"Pour un développement complet de l''enfance et de l''adolescence; quelle place pour les parents ?\\""}', '{"fr":"Les enfants et les adolescents ont l''impression de mener une vie \\"fractionnée\\" entre les contraintes de l''école et les attraits du temps libre."}', '{"fr":"Ce cloisonnement est redoublé au niveau politiques publiques, chacune fixant ses propres objectifs de moyens et longs termes. Écartelés entre des normes contradictoires et devant répondre à des défis nouveaux, bien des jeunes ont des difficultés à dessiner un parcours pour devenir eux-mêmes. Toutefois, décloisonner n''implique pas de confondre les espaces dans lesquels les enfants se développent (école, loisirs, famille etc...). Il s''agit avant tout de construire une vision d''ensemble pour dégager des priorités et intégrer les différents champs dont procède le développement de l''enfant. Quelle est la place des parents dans cette perspective ?\\n\\nAvec Vanessa Wisnia-Weill, co-auteure du rapport Pour un développement complet de l''enfant et de l''adolescent de la Commission Enfance et adolescence de France Stratégie. Vanessa Wisnia-Weill travaille sur des questions de famille, d''égalité entre les femmes et les hommes, d''éducation et de protection sociale. Elle articule cette activité avec une pratique clinique en tant que psychanalyste et psychologue clinicienne. Elle est également ingénieur de l''école polytechnique et de l''Ecole nationale des ponts et chaussées.\\n\\n**Cette conférence est organisée dans le cadre du cycle \\"La place des parents\\".** Deux conférences qu visent à prendre le temps de mieux élaborer la place des parents dans le développement de l''enfant et à mieux saisir les modes de participation avec les enfants au sein des familles.\\n\\n**Les soirées-conférences de l''espace Parent Enfant** Sous le thème générique \\"pour mieux comprendre la condition parentale\\", ces soirées-conférences son animées par des intervenants reconnus pour la qualité de leur travaux et leur expertise. Véritables temps d''apports d''expériences, de pratiques professionnelles, de réflexions, elles sont suivies d''un débat avec le public."}', '{"fr":"conférence,     parent,    parentalité,   enfant,  père,  mère"}', NULL, '{"filename":"event_conference-pour-un-developpement-complet-de-l-enfance-et-de-l-adolescence-quelle-place-pour-les-parents_174360.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-pour-un-developpement-complet-de-l-enfance-et-de-l-adolescence-quelle-place-pour-les-parents_174360.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-pour-un-developpement-complet-de-l-enfance-et-de-l-adolescence-quelle-place-pour-les-parents_174360.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-02-21T19:30:00.000Z","end":"2017-02-21T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["espaceparent-enfant@ville-issy.fr"]', '2016-11-04 09:19:37', '2016-11-04 09:19:37', NULL ),
