(147387, 21195604, 95280519, NULL, 42959545, 'conference-sur-le-burn-out', '{"fr":"Conférence sur le Burn-out"}', '{"fr":"Burn-out: Le reconnaître, le comprendre, s''en sortir."}', '{"fr":"**Le Burn out** : \\n\\nJe vous propose de partager mon vécu et ouvrir le débat autour de ce sujet ardent!\\n\\nQue cela soit pour répondre à un questionnement, sortir de l’isolement ou pour faire la paix avec ce Syndrome \\"en vogue\\" mais finalement peu compris."}', '{"fr":"santé au travail,  burnout, syndrome d''épuisement professionnel"}', NULL, '{"filename":"event_conference-sur-le-burn-out_753735.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-sur-le-burn-out_753735.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-sur-le-burn-out_753735.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-27T18:00:00.000Z","end":"2016-10-27T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":99}', '["0661253920"]', '2016-11-04 09:18:36', '2016-11-04 09:18:36', NULL ),
(146559, 93724768, 90183774, 44717094, 49645617, 'conference-sur-les-communs-de-la-connaissance-20-22-octobre-2016-paris', '{"fr":"CONFÉRENCE SUR LES COMMUNS DE LA CONNAISSANCE, 20-22 OCTOBRE 2016, PARIS"}', '{"fr":"Conference organisée par l’École de droit de Sciences Po et l’International Association for the Study of the Commons (IASC)."}', '{"fr":"Advancing Knowledge Commons through Legal and Social Changes : when commons meet law and public policy\\", 3ème conférence thématique sur les communs de la connaissance\\n\\nDu 20 au 22 octobre 2016\\\\. Sciences Po, Paris\\n\\nConference organisée par l’École de droit de Sciences Po et l’International Association for the Study of the Commons (IASC). http://www.iasc-commons.org/\\n\\nCette troisième rencontre vise à analyser les effets normatifs et l’institutionnalisation d’initiatives, notamment citoyennes, fondées sur les communs. Les communs incluent toute situation où l’usage d’une ressource est partagée et utilisée collectivement, que cette ressource fasse l’objet d’une propriété individuelle ou collective, ou non. La notion s’oppose à la vision traditionnelle de la propriété, soit privée soit publique, définie sur le pouvoir d’exclusion d’autrui qu’elle comporte. La recherche sur les communs a connu une expansion croissante depuis 30 ans. Elle concerne toutes les disciplines scientifiques, de l’économie, où les travaux d’Elinor Ostrom sur le sujet ont été couronnés d’un prix Nobel, de la sociologie, au droit, à l’histoire ou à la science politique. Initialement enracinée aux Etats-Unis, elle devient importante en France où se constitue une véritable communauté de recherche transdisciplinaire sur les communs.La réflexion sur les communs est également sortie des laboratoires de recherche pour investir la société civile qui s’est investie dans de nombreuses revendications ou construction de communs, favorisant l’usage collectif et organisé de ressources à des fins d’écologie, d’économie, de solidarité sociale. Le mouvement des communs prend ainsi pour objet l’accès au logement, à l’eau, à la culture et au savoir, le partage des données utiles pour la recherche, le droit à la ville, etc… De telles initiatives ont également suscité des modifications législatives ou s’institutionnalisent par leur inscription dans les politiques publiques à différents échelons du pouvoir.C’est cette inscription des communs de la connaissance dans le droit ou les politiques publiques que cette conférence souhaite interroger et étudier. Comment les communs de la connaissance peuvent-ils être soutenus par la reconnaissance d’effets normatifs aux relations collectives qu’ils créent ? La politique publique est-elle un outil adéquat pour préserver des biens publics informationnels basés sur du commun ? Quels effets durables les nouveaux modèles de production de savoir basés sur les communs ont-ils sur l’organisation juridique ? Que prévoient les chartes des communs qui apparaissent dans le politiques locales, notamment dans les villes italiennes, pour les communs de la connaissance et de la culture ?\\n\\nPlus d’informations : http://www.sciencespo.fr/ecole-de-droit/fr/content/advancing-knowledge-commons-through-legal-and-social-changes-when-commons-meet-law-and-publi"}', '{"fr":",  communs,  droit"}', NULL, '{"filename":"event_conference-sur-les-communs-de-la-connaissance-20-22-octobre-2016-paris_63963.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-sur-les-communs-de-la-connaissance-20-22-octobre-2016-paris_63963.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-sur-les-communs-de-la-connaissance-20-22-octobre-2016-paris_63963.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-20T07:00:00.000Z","end":"2016-10-20T16:00:00.000Z"},{"begin":"2016-10-21T07:00:00.000Z","end":"2016-10-21T16:00:00.000Z"},{"begin":"2016-10-22T07:00:00.000Z","end":"2016-10-22T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '[]', '2016-11-04 09:19:23', '2016-11-04 09:19:23', NULL ),
(146966, 63404709, 44783805, NULL, 3695861, 'conference-sur-les-risques-lies-a-l-utilisation-d-internet', '{"fr":"Conférence sur les risques liés à l''utilisation d''internet"}', '{"fr":"Lors d''une conférence, le Commandant Fantin interviendra auprès des classes de 3ème et 2de générale et professionnelle,  le jeudi 3 et vendredi 4 novembre."}', '{}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-04T07:30:00.000Z","end":"2016-11-04T16:30:00.000Z"},{"begin":"2016-11-03T07:30:00.000Z","end":"2016-11-03T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":77}', '[]', '2016-11-04 09:19:00', '2016-11-04 09:19:00', NULL ),
(145891, 32265948, 67248378, NULL, 45012031, 'conference-ville-et-patrimoine', '{"fr":"Conférence \\"Ville et Patrimoine\\""}', '{"fr":"La conférence portera sur la restauration et l''aménagement de l''architecture créole"}', '{"fr":"Apprenez en plus sur la restauration et l''aménagement de l''architecture créole grâce à l''intervention d''architectes qui évoqueront différents exemples de restauration.\\n\\nPour plus de renseignements:\\n\\n05-9425-54-15\\n\\n[maria.mejia-schuster@culture.gouv.fr](http://mailto:maria.mejia-schuster@culture.gouv.fr)"}', '{}', NULL, '{"filename":"event_conference-ville-et-patrimoine_593904.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conference-ville-et-patrimoine_593904.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conference-ville-et-patrimoine_593904.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T15:00:00.000Z","end":"2016-10-15T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":99}', '[]', '2016-11-04 09:19:56', '2016-11-04 09:19:56', NULL ),
(147071, 5376784, 56119077, NULL, 58372938, 'conferences-et-echanges-a-l-upjv-d-amiens-ufr-des-sciences', '{"fr":"Conférences et échanges à l''UPJV d''Amiens, UFR des Sciences !"}', '{"fr":"Cerveau, plante et médicament, cellule, temps, espace ou sondages préélectoraux, venez participer aux conférences du l''UPJV sur ces thèmes variés !"}', '{"fr":"L''UPJV d''Amiens vous attend à l''UFR des sciences du lundi 10 au vendredi 14 octobre pour une série de conférences sur des thématiques variées :\\n\\n**• « Le cerveau d''hier à aujourd’hui »**  - par Céline CHERICI -Lundi 10 octobre 17H30-19H00\\n\\nCentre d’Histoire des Sociétés, des Sciences et des Conflits (CHSSC EA 4289)\\n\\nUFR des Sciences – 33 rue St.-Leu, Amiens\\n\\nAmphi Parmentier\\n\\n**• « De la plante au médicament »** - par Vincent CHAGNAULT - Mardi 11 octobre 17H30-19H00\\n\\nLaboratoire de Glycochimie des Antimicrobiens et des Agro-ressources (LG2A UMR 7378)\\n\\nUFR des Sciences – 33 rue St.-Leu, Amiens\\n\\nAmphi Cassini\\n\\n**• « La cellule, un assemblage progressif »** - par José Edmundo NAVA SAUCEDO - Mercredi 12 octobre 12H45-14H15\\n\\nEcologie et Dynamique des Systèmes Anthropisés (EDYSAN FRE 3498)\\n\\nUFR des Sciences – 33 rue St.-Leu, Amiens\\n\\nAmphi Baudelocque\\n\\n**• « Chaos et irréversibilité. Origine de la flèche du temps »** - par Robert BOUZERAR - Mercredi 12 octobre 17H30-19H00\\n\\nLaboratoire de Physique de la Matière Condensée  (LPMC EA 2081)\\n\\nUFR des Sciences – 33 rue St.-Leu, Amiens\\n\\nAmphi Baudelocque\\n\\n**• « L''espace : Histoires et découvertes d''hier à aujourd''hui »** - par Eddy CHEVALLIER - Jeudi 13 octobre 17H30-19H00\\n\\nDépartement de Physique - UFR des Sciences\\n\\nUFR des Sciences – 33 rue St.-Leu, Amiens\\n\\nAmphi Lavoisier\\n\\n**• « Les sondages pré électoraux : marges d''erreurs ou erreurs \\"à la marge\\" ? »** - par Patrick LEHINGUE - Vendredi 14 octobre 12H45-14H15\\n\\nCentre Universitaire de Recherches sur l’Action\\n\\nPublique et le Politique (CURAPP-ESS UMR 7319)\\n\\nUFR des Sciences – 33 rue St.-Leu, Amiens\\n\\nAmphi Cassini"}', '{"fr":"conférence, cerveau, plante, médicament, cellule, temps, espace, sondages"}', NULL, '{"filename":"event_conferences-et-echanges-a-l-upjv-d-amiens-ufr-des-sciences_204160.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conferences-et-echanges-a-l-upjv-d-amiens-ufr-des-sciences_204160.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conferences-et-echanges-a-l-upjv-d-amiens-ufr-des-sciences_204160.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-10T15:30:00.000Z","end":"2016-10-10T17:00:00.000Z"},{"begin":"2016-10-11T15:30:00.000Z","end":"2016-10-11T17:00:00.000Z"},{"begin":"2016-10-12T10:30:00.000Z","end":"2016-10-12T12:30:00.000Z"},{"begin":"2016-10-13T15:30:00.000Z","end":"2016-10-13T17:00:00.000Z"},{"begin":"2016-10-14T10:30:00.000Z","end":"2016-10-14T12:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '[]', '2016-11-04 09:18:55', '2016-11-04 09:18:55', NULL ),
(147309, 87752336, 10771347, NULL, 95435537, 'conferences-paris-la-defense-art-collection', '{"fr":"Conférences Paris La Défense Art Collection"}', '{"fr":"Defacto vous invite à retrouver les grandes étapes du projet de mise en valeur des œuvres d''art de La Défense ou l''émergence de Paris La Défense Art Collection."}', '{"fr":"À la galerie Defacto, dans un paysage urbain créé par l''artiste Alain Bublex, redécouvrez les œuvres phares de la collection et leur transformation à travers les chantiers déployés depuis juin 2015 à La Défense.\\n\\nVenez rencontrer les acteurs du projet et participer aux conférences thématiques :\\n\\n**Lundi 17 octobre  \\n**\\"Le Moretti de Raymond Moretti, une restauration hors normes\\" présenté Barbara Brunet et Clément Guinamard, Studiolo (cabinet de restauration)  \\n[> INSCRIVEZ-VOUS ICI](https://www.eventbrite.fr/e/billets-paris-la-defense-art-collection-le-moretti-une-restauration-hors-normes-28328011846)\\n\\n**Mercredi 19 octobre  \\n**\\"Conserver les œuvres d''art dans l''espace public de La Défense - un défi patrimonial, un exemple emblématique : la restauration d''After Olympia d''Anthony Caro\\" présenté par Sylvie Ramel (conservation préventive) et Philippe de Viviés (A-Corros)   \\n[> INSCRIVEZ-VOUS ICI](https://www.eventbrite.fr/e/billets-paris-la-defense-art-collection-restauration-dafter-olympia-de-caro-28328295695)\\n\\n**Jeudi 20 octobre  \\n**\\"Faire collection, le projet de mise en valeur des œuvres d''art de La Défense\\" présenté par Béatrice Jullien, Catherine Frenak et Sylvain Le Stum de l''agence Frenak+Jullien Architectes   \\n[> INSCRIVEZ-VOUS ICI](https://www.eventbrite.fr/e/billets-paris-la-defense-art-collection-mise-en-valeur-des-uvres-de-la-defense-28328872420)\\n\\n**Vendredi 21 octobre  \\n**\\"Retrouver une œuvre, la transformation des Signaux et du Bassin Takis\\" présenté par Sara Kuperholc et Nicolas Imbert (restaurateurs)   \\n[> INSCRIVEZ-VOUS ICI](https://www.eventbrite.fr/e/billets-paris-la-defense-art-collection-restauration-des-signauxdu-bassin-takis-28328396998)"}', '{"fr":", Paris La Défense Art Collection œuvres d''art restauration"}', NULL, '{"filename":"event_conferences-paris-la-defense-art-collection_257770.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conferences-paris-la-defense-art-collection_257770.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conferences-paris-la-defense-art-collection_257770.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-17T10:30:00.000Z","end":"2016-10-17T11:30:00.000Z"},{"begin":"2016-10-18T10:30:00.000Z","end":"2016-10-18T11:30:00.000Z"},{"begin":"2016-10-20T10:30:00.000Z","end":"2016-10-20T11:30:00.000Z"},{"begin":"2016-10-21T10:30:00.000Z","end":"2016-10-21T11:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":15,"max":99}', '["https://www.eventbrite.fr/d/france--paris/defacto/?crt=regular&sort=best"]', '2016-11-04 09:18:41', '2016-11-04 09:18:41', NULL ),
(147383, 11509246, 38312558, 16831813, 40887237, 'conjurer-la-peur-etape-de-travail', '{"fr":"Conjurer la peur (étape de travail)"}', '{"fr":"Présentation d’une étape de travail pour la création 2017 de Gaëlle Bourges dans le cadre des Instantanés d''Arcadi"}', '{"fr":"Conjurer la peur projette d’expérimenter - à neuf – un « sentiment social » de ce que serait un bien gouverner, en prenant appui sur une œuvre célèbre : les fresques siennoises appelées « les effets du bon et du mauvais gouvernement », peintes par A. Lorenzetti en 1338 et analysées par l’historien Patrick Boucheron, à qui nous empruntons le titre. La pièce s’articulera autour de deux points :\\n\\n1 - une forme : celle d’une danse à neuf - une ridda – visible dans la fresque du bon gouvernement, et motif central de la pièce\\n\\n2 - une posture : un mauvais gouvernement est celui qui dérègle les usages de la parole ; un bon organise la dispute, et se fonde sur l’exactitude du mot"}', '{}', NULL, '{"filename":"event_conjurer-la-peur-etape-de-travail_949223.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conjurer-la-peur-etape-de-travail_949223.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conjurer-la-peur-etape-de-travail_949223.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-15T09:00:00.000Z","end":"2016-11-15T19:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":99}', '[]', '2016-11-04 09:18:36', '2016-11-04 09:18:36', NULL ),
