(145579, 61880603, 11814497, NULL, 3814383, 'conseils-gratuits', '{"fr":"Portes ouvertes \\"Conseils gratuits\\""}', '{"fr":"Vous avez un projet! Un architecte vous reçoit pour vous guider et vous conseiller dans une démarche de projet."}', '{"fr":"Vous souhaitez construire, rénover, agrandir, réhabiliter...\\n\\nLe CAUE VAR met en place des permanences le jeudi 13 et vendredi 14 octobre 2016 de 10h à 16h.\\n\\nUn architecte vous recevra pour vous guider et vous conseiller sur votre projet de construction, réhabilitation, rénovation, extension.\\n\\nPrise de rendez-vous obligatoire au 04 94 22 65 75."}', '{"fr":"architecture, conseils"}', NULL, '{"filename":"event_conseils-gratuits_584719.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conseils-gratuits_584719.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conseils-gratuits_584719.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T08:00:00.000Z","end":"2016-10-13T14:00:00.000Z"},{"begin":"2016-10-14T08:00:00.000Z","end":"2016-10-14T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["0494226575","contact@cauevar.fr"]', '2016-11-04 09:20:09', '2016-11-04 09:20:09', NULL ),
(147295, 74827196, 99535145, NULL, 62613701, 'conservatoire-henri-dutilleux-de-belfort-concert-lecture-par-l-ensemble-confluences', '{"fr":"Conservatoire Henri Dutilleux de Belfort : concert-lecture par l''Ensemble confluences"}', '{"fr":"Les pièces de musique de chambre d''Henri Dutilleux et de compositeurs d''aujourd''hui ponctuées par la lecture de Baudelaire"}', '{"fr":"L’année 2016 marque le centenaire de la naissance d’Henri Dutilleux. L’occasion est donnée à l’ensemble instrumental Confluences de lui rendre hommage en proposant un concert-lecture autour d’œuvres de musique de chambre d''Henri Dutilleux mais aussi de compositeurs d''aujourd''hui, dans l''Auditorium du dernier Conservatoire baptisé de son nom.\\n\\n## Ensemble Confluences\\n\\n*   Isabelle Isler, piano\\n*   Fabienne Voinot, flûte traversière et lecture\\n*   Heidi Braesch-Caillet, hautbois\\n*   Thérèse Meyer, violoncelle\\n*   Faustine Ragonnet-Mauvais, piano\\n*   Myriam Joly, accordéon\\n*   Claire Poncet, mezzo-sopprano\\n\\n**Clés d''écoute :**\\n\\nPaul Boissieux, compositeur et professeur de composition-analyse"}', '{"fr":",           concert,          poésie,         Dutilleux,        centenaire,       conservatoire,      pédagogie,     2016-2017,    Belfort,   musique de chambre,  création, musiques d''aujourd''hui"}', NULL, '{"filename":"event_conservatoire-henri-dutilleux-de-belfort-concert-lecture-par-l-ensemble-confluences_124866.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_conservatoire-henri-dutilleux-de-belfort-concert-lecture-par-l-ensemble-confluences_124866.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_conservatoire-henri-dutilleux-de-belfort-concert-lecture-par-l-ensemble-confluences_124866.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-22T19:00:00.000Z","end":"2016-11-22T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":99}', '["http://www.agglo-belfort.com/fr/conservatoire/agenda/evenement/article/ensemble-confluences-hommage-a-henri-dutilleux.html?no_cache=1"]', '2016-11-04 09:18:42', '2016-11-04 09:18:42', NULL ),
(145862, 61040767, 42372231, NULL, 28642736, 'construction-et-renovation-de-l-habitat-dans-le-cadre-de-la-transition-energetique', '{"fr":"Exposition visible par tous : \\"Construction et rénovation de l''habitat dans le cadre de la transition énergétique\\""}', '{"fr":"Exposition sur les grilles de la Préfecture d''Ajaccio de projets d''architecture réalisés en Corse. MAISON DE L''ARCHITECTURE DE CORSE en partenariat avec la D° REG. DES AFFAIRES CULTURELLES DE CORSE"}', '{"fr":"Pour la deuxième année consécutive, la Maison de l''Architecture de Corse poursuit son action de sensibilisation de tous les publics au rôle incontournable des architectes dans la transition énergétique.\\n\\nAfin de toucher au plus près le maximum de personnes, la Maison de l''Architecture de Corse a demandé à tous les architectes qui le souhaitaient de présenter leurs réalisations en Corse en relation avec ces enjeux sur des panneaux destinés à être exposés dans la rue, dans différents lieux de Corse.\\n\\nLe choix des projets présentés a suivi le thème principal de l''opération \\"construction et rénovation de l''habitat dans le cadre de la transition énergétique\\".\\n\\nCes panneaux seront exposés sur les grilles de la Préfecture d’Ajaccio les 14, 15 et 16 octobre 2016.\\n\\nL''objectif est d''échanger et de s''interroger par la rencontre autour de ces panneaux sur l''évolution des comportements liés à la construction et à l''aménagement du territoire  en réponse aux enjeux d''un développement plus soucieux des impacts environnementaux, économiques et sociaux."}', '{"fr":"corse,      construction,     rénovation,    habitat,   transition énergétique,  architecte, ajaccio"}', NULL, '{"filename":"event_construction-et-renovation-de-l-habitat-dans-le-cadre-de-la-transition-energetique_949622.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_construction-et-renovation-de-l-habitat-dans-le-cadre-de-la-transition-energetique_949622.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_construction-et-renovation-de-l-habitat-dans-le-cadre-de-la-transition-energetique_949622.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T05:00:00.000Z","end":"2016-10-13T22:00:00.000Z"},{"begin":"2016-10-15T05:00:00.000Z","end":"2016-10-14T22:00:00.000Z"},{"begin":"2016-10-16T05:00:00.000Z","end":"2016-10-15T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":3,"max":99}', '["maisonarchitecturecorse@gmail.com","0771730303"]', '2016-11-04 09:19:58', '2016-11-04 09:19:58', NULL ),
(146463, 31738246, 82460052, NULL, 66738119, 'construire-autrement', '{"fr":"Projection du documentaire \\"Construire autrement\\""}', '{"fr":"Documentaire - réalisateur J. Kébadian - 2010 - 73''"}', '{"fr":"Comment traduire l''acte de construire dans une démocratie participative en action ? L''architecte Patrick Bouchain transforme depuis longtemps des friches industrielles en lieux culturels ; il met en place des chantiers vivants, ouverts au public, où s''organise un échange d''expériences autour de l''acte de construire.\\n\\nLe chantier du Channel est lui aussi propice à la mise en scène de la méthode de l''architecte : métamorphose du lieu en recyclant, en modifiant plutôt qu''en pratiquant la table rase ; travail collectif avec des artistes comme le scénographe-constructeur François Delarozière ; invention d''un \\"lieu du don... pas de l''autorité\\" ; une cabane de chantier à la fois restaurant, salle de réunions et lieu de spectacles, où ouvriers, architectes, visiteurs, artistes, scolaires discutent de la transformation du site.\\n\\nIngénieurs, artistes mais aussi démolisseurs ou habitants munis de porte-voix s''expriment ici dans un joyeux brouhaha de scies mécaniques. Chacun trouve sa place dans ce lieu de vie, festif et populaire."}', '{"fr":"construire, démocratie"}', NULL, '{"filename":"event_construire-autrement_828577.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_construire-autrement_828577.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_construire-autrement_828577.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T13:30:00.000Z","end":"2016-10-15T14:45:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '[]', '2016-11-04 09:19:28', '2016-11-04 09:19:28', NULL ),
(147149, 15169592, 45381015, NULL, 86271164, 'construire-en-pierre', '{"fr":"Workshop et exposition \\"Construire en pierre\\""}', '{"fr":"Restitution d''un workshop inter-écoles (ENSA Grenoble, Lyon et Saint-Etienne) organisé par l''association de l''ENSASE, Imhotep, aux Grands Ateliers de l''Isle d''Abeau."}', '{"fr":"Restitution du workshop \\"Construction en pierre\\" organisé par l’association [Imhotep](http://imhotepassociation.wixsite.com/ensase), association étudiante de l''ENSASE, et animé par Christophe et Claude Chevènement, tailleurs de pierre originaires de Saint-Antoine l’Abbaye.\\n\\nCe workshop inter-écoles (ENSA de la Région Auvergne Rhône-Alpes) s’est tenu du 20 au 22 juin 2016 aux [Grands Ateliers de l’Isle d’Abeau,](http://www.lesgrandsateliers.org/) pôle d''enseignement, de recherche et d''expérimentation de la construction, avec le soutien de l’ENSASE et de la Région Auvergne Rhône-Alpes."}', '{"fr":"Pierre, tailleur, workshop, architecture, construction, matériau"}', NULL, '{"filename":"event_construire-en-pierre_894078.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_construire-en-pierre_894078.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_construire-en-pierre_894078.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T06:30:00.000Z","end":"2016-10-14T16:00:00.000Z"},{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":4,"max":99}', '[]', '2016-11-04 09:18:50', '2016-11-04 09:18:50', NULL ),
(145883, 24629001, 99246400, NULL, 69995179, 'construire-la-ville-sur-la-ville', '{"fr":"Exposition \\"Construire la ville sur la ville\\""}', '{"fr":"exposition de maquettes"}', '{"fr":"L’exposition Construire la ville sur la ville , illustre le premier des objectifs de la Stratégie Nationale : sensibiliser tout un chacun et l’ensemble des acteurs publics et privés de la construction. Elle suscite une réflexion sur le devenir des villes, sur les ZAC et les ZUP comme alternatives pour le développement des villes, un thème d’actualité qui s’imposait pour ces Journées Nationales de l’Architecture.\\n\\nLe programme concernait la Maison d’Enfants Marie Caizergues, située à Montpellier dans le quartier de Boutonnet. Cet établissement participe du dispositif départemental de protection de l’enfance. Il imposait la réalisation d’un internat dans le bâtiment principal existant, la création de dix villas éducatives, d’une salle polyvalente, d’un équipement pour le Service d’Accompagnement à la Vie Autonome (SAVA) et un Atelier Maturation Insertion (AMI) avec une salle de stockage. Les réponses apportées par des étudiants de deuxième année ont tenté de respecter les spécificités d’un tel établissement, son insertion dans le tissu urbain et dans la programmation de nouveaux espaces publics mais plus encore l’échelle humaine qui le définit."}', '{"fr":"maquettes, visuel, ville, urbanisme, Montpellier, Aigues Mortes, CMN, ENSAM,  Ecole d''architecture"}', NULL, '{"filename":"event_construire-la-ville-sur-la-ville_429291.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_construire-la-ville-sur-la-ville_429291.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_construire-la-ville-sur-la-ville_429291.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T08:00:00.000Z","end":"2016-10-14T15:30:00.000Z"},{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T15:30:00.000Z"},{"begin":"2016-10-16T08:00:00.000Z","end":"2016-10-16T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '[]', '2016-11-04 09:19:57', '2016-11-04 09:19:57', NULL ),
(146854, 15095600, 86837088, NULL, 58997685, 'contrebrassens-a-lectoure-32', '{"fr":"Contrebrassens à Lectoure (32)"}', '{"fr":"Brassens au féminin (duo)"}', '{"fr":"Une femme, une contrebasse :  \\nUn ménage à deux qui révèle toute la saveur musicale des mélodies,  \\nla finesse des textes et nous fait redécouvrir Brassens.  \\nPromenade dans des histoires choisies autour de la femme.\\n\\nAvec : Pauline Dupuy (contrebasse) et Michael Wookey (guitare)\\n\\n[https://www.youtube.com/watch?v=xEN973TUjNQ](https://www.youtube.com/watch?v=xEN973TUjNQ)"}', '{"fr":"Concert, Brassens, Contrebrasse, Chanson"}', NULL, '{"filename":"event_contrebrassens-a-lectoure-32_234964.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_contrebrassens-a-lectoure-32_234964.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_contrebrassens-a-lectoure-32_234964.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-18T19:00:00.000Z","end":"2016-11-18T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":13,"max":99}', '["assolouiselabe@gmail.com","05 62 68 98 59","http://facebook.com/A3L-Association-Louise-Labé-Lectoure-1026015374156687"]', '2016-11-04 09:19:07', '2016-11-04 09:19:07', NULL ),
