(146848, 22908608, 86837088, NULL, 15482777, 'contrebrassens-a-pierrefeu-du-var-83', '{"fr":"Contrebrassens à Pierrefeu du Var (83)"}', '{"fr":"Contrebrassens en duo"}', '{"fr":"Une femme, une contrebasse :  \\nUn ménage à deux qui révèle toute la saveur musicale des mélodies,  \\nla finesse des textes et nous fait redécouvrir Brassens.  \\nPromenade dans des histoires choisies autour de la femme.\\n\\nAvec : Pauline Dupuy (contrebasse) et Michael Wookey (guitare)\\n\\n[https://www.youtube.com/watch?v=xEN973TUjNQ](https://www.youtube.com/watch?v=xEN973TUjNQ)"}', '{"fr":"Concert, Brassens, Contrebrasse, Chanson"}', NULL, '{"filename":"event_contrebrassens-a-pierrefeu-du-var-83_600933.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_contrebrassens-a-pierrefeu-du-var-83_600933.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_contrebrassens-a-pierrefeu-du-var-83_600933.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T18:30:00.000Z","end":"2016-10-22T20:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":13,"max":99}', '[]', '2016-11-04 09:19:07', '2016-11-04 09:19:07', NULL ),
(147418, 54025140, 31558343, 16831813, 21883006, 'coproud-proposition-pour-danseuse-experimentee', '{"fr":"COPROUD, proposition pour danseuse expérimentée"}', '{"fr":"Ni danseur ni chorégraphe César Vayssié tente un duo avec Olivia Grandville. A partir de cette situation préméditée, le duo engage les gestes d’une hypothèse esthétique de cette relation inopinée."}', '{"fr":"Ni danseur ni chorégraphe César Vayssié utilise le matériau chorégraphique dans des évènements performatifs ou des films, comme argument physique de l’idée d’engagement (artistique, politique, amoureux). En spectateur idéal, il décide l’aventure d’un duo avec une danseuse-chorégraphe, Olivia Grandville et son expérience emblématique de la danse. A partir de cette situation préméditée, le duo engage sans fiction les gestes d’une hypothèse esthétique de la relation. Le réel guide une rencontre inopinée, indexée au patrimoine sensible et aux compétences de chacun. La danseuse pactise avec un inconnu chorégraphique qui questionne son expérience. L’intrus porte avec lui des sensations festives, le souvenirs de la pratique du ski de descente et la mémoire de la danse vue. Danseur profane, il devient un chorégraphe ignorant. Ce qui surgit, c’est la dramaturgie muette et non écrite de cette rencontre. L’expérience sera renouvelée à chaque opus et aussi proposée à d’autres danseuses « expérimentées ». COPROUD sera créé les 8, 9 et 10 novembre 2016 à la Ménagerie de Verre à Paris."}', '{"fr":"performance, duo"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-23T14:00:00.000Z","end":"2016-10-23T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":10,"max":99}', '[]', '2016-11-04 09:18:35', '2016-11-04 09:18:35', NULL ),
(147423, 67889197, 31558343, 16831813, 79011776, 'coproud-proposition-pour-danseuse-experimentee_604', '{"fr":"COPROUD, proposition pour danseuse expérimentée"}', '{"fr":"Ni danseur ni chorégraphe César Vayssié tente un duo avec Olivia Grandville. A partir de cette situation préméditée, le duo engage les gestes d’une hypothèse esthétique de cette relation inopinée."}', '{"fr":"Ni danseur ni chorégraphe César Vayssié utilise le matériau chorégraphique dans des évènements performatifs ou des films, comme argument physique de l’idée d’engagement (artistique, politique, amoureux). En spectateur idéal, il décide l’aventure d’un duo avec une interprète, Olivia Grandville et son expérience emblématique de la danse. A partir de cette situation préméditée, le duo engage sans fiction les gestes d’une hypothèse esthétique de la relation. Le réel guide une rencontre inopinée, indexée au patrimoine sensible et aux compétences de chacun. La danseuse pactise avec un inconnu chorégraphique qui questionne son expérience. L’intrus porte avec lui des sensations festives, le souvenirs de la pratique du ski de descente et la mémoire de la danse vue. Danseur profane, il devient un chorégraphe ignorant. Ce qui surgit, c’est la dramaturgie muette et non écrite de cette rencontre. L’expérience sera renouvelée à chaque opus et aussi proposée à d’autres danseuses « expérimentées ». COPROUD sera créé les 8, 9 et 10 novembre 2016 à la Ménagerie de Verre à Paris."}', '{"fr":"performance, duo"}', NULL, '{"filename":"event_coproud-proposition-pour-danseuse-experimentee_604_903755.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_coproud-proposition-pour-danseuse-experimentee_604_903755.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_coproud-proposition-pour-danseuse-experimentee_604_903755.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-08T19:30:00.000Z","end":"2016-11-