(147615, 86913171, 93046868, NULL, 34938054, 'cours-de-coding-pour-tous', '{"fr":"Cours de coding pour tous"}', '{"fr":"Dans le cadre de la code week, venez apprendre à coder facilement avec Toxicode"}', '{"fr":"L''événement est gratuit et accessible à tous (adultes, enfants à partir de 10 ans), et s''adresse à la fois aux débutants qui n''ont jamais programmé et aux expérimentés !\\n\\nVous créerez votre niveau seul ou en groupe.\\n\\nVous pourrez utiliser pour ça notre outil, Code n'' Slash, conçu pour vous simplifier la vie. N''ayez pas peur vous aurez le temps de le prendre en, mais vous pouvez déjà prendre de l''avance en visionnant cette vidéo de présentation :\\n\\n[https://youtu.be/ZYv90pAvGe8](https://youtu.be/ZYv90pAvGe8)\\n\\nVenez avec votre propre PC."}', '{"fr":",              code,             coding,            coder,           code_week,          developpeur,         digital,        initiation,       enfant,      avenir,     web,    Internet,   French_Tech,  Rennes, Mabilay"}', NULL, '{"filename":"event_cours-de-coding-pour-tous_645020.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cours-de-coding-pour-tous_645020.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cours-de-coding-pour-tous_645020.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T07:00:00.000Z","end":"2016-10-15T11:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":false,"vi":false,"sl":true}', '{"min":8,"max":99}', '["http://www.meetup.com/fr-FR/code-creatif/events/234771978/"]', '2016-11-04 09:18:23', '2016-11-04 09:18:23', NULL ),
