(146437, 86961941, 46668298, NULL, 8543638, 'creer-agrandir-ou-transformer-votre-habitation', '{"fr":"Table ronde \\"Créer, agrandir ou transformer votre habitation\\""}', '{"fr":"Trois architectes expliqueront comment ils ont pu accompagner des particuliers dans la recherche de solutions pour améliorer, relooker ou créer leur nouvelle habitation, leur nouveau lieu de vie"}', '{"fr":"En partenariat avec le Conseil Régional de l’Ordre des Architectes de Picardie\\n\\n16h00 – **Table ronde « Créer, agrandir ou transformer votre habitation »**\\n\\nA travers une table ronde interactive avec les participants, plusieurs architectes expliqueront comment ils ont pu accompagner des particuliers dans la recherche de solutions créatives pour améliorer, relooker ou créer leur nouvelle habitation, leur nouveau lieu de vie.\\n\\nL’objet de la table ronde sera l’intervention sur le bâti existant, pavillon des années 70-80, hangar ou maison de ville. La qualité d’éclairement des espaces, leur fonctionnalité et bien sûr la performance énergétique de l’intervention constituent des éléments de confort prépondérants auxquels ces architectes Samariens ont été particulièrement attentifs.\\n\\n**Samuel Ridoux** **- « Relooking extrême d’un pavillon » :**\\n\\nLa maison LASA - Projet Lauréat du Palmarès TECHNAL 2015 \\"réhabiliter\\" – est un projet particulièrement original qui consista à véritablement « envelopper » la maison d’habitation à l’aide de bacs acier. Une extension a également été réalisée.\\n\\n**Philippe Dumont - « Transformer un hangar en loft » :**\\n\\nHabiter un loft peut constituer une idée séduisante. Toutefois les contraintes liées au site impliquent souvent une approche subtile notamment au regard de la diffusion de lumière naturelle dans le logement ou son organisation fonctionnelle.\\n\\n**Régis Thévenet - « Créer des pièces supplémentaires » :**\\n\\nAgrandir et réorganiser son habitation peut parfois constituer une solution lorsqu’on ne la trouve plus adaptée à ses besoins. L’architecte peut très souvent proposer un panel de solutions au cas par cas qui peuvent permettre d’apporter des réponses concrètes à vos envies.\\n\\ncrédit d''image: Philippe Dumont"}', '{"fr":",     bâti existant,     ,   pavillon,  maison de ville, performance énergétique"}', NULL, '{"filename":"event_creer-agrandir-ou-transformer-votre-habitation_632492.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_creer-agrandir-ou-transformer-votre-habitation_632492.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_creer-agrandir-ou-transformer-votre-habitation_632492.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T14:00:00.000Z","end":"2016-10-15T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '["03 22 91 11 65"]', '2016-11-04 09:19:30', '2016-11-04 09:19:30', NULL ),
(145916, 82027246, 40364112, NULL, 69982144, 'creer-une-page-facebook-professionelle', '{"fr":"Créer une page Facebook professionnelle"}', '{"fr":"Créer et gérer sa page"}', '{"fr":"Créez votre page pour votre activité ou association, et améliorez votre visibilité sur le web.\\n\\n*   Découverte ou re-découverte de l’outil : fonctions de base, utilisation correcte, compréhension de la « mécanique »\\n*   Création et paramétrage de sa propre page professionnelle\\n*   Utilisation de la page professionnelle"}', '{}', NULL, '{"filename":"event_creer-une-page-facebook-professionelle_757509.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_creer-une-page-facebook-professionelle_757509.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_creer-une-page-facebook-professionelle_757509.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-17T08:00:00.000Z","end":"2016-10-17T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["coworking@mairie-livron.fr","0786908320"]', '2016-11-04 09:19:55', '2016-11-04 09:19:55', NULL ),
