(146050, 23807647, 51980619, NULL, 7399147, 'croquer-la-ville', '{"fr":"Promenade urbaine \\"Croquer la ville !\\""}', '{"fr":"Le CAUE du Val-d''Oise propose une visite/atelier croquis autour de l’architecture du quartier Axe Majeur-Horloge de Cergy."}', '{"fr":"Découverte du second quartier de la Ville Nouvelle, de l''architecture du quartier Axe Majeur-Horloge de la ville de Cergy par le dessin.\\n\\nLes participants alimenteront un carnet de bord qui leur sera fourni. Croquis de façades, volumes, détails… illustreront la diversité des architectures et des formes urbaines.\\n\\nAucun niveau requis en dessin."}', '{}', NULL, '{"filename":"event_croquer-la-ville_711283.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_croquer-la-ville_711283.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_croquer-la-ville_711283.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T12:30:00.000Z","end":"2016-10-16T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '["http://formulaire.caue-idf.fr/index.php/341889/lang-fr"]', '2016-11-04 09:19:48', '2016-11-04 09:19:48', NULL ),
