(147364, 61263552, 40399386, NULL, 17700793, 'cultivons-l-avenir-au-jardin-des-sciences', '{"fr":"Cultivons l''avenir au jardin des sciences UEVE-Génopole"}', '{"fr":"L''université Evry Val d''Essonne et le Genopole vous invitent à découvrir leurs recherches, leurs métiers de façon interactive et ludique."}', '{"fr":"**Cultivez votre avenir !**\\n\\nComme chaque année, cinq journées intenses ponctuées d’animations, de conférences, ateliers, visites de laboratoires, stands et spectacles attendent grand public, scolaires et étudiants pour répondre à cet important enjeu qu’est le partage de la culture scientifique.\\n\\nVenez fêter la science avec nous ! Toutes les manifestations organisées dans le cadre de la Fête de la science sont gratuites et ouvertes à tous.\\n\\n[Tout le programme](http://www.fetedelascience.univ-evry.fr/)"}', '{"fr":"recherche, innovation, genomique, thérapie"}', NULL, '{"filename":"event_cultivons-l-avenir-au-jardin-des-sciences_723951.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cultivons-l-avenir-au-jardin-des-sciences_723951.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cultivons-l-avenir-au-jardin-des-sciences_723951.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-12T08:30:00.000Z","end":"2016-10-12T16:30:00.000Z"},{"begin":"2016-10-13T08:30:00.000Z","end":"2016-10-13T16:30:00.000Z"},{"begin":"2016-10-14T08:30:00.000Z","end":"2016-10-14T16:30:00.000Z"},{"begin":"2016-10-15T08:30:00.000Z","end":"2016-10-15T16:30:00.000Z"},{"begin":"2016-10-16T08:30:00.000Z","end":"2016-10-16T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":18,"max":119}', '["communication@genopole.fr","fds@univ-evry.fr"]', '2016-11-04 09:18:38', '2016-11-04 09:18:38', NULL ),
(147339, 65648753, 94722865, NULL, 2631270, 'cycle-de-conferences-sur-les-cetaces', '{"fr":"A la découverte des Cétacés"}', '{"fr":"Les baleines à bosse sont des cétacés qui viennent proches des côtes. Mais existe-t-il des préférences en fonction du sexe, de l''âge, de paramètres, des paramètres environnementaux ?"}', '{"fr":"L’étude des déplacements des baleines à bosse (**Megaptera novaeangliae**) en relation avec les paramètres environnementaux permet d’apporter des informations précieuses sur leur distribution et leurs préférences d’habitats.\\n\\nGrâce à des données d’observations opportunistes collectées dans le canal de Sainte Marie (Nord-Est de Madagascar) et des données de télémétrie collectées pour cette étude, ce travail a eu pour objectif de décrire les déplacements des baleines à bosse en période de reproduction et de caractériser leurs habitats de reproduction dans la région de Madagascar.\\n\\nSi l’approche employée et les résultats obtenus offrent de nouvelles perspectives pour mieux comprendre l’écologie de l’espèce, une question centrale restait cependant sans réponse : existe-t-il des stratégies d’utilisation de l’habitat différentes d’une région de reproduction à une autre, à l’échelle de l’hémisphère sud. ?\\n\\nUne étude comparative sur l’utilisation de l’habitat en période de reproduction a ainsi été menée à partir de nos données à Madagascar et de trajectoires de baleines à bosses se reproduisant au Brésil, et le long des côtes est et ouest de l’Australie. La prise en compte des différences d’utilisation de l’habitat des mâles et des femelles en zone de reproduction apparait être une nécessité pour mieux comprendre l’écologie des baleines à bosse et contribuer à la conservation de l’espèce."}', '{"fr":",     baleines,     cétacés,    écologie,   biologie,"}', NULL, '{"filename":"event_cycle-de-conferences-sur-les-cetaces_843085.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_cycle-de-conferences-sur-les-cetaces_843085.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_cycle-de-conferences-sur-les-cetaces_843085.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-15T13:00:00.000Z","end":"2016-10-15T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":11,"max":15}', '["olivier.adam@upmc.fr"]', '2016-11-04 09:18:39', '2016-11-04 09:18:39', NULL ),
(145942, 99000100, 19053060, NULL, 71757679, 'd-histoire-en-histoire-le-port-de-concarneau', '{"fr":"Visite guidée \\"D''Histoire en histoire, le port de Concarneau\\""}', '{"fr":"Visite à deux voix en partenariat avec la Semcar à la découverte des installations portuaires"}', '{"fr":"Parler de l’histoire du port de Concarneau, c’est parler de l’histoire de la ville. Zone portuaire dynamique et toujours en activité, mais aussi zone patrimoniale, la zone portuaire évolue et se modernise. Comment concilier histoire, patrimoine et modernisation ? Accompagné d’un guide-conférencier du service patrimoine et du Directeur d’exploitation de la Semcar, nous vous proposons de suivre cette visite qui invite à la réflexion."}', '{"fr":"Concarneau, port, Semcar, patrimoine industriel"}', NULL, '{"filename":"event_d-histoire-en-histoire-le-port-de-concarneau_473993.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_d-histoire-en-histoire-le-port-de-concarneau_473993.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_d-histoire-en-histoire-le-port-de-concarneau_473993.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-16T13:00:00.000Z","end":"2016-10-16T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '["patrimoine@concarneau.fr","02 98 60 76 06","02 98 97 01 44"]', '2016-11-04 09:19:53', '2016-11-04 09:19:53', NULL ),
