(146695, 68746945, 38565623, 27545135, 84267844, 'dans-la-mer-il-n-y-a-pas-que-des-poissons', '{"fr":"Dans la mer il n’y a pas que des poissons !"}', '{"fr":"Sensibilisation à la biodiversité marine."}', '{"fr":"La mer est un lieu où il y a une grande biodiversité. Nous vous proposons de mieux faire connaissance avec les êtres vivants du récif corallien et de voir les menaces pesant sur cet écosystème.\\n\\nSupports d’animation : affiches, jeux, observations à la loupe de sable corallien"}', '{"fr":",   Observation,  biodiversité, Martinique"}', NULL, '{"filename":"event_dans-la-mer-il-n-y-a-pas-que-des-poissons_308100.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_dans-la-mer-il-n-y-a-pas-que-des-poissons_308100.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_dans-la-mer-il-n-y-a-pas-que-des-poissons_308100.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-13T12:30:00.000Z","end":"2016-10-13T14:30:00.000Z"},{"begin":"2016-10-14T06:30:00.000Z","end":"2016-10-14T10:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["0696 212 868","http://cms.ac-martinique.fr/etablissement/clgterreville/"]', '2016-11-04 09:19:15', '2016-11-04 09:19:15', NULL ),
(147519, 12936986, 15723194, NULL, 85447639, 'dans-le-jardin-de-jupiter', '{"fr":"Dans le jardin de Jupiter"}', '{"fr":"Récits extraordinaires et créations fantastiques..."}', '{"fr":"Après avoir écouté les récits extraordinaires de quelques dieux et héros de la mythologie, créez votre propre créature fantastique mi-végétale, mi-humaine ou mi-animale.\\n\\nRécit et atelier pour les enfants de 6 à 12 ans.\\n\\nGratuit pour les enfants - 2,80 € pour un adulte accompagnant, 3€ pour les autres adultes."}', '{"fr":"famille, animation, enfant, monument"}', NULL, '{"filename":"event_dans-le-jardin-de-jupiter_664335.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_dans-le-jardin-de-jupiter_664335.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_dans-le-jardin-de-jupiter_664335.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T12:30:00.000Z","end":"2016-10-22T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":12}', '["04 70 56 94 28","http://www.chareil-cintrat.fr"]', '2016-11-04 09:18:29', '2016-11-04 09:18:29', NULL ),
(145676, 97902928, 44642279, 19096631, 54813425, 'dans-le-noir', '{"fr":"Dans le noir"}', '{"fr":"Film d''horreur"}', '{"fr":"Date de sortie 24 août 2016\\n\\n(1h 21min)\\n\\nDe David F. Sandberg\\n\\nAvec Teresa Palmer, Maria Bello, Billy Burke plus\\n\\nGenre Epouvante-horreur\\n\\nNationalité Britannique\\n\\n### Synopsis et détails\\n\\n### Interdit aux moins de 12 ans\\n\\nUne famille en proie à une mystérieuse créature qui ne vit que dans le noir. Petite, Rebecca a toujours eu peur du noir. Mais quand elle est partie de chez elle, elle pensait avoir surmonté ses terreurs enfantines. Désormais, c''est au tour de son petit frère Martin d''être victime des mêmes phénomènes surnaturels qui ont failli lui faire perdre la raison. Car une créature terrifiante, mystérieusement liée à leur mère Sophie, rôde de nouveau dans la maison familiale. Cherchant à découvrir la vérité, Rebecca comprend que le danger est imminent… Surtout dans le noir.\\n\\nTitre original Lights Out\\n\\nDistributeur Warner Bros. France\\n\\n### lien bande annonce\\n\\n[http://www.allocine.fr/video/player_gen_cmedia=19564299&cfilm=238670.html](http://www.allocine.fr/video/player_gen_cmedia=19564299&cfilm=238670.html)"}', '{"fr":"dans le noir"}', NULL, '{"filename":"event_dans-le-noir_618010.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_dans-le-noir_618010.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_dans-le-noir_618010.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-09-23T19:00:00.000Z","end":"2016-09-23T20:25:00.000Z"},{"begin":"2016-09-24T20:00:00.000Z","end":"2016-09-24T21:25:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":8,"max":99}', '["0238448101"]', '2016-11-04 09:20:05', '2016-11-04 09:20:05', '2016-11-07 09:14:32' );
