(147544, 33021041, 15723194, NULL, 14232180, 'dans-les-pas-de-bazille', '{"fr":"Dans les pas de Bazille…"}', '{"fr":"Aquarelle et carnets de voyage"}', '{"fr":"En 1867, le peintre Frédéric Bazille séjournait à Aigues-Mortes pour dessiner la ville et ses fortifications. Il en a laissé un carnet de voyage d’où sont sortis ses trois tableaux représentant les fronts sud et ouest et la Porte de la Reine.\\n\\nVenez avec Dany, aquarelliste, découvrir les techniques du dessin et de l’aquarelle pour créer des carnets de souvenirs bien plus artistiques et personnels que les photos ou cartes postales..."}', '{"fr":"famille, animation, enfant, monument"}', NULL, '{"filename":"event_dans-les-pas-de-bazille_698809.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_dans-les-pas-de-bazille_698809.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_dans-les-pas-de-bazille_698809.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T08:00:00.000Z","end":"2016-10-22T11:00:00.000Z"},{"begin":"2016-10-23T08:00:00.000Z","end":"2016-10-23T11:00:00.000Z"},{"begin":"2016-10-22T12:00:00.000Z","end":"2016-10-22T14:30:00.000Z"},{"begin":"2016-10-23T12:00:00.000Z","end":"2016-10-23T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":6,"max":14}', '["04 66 53 95 50","http://www.aigues-mortes-monument.fr"]', '2016-11-04 09:18:27', '2016-11-04 09:18:27', NULL ),
(146116, 34093046, 36716187, 82480779, 5330611, 'dans-les-plis-de-mes-reves', '{"fr":"Dans les plis de mes rêves"}', '{"fr":"Mathilde Lechat propose un voyage sonore en résonance avec le champ sensoriel et émotionnel des tout-petits. Dans un espace poétique, la voix circule et le corps danse."}', '{"fr":"Conception artistique et création musicale Mathilde Lechat\\n\\nLe pli, de la matière qui ondule, se brise, se sculpte, est aussi un creux, un intérieur où se logent le mystère, le secret, l’inconnu, le rêve. Mathilde Lechat musicienne, chanteuse, conteuse et exploratrice de matières sonores interprète un solo de voix en mouvement, sous la forme d’un parcours au plus près des enfants. Pour cette création, l’artiste a passé plusieurs semaines de résidence dans des crèches afin d’observer leurs rituels et leur curiosité sonore. Nourrie de ces rencontres et s’appuyant sur sa pratique de la musique contemporaine, de l’improvisation et des musiques du monde, elle propose un voyage sonore en résonance avec le champ sensoriel et émotionnel des tout-petits. Dans un espace poétique, la voix circule et le corps danse."}', '{}', NULL, '{"filename":"event_dans-les-plis-de-mes-reves_510409.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_dans-les-plis-de-mes-reves_510409.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_dans-les-plis-de-mes-reves_510409.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-05T10:00:00.000Z","end":"2016-11-05T10:30:00.000Z"},{"begin":"2016-11-05T15:00:00.000Z","end":"2016-11-05T15:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":77}', '["0557936540","http://www.guichetnet.fr/pessac/index.html","kioque@mairie-pessac.fr"]', '2016-11-04 09:19:45', '2016-11-04 09:19:45', NULL ),
(145727, 57736504, 35786151, NULL, 80188014, 'danse-jours-etranges-de-dominique-bagouet-re-creation-par-catherine-legrand', '{"fr":"[Visuel / Boucles magnétiques / Vibrations] Jours étranges, de Dominique Bagouet / re-création par Catherine Legrand"}', '{"fr":"Spectacle de danse visuel mettant à disposition des boucles magnétiques."}', '{"fr":"**_La représentation bénéficie d''un système d''amplification sonore par le biais de boucles magnétiques disponibles gratuitement auprès de l''accueil. Une réservation quelques jours à l''avance est préférable._**\\n\\nCatherine Legrand a proposé à six interprètes, six femmes fortes et talentueuses, d''entrer dans l''écriture chorégraphique précise et inventive de _Jours étranges_ de Dominique Bagouet.\\n\\nRé-interprétation, exclusivement féminine donc, d''une pièce de répertoire sur la musique rock des Doors !"}', '{"fr":",       danse,       triangle,     boucles magnétiques,    jours,   étranges,  doors, mettre en scène"}', NULL, '{"filename":"event_danse-jours-etranges-de-dominique-bagouet-re-creation-par-catherine-legrand_643645.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_danse-jours-etranges-de-dominique-bagouet-re-creation-par-catherine-legrand_643645.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_danse-jours-etranges-de-dominique-bagouet-re-creation-par-catherine-legrand_643645.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-02T18:00:00.000Z","end":"2016-11-02T19:30:00.000Z"},{"begin":"2016-11-03T20:00:00.000Z","end":"2016-11-03T21:30:00.000Z"},{"begin":"2016-11-04T18:00:00.000Z","end":"2016-11-04T19:30:00.000Z"},{"begin":"2016-11-05T20:00:00.000Z","end":"2016-11-05T21:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":12}', '[]', '2016-11-04 09:20:03', '2016-11-04 09:20:03', NULL ),
(147558, 64571139, 15723194, NULL, 96889364, 'dansons-et-jouons-au-chateau-de-coucy', '{"fr":"Dansons et jouons au château de Coucy !"}', '{"fr":"Danse médiévale et marionnettes au château de Coucy..."}', '{"fr":"Petits et grands, venez replonger dans les divertissements et les amusements du Moyen-Âge par une initiation aux danses d’antan et par des spectacles de marionnettes.\\n\\nInitiation aux danses médiévales en continu pendant l’après-midi, de 14h à 17h.\\n\\nSpectacle de marionnettes « La Couronne du Roi Dagobert » à 14h30 et à 16h"}', '{"fr":"famille, animatin, enfant, monument"}', NULL, '{"filename":"event_dansons-et-jouons-au-chateau-de-coucy_432111.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_dansons-et-jouons-au-chateau-de-coucy_432111.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_dansons-et-jouons-au-chateau-de-coucy_432111.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-22T12:00:00.000Z","end":"2016-10-22T15:00:00.000Z"},{"begin":"2016-10-23T12:00:00.000Z","end":"2016-10-23T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":5,"max":14}', '["03 23 52 71 28","http://www.chateau-coucy.fr"]', '2016-11-04 09:18:26', '2016-11-04 09:18:26', NULL ),
(146081, 1591131, 57919484, NULL, 56922156, 'das-kapital-kind-of-red', '{"fr":"Das Kapital KIND OF RED"}', '{"fr":"concert"}', '{"fr":"Hasse Poulsen, guitare – préparation électronique\\n\\nDaniel Erdmann, saxophone ténor et soprano - électronique\\n\\nEdward Perraud, batterie - percussions – électronique\\n\\nConcert événement : le trio Das Kapital est devenu un groupe incontournable des scènes et festivals européens. Les trois musiciens qui le composent (Danois, Allemand et Français) signent leur 4e album, « Kind of red », en écho lointain au « Kind of blue» de Miles Davis.\\n\\n\\"On dit que le rock est mort. On dit que le jazz l''est aussi. On a enterré le socialisme. La liberté a été sécurisée. 68 est en retraite. On nous ordonne de divertir. On nous impose d''avoir peur et de se méfier d''autrui. Enfin... ce n''est pas vraiment notre genre\\" (Das Kapital).\\n\\nAdhésion jazz club 20€ / place adhérent 8€\\n\\nplace non adhérent 14€\\n\\nRESERVATIONS\\n\\nTél. +33 (0)1 48 13 70 00\\n\\nreservation@theatregerardp\\n\\nhilipe.com"}', '{"fr":", jazz"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-10T18:30:00.000Z","end":"2016-10-10T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":3,"max":99}', '[]', '2016-11-04 09:19:47', '2016-11-04 09:19:47', NULL ),
(146166, 56477452, 30061828, NULL, 99625330, 'data-objets-connectes-nouveaux-tresors-de-l-industrie', '{"fr":"Data & objets connectés nouveaux trésors de l''industrie"}', '{"fr":"Data & objets connectés nouveaux trésors de l''industrie"}', '{"fr":"Conférences, ateliers, stands autour des enjeux du digital dans l''Industrie.\\n\\nLe programme est en cours de finalisation et vous sera présenté très bientôt…\\n\\nCet évènement est soutenu par le Crédit Mutuel"}', '{}', NULL, '{"filename":"event_data-objets-connectes-nouveaux-tresors-de-l-industrie_611406.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_data-objets-connectes-nouveaux-tresors-de-l-industrie_611406.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_data-objets-connectes-nouveaux-tresors-de-l-industrie_611406.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-15T17:00:00.000Z","end":"2016-11-15T21:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":6,"max":12}', '[]', '2016-11-04 09:19:43', '2016-11-04 09:19:43', NULL ),
