(147153, 29709512, 98914664, NULL, 23826502, 'dave-johns_992', '{"fr":"DAVE JOHNS"}', '{"fr":"Stand-up comedy"}', '{"fr":"Karel Beer’s Laughing Matters présente le vrai stand-up comedy en VO avec des comiques reconnus qui pratiquent la langue de Robin des Bois.\\n\\nAvant d’être l''un des acteurs principaux du film Moi Daniel Blake de Ken Loach (Palme d’Or Cannes 2016), DAVE JOHNS menait déjà une carrière de stand-up comédien en Angleterre.\\n\\nSpectacle en anglais"}', '{"fr":"Stand-up comedy, SPECTACLE, HUMOUR, PARIS, LAJAVA"}', NULL, '{"filename":"event_dave-johns_992_295625.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_dave-johns_992_295625.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_dave-johns_992_295625.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-11-15T19:30:00.000Z","end":"2016-11-15T22:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":7,"max":18}', '[]', '2016-11-04 09:18:50', '2016-11-04 09:18:50', NULL ),
