(146774, 4354563, 7825239, NULL, 73714123, 'decouverte-des-hydrosytemes', '{"fr":"Découverte des hydrosystèmes"}', '{"fr":"A travers une maquette géante, découvrez comment se forment les rivières !"}', '{}', '{}', NULL, '{"filename":"event_decouverte-des-hydrosytemes_860738.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouverte-des-hydrosytemes_860738.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouverte-des-hydrosytemes_860738.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T07:00:00.000Z","end":"2016-10-13T15:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:11', '2016-11-04 09:19:11', NULL ),
(147291, 71477747, 65570947, 21475128, 88670536, 'decouverte-du-handball-et-valorisation-du-mondial-de-handball', '{"fr":"Découverte du handball et valorisation du mondial de Handball"}', '{"fr":"Animation de proximité sur les city-stade des quartiers prioritaires ou veille de la politique de la ville  du 24 au 28 octobre"}', '{"fr":"Date du projet : Du lundi 24 au vendredi 28 octobre\\n\\nHoraires du projet : De 14h00 à 16h30\\n\\nDéroulement du projet : Les quatre premiers jours vont permettre de faire découvrir le handball en initiant les enfants, les adolescents, les adultes aux spécificités de ce sport. Sur le dernier jour, un tournoi ludique pour les 10-17 ans sera organisé.\\n\\nObjectifs du projet :\\n\\nFavoriser la découverte du handball et valoriser l’évènement « championnat du monde de handball » Promouvoir le sport comme outil de santé Promouvoir le sport comme outil d’égalité notamment entre le public féminin et masculin\\n\\nLieu :\\n\\nLe lundi 24 octobre : city-stade du quartier Saint-Sauveur Le mardi 25 octobre : city-stade du quartier Saint-Michel Le mercredi 26 octobre : city-stade du quartier du Pont-Féron Le jeudi 27 octobre : gymnase Godard du complexe sportif Saint-Sauveur Le vendredi 28 octobre : gymnase Godard du complexe sportif Saint-Sauveur\\n\\nIntervenants :\\n\\nUn animateur de la Maison d’Activités Saint-Sauveur Un éducateur du club de handball de Flers"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-24T12:00:00.000Z","end":"2016-10-24T13:00:00.000Z"},{"begin":"2016-10-24T13:00:00.000Z","end":"2016-10-24T14:30:00.000Z"},{"begin":"2016-10-25T12:00:00.000Z","end":"2016-10-25T13:00:00.000Z"},{"begin":"2016-10-25T13:00:00.000Z","end":"2016-10-25T14:30:00.000Z"},{"begin":"2016-10-26T12:00:00.000Z","end":"2016-10-26T13:00:00.000Z"},{"begin":"2016-10-26T13:00:00.000Z","end":"2016-10-26T14:30:00.000Z"},{"begin":"2016-10-27T12:00:00.000Z","end":"2016-10-27T13:00:00.000Z"},{"begin":"2016-10-27T13:00:00.000Z","end":"2016-10-27T14:30:00.000Z"},{"begin":"2016-10-28T12:00:00.000Z","end":"2016-10-28T13:00:00.000Z"},{"begin":"2016-10-28T13:00:00.000Z","end":"2016-10-28T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":17}', '[]', '2016-11-04 09:18:42', '2016-11-04 09:18:42', NULL ),
(145633, 78596875, 96538699, NULL, 44155844, 'decouverte-du-handball-pour-des-eleves-de-quartier-prioritaire', '{"fr":"Découverte du handball pour des élèves de quartier prioritaire"}', '{"fr":"Permettre aux 53 élèves de la section handball d''un collège REP d''assister à un match du Mondial de handball"}', '{"fr":"Notre objectif principal est de favoriser un accès au sport pour tous.\\n\\nUn tel projet permettrait de promouvoir le handball chez les jeunes issus d''un quartier prioritaire, et scolarisés dans un collège classé REP. En effet, nous voyons au quotidien le sport comme un formidable instrument d’éducation populaire et d’intégration. Assister à un match de l''équipe de France peut sans aucun doute motiver et inspirer les élèves, et favoriser pour eux l''accès à une pratique sportive régulière. Participer à une manifestation sportive de cette envergure nous semble être un bon moyen pour ces jeunes de s’inscrire dans un parcours de réussite via l’identification à des sportifs de hauts niveaux."}', '{"fr":",   collège REP,   section handball,  quartier prioritaire"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-01-17T14:30:00.000Z","end":"2017-01-17T15:30:00.000Z"},{"begin":"2017-01-17T15:30:00.000Z","end":"2017-01-17T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":15}', '[]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
(146651, 53583605, 38565623, 27545135, 72989933, 'decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes', '{"fr":"Découverte du milieu marin de Martinique. Visite de 1h par groupe de 12 personnes"}', '{"fr":"Ecotourisme Nautique en Martinique"}', '{"fr":"Dénébola développe l’Ecotourisme Nautique en Martinique et propose de venir participer à ses ateliers pédagogiques sur les écosystèmes marins. Un premier échange sera fait sur l’écotourisme nautique (comment réduire notre impact sur le milieu marin lors de la pratique de loisirs nautiques : les éco-gestes, la réglementation, l’éconavigation...). Ensuite l’intervenant donnera quelques notions sur la navigation à la voile, à bord du voilier qui sera à quai, afin de partager avec le public cette passion pour une navigation plus douce et plus silencieuse. Puis, il présentera le CHATROU (outil pédagogique à bord du voilier) et le visiteur choisira parmi les 8 thèmes développés celui qui lui plait (poissons, coraux, tortues et cétacés, mollusques et crustacés, oiseaux marins, mangrove, 7ème continent et iguanes endémiques). Le CHATROU a été réalisé avec des partenaires spécialistes de chaque thème et a été conçu spécialement pour un public de loisir. C’est donc l’idéal pour enrichir ses connaissances tout en s’amusant !\\n\\nVisite de 1h par groupe de 12 personnes."}', '{"fr":",    Ecotourisme,    Nautisme,   Martinique, atelié pédagogique"}', NULL, '{"filename":"event_decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes_633546.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes_633546.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes_633546.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T09:00:00.000Z"},{"begin":"2016-10-15T09:00:00.000Z","end":"2016-10-15T10:00:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T13:00:00.000Z"},{"begin":"2016-10-15T13:00:00.000Z","end":"2016-10-15T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '["0696 170 700"]', '2016-11-04 09:19:18', '2016-11-04 09:19:18', NULL ),
(146687, 2875149, 38565623, 27545135, 64235133, 'decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma', '{"fr":"Découverte du pavillon pédagogique «Energies renouvelables» du RSMA"}', '{"fr":"Visite du pavillon pédagogique du RSMA"}', '{"fr":"Déroulement de la visite :\\n\\n- Départ en bus vers le site (le lieu de RDV sera communiqué à l’inscription).\\n\\n- Accueil du RSMA\\n\\n- Visite du pavillon pédagogique. Objectif : expliquer au visiteur le fonctionnement d’un chauffe-eau solaire,\\n\\n- Intervention des apprentis sur leur métier, leurs visions de la filière chauffe-eau solaire (solariste)\\n\\n- Présentation de la filière solaire en Martinique, les acteurs, la réglementation, les métiers, les dispositifs d’aides."}', '{"fr":"RSMA,  Energie solaire,  Energies renouvelables, Martinique"}', NULL, '{"filename":"event_decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma_877473.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma_877473.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma_877473.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-12T11:00:00.000Z","end":"2016-10-12T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":18,"max":99}', '["vie@pnr-martinique.com","0696 220 310"]', '2016-11-04 09:19:16', '2016-11-04 09:19:16', NULL ),
(146739, 1025581, 45388483, NULL, 20067179, 'decouvertes-des-metiers-du-chu', '{"fr":"Découvertes des Métiers du CHU"}', '{"fr":"Présentation des différentes métiers dans un CHU"}', '{"fr":"Conférences sur la relation entre alimentation et cancer, alimentation et la vision, l’alimentation chez les personnes agées, présentation des différents métiers du CHU."}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-10T07:00:00.000Z","end":"2016-10-10T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:13', '2016-11-04 09:19:13', NULL ),
(146447, 59481036, 54534699, NULL, 88599907, 'decouvrez-hololens-avec-infinite-square', '{"fr":"Découvrez HoloLens avec Infinite Square !"}', '{"fr":"#HoloLens #Réalitéaugmentée #Microsoft #Player"}', '{"fr":"Nous vous invitons à découvrir HoloLens, la technologie de réalité augmentée de Microsoft, au travers du programme suivant :\\n\\n- Présentation des différentes réalités\\n\\n- Qu’est-ce que HoloLens et comment ça marche ?\\n\\n- Les usages concrets de HoloLens\\n\\n- Comment développer sur HoloLens ?\\n\\n- Q&A Soyez attentifs, un petit quizz vous sera proposé en fin de session.\\n\\nLes 5 gagnants auront la possibilité de tester HoloLens !\\n\\nNous avons le plaisir d''accueillir : Jonathan ANTOINE. Jonathan ANTOINE est développeur .NET chez Infinite Square. Il est reconnu Microsoft MVP (Most Valuable Professional) dans la catégorie Développement d’applications Windows."}', '{}', NULL, '{"filename":"event_decouvrez-hololens-avec-infinite-square_768930.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-hololens-avec-infinite-square_768930.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-hololens-avec-infinite-square_768930.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-18T13:00:00.000Z","end":"2016-10-18T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '["https://intra.epitech.eu/module/2016/G-EPI-007/PAR-0-1/#!/all/Conference-4-Decouvrez-HoloLens-avec-Infinite-Square"]', '2016-11-04 09:19:29', '2016-11-04 09:19:29', NULL ),
(146462, 88161554, 23307857, NULL, 73924923, 'decouvrez-le-livre-le-plus-froid-du-monde', '{"fr":"Découvrez le livre le plus froid du monde"}', '{"fr":"Le livre qui vous dévoile en direct ses secrets et ses expériences à -196°C"}', '{"fr":"Avec la collaboration d’une étudiante en illustration scientifique, l’équipe **La Physique Autrement ** a créé le livre le plus froid du monde. Venez découvrir le résultat, à mi-chemin entre cuve à expériences, livre scientifique et recueil d''images !"}', '{"fr":"physique quantique, livre, conférence, froid"}', NULL, '{"filename":"event_decouvrez-le-livre-le-plus-froid-du-monde_258353.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-le-livre-le-plus-froid-du-monde_258353.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-le-livre-le-plus-froid-du-monde_258353.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T10:30:00.000Z","end":"2016-10-13T11:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '[]', '2016-11-04 09:19:28', '2016-11-04 09:19:28', NULL ),
(146160, 88181677, 14963029, NULL, 22263034, 'decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy', '{"fr":"Découvrez le nouveau film avec Pierre Niney en avant-première au Ciné d''Issy !"}', '{"fr":"Venez découvrir l''histoire de Jacques-Yves Cousteau au Ciné d''Issy/"}', '{"fr":"1948 : Jacques Cousteau, sa femme et ses deux fils, vivent au paradis dans une jolie maison surplombant la mer Méditerranée. Mais Cousteau ne rêve que d''aventure. Grâce à son invention, un scaphandre autonome qui permet de respirer sous l''eau, il a découvert un nouveau monde. Désormais, ce monde il va l''explorer. Et pour ça, il est prêt à tout sacrifier.\\n\\n[https://www.youtube.com/watch?v=Goy8YMc3KHg](https://www.youtube.com/watch?v=Goy8YMc3KHg)"}', '{}', NULL, '{"filename":"event_decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy_164509.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy_164509.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy_164509.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-09T14:30:00.000Z","end":"2016-10-09T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:43', '2016-11-04 09:19:43', NULL ),
(147604, 686270, 97862464, NULL, 87998085, 'decouvrez-les-coulisses-du-futur-musee-albert-kahn', '{"fr":"Découvrez les coulisses du futur Musée Albert-Kahn"}', '{"fr":"Visite inédite du site, jusqu''à la fin des travaux de rénovation"}', '{"fr":"MUSEE DEPARTEMENTAL ALBERT-KAHN\\n\\nPrélude d''un nouveau musée\\n\\nJusqu''à la fin des travaux de rénovation, le musée départemental Albert-Kahn propose au public de passer de l''autre côté des palissades et bénéficier d''une visite inédite du site, à travers une promenade en images dans le jardin. Pendant les travaux, le Département a choisi de ne pas fermer le site et de continuer d''accueillir le public, avec une offre inédite : découvrir l''envers du décor.\\n\\n A travers cette nouvelle expérience, le visiteur aura une occasion exceptionnelle de découvrir les coulisses du projet du musée et la préparation de la future offre culturelle proposée à partir de mars 2018\\\\. Le parcours proposé, uniquement sur réservation préalable, s''appuie sur une série d''images présentées en bouquets répartis sur le site : autochromes du jardin, photographies sur l''histoire du site et vues des bâtiments du nouveau musée, pour découvrir ou de redécouvrir Albert Kahn, son œuvre, la richesse des collections et le programme de rénovation. Ils permettent de visiter l''ensemble des scènes paysagères qui composent le jardin. Prenez-vite rendez-vous !\\n\\nInformations pratiques :\\n\\nMusée départemental Albert-Kahn\\n\\n10-14, rue du Port - 92100 Boulogne-Billancourt\\n\\nTél. : 01 55 19 28 00 - museealbertkahn@hauts-de-seine.fr - albert-kahn.hauts-de-seine.fr\\n\\nAccès au site: 1, rue des Abondances - 92100 Boulogne-Billancourt\\n\\nBilletterie : 1bis, rue des Abondances\\n\\nIndividuels\\n\\nDurée estimée de la visite : 1h30\\\\. Sur réservation uniquement.\\n\\nPromenade accompagnée d''un médiateur\\n\\nJusqu''au 30 avril\\n\\n-          Le samedi à 15h\\n\\n-          Le dimanche à 11h\\n\\n-          Le dimanche à 15h\\n\\nDu 1er mai au 30 septembre\\n\\n-          Le mardi à 15h\\n\\n-          Le vendredi à 15h\\n\\n-          Le samedi à 14h\\n\\n-          Le samedi à 16h30\\n\\n-          Le dimanche à 11h\\n\\n-          Le dimanche à 15h \\n\\nTarifs : 3 €, tarif réduit 1,50 €.\\n\\nGroupes\\n\\nOrganisation de visites sur mesure sur demande (minimum 10 personnes)\\n\\nTarifs  (minimum de 10 personnes) : 1,50 € par visiteur.\\n\\nInformations/réservations : accueilmak@hauts-de-seine.fr ou\\n\\naccueilmak@hauts-de-seine.fr ou 01 55 19 28 27"}', '{}', NULL, '{"filename":"event_decouvrez-les-coulisses-du-futur-musee-albert-kahn_351167.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-les-coulisses-du-futur-musee-albert-kahn_351167.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-les-coulisses-du-futur-musee-albert-kahn_351167.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-01-21T14:00:00.000Z","end":"2017-01-21T16:00:00.000Z"},{"begin":"2016-10-15T13:00:00.000Z","end":"2016-10-15T15:00:00.000Z"},{"begin":"2017-01-15T14:00:00.000Z","end":"2017-01-15T16:00:00.000Z"},{"begin":"2017-04-29T13:00:00.000Z","end":"2017-04-29T15:00:00.000Z"},{"begin":"2017-01-15T10:00:00.000Z","end":"2017-01-15T12:00:00.000Z"},{"begin":"2017-04-23T09:00:00.000Z","end":"2017-04-23T11:00:00.000Z"},{"begin":"2017-01-14T14:00:00.000Z","end":"2017-01-14T16:00:00.000Z"},{"begin":"2017-04-16T13:00:00.000Z","end":"2017-04-16T15:00:00.000Z"},{"begin":"2017-01-08T14:00:00.000Z","end":"2017-01-08T16:00:00.000Z"},{"begin":"2017-04-15T13:00:00.000Z","end":"2017-04-15T15:00:00.000Z"},{"begin":"2017-01-08T10:00:00.000Z","end":"2017-01-08T12:00:00.000Z"},{"begin":"2017-04-09T09:00:00.000Z","end":"2017-04-09T11:00:00.000Z"},{"begin":"2017-01-07T14:00:00.000Z","end":"2017-01-07T16:00:00.000Z"},{"begin":"2017-04-02T13:00:00.000Z","end":"2017-04-02T15:00:00.000Z"},{"begin":"2017-01-01T14:00: