(146384, 59564802, 69068533, NULL, 32688175, 'decouvrir-l-architecture-de-son-ecole', '{"fr":"\\"Découvrir l''architecture de son école\\""}', '{"fr":"\\"Apprendre à voir\\" l''architecture et développer la curiosité sur le sujet de l’architecture à partir de l''observation de l''architecture de son école."}', '{"fr":"Attention : atelier sur le temps scolaire, uniquement pour les élèves de CM1 et CM2 de l''école Brizeux.\\n\\n**Pour plus d''information voir sur le site du Caue 56**\\n\\nLe Caue 56 propose un atelier de découverte de l''architecture.  Animée par Heleen Statius Muller, historienne de l’art et chargée de mission au caue 56, les deux classes de CM1 et CM2 vont découvrir l''architecture de leur école à travers leurs dessins d''observations mais aussi une maquette, les plans d''archives et l''histoire de sa construction.\\n\\nCe groupe scolaire de 1958/62 constitue un beau terrain d’initiation à la culture architecturale moderne.\\n\\nAujourd’hui, le groupe scolaire Brizeux se situe dans le quartier Nord Gare en restructuration urbaine."}', '{"fr":"architecture scolaire, atelier pédagogique, sensibilisation culture architecturale"}', NULL, '{"filename":"event_decouvrir-l-architecture-de-son-ecole_900031.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrir-l-architecture-de-son-ecole_900031.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrir-l-architecture-de-son-ecole_900031.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-14T06:30:00.000Z","end":"2016-10-14T07:30:00.000Z"},{"begin":"2016-10-14T07:30:00.000Z","end":"2016-10-14T08:30:00.000Z"},{"begin":"2016-10-14T08:30:00.000Z","end":"2016-10-14T09:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":16}', '["http://www.caue56.fr/sensibilisation-architecture-milieu-scolaire-morbihan-1/","http://www.caue56.fr/histoire-des-arts-ecole-morbihan-1/"]', '2016-11-04 09:19:33', '2016-11-04 09:19:33', '2016-11-07 09:14:32' );
